(globalThis.TURBOPACK||(globalThis.TURBOPACK=[])).push(["object"==typeof document?document.currentScript:void 0,73493,91524,e=>{"use strict";e.s(["EIKEN_PRE1_VOCAB",0,[{word:"abide",meaning:"従う、耐える",example:"All employees must abide by the company rules.",category:"society",difficulty:4,examples:[{en:"I will abide by the rules of the organization.",ja:"私はその組織のルールに従います。",wrong:["私はそのルールを破ります。","私はそのルールに反対します。","私はそのルールを無視します。"]},{en:"She cannot abide the cold weather.",ja:"彼女は寒い天気に耐えられません。",wrong:["彼女は寒い天気を楽しみます。","彼女は寒い天気が好きです。","彼女は寒い天気を求めています。"]},{en:"They decided to abide in the mountains for the summer.",ja:"彼らは夏の間、山に住むことに決めました。",wrong:["彼らは山から離れることに決めました。","彼らは山を避けることに決めました。","彼らは山を去ることに決めました。"]}]},{word:"abstract",meaning:"抽象的な",example:"The concept was too abstract for the students to grasp.",category:"science",difficulty:4,examples:[{en:"The painting was completely abstract with no recognizable shapes.",ja:"その絵画は認識できる形のない完全に抽象的でした。",wrong:["その絵画は非常に具体的で詳細でした。","その絵画は現実的で正確でした。","その絵画は写実的で明確でした。"]},{en:"Please abstract the main points from the document.",ja:"ドキュメントから主要なポイントを抽出してください。",wrong:["ドキュメントにポイントを追加してください。","ドキュメントをすべて読んでください。","ドキュメントを隠してください。"]},{en:"The abstract concept of justice is difficult to define.",ja:"正義の抽象的な概念は定義するのが難しいです。",wrong:["正義の具体的な例は定義するのが難しいです。","正義の明確な意味は理解しやすいです。","正義の実際の形態は変わりません。"]}]},{word:"absurd",meaning:"不合理な、ばかげた",example:"The proposal was dismissed as absurd.",category:"society",difficulty:3,examples:[{en:"His idea to paint the house purple was absolutely absurd.",ja:"家を紫色に塗るという彼のアイデアは完全にばかげていました。",wrong:["彼のアイデアは非常に実用的でした。","彼のアイデアは素晴らしい提案でした。","彼のアイデアは慎重に計画されていました。"]},{en:"It is absurd to think we can finish this project in one day.",ja:"このプロジェクトを1日で完了できると考えるのは不合理です。",wrong:["このプロジェクトを1日で完了するのは簡単です。","このプロジェクトを1日で完了するのは可能です。","このプロジェクトを1日で完了するのは現実的です。"]},{en:"The absurd rules made no sense to anyone.",ja:"そのばかげたルールは誰にも意味がありませんでした。",wrong:["その合理的なルールは誰もが理解していました。","その明確なルールは完璧に説明されていました。","その論理的なルールは誰もが同意していました。"]}]},{word:"abundant",meaning:"豊富な",example:"The region is abundant in natural resources.",category:"science",difficulty:3,examples:[{en:"The region has abundant natural resources.",ja:"その地域は豊富な天然資源を持っています。",wrong:["その地域は限定的な天然資源を持っています。","その地域は不足している天然資源を持っています。","その地域はほとんど天然資源がありません。"]},{en:"There was abundant evidence to support the theory.",ja:"その理論を支持する豊富な証拠がありました。",wrong:["その理論を支持する証拠が不足していました。","その理論に反対する証拠がありました。","その理論を支持する証拠はありませんでした。"]},{en:"The harvest was abundant this year.",ja:"今年の収穫は豊富でした。",wrong:["今年の収穫は貧弱でした。","今年の収穫は失敗に終わりました。","今年の収穫は不十分でした。"]}]},{word:"acknowledge",meaning:"認める、感謝する",example:"She acknowledged the contribution of her colleagues.",category:"society",difficulty:3,examples:[{en:"I acknowledge your hard work and dedication.",ja:"あなたの懸命な仕事と献身を認めます。",wrong:["あなたの努力を無視します。","あなたの仕事を否定します。","あなたの貢献を認識しません。"]},{en:"She acknowledged the letter by sending a reply.",ja:"彼女は返信を送ってその手紙を受け取ったことを認めました。",wrong:["彼女はその手紙を読まずに捨てました。","彼女はその手紙を無視して返信しませんでした。","彼女はその手紙の受け取りを否定しました。"]},{en:"The government finally acknowledged the problem.",ja:"政府はついにその問題を認めました。",wrong:["政府はその問題を否定しました。","政府はその問題を隠し続けました。","政府はその問題の存在を否認しました。"]}]},{word:"acquisition",meaning:"取得、習得",example:"Language acquisition begins in early childhood.",category:"science",difficulty:4,examples:[{en:"The acquisition of new skills takes time and practice.",ja:"新しいスキルの習得には時間と練習が必要です。",wrong:["新しいスキルを失うことは時間がかかります。","新しいスキルの忘却には練習が必要です。","新しいスキルの放棄には献身が必要です。"]},{en:"The company's acquisition of a competitor was controversial.",ja:"その会社の競合他社の買収は物議を醸しました。",wrong:["その会社の競合他社への売却は歓迎されました。","その会社の競合他社からの分離は論争的でした。","その会社の競合他社への譲渡は簡単でした。"]},{en:"His acquisition of wealth came from inheritance.",ja:"彼の富の獲得は相続からきました。",wrong:["彼の富の喪失は相続からきました。","彼の貧困は相続の結果です。","彼の金銭の浪費は相続からきました。"]}]},{word:"acute",meaning:"鋭い、深刻な",example:"There is an acute shortage of trained nurses.",category:"society",difficulty:4,examples:[{en:"She has an acute sense of hearing.",ja:"彼女は鋭い聴覚を持っています。",wrong:["彼女は聴覚が鈍いです。","彼女は耳が聞こえません。","彼女の聴覚は劣っています。"]},{en:"The acute shortage of water caused a crisis.",ja:"深刻な水不足が危機を引き起こしました。",wrong:["水の豊富さが危機を引き起こしました。","水の十分な供給が問題を引き起こしました。","水の余剰が緊急事態を引き起こしました。"]},{en:"He suffered from acute pain in his back.",ja:"彼は背中に鋭い痛みを感じていました。",wrong:["彼は背中にわずかな不快感を感じていました。","彼は背中の痛みが完全に治っていました。","彼は背中に慢性的な痛みを感じていました。"]}]},{word:"adhere",meaning:"固守する、付着する",example:"Students must adhere to the dress code.",category:"society",difficulty:4,examples:[{en:"The students must adhere to the school's code of conduct.",ja:"学生は学校の行動規範に従わなければなりません。",wrong:["学生は学校の行動規範に反抗しなければなりません。","学生は学校の行動規範を無視しなければなりません。","学生は学校の行動規範を破棄しなければなりません。"]},{en:"The sticker will adhere to any smooth surface.",ja:"そのステッカーは滑らかなどの表面にも付着します。",wrong:["そのステッカーは表面から簡単に剥がれます。","そのステッカーはどの表面にも付着しません。","そのステッカーはすぐに落ちます。"]},{en:"She adheres to her principles no matter what.",ja:"彼女はどんなことがあっても彼女の原則に固守しています。",wrong:["彼女は彼女の原則を簡単に変えます。","彼女は彼女の信念を容易に放棄します。","彼女は彼女の価値観に背きます。"]}]},{word:"adolescent",meaning:"青年期の",example:"Adolescent behaviour can be unpredictable.",category:"science",difficulty:4,examples:[{en:"Adolescent behavior can be unpredictable and moody.",ja:"青年期の行動は予測不可能で気分が変わりやすいです。",wrong:["幼児の行動は予測不可能で気分が変わりやすいです。","成人の行動は常に予測可能で安定しています。","老齢の人の行動は気まぐれです。"]},{en:"Many adolescents struggle with their identity.",ja:"多くの青少年はアイデンティティで悩んでいます。",wrong:["多くの子供は自分のアイデンティティについて完全に確実です。","多くの成人は自分のアイデンティティを失っています。","多くの若者は自分が誰であるかを完全に知っています。"]},{en:"Adolescent development involves physical and emotional changes.",ja:"青年期の発達には身体的および感情的な変化が含まれます。",wrong:["幼児期の発達は変化がありません。","成人期の発達は身体的な変化を伴いません。","老年期の発達は急速です。"]}]},{word:"adverse",meaning:"不利な、有害な",example:"Adverse weather conditions delayed the flight.",category:"current",difficulty:4,examples:[{en:"The adverse weather conditions delayed the flight.",ja:"有害な天気条件がフライトを遅延させました。",wrong:["有利な天気条件がフライトを遅延させました。","良い天気がフライトをキャンセルしました。","穏やかな状況が飛行を妨害しました。"]},{en:"The drug had adverse effects on some patients.",ja:"その薬は一部の患者に有害な影響を与えました。",wrong:["その薬はすべての患者に有益な効果を与えました。","その薬は治療効果をもたらしました。","その薬は患者に何の影響も与えませんでした。"]},{en:"Despite adverse circumstances, she succeeded.",ja:"不利な状況にもかかわらず、彼女は成功しました。",wrong:["有利な状況のため、彼女は失敗しました。","良い条件により、彼女は何もできませんでした。","好ましい環境で、彼女は挫折しました。"]}]},{word:"affiliate",meaning:"提携する、関連会社",example:"The clinic is affiliated with a major hospital.",category:"society",difficulty:4,examples:[{en:"The company decided to affiliate with a larger corporation.",ja:"その会社はより大きな企業と提携することに決めました。",wrong:["その会社は他の企業との関係を断ち切ることに決めました。","その会社は独立したままでいることに決めました。","その会社は競合他社と対抗することに決めました。"]},{en:"She is an affiliate member of the professional organization.",ja:"彼女は専門組織の関連会社のメンバーです。",wrong:["彼女はその組織から除外されています。","彼女は主要なメンバーではなく、関連性がありません。","彼女はその組織と全く無関係です。"]},{en:"The university has several international affiliates.",ja:"その大学には複数の国際的な関連機関があります。",wrong:["その大学は他の機関と関係がありません。","その大学は独立した機関です。","その大学は他の機関と提携していません。"]}]},{word:"aggravate",meaning:"悪化させる",example:"Pollution aggravates respiratory problems.",category:"science",difficulty:4,examples:[{en:"The heavy rain will aggravate the flooding problem.",ja:"大雨は洪水問題を悪化させるでしょう。",wrong:["大雨は洪水問題を改善するでしょう。","大雨は洪水の状況を良くするでしょう。","大雨は洪水を解決するでしょう。"]},{en:"His constant complaining aggravated everyone.",ja:"彼の絶え間ない不平は皆をイライラさせました。",wrong:["彼の黙っていることは皆を喜ばせました。","彼の肯定的な態度は皆を慰めました。","彼の親切な言葉は皆を幸せにしました。"]},{en:"Stress can aggravate existing health conditions.",ja:"ストレスは既存の健康状態を悪化させることができます。",wrong:["ストレスは既存の健康状態を改善できます。","ストレスは病気を治すことができます。","ストレスは健康を向上させます。"]}]},{word:"agile",meaning:"機敏な",example:"Cats are incredibly agile creatures.",category:"science",difficulty:3,examples:[{en:"The agile dancer moved gracefully across the stage.",ja:"機敏なダンサーは舞台を優雅に移動しました。",wrong:["のろいダンサーは舞台を動かずに立っていました。","不器用なダンサーは舞台で転びました。","硬いダンサーは動くのが困難でした。"]},{en:"The company adopted an agile approach to project management.",ja:"その会社はプロジェクト管理に機敏なアプローチを採用しました。",wrong:["その会社は厳格で融通性のない方法を採用しました。","その会社は遅く、応答性の低い戦略を採用しました。","その会社は非効率で不器用なプロセスを採用しました。"]},{en:"The agile mind quickly adapts to new situations.",ja:"機敏な心は新しい状況にすばやく適応します。",wrong:["硬い心は新しい状況に適応できません。","遅い心は変化に対応できません。","柔軟性のない心は新しい考えを受け入れません。"]}]},{word:"allege",meaning:"主張する（証拠なく）",example:"He alleged that the contract had been forged.",category:"society",difficulty:4,examples:[{en:"The witness alleged that she saw the suspect at the scene.",ja:"目撃者は現場で被疑者を見たと主張しました。",wrong:["目撃者は確実に被疑者の有罪を証明しました。","目撃者は被疑者がそこにいなかったと証言しました。","目撃者は確実な証拠を提供しました。"]},{en:"The report alleges that the company violated environmental regulations.",ja:"報告書は会社が環境規制に違反したと主張しています。",wrong:["報告書は会社が全ての規制に従ったことを証明しています。","報告書は会社の合法性を確認しています。","報告書は違反の証拠を提供しています。"]},{en:"He alleged without proof that his neighbor stole his tools.",ja:"彼は証拠なく隣人が彼のツールを盗んだと主張しました。",wrong:["彼は隣人の無罪を証明しました。","彼は法廷で有罪判決を下しました。","彼は確実な証拠で隣人を告発しました。"]}]},{word:"alliance",meaning:"同盟",example:"The two nations formed a strategic alliance.",category:"history",difficulty:3,examples:[{en:"The two countries formed a military alliance.",ja:"2つの国は軍事同盟を形成しました。",wrong:["2つの国は戦争を宣言しました。","2つの国は敵対する関係を結びました。","2つの国は独立を保つことに合意しました。"]},{en:"The alliance between the environmental groups strengthened their cause.",ja:"環境グループ間の同盟は彼らの大義を強化しました。",wrong:["グループ間の対立は彼らの目標を弱めました。","グループの分裂は彼らの力を増しました。","グループの敵対は彼らの影響力を高めました。"]},{en:"They entered into a strategic alliance to compete with larger companies.",ja:"彼らはより大きな企業と競争するために戦略的同盟を結びました。",wrong:["彼らは競争を避けるために分離しました。","彼らは他の企業との関係を断ち切ることを決めました。","彼らは孤立したままでいることを選びました。"]}]},{word:"alongside",meaning:"〜と並んで",example:"She worked alongside experienced engineers.",category:"society",difficulty:3,examples:[{en:"The new building stands alongside the old one.",ja:"新しい建物は古い建物と並んで立っている。",wrong:["新しい建物は古い建物の中に立っている。","新しい建物は古い建物より下に立っている。","新しい建物は古い建物を通り抜けている。"]},{en:"She worked alongside her colleagues to complete the project.",ja:"彼女は同僚と並んで働いてプロジェクトを完成させた。",wrong:["彼女は同僚の下で働いてプロジェクトを完成させた。","彼女は同僚に対抗して働いてプロジェクトを完成させた。","彼女は同僚なしで働いてプロジェクトを完成させた。"]},{en:"Innovation must go alongside tradition.",ja:"革新は伝統と並んで進まなければならない。",wrong:["革新は伝統に置き換わらなければならない。","革新は伝統の後ろにいなければならない。","革新は伝統を完全に消す必要がある。"]}]},{word:"alter",meaning:"変える",example:"The accident altered the course of his life.",category:"society",difficulty:3,examples:[{en:"The tailor will alter your pants to fit better.",ja:"仕立屋があなたのズボンをより良くフィットするように変えます。",wrong:["仕立屋があなたのズボンを破壊します。","仕立屋があなたのズボンを色褪せさせます。","仕立屋があなたのズボンを洗います。"]},{en:"The weather altered our plans for the picnic.",ja:"天気がピクニックの計画を変えました。",wrong:["天気がピクニックを確認しました。","天気がピクニックを安全にしました。","天気がピクニックを始めました。"]},{en:"Do not alter the documents without permission.",ja:"許可なしに文書を変えてはいけません。",wrong:["許可なしに文書を読んではいけません。","許可なしに文書を保管してはいけません。","許可なしに文書を見てはいけません。"]}]},{word:"ambiguity",meaning:"曖昧さ",example:"The law is open to ambiguity in several areas.",category:"society",difficulty:5,examples:[{en:"The ambiguity in the contract led to disputes.",ja:"契約の曖昧さが紛争につながった。",wrong:["契約の透明性が紛争につながった。","契約の詳細さが紛争につながった。","契約の公開性が紛争につながった。"]},{en:"Her statement was full of ambiguity.",ja:"彼女の声明は曖昧さでいっぱいだった。",wrong:["彼女の声明は真実でいっぱいだった。","彼女の声明は明確さでいっぱいだった。","彼女の声明は証拠でいっぱいだった。"]},{en:"The ambiguity of the law makes enforcement difficult.",ja:"法律の曖昧さが執行を困難にします。",wrong:["法律の厳密さが執行を困難にします。","法律の詳細さが執行を困難にします。","法律の明確さが執行を困難にします。"]}]},{word:"amend",meaning:"修正する",example:"Parliament voted to amend the constitution.",category:"society",difficulty:4,examples:[{en:"Congress voted to amend the constitution.",ja:"議会は憲法を修正することに投票した。",wrong:["議会は憲法を廃止することに投票した。","議会は憲法を作成することに投票した。","議会は憲法を翻訳することに投票した。"]},{en:"We need to amend our approach to this problem.",ja:"この問題へのアプローチを修正する必要があります。",wrong:["この問題へのアプローチを忘れる必要があります。","この問題へのアプローチを拒否する必要があります。","この問題へのアプローチを繰り返す必要があります。"]},{en:"She asked me to amend my mistake in the report.",ja:"彼女はレポートの間違いを修正するよう頼んだ。",wrong:["彼女はレポートの間違いを隠すよう頼んだ。","彼女はレポートの間違いを強調するよう頼んだ。","彼女はレポートの間違いを受け入れるよう頼んだ。"]}]},{word:"ample",meaning:"十分な、豊富な",example:"There is ample evidence to support the theory.",category:"science",difficulty:3,examples:[{en:"There is ample time to complete the assignment.",ja:"課題を完成させるための十分な時間があります。",wrong:["課題を完成させるための限定的な時間があります。","課題を完成させるための不足している時間があります。","課題を完成させるための短い時間があります。"]},{en:"The garden has ample space for flowers.",ja:"庭は花のための十分なスペースがあります。",wrong:["庭は花のための狭いスペースがあります。","庭は花のための限定的なスペースがあります。","庭は花のための不十分なスペースがあります。"]},{en:"We have ample resources to handle this project.",ja:"このプロジェクトを処理するための十分なリソースがあります。",wrong:["このプロジェクトを処理するための限定的なリソースがあります。","このプロジェクトを処理するための欠けているリソースがあります。","このプロジェクトを処理するための不足しているリソースがあります。"]}]},{word:"annex",meaning:"併合する、付属建物",example:"The country annexed the neighbouring territory.",category:"history",difficulty:5,examples:[{en:"The country decided to annex the neighboring territory.",ja:"その国は隣接する領土を併合することにした。",wrong:["その国は隣接する領土を訪問することにした。","その国は隣接する領土を放棄することにした。","その国は隣接する領土を放棄することにした。"]},{en:"The building has an annex for storage.",ja:"建物は保管用の付属建物があります。",wrong:["建物は保管用のメインホールがあります。","建物は保管用のロビーがあります。","建物は保管用の塔があります。"]},{en:"The university will annex the new research facility.",ja:"大学は新しい研究施設を併合します。",wrong:["大学は新しい研究施設を破壊します。","大学は新しい研究施設を売却します。","大学は新しい研究施設を閉鎖します。"]}]},{word:"anonymous",meaning:"匿名の",example:"The donation was made by an anonymous benefactor.",category:"society",difficulty:3,examples:[{en:"He made an anonymous donation to the charity.",ja:"彼は慈善団体に匿名で寄付した。",wrong:["彼は慈善団体に公開で寄付した。","彼は慈善団体に署名入りで寄付した。","彼は慈善団体に有名人として寄付した。"]},{en:"The anonymous author won the literary prize.",ja:"匿名の著者が文学賞を受賞した。",wrong:["著名な著者が文学賞を受賞した。","有名な著者が文学賞を受賞した。","識別可能な著者が文学賞を受賞した。"]},{en:"The survey allows anonymous responses.",ja:"調査は匿名での回答を許可しています。",wrong:["調査は公開での回答を許可しています。","調査は署名入りの回答を許可しています。","調査は個人識別の回答を許可しています。"]}]},{word:"anthropology",meaning:"人類学",example:"She studied anthropology at university.",category:"science",difficulty:5,examples:[{en:"She studied anthropology to understand different cultures.",ja:"彼女は異なる文化を理解するために人類学を勉強した。",wrong:["彼女は異なる文化を理解するために地質学を勉強した。","彼女は異なる文化を理解するために天文学を勉強した。","彼女は異なる文化を理解するために心理学を勉強した。"]},{en:"Anthropology examines human societies and their customs.",ja:"人類学は人間社会とその習慣を検査します。",wrong:["動物学は人間社会とその習慣を検査します。","言語学は人間社会とその習慣を検査します。","考古学は人間社会とその習慣を検査します。"]},{en:"The anthropology professor conducted fieldwork in Africa.",ja:"人類学の教授はアフリカでフィールドワークを行った。",wrong:["生物学の教授はアフリカでフィールドワークを行った。","化学の教授はアフリカでフィールドワークを行った。","物理学の教授はアフリカでフィールドワークを行った。"]}]},{word:"appease",meaning:"なだめる",example:"The manager tried to appease the angry customer.",category:"society",difficulty:5,examples:[{en:"The government tried to appease the angry protesters.",ja:"政府は怒ったデモ参加者をなだめようとした。",wrong:["政府は怒ったデモ参加者を逮捕しようとした。","政府は怒ったデモ参加者を無視しようとした。","政府は怒ったデモ参加者を挑発しようとした。"]},{en:"She gave him a snack to appease his hunger.",ja:"彼女は彼の空腹をなだめるために彼にスナックをあげた。",wrong:["彼女は彼の空腹を増やすために彼にスナックをあげた。","彼女は彼の空腹を無視するために彼にスナックをあげた。","彼女は彼の空腹を悪化させるために彼にスナックをあげた。"]},{en:"The company offered discounts to appease dissatisfied customers.",ja:"会社は不満の顧客をなだめるために割引を提供した。",wrong:["会社は不満の顧客を怒らせるために割引を提供した。","会社は不満の顧客を失望させるために割引を提供した。","会社は不満の顧客を傷つけるために割引を提供した。"]}]},{word:"appraise",meaning:"評価する、査定する",example:"An expert was called to appraise the painting.",category:"culture",difficulty:4,examples:[{en:"The appraiser will appraise the value of your property.",ja:"鑑定士があなたの財産の価値を評価します。",wrong:["鑑定士があなたの財産を破壊します。","鑑定士があなたの財産を売却します。","鑑定士があなたの財産を購入します。"]},{en:"The manager will appraise the employee's performance.",ja:"マネージャーは従業員のパフォーマンスを評価します。",wrong:["マネージャーは従業員のパフォーマンスを無視します。","マネージャーは従業員のパフォーマンスを隠します。","マネージャーは従業員のパフォーマンスを否定します。"]},{en:"We need to appraise the damage from the storm.",ja:"嵐からのダメージを評価する必要があります。",wrong:["嵐からのダメージを修復する必要があります。","嵐からのダメージを隠す必要があります。","嵐からのダメージを加える必要があります。"]}]},{word:"apprehend",meaning:"逮捕する、理解する",example:"Police apprehended the suspect within hours.",category:"society",difficulty:5,examples:[{en:"The police will apprehend the criminal.",ja:"警察は犯人を逮捕します。",wrong:["警察は犯人を釈放します。","警察は犯人を見落とします。","警察は犯人を支援します。"]},{en:"I apprehend the danger of this situation.",ja:"私はこの状況の危険を理解しています。",wrong:["私はこの状況の安全性を理解しています。","私はこの状況を無視しています。","私はこの状況を誤解しています。"]},{en:"Do you apprehend what I am saying?",ja:"私が言っていることを理解していますか？",wrong:["私が言っていることを忘れていますか？","私が言っていることを否定していますか？","私が言っていることを拒否していますか？"]}]},{word:"archive",meaning:"記録保管所、保存する",example:"Historical documents are stored in the national archive.",category:"history",difficulty:4,examples:[{en:"The library will archive all the old documents.",ja:"図書館はすべての古い文書を保存します。",wrong:["図書館はすべての古い文書を破壊します。","図書館はすべての古い文書を売却します。","図書館はすべての古い文書を焼却します。"]},{en:"She works in the university archive.",ja:"彼女は大学の記録保管所で働いています。",wrong:["彼女は大学の図書館で働いています。","彼女は大学の学食で働いています。","彼女は大学の美術館で働いています。"]},{en:"We should archive this email for future reference.",ja:"将来の参照のためにこのメールを保存すべきです。",wrong:["将来の参照のためにこのメールを削除すべきです。","将来の参照のためにこのメールを無視すべきです。","将来の参照のためにこのメールを忘れるべきです。"]}]},{word:"arid",meaning:"乾燥した",example:"Few plants can survive in arid climates.",category:"science",difficulty:4,examples:[{en:"The arid desert has very little water.",ja:"乾燥した砂漠は水がほとんどありません。",wrong:["湿った砂漠は水がほとんどありません。","湿润した砂漠は水がほとんどありません。","濡れた砂漠は水がほとんどありません。"]},{en:"The region has an arid climate.",ja:"その地域は乾燥した気候があります。",wrong:["その地域は湿った気候があります。","その地域は熱帯気候があります。","その地域は温帯気候があります。"]},{en:"Arid soil makes farming difficult.",ja:"乾燥した土壌は農業を困難にします。",wrong:["肥沃な土壌は農業を困難にします。","湿った土壌は農業を困難にします。","栄養豊富な土壌は農業を困難にします。"]}]},{word:"aspire",meaning:"熱望する",example:"Many young athletes aspire to compete in the Olympics.",category:"society",difficulty:3,examples:[{en:"She aspires to become a doctor.",ja:"彼女は医者になることを熱望しています。",wrong:["彼女は医者を避けることを熱望しています。","彼女は医者を否定することを熱望しています。","彼女は医者を恐れることを熱望しています。"]},{en:"Young athletes aspire to win Olympic medals.",ja:"若いアスリートはオリンピックメダルを獲得することを熱望しています。",wrong:["若いアスリートはオリンピックメダルを失うことを熱望しています。","若いアスリートはオリンピックに参加しないことを熱望しています。","若いアスリートは敗北することを熱望しています。"]},{en:"He aspires to make a difference in the world.",ja:"彼は世界に違いを作ることを熱望しています。",wrong:["彼は世界を破壊することを熱望しています。","彼は世界を無視することを熱望しています。","彼は世界を変えないことを熱望しています。"]}]},{word:"assault",meaning:"暴行、攻撃する",example:"The soldier was charged with assault.",category:"society",difficulty:3,examples:[{en:"The man was charged with assault.",ja:"その男は暴行で起訴された。",wrong:["その男は親切さで起訴された。","その男は援助で起訴された。","その男は保護で起訴された。"]},{en:"The enemy decided to assault the fort.",ja:"敵は砦を攻撃することを決めた。",wrong:["敵は砦を守ることを決めた。","敵は砦を退去することを決めた。","敵は砦を支援することを決めた。"]},{en:"The witness reported an assault on the street.",ja:"目撃者は通りでの暴行を報告した。",wrong:["目撃者は通りでの親切さを報告した。","目撃者は通りでの助け合いを報告した。","目撃者は通りでの平和を報告した。"]}]},{word:"assemble",meaning:"組み立てる、集める",example:"Workers assemble the cars on the production line.",category:"technology",difficulty:3,examples:[{en:"The workers will assemble the furniture according to the instructions.",ja:"作業員は指示に従って家具を組み立てます。",wrong:["家具を分解します。","家具を売却します。","家具を配達します。"]},{en:"A large crowd assembled in the town square to hear the speech.",ja:"大勢の群衆が演説を聞くために町の広場に集まりました。",wrong:["大勢の群衆が町の広場から散りました。","大勢の群衆が町を破壊しました。","大勢の群衆が町を去りました。"]},{en:"The company assembles electronic components in their factory.",ja:"その会社は工場で電子部品を組み立てています。",wrong:["その会社は電子部品を輸入しています。","その会社は電子部品を廃棄しています。","その会社は電子部品を販売しています。"]}]},{word:"assertion",meaning:"主張、断言",example:"His assertion lacked supporting evidence.",category:"society",difficulty:4,examples:[{en:"His assertion that he was innocent was not believed by the jury.",ja:"彼が無実であるという主張は陪審員に信じられませんでした。",wrong:["彼が有罪であるという証拠は陪審員に信じられました。","彼の無罪は陪審員によって認定されました。","彼が不当に扱われたという主張は受け入れられました。"]},{en:"The politician made a bold assertion about the economy's future.",ja:"その政治家は経済の将来について大胆な主張をしました。",wrong:["その政治家は経済について疑問を表明しました。","その政治家は経済について謝罪しました。","その政治家は経済について沈黙を守りました。"]},{en:"Despite the lack of evidence, she maintained her assertion.",ja:"証拠がないにもかかわらず、彼女は彼女の主張を維持しました。",wrong:["証拠がないため、彼女は彼女の主張を取り下げました。","彼女は証拠を提出しました。","彼女は沈黙しました。"]}]},{word:"asset",meaning:"資産、強み",example:"Her language skills are a valuable asset.",category:"society",difficulty:3,examples:[{en:"The company's main asset is its talented workforce.",ja:"その会社の主な強みは才能のある労働力です。",wrong:["その会社の主な負債は才能のある労働力です。","その会社の主な問題は労働力です。","その会社は労働力を必要としていません。"]},{en:"Real estate is considered a valuable asset for investors.",ja:"不動産は投資家にとって貴重な資産と見なされています。",wrong:["不動産は投資家にとって負債と見なされています。","不動産は価値がありません。","不動産は投資家を避けます。"]},{en:"Your communication skills are a great asset in this job.",ja:"あなたのコミュニケーション能力はこの仕事の大きな強みです。",wrong:["あなたのコミュニケーション能力はこの仕事に不利です。","あなたは話す能力がありません。","あなたのスキルは不要です。"]}]},{word:"assimilate",meaning:"同化する、吸収する",example:"Immigrants gradually assimilate into the culture.",category:"society",difficulty:5,examples:[{en:"Immigrants often take time to assimilate into their new culture.",ja:"移民は新しい文化に同化するのに時間がかかることがよくあります。",wrong:["移民は新しい文化を拒否します。","移民は元の文化を失いません。","移民は孤立したままです。"]},{en:"The body assimilates nutrients from the food we eat.",ja:"体は食べた食べ物から栄養を吸収します。",wrong:["体は食べ物から栄養を排出します。","体は栄養を必要としません。","体は食べ物を消化しません。"]},{en:"The company assimilated the new technologies into its operations.",ja:"その会社は新しい技術をその業務に吸収しました。",wrong:["その会社は新しい技術を拒否しました。","その会社は古い技術を使い続けています。","その会社は技術に興味がありません。"]}]},{word:"attain",meaning:"達成する",example:"She attained the highest grade in the exam.",category:"society",difficulty:3,examples:[{en:"Through hard work and determination, she attained her dream of becoming a doctor.",ja:"努力と決意を通じて、彼女は医者になるという夢を達成しました。",wrong:["彼女は医者になることを放棄しました。","彼女は医学の勉強をしませんでした。","彼女は医者になることを失敗しました。"]},{en:"The company attained record profits this year.",ja:"その会社は今年記録的な利益を達成しました。",wrong:["その会社は大きな損失を出しました。","その会社は利益を減らしました。","その会社は倒産しました。"]},{en:"Students must attain a passing grade to graduate.",ja:"学生は卒業するために合格点を達成する必要があります。",wrong:["学生は落第してもかまいません。","学生は試験を受ける必要がありません。","学生は低い成績で卒業できます。"]}]},{word:"attribute",meaning:"〜に帰する、属性",example:"The success was attributed to careful planning.",category:"society",difficulty:4,examples:[{en:"The detective attributed the crime to the suspect based on evidence.",ja:"刑事は証拠に基づいて犯罪を容疑者に帰しました。",wrong:["刑事は証拠がないのに容疑者を釈放しました。","刑事は犯罪を解決できませんでした。","刑事は犯人を見つけられませんでした。"]},{en:"Honesty is an important attribute of a good leader.",ja:"誠実さは良いリーダーの重要な属性です。",wrong:["不誠実さは良いリーダーの属性です。","リーダーは正直である必要がありません。","誠実さはリーダーシップに無関係です。"]},{en:"She attributed her success to her supportive family.",ja:"彼女は彼女の成功を支援的な家族に帰しました。",wrong:["彼女は自分の成功を否定しました。","彼女の家族は彼女を支援しませんでした。","彼女は成功について言及しませんでした。"]}]},{word:"audit",meaning:"監査する",example:"The firm was audited by the tax authority.",category:"society",difficulty:4,examples:[{en:"The company underwent a financial audit to ensure transparency.",ja:"その会社は透明性を確保するために財務監査を受けました。",wrong:["その会社は監査を避けました。","その会社は違法な会計を隠しました。","その会社は財務報告を提出しませんでした。"]},{en:"The auditor will audit all the company's financial records.",ja:"監査役はその会社の全ての財務記録を監査します。",wrong:["監査役は財務記録を無視します。","監査役は記録を改ざんします。","監査役は調査しません。"]},{en:"Students can audit a course without receiving a grade.",ja:"学生は成績を受け取らずにコースを監査できます。",wrong:["学生は監査コースで成績を取得する必要があります。","学生はコースに登録することができません。","学生は授業に参加できません。"]}]},{word:"augment",meaning:"増大させる",example:"Technology can augment human capabilities.",category:"technology",difficulty:5,examples:[{en:"The company decided to augment its workforce by hiring more employees.",ja:"その会社はより多くの従業員を雇うことによって労働力を増大させることに決めました。",wrong:["その会社は従業員を削減することに決めました。","その会社は採用を停止しました。","その会社はリストラを実施しました。"]},{en:"Virtual reality technology can augment the learning experience.",ja:"バーチャルリアリティ技術は学習体験を増大させることができます。",wrong:["バーチャルリアリティは学習を妨害します。","バーチャルリアリティは学習に役立ちません。","バーチャルリアリティは古い技術です。"]},{en:"The government plans to augment funding for education.",ja:"政府は教育への資金を増大させる計画です。",wrong:["政府は教育予算を削減します。","政府は教育に投資しません。","政府は教育資金を廃止します。"]}]},{word:"baffle",meaning:"困惑させる",example:"The mystery baffled investigators for decades.",category:"society",difficulty:4,examples:[{en:"The complex math problem baffled the students.",ja:"複雑な数学の問題は学生たちを困惑させました。",wrong:["学生たちは問題を簡単に解きました。","学生たちは問題を理解しました。","学生たちは明確な答えを知っていました。"]},{en:"The detective was baffled by the lack of evidence.",ja:"刑事は証拠の欠落に困惑しました。",wrong:["刑事は明確な証拠を見つけました。","刑事は事件をすぐに解決しました。","刑事は答えをすぐに知っていました。"]},{en:"Her unexplained absence baffled everyone in the office.",ja:"彼女の説明のない欠席はオフィスの誰もを困惑させました。",wrong:["彼女の不在は理由が明確でした。","誰もが彼女の理由を理解していました。","彼女は毎日出勤していました。"]}]},{word:"ballot",meaning:"投票",example:"Citizens cast their ballots in the general election.",category:"society",difficulty:4,examples:[{en:"Citizens cast their ballot in the presidential election.",ja:"市民は大統領選挙で投票しました。",wrong:["市民は投票できませんでした。","市民は選挙に参加しませんでした。","市民は候補者を選びませんでした。"]},{en:"The ballot contains the names of all candidates running for office.",ja:"投票用紙には立候補しているすべての候補者の名前が含まれています。",wrong:["投票用紙は候補者の名前を含みません。","投票用紙は白紙です。","投票用紙は候補者を隠します。"]},{en:"The company will hold a ballot to decide on the merger.",ja:"その会社は合併を決定するための投票を実施します。",wrong:["その会社は投票なしで決定を下します。","その会社は従業員の意見を求めません。","その会社は独裁的に決定します。"]}]},{word:"ban",meaning:"禁止する",example:"The city banned single-use plastic bags.",category:"current",difficulty:3,examples:[{en:"The government banned the production and sale of plastic bags.",ja:"政府はプラスチック袋の生産と販売を禁止しました。",wrong:["政府はプラスチック袋の使用を奨励しました。","政府はプラスチック袋の生産を支援しました。","政府はプラスチック袋を推奨しました。"]},{en:"The school banned the use of mobile phones during class.",ja:"学校は授業中の携帯電話の使用を禁止しました。",wrong:["学校は携帯電話の使用を許可しました。","学校は生徒に携帯電話を使うよう促しました。","学校は携帯電話を配布しました。"]},{en:"The athlete was banned from competition for doping violations.",ja:"その選手はドーピング違反により競技から禁止されました。",wrong:["その選手は競技を続けることが許可されました。","その選手はチャンピオンになりました。","その選手は賞を受けました。"]}]},{word:"bankrupt",meaning:"破産した",example:"The company went bankrupt after the scandal.",category:"society",difficulty:3,examples:[{en:"The company declared itself bankrupt after years of losses.",ja:"その会社は何年もの損失の後に破産を宣告しました。",wrong:["その会社は利益を上げました。","その会社は繁栄しています。","その会社は新しく設立されました。"]},{en:"Many small businesses went bankrupt during the economic crisis.",ja:"経済危機の間に多くの小企業が破産しました。",wrong:["多くの小企業は経済危機から利益を得ました。","小企業は危機中に成長しました。","小企業は投資を受けました。"]},{en:"He was declared bankrupt and had to liquidate all his assets.",ja:"彼は破産を宣告され、彼の全ての資産を清算する必要がありました。",wrong:["彼は裕福で多くの資産を所有していました。","彼は資産を売却する必要がありませんでした。","彼は金銭的に安全でした。"]}]},{word:"barren",meaning:"不毛の",example:"The explorers crossed a barren desert.",category:"science",difficulty:4,examples:[{en:"The desert landscape was barren and lifeless.",ja:"砂漠の景観は不毛で生命がありませんでした。",wrong:["砂漠は緑が茂っていました。","砂漠は豊かな植生に満ちていました。","砂漠は多くの動物で満ちていました。"]},{en:"After years of drought, the farmland became barren.",ja:"何年もの干ばつの後、農地は不毛になりました。",wrong:["農地は豊作を産みました。","農地は多くの作物を育てました。","農地は緑色に変わりました。"]},{en:"The barren trees showed no signs of life in winter.",ja:"冬に不毛な木々は生命の兆候を示しませんでした。",wrong:["木々は春に花が咲きました。","木々は緑の葉で満ちていました。","木々は果実を実らせました。"]}]},{word:"baseline",meaning:"基準線、基本",example:"Doctors measured his baseline blood pressure.",category:"science",difficulty:4,examples:[{en:"The study established a baseline measurement before the treatment began.",ja:"その研究は治療が始まる前にベースライン測定を確立しました。",wrong:["その研究は治療後に測定を開始しました。","その研究は初期測定をスキップしました。","その研究は基準を設定しませんでした。"]},{en:"We need to establish a baseline for comparison.",ja:"比較のための基準線を確立する必要があります。",wrong:["私たちは比較を避けるべきです。","私たちは標準を設定する必要がありません。","私たちは測定をスキップしましょう。"]},{en:"The baseline data shows significant improvements after six months.",ja:"ベースラインデータは6ヶ月後の大幅な改善を示しています。",wrong:["初期データは改善を示していません。","データは悪化を示しています。","データには変化がありません。"]}]},{word:"benevolent",meaning:"慈悲深い",example:"The benevolent donor funded the orphanage.",category:"society",difficulty:5,examples:[{en:"The benevolent philanthropist donated millions to charity.",ja:"その慈悲深い慈善家は慈善事業に何百万ドルも寄付しました。",wrong:["その慈善家はお金を寄付しませんでした。","その慈善家はお金をため込みました。","その慈善家は慈善活動を反対していました。"]},{en:"The king was known for his benevolent policies toward the poor.",ja:"その王は貧困者に対する慈悲深い政策で知られていました。",wrong:["その王は貧困者を抑圧しました。","その王は冷酷な統治者でした。","その王は貧困者を無視しました。"]},{en:"A benevolent organization provides free medical services to underprivileged communities.",ja:"慈悲深い組織は恵まれない地域に無料の医療サービスを提供します。",wrong:["その組織は貧困地域を支援しません。","その組織は医療サービスを拒否しています。","その組織は利益を独占しています。"]}]},{word:"bilateral",meaning:"二国間の",example:"The two countries signed a bilateral trade agreement.",category:"society",difficulty:5,examples:[{en:"The two countries signed a bilateral trade agreement.",ja:"2つの国は二国間の貿易協定に署名した。",wrong:["一方的な貿易協定に署名した。","多国間の貿易協定に署名した。","片側の貿易協定に署名した。"]},{en:"Bilateral negotiations between the US and China are ongoing.",ja:"米国と中国の間の二国間交渉が進行中である。",wrong:["米国と複数の国との交渉が進行中である。","一方的な交渉が進行中である。","米国内の交渉が進行中である。"]},{en:"This bilateral agreement benefits both nations equally.",ja:"この二国間協定は両国に等しく利益をもたらす。",wrong:["この一方的な協定は一国に利益をもたらす。","この多国間協定は複数の国に利益をもたらす。","この片側の協定は片方の国だけに利益をもたらす。"]}]},{word:"blunt",meaning:"鈍い、率直な",example:"She was blunt in her criticism of the proposal.",category:"society",difficulty:3,examples:[{en:"He was very blunt about his opinion on the project.",ja:"彼はプロジェクトについての意見について非常に率直だった。",wrong:["彼は曖昧な意見を述べた。","彼は鋭い意見を述べた。","彼は丁寧に意見を述べた。"]},{en:"The knife became blunt after cutting the hard material.",ja:"硬い材料を切った後、ナイフは鈍くなった。",wrong:["硬い材料を切った後、ナイフはより鋭くなった。","硬い材料を切った後、ナイフは丸くなった。","硬い材料を切った後、ナイフは曲がった。"]},{en:"Her blunt response surprised everyone in the meeting.",ja:"彼女の率直な返答は会議の全員を驚かせた。",wrong:["彼女の曖昧な返答は全員を驚かせた。","彼女の丁寧な返答は全員を驚かせた。","彼女の複雑な返答は全員を驚かせた。"]}]},{word:"boom",meaning:"急成長、ブーム",example:"The tech industry experienced a boom in the 1990s.",category:"current",difficulty:3,examples:[{en:"The economy experienced a boom in the 1990s.",ja:"経済は1990年代に急成長を経験した。",wrong:["経済は1990年代に衰退を経験した。","経済は1990年代に停滞を経験した。","経済は1990年代に崩壊を経験した。"]},{en:"We heard a loud boom when the fireworks exploded.",ja:"花火が爆発したときに大きな音がした。",wrong:["花火が爆発したときに小さな音がした。","花火が爆発したときに沈黙があった。","花火が爆発したときに音楽が聞こえた。"]},{en:"The tech boom created many new job opportunities.",ja:"テックブームは多くの新しい雇用機会を生み出した。",wrong:["テックの衰退は多くの雇用機会を失わせた。","テックの停滞は雇用機会を減らした。","テックの崩壊は失業を増やした。"]}]},{word:"bound",meaning:"〜行きの、義務がある",example:"We are bound by the terms of the contract.",category:"society",difficulty:3,examples:[{en:"This flight is bound for Tokyo tomorrow.",ja:"このフライトは明日東京行きです。",wrong:["このフライトは明日東京から来ます。","このフライトは東京に関係がない。","このフライトは東京に停止している。"]},{en:"You are bound by the contract to complete the work.",ja:"あなたは契約によって仕事を完了する義務がある。",wrong:["あなたは契約によって仕事をしてもしなくても良い。","あなたは契約によって仕事をする権利がある。","あなたは契約によって仕事を中止する義務がある。"]},{en:"The package is bound with strong tape.",ja:"パッケージは強いテープで縛られている。",wrong:["パッケージは弱いテープで縛られている。","パッケージは何も縛られていない。","パッケージは開かれている。"]}]},{word:"brink",meaning:"瀬戸際",example:"The country was on the brink of civil war.",category:"history",difficulty:4,examples:[{en:"The country was on the brink of war.",ja:"その国は戦争の瀬戸際にあった。",wrong:["その国は戦争から遠かった。","その国はすでに戦争中だった。","その国は平和の真っ最中だった。"]},{en:"He stood at the brink of the cliff, looking down.",ja:"彼は崖の瀬戸際に立って、下を見ていた。",wrong:["彼は崖の中央に立っていた。","彼は崖から遠く離れていた。","彼は崖の上の安全な場所に立っていた。"]},{en:"We are on the brink of a major breakthrough.",ja:"私たちは大きな突破口の瀬戸際にある。",wrong:["私たちはすでに大きな突破口を達成した。","私たちは突破口から遠い。","私たちは突破口に失敗した。"]}]},{word:"brochure",meaning:"パンフレット",example:"The travel brochure described exotic destinations.",category:"culture",difficulty:3,examples:[{en:"I picked up a travel brochure at the airport.",ja:"私は空港で旅行パンフレットを手に取った。",wrong:["私は空港でチケットを手に取った。","私は空港で荷物を手に取った。","私は空港で飲食物を手に取った。"]},{en:"The company sent me a brochure about their new products.",ja:"その会社は彼らの新製品についてのパンフレットを私に送った。",wrong:["その会社は彼らの古い製品についての契約書を送った。","その会社は彼らの製品についての請求書を送った。","その会社は彼らの製品についてのカタログのみを送った。"]},{en:"Please read this brochure for more information.",ja:"詳細については、このパンフレットをお読みください。",wrong:["詳細については、この契約書をお読みください。","詳細については、この請求書をお読みください。","詳細については、このメールをお読みください。"]}]},{word:"browse",meaning:"閲覧する",example:"She browsed the shelves for an interesting book.",category:"culture",difficulty:3,examples:[{en:"I like to browse the internet in my free time.",ja:"私は自由な時間にインターネットを閲覧するのが好きです。",wrong:["私は自由な時間にインターネットを削除するのが好きです。","私は自由な時間にインターネットを破壊するのが好きです。","私は自由な時間にインターネットを編集するのが好きです。"]},{en:"She was browsing through the bookstore.",ja:"彼女は本屋を閲覧していた。",wrong:["彼女は本屋を営業していた。","彼女は本屋を掃除していた。","彼女は本屋を建設していた。"]},{en:"You can browse the catalog without making a purchase.",ja:"購入しなくてもカタログを閲覧できます。",wrong:["購入しなくてもカタログを削除できます。","購入しなくてもカタログを破棄できます。","購入しなくてもカタログを返金できます。"]}]},{word:"brutal",meaning:"残忍な",example:"The regime imposed brutal measures on dissidents.",category:"history",difficulty:3,examples:[{en:"The criminal committed a brutal attack on the victim.",ja:"その犯人は被害者に残忍な攻撃を行った。",wrong:["その犯人は被害者に親切な支援を行った。","その犯人は被害者に優しい言葉をかけた。","その犯人は被害者に軽い冗談を言った。"]},{en:"Winter this year has been particularly brutal.",ja:"今年の冬は特に厳しい。",wrong:["今年の冬は特に温暖である。","今年の冬は特に穏やかである。","今年の冬は特に快適である。"]},{en:"The coach gave a brutal assessment of the team's performance.",ja:"コーチはチームのパフォーマンスについて残忍な評価を与えた。",wrong:["コーチはチームのパフォーマンスについて優しい評価を与えた。","コーチはチームのパフォーマンスについて甘い評価を与えた。","コーチはチームのパフォーマンスについて曖昧な評価を与えた。"]}]},{word:"budget",meaning:"予算",example:"The school had to operate on a tight budget.",category:"society",difficulty:3,examples:[{en:"We need to create a monthly budget for our expenses.",ja:"私たちは月間支出のための予算を作成する必要があります。",wrong:["私たちは月間支出のための請求書を作成する必要があります。","私たちは月間支出のための契約書を作成する必要があります。","私たちは月間支出のための領収書を作成する必要があります。"]},{en:"The government allocated a large budget for education.",ja:"政府は教育のための大きな予算を配分した。",wrong:["政府は教育のための小さな寄付をした。","政府は教育のための税金を免除した。","政府は教育のための補助金を取り消した。"]},{en:"You should budget your money carefully.",ja:"あなたはあなたのお金を慎重に予算化すべきです。",wrong:["あなたはあなたのお金を無駄に使うべきです。","あなたはあなたのお金を全て費やすべきです。","あなたはあなたのお金を隠すべきです。"]}]},{word:"bulk",meaning:"大量、大部分",example:"The bulk of the work was completed on time.",category:"society",difficulty:3,examples:[{en:"We buy our supplies in bulk to save money.",ja:"お金を節約するために、私たちは大量に供給品を購入します。",wrong:["お金を無駄にするために、私たちは少量に供給品を購入します。","品質を下げるために、私たちは供給品を購入します。","価格を上げるために、私たちは供給品を購入します。"]},{en:"The bulk of the work was completed last week.",ja:"仕事の大部分は先週完了した。",wrong:["仕事のごく一部は先週完了した。","仕事は全く完了していない。","仕事は来週完了する予定である。"]},{en:"The large bulk of the cargo was difficult to transport.",ja:"貨物の大きな量は輸送が困難だった。",wrong:["貨物の小さな量は輸送が簡単だった。","貨物は輸送する必要がなかった。","貨物は非常に軽かった。"]}]},{word:"burden",meaning:"負担",example:"Tax increases place a heavy burden on families.",category:"society",difficulty:3,examples:[{en:"He felt the burden of responsibility on his shoulders.",ja:"彼は肩に責任の負担を感じた。",wrong:["彼は肩に喜びの感覚を感じた。","彼は肩に軽さを感じた。","彼は肩に何も感じなかった。"]},{en:"The heavy bags were a burden to carry.",ja:"重いバッグを運ぶことは負担だった。",wrong:["重いバッグを運ぶことは喜びだった。","重いバッグを運ぶことは簡単だった。","重いバッグを運ぶことは楽だった。"]},{en:"Don't burden others with your problems.",ja:"他の人にあなたの問題で負担をかけないでください。",wrong:["他の人にあなたの喜びを共有してください。","他の人にあなたの秘密を守ってもらうことはしません。","他の人に喜びを与えてください。"]}]},{word:"cabinet",meaning:"内閣、戸棚",example:"The Prime Minister reshuffled the cabinet.",category:"society",difficulty:3,examples:[{en:"The president met with his cabinet to discuss policy.",ja:"大統領は政策について議論するために彼の内閣と会合した。",wrong:["大統領は個人的に政策について考えた。","大統領は国会で政策について議論した。","大統領は市民に政策について相談した。"]},{en:"I stored the dishes in the kitchen cabinet.",ja:"私はキッチンの戸棚にお皿を保管した。",wrong:["私はキッチンのテーブルの上にお皿を置いた。","私は冷蔵庫の中にお皿を入れた。","私はキッチンの床にお皿を置いた。"]},{en:"The wooden cabinet was antique and very valuable.",ja:"木製の戸棚は骨董品で非常に価値があった。",wrong:["金属製の棚は新しく価値がなかった。","ガラスの棚は価値がなかった。","プラスチックの棚は古かった。"]}]},{word:"campaign",meaning:"運動、キャンペーン",example:"They launched a campaign against air pollution.",category:"current",difficulty:3,examples:[{en:"The political campaign lasted for several months.",ja:"政治キャンペーンは数ヶ月間続いた。",wrong:["政治的な行動は1日だけ続いた。","選挙投票は数週間続いた。","政治的な会議は1時間だけ続いた。"]},{en:"We launched a marketing campaign to promote the new product.",ja:"私たちは新製品を宣伝するためのマーケティングキャンペーンを開始した。",wrong:["私たちは製品を隠すための計画を立てた。","私たちは製品の販売を中止した。","私たちは製品の広告を停止した。"]},{en:"The charity campaign raised millions for the cause.",ja:"慈善キャンペーンはその目的のために数百万ドルを集めた。",wrong:["慈善活動はお金を失った。","慈善事業は資金を調達しなかった。","慈善活動は寄付を拒否した。"]}]},{word:"capable",meaning:"能力がある",example:"She is capable of handling complex negotiations.",category:"society",difficulty:3,examples:[{en:"She is capable of achieving great things.",ja:"彼女は素晴らしいことを達成する能力がある。",wrong:["彼女は何もできない。","彼女は失敗するしかない。","彼女は無能である。"]},{en:"The new software is capable of handling large datasets.",ja:"新しいソフトウェアは大規模なデータセットを処理する能力がある。",wrong:["新しいソフトウェアは小さなデータセットのみを処理できる。","新しいソフトウェアはデータを処理できない。","新しいソフトウェアは壊れている。"]},{en:"He proved himself capable during the crisis.",ja:"彼は危機の間に自分が能力があることを証明した。",wrong:["彼は危機の間に無能であることを示した。","彼は危機の間に逃げた。","彼は危機の間に何もしなかった。"]}]},{word:"captive",meaning:"捕虜の、とりこの",example:"The explorers were held captive for months.",category:"history",difficulty:4,examples:[{en:"The captive audience listened intently to the speaker.",ja:"とりこの聴衆はスピーカーに注意深く耳を傾けた。",wrong:["自由な聴衆は散り散りになった。","逃げた聴衆は戻らなかった。","注意をそらした聴衆は他のことを考えていた。"]},{en:"The soldiers treated the captive with respect.",ja:"兵士たちは捕虜を尊重して扱った。",wrong:["兵士たちは捕虜を釈放した。","兵士たちは捕虜を虐待した。","兵士たちは捕虜を無視した。"]},{en:"She felt captive in her unhappy marriage.",ja:"彼女は幸せでない結婚の中でとりこになった感じがした。",wrong:["彼女は幸せな結婚の中で自由を感じた。","彼女は結婚から解放された。","彼女は結婚について幸福感を持っていた。"]}]},{word:"carve",meaning:"彫る、切り分ける",example:"The sculptor carved the statue from marble.",category:"culture",difficulty:3,examples:[{en:"The sculptor will carve a statue from marble.",ja:"彫刻家は大理石から像を彫刻するでしょう。",wrong:["彫刻家は大理石から像を描くでしょう。","彫刻家は大理石から像を作成するでしょう。","彫刻家は大理石から像を組み立てるでしょう。"]},{en:"He carved his initials into the tree bark.",ja:"彼は木の皮に自分のイニシャルを彫った。",wrong:["彼は木の皮に自分のイニシャルを書いた。","彼は木の皮に自分のイニシャルを塗った。","彼は木の皮に自分のイニシャルを貼った。"]},{en:"The chef carved the roast chicken at the table.",ja:"シェフはテーブルでローストチキンを切り分けた。",wrong:["シェフはテーブルでローストチキンを焼いた。","シェフはテーブルでローストチキンを調理した。","シェフはテーブルでローストチキンを煮た。"]}]},{word:"cater",meaning:"要求を満たす",example:"The restaurant caters to vegetarian customers.",category:"society",difficulty:3,examples:[{en:"The restaurant caters to vegetarian customers.",ja:"そのレストランはベジタリアンの顧客に対応している。",wrong:["そのレストランはベジタリアンの顧客を雇用している。","そのレストランはベジタリアンの顧客を訪問する。","そのレストランはベジタリアンの顧客を批判している。"]},{en:"We need to cater the wedding reception with Italian food.",ja:"結婚式の披露宴にイタリア料理をケータリングする必要があります。",wrong:["結婚式の披露宴をイタリア料理で飾る必要があります。","結婚式の披露宴をイタリア料理で清掃する必要があります。","結婚式の披露宴をイタリア料理で修復する必要があります。"]},{en:"The hotel caters to business travelers with modern facilities.",ja:"そのホテルはビジネス旅行者に現代的な設備で対応している。",wrong:["そのホテルはビジネス旅行者を現代的な設備で雇用している。","そのホテルはビジネス旅行者を現代的な設備で移動させる。","そのホテルはビジネス旅行者を現代的な設備で監視している。"]}]},{word:"cease",meaning:"中止する",example:"Hostilities ceased after the truce was signed.",category:"history",difficulty:3,examples:[{en:"The company decided to cease operations in that country.",ja:"その会社はその国での事業を中止することを決定した。",wrong:["その会社はその国での事業を開始することを決定した。","その会社はその国での事業を拡大することを決定した。","その会社はその国での事業を加速することを決定した。"]},{en:"Please cease making noise after midnight.",ja:"午前0時以降、音を出すことをやめてください。",wrong:["午前0時以降、音を大きくしてください。","午前0時以降、音を聞いてください。","午前0時以降、音を記録してください。"]},{en:"The rain has ceased, and the sun is shining.",ja:"雨が止み、太陽が輝いている。",wrong:["雨が降り始め、太陽が隠れている。","雨が増加し、太陽が消えている。","雨が加速し、太陽が反射している。"]}]},{word:"censor",meaning:"検閲する",example:"The government censored the media during the crisis.",category:"society",difficulty:4,examples:[{en:"The government decided to censor certain websites.",ja:"政府は特定のウェブサイトを検閲することを決定した。",wrong:["政府は特定のウェブサイトを推奨することを決定した。","政府は特定のウェブサイトを宣伝することを決定した。","政府は特定のウェブサイトを管理することを決定した。"]},{en:"The movie was censored before its release.",ja:"その映画は公開前に検閲された。",wrong:["その映画は公開前に編集された。","その映画は公開前に上映された。","その映画は公開前に承認された。"]},{en:"A censor reviewed the letter before it was mailed.",ja:"郵送される前に検閲官がその手紙を確認した。",wrong:["郵送された後に検閲官がその手紙を確認した。","配達中に検閲官がその手紙を確認した。","受け取った後に検閲官がその手紙を確認した。"]}]},{word:"chronic",meaning:"慢性の",example:"He suffers from chronic back pain.",category:"science",difficulty:3,examples:[{en:"He suffers from chronic pain in his lower back.",ja:"彼は腰の慢性的な痛みに苦しんでいる。",wrong:["彼は腰の一時的な痛みに苦しんでいる。","彼は腰の急性の痛みに苦しんでいる。","彼は腰の軽度の痛みに苦しんでいる。"]},{en:"Chronic smoking can lead to serious health problems.",ja:"長期的な喫煙は深刻な健康問題につながる可能性があります。",wrong:["一時的な喫煙は深刻な健康問題につながる可能性があります。","稀な喫煙は深刻な健康問題につながる可能性があります。","軽度の喫煙は深刻な健康問題につながる可能性があります。"]},{en:"The patient was diagnosed with chronic diabetes.",ja:"その患者は慢性糖尿病と診断された。",wrong:["その患者は急性糖尿病と診断された。","その患者は一時的な糖尿病と診断された。","その患者は軽度の糖尿病と診断された。"]}]},{word:"circulate",meaning:"流通する、循環する",example:"Blood circulates through the body via arteries.",category:"science",difficulty:3,examples:[{en:"Blood circulates throughout the human body.",ja:"血液は人体全体を循環している。",wrong:["血液は人体全体を静止している。","血液は人体全体を貯蔵している。","血液は人体全体を濃縮している。"]},{en:"The newspaper will circulate to all subscribers.",ja:"その新聞はすべての購読者に配信されます。",wrong:["その新聞はすべての購読者に保存されます。","その新聞はすべての購読者に隠されます。","その新聞はすべての購読者に回収されます。"]},{en:"The memo was circulated among all employees.",ja:"そのメモはすべての従業員の間で流通した。",wrong:["そのメモはすべての従業員によって没収された。","そのメモはすべての従業員によって破棄された。","そのメモはすべての従業員によって隠された。"]}]},{word:"cite",meaning:"引用する",example:"The professor cited several studies in his lecture.",category:"science",difficulty:4,examples:[{en:"The researcher cited three studies in her paper.",ja:"その研究者は彼女の論文で3つの研究を引用した。",wrong:["その研究者は彼女の論文で3つの研究を否定した。","その研究者は彼女の論文で3つの研究を批判した。","その研究者は彼女の論文で3つの研究を改ざんした。"]},{en:"He was cited for speeding on the highway.",ja:"彼は高速道路でのスピード違反で引用された。",wrong:["彼は高速道路でのスピード違反で賞賛された。","彼は高速道路でのスピード違反で昇進した。","彼は高速道路でのスピード違反で採用された。"]},{en:"Please cite your sources at the end of the essay.",ja:"エッセイの最後に出典を引用してください。",wrong:["エッセイの最後に出典を隠してください。","エッセイの最後に出典を削除してください。","エッセイの最後に出典を改ざんしてください。"]}]},{word:"civic",meaning:"市民の",example:"Voting is an important civic duty.",category:"society",difficulty:3,examples:[{en:"Voting is an important civic duty.",ja:"投票は重要な市民の義務です。",wrong:["投票は重要な個人の義務です。","投票は重要な宗教的義務です。","投票は重要な家族の義務です。"]},{en:"The civic center hosts community events.",ja:"シビックセンターはコミュニティイベントを主催している。",wrong:["シビックセンターはプライベートイベントを主催している。","シビックセンターは宗教的イベントを主催している。","シビックセンターは企業イベントを主催している。"]},{en:"Civic pride is important for the community.",ja:"市民の誇りはコミュニティにとって重要です。",wrong:["個人的な誇りはコミュニティにとって重要です。","家族の誇りはコミュニティにとって重要です。","国家的な誇りはコミュニティにとって重要です。"]}]},{word:"cling",meaning:"しがみつく",example:"The child clung to her mother during the storm.",category:"society",difficulty:3,examples:[{en:"The child clung to her mother's hand.",ja:"その子は母親の手にしがみついた。",wrong:["その子は母親の手を押した。","その子は母親の手を引いた。","その子は母親の手を振った。"]},{en:"Wet clothes cling to the body.",ja:"濡れた衣服は体にしがみつく。",wrong:["濡れた衣服は体を離れる。","濡れた衣服は体を乾燥させる。","濡れた衣服は体を温かくする。"]},{en:"He clung to the hope that things would improve.",ja:"彼は状況が改善するという希望にしがみついた。",wrong:["彼は状況が改善するという希望を放棄した。","彼は状況が改善するという希望を否定した。","彼は状況が改善するという希望を忘れた。"]}]},{word:"coarse",meaning:"粗い、下品な",example:"The fabric has a coarse texture.",category:"society",difficulty:3,examples:[{en:"The sandpaper had a coarse texture.",ja:"その紙やすりは粗いテクスチャーを持っていた。",wrong:["その紙やすりは滑らかなテクスチャーを持っていた。","その紙やすりは細かいテクスチャーを持っていた。","その紙やすりは光沢のあるテクスチャーを持っていた。"]},{en:"His language was coarse and offensive.",ja:"彼の言葉遣いは下品で不快だった。",wrong:["彼の言葉遣いは洗練され好意的だった。","彼の言葉遣いは丁寧で敬意を表していた。","彼の言葉遣いは優雅で魅力的だった。"]},{en:"The fabric was too coarse for delicate skin.",ja:"その生地は敏感肌には粗すぎた。",wrong:["その生地は敏感肌には細かすぎた。","その生地は敏感肌には滑らかすぎた。","その生地は敏感肌には柔らかすぎた。"]}]},{word:"coerce",meaning:"強制する",example:"No one should be coerced into signing a contract.",category:"society",difficulty:5,examples:[{en:"They tried to coerce him into signing the contract.",ja:"彼らは彼に契約書に署名するよう強制しようとした。",wrong:["彼らは彼に契約書に署名するよう勧めた。","彼らは彼に契約書に署名するよう説得した。","彼らは彼に契約書に署名するよう促した。"]},{en:"The government cannot coerce citizens to work.",ja:"政府は市民に労働を強制することはできない。",wrong:["政府は市民に労働を奨励することはできない。","政府は市民に労働を提供することはできない。","政府は市民に労働を支援することはできない。"]},{en:"No one should be coerced into making decisions.",ja:"誰も決定を強制されるべきではない。",wrong:["誰も決定を助言されるべきではない。","誰も決定を支援されるべきではない。","誰も決定を指導されるべきではない。"]}]},{word:"colonial",meaning:"植民地の",example:"The country has a long colonial history.",category:"history",difficulty:3,examples:[{en:"The colonial architecture was well preserved.",ja:"その植民地時代の建築は良好に保存されていた。",wrong:["その現代の建築は良好に保存されていた。","その古代の建築は良好に保存されていた。","その中世の建築は良好に保存されていた。"]},{en:"Colonial powers exploited resources in Africa.",ja:"植民地大国はアフリカの資源を搾取した。",wrong:["独立国家はアフリカの資源を搾取した。","同盟国はアフリカの資源を搾取した。","民族はアフリカの資源を搾取した。"]},{en:"The colonial period lasted for centuries.",ja:"植民地時代は数世紀続いた。",wrong:["現代時代は数世紀続いた。","古代時代は数世紀続いた。","中世時代は数世紀続いた。"]}]},{word:"commence",meaning:"開始する",example:"The ceremony will commence at ten o'clock.",category:"society",difficulty:4},{word:"commend",meaning:"称賛する",example:"The teacher commended the student for her effort.",category:"society",difficulty:4,examples:[{en:"The teacher commended the students for their hard work.",ja:"その教師は学生たちの懸命な努力を称賛した。",wrong:["その教師は学生たちの懸命な努力を批判した。","その教師は学生たちの懸命な努力を罰した。","その教師は学生たちの懸命な努力を無視した。"]},{en:"I commend your courage in facing this challenge.",ja:"この課題に直面するあなたの勇気を称賛します。",wrong:["この課題に直面するあなたの臆病さを称賛します。","この課題に直面するあなたの躊躇を称賛します。","この課題に直面するあなたの怯えを称賛します。"]},{en:"The company commended the employee for exceptional service.",ja:"その会社は従業員の優れたサービスを称賛した。",wrong:["その会社は従業員の貧弱なサービスを称賛した。","その会社は従業員の平凡なサービスを称賛した。","その会社は従業員の不十分なサービスを称賛した。"]}]},{word:"communal",meaning:"共同の",example:"Residents share a communal garden.",category:"society",difficulty:4,examples:[{en:"The village has a communal garden.",ja:"その村は共同の庭園を持っている。",wrong:["その村は私有の庭園を持っている。","その村は個人の庭園を持っている。","その村は王立の庭園を持っている。"]},{en:"They shared communal spaces in the apartment building.",ja:"彼らはアパート建物の共有スペースを共有していた。",wrong:["彼らはアパート建物の個室スペースを共有していた。","彼らはアパート建物のプライベートスペースを共有していた。","彼らはアパート建物の専用スペースを共有していた。"]},{en:"Communal living has many advantages.",ja:"共同生活には多くの利点があります。",wrong:["独居生活には多くの利点があります。","家族生活には多くの利点があります。","隠遁生活には多くの利点があります。"]}]},{word:"comparable",meaning:"匹敵する",example:"The quality is comparable to much more expensive brands.",category:"society",difficulty:3,examples:[{en:"The quality of these two products is comparable.",ja:"これら2つの製品の品質は匹敵する。",wrong:["この2つの製品は全く異なっている。","製品の品質は比較することができない。","これらの製品は互いに競争している。"]},{en:"Her skills are comparable to those of a professional.",ja:"彼女のスキルはプロのものに匹敵する。",wrong:["彼女のスキルはプロより劣っている。","彼女はプロのスキルを持っていない。","プロフェッショナルは彼女を助けるべきだ。"]},{en:"The prices are comparable between the two stores.",ja:"2つの店の価格は匹敵している。",wrong:["2つの店の価格は全く異なっている。","この店の方が絶対に安い。","価格の比較は不可能である。"]}]},{word:"compel",meaning:"強いる",example:"The evidence compelled him to change his mind.",category:"society",difficulty:4,examples:[{en:"The law compels all citizens to pay taxes.",ja:"法律はすべての市民に税金を支払うことを強いる。",wrong:["法律は市民が税金を支払うのを禁止している。","税金の支払いは自由である。","市民は税金を払わなくてもよい。"]},{en:"Hunger compelled him to steal food.",ja:"飢えは彼に食べ物を盗むことを強いた。",wrong:["彼は食べ物を盗むことを選んだ。","飢えは彼を助けた。","彼は食べ物を持っていた。"]},{en:"The circumstances compel us to make a difficult decision.",ja:"状況は私たちに困難な決定をすることを強いる。",wrong:["状況は簡単な決定を許している。","私たちは決定を避けることができる。","状況は関係ない。"]}]},{word:"compensate",meaning:"補償する",example:"The airline compensated passengers for the delay.",category:"society",difficulty:3,examples:[{en:"The company will compensate employees for the overtime work.",ja:"会社は残業に対して従業員に補償する。",wrong:["会社は残業代を支払わない。","従業員は補償を受けるべきではない。","残業は無給である。"]},{en:"His talent compensates for his lack of experience.",ja:"彼の才能は経験不足を補償する。",wrong:["彼の才能は経験不足を補う。","才能と経験の欠如は相手を打ち消す。","才能は経験を取る代わりになることはできない。"]},{en:"We must compensate the victims of the accident.",ja:"私たちは事故の被害者に補償しなければならない。",wrong:["被害者は補償を受ける権利がない。","事故は誰にも補償を必要としない。","被害者を無視すべきである。"]}]},{word:"compile",meaning:"編集する、まとめる",example:"She compiled a list of potential investors.",category:"technology",difficulty:4,examples:[{en:"The researcher compiled all the data into a single report.",ja:"研究者はすべてのデータを1つのレポートに編集した。",wrong:["研究者はデータを散らばせたままにした。","データは報告書に含まれていない。","研究者はデータを収集しなかった。"]},{en:"She is compiling a dictionary of rare words.",ja:"彼女は希少な単語の辞書を編集している。",wrong:["彼女は一般的な単語だけを集めている。","彼女は辞書を作成していない。","単語を集めることは時間の無駄である。"]},{en:"The programmer compiled the code into an executable file.",ja:"プログラマーはコードを実行可能ファイルに編集した。",wrong:["プログラマーはコードをコンパイルしなかった。","コードは実行できない状態のままだ。","ファイルは作成されなかった。"]}]},{word:"comply",meaning:"従う、遵守する",example:"All factories must comply with safety regulations.",category:"society",difficulty:4,examples:[{en:"All employees must comply with the company's safety regulations.",ja:"すべての従業員は会社の安全規則に従わなければならない。",wrong:["従業員は安全規則を無視してもよい。","安全規則に従う必要はない。","会社は安全規則を強制していない。"]},{en:"The government demands that citizens comply with the new law.",ja:"政府は市民が新しい法律に従うことを要求している。",wrong:["市民は法律を無視することができる。","政府は強制力を持たない。","法律に従うことは不可能である。"]},{en:"He refused to comply with the doctor's orders.",ja:"彼は医者の指示に従うことを拒否した。",wrong:["彼は医者の指示に従った。","彼は指示を無視しなかった。","彼は医者の命令を聞いた。"]}]},{word:"component",meaning:"構成要素",example:"Trust is a key component of any relationship.",category:"science",difficulty:3,examples:[{en:"The engine is the main component of a car.",ja:"エンジンは車の主要な構成要素である。",wrong:["エンジンは車の最も重要な部分ではない。","車はエンジンなしで走ることができる。","エンジンは車の一部ではない。"]},{en:"Each component of the project must be completed on time.",ja:"プロジェクトの各構成要素は期間内に完了する必要がある。",wrong:["プロジェクトの部分は期限を無視できる。","すべての部分が同時に完了する必要はない。","プロジェクトに部分はない。"]},{en:"The recipe contains several key components.",ja:"レシピには複数の重要な構成要素が含まれている。",wrong:["レシピは1つの材料だけで構成されている。","成分は関係ない。","レシピに部分がない。"]}]},{word:"compound",meaning:"化合物、悪化させる",example:"The rain compounded the flooding problem.",category:"science",difficulty:4,examples:[{en:"Water is a chemical compound made of hydrogen and oxygen.",ja:"水は水素と酸素で作られた化合物である。",wrong:["水は単一の元素である。","水素と酸素は別々の物質である。","水は化学的に作られていない。"]},{en:"His mistakes compound the problem significantly.",ja:"彼の間違いは問題を大幅に悪化させる。",wrong:["彼の間違いは問題を改善する。","間違いは何も影響しない。","問題は良くなっている。"]},{en:"The financial losses compound each quarter.",ja:"財務的損失は毎四半期に悪化する。",wrong:["損失は減っている。","四半期ごとに利益が増えている。","財務状況は安定している。"]}]},{word:"comprehensive",meaning:"包括的な",example:"The report provides a comprehensive overview.",category:"society",difficulty:3,examples:[{en:"The book provides a comprehensive overview of world history.",ja:"この本は世界史の包括的な概要を提供している。",wrong:["この本は世界史の一部だけをカバーしている。","この本は歴史について何も教えない。","この本は不完全である。"]},{en:"The insurance policy offers comprehensive coverage.",ja:"保険契約は包括的な補償を提供している。",wrong:["保険は限定的な補償しかない。","保険は何もカバーしていない。","保険は不十分である。"]},{en:"She gave a comprehensive presentation of her research.",ja:"彼女は彼女の研究の包括的なプレゼンテーションを行った。",wrong:["彼女のプレゼンテーションは部分的だった。","彼女は重要な情報を省いた。","プレゼンテーションは不十分だった。"]}]},{word:"compromise",meaning:"妥協する",example:"Both sides were willing to compromise.",category:"society",difficulty:3,examples:[{en:"Both parties agreed to compromise and reached a settlement.",ja:"両者は妥協することに同意し、和解に達した。",wrong:["両者は妥協を拒否した。","どちらかが完全に勝った。","和解は達成されなかった。"]},{en:"We need to compromise on the budget to satisfy everyone.",ja:"すべての人を満足させるために予算で妥協する必要がある。",wrong:["予算について妥協する必要はない。","全員が同意することは不可能である。","予算を変更することはできない。"]},{en:"His security was compromised when his password was stolen.",ja:"パスワードが盗まれたとき、彼のセキュリティが侵害された。",wrong:["パスワード盗難は安全性に影響しない。","セキュリティは損なわれなかった。","彼のアカウントは安全のままである。"]}]},{word:"concede",meaning:"認める、譲歩する",example:"The candidate conceded defeat graciously.",category:"society",difficulty:4,examples:[{en:"The politician conceded defeat after losing the election.",ja:"政治家は選挙に落選した後、敗北を認めた。",wrong:["政治家は敗北を認めなかった。","彼は選挙に勝った。","敗北を受け入れることを拒否した。"]},{en:"She conceded that her opponent made a valid point.",ja:"彼女は相手が妥当なポイントを作ったことを認めた。",wrong:["彼女は相手の議論を否定した。","相手は正しくない。","彼女は相手に同意しなかった。"]},{en:"The team conceded three goals in the first half.",ja:"チームは前半に3ゴールを譲歩した。",wrong:["チームは1ゴールも許さなかった。","チームは3ゴール得点した。","前半にゴールはなかった。"]}]},{word:"condemn",meaning:"非難する",example:"World leaders condemned the terrorist attack.",category:"current",difficulty:3,examples:[{en:"The government condemned the terrorist attack.",ja:"政府はテロ攻撃を非難した。",wrong:["政府はテロ攻撃を支持した。","テロ攻撃は非難されなかった。","政府は何も言わなかった。"]},{en:"The judge condemned him to ten years in prison.",ja:"裁判官は彼に10年の懲役を宣告した。",wrong:["裁判官は彼を無罪とした。","彼は刑務所に行かなくてもよい。","彼は釈放された。"]},{en:"Critics condemned the film for its poor quality.",ja:"批評家は品質の悪さについて映画を非難した。",wrong:["批評家は映画を高く評価した。","映画は高品質だと考えられている。","批評家は映画について何も言わなかった。"]}]},{word:"condense",meaning:"凝縮する、要約する",example:"Steam condenses into water when cooled.",category:"science",difficulty:4,examples:[{en:"The author condensed the long novel into a short summary.",ja:"著者は長編小説を短い要約に凝縮した。",wrong:["著者は小説を拡張した。","要約はより長くなった。","凝縮されなかった。"]},{en:"Steam condenses into water when it cools down.",ja:"蒸気は冷えると水に凝縮する。",wrong:["蒸気は冷えてもそのままである。","蒸気は液体にならない。","温度低下は蒸気に影響しない。"]},{en:"Please condense your presentation to fifteen minutes.",ja:"プレゼンテーションを15分に凝縮してください。",wrong:["プレゼンテーションを長くしてください。","15分では短すぎる。","時間制限はない。"]}]},{word:"confiscate",meaning:"没収する",example:"Customs officials confiscated the illegal goods.",category:"society",difficulty:4,examples:[{en:"The customs officer confiscated the prohibited items.",ja:"税関職員は禁止品を没収した。",wrong:["税関職員は禁止品を許可した。","禁止品は持ち込める。","没収されなかった。"]},{en:"The teacher confiscated the student's phone during class.",ja:"先生は授業中に生徒の携帯電話を没収した。",wrong:["先生は携帯電話を返した。","携帯電話は持ち込める。","先生は何もしなかった。"]},{en:"The government confiscated the land for public use.",ja:"政府は公共利用のために土地を没収した。",wrong:["政府は土地を所有者に返した。","土地は公共利用に使用されていない。","没収は違法である。"]}]},{word:"conform",meaning:"従う、適合する",example:"Products must conform to safety standards.",category:"society",difficulty:4,examples:[{en:"All products must conform to safety standards.",ja:"すべての製品は安全基準に適合する必要がある。",wrong:["製品は安全基準を無視できる。","基準に適合する必要はない。","製品は規制されていない。"]},{en:"He refused to conform to social expectations.",ja:"彼は社会的期待に従うことを拒否した。",wrong:["彼は社会的期待に従った。","彼は慣習に従った。","彼は規範を受け入れた。"]},{en:"The building conforms to all local building codes.",ja:"建物はすべての地域の建築基準に適合している。",wrong:["建物は基準に違反している。","建物は規制を無視している。","建物は不法である。"]}]},{word:"confront",meaning:"直面する、立ち向かう",example:"She confronted him about the missing money.",category:"society",difficulty:3,examples:[{en:"She decided to confront her boss about the unfair treatment.",ja:"彼女は不公正な扱いについて上司に立ち向かうことを決めた。",wrong:["彼女は上司を避けた。","彼女は不公正さについて何も言わなかった。","彼女は問題を無視した。"]},{en:"The team must confront the challenges ahead.",ja:"チームは前方の課題に直面する必要がある。",wrong:["チームは課題を避けることができる。","課題は存在しない。","チームは無視することができる。"]},{en:"When confronted with the evidence, he admitted his guilt.",ja:"証拠に直面すると、彼は彼の有罪を認めた。",wrong:["彼は証拠を見なかった。","彼は有罪を否定した。","証拠は提示されなかった。"]}]},{word:"congregate",meaning:"集合する",example:"Crowds congregated in the town square.",category:"society",difficulty:5,examples:[{en:"Thousands of fans congregated outside the stadium for the concert.",ja:"コンサートのためにスタジアムの外に何千人ものファンが集合した。",wrong:["ファンが解散した","ファンが逃げた","ファンが分散した"]},{en:"Birds congregate on the telephone wires every evening.",ja:"鳥たちは毎晩電話線に集合する。",wrong:["鳥たちは毎晩飛び去る","鳥たちは毎晩巣に戻る","鳥たちは毎晩分散する"]},{en:"People congregated in the square to celebrate the victory.",ja:"人々は勝利を祝うために広場に集合した。",wrong:["人々は広場から去った","人々は広場を避けた","人々は広場で喧嘩した"]}]},{word:"conscience",meaning:"良心",example:"His conscience would not let him lie.",category:"society",difficulty:3,examples:[{en:"Her conscience bothered her after she lied to her friend.",ja:"友人に嘘をついた後、彼女の良心が彼女を悩ませた。",wrong:["彼女の意識が覚醒した","彼女の感情が高ぶった","彼女の気持ちが軽くなった"]},{en:"He acted according to his conscience and refused the bribe.",ja:"彼は自分の良心に従って賄賂を拒否した。",wrong:["彼は自分の欲望に従った","彼は自分の恐怖に従った","彼は自分の野心に従った"]},{en:"A clear conscience allows you to sleep peacefully at night.",ja:"澄んだ良心があれば、夜間に平穏に眠ることができます。",wrong:["汚れた良心があれば眠れる","弱い良心があれば安心できる","強い良心があれば目覚める"]}]},{word:"consecutive",meaning:"連続した",example:"It rained for five consecutive days.",category:"science",difficulty:4,examples:[{en:"The team won five consecutive games without losing.",ja:"チームは負けずに連続5試合に勝利した。",wrong:["チームは交互に勝った","チームは連続で負けた","チームは同時に勝った"]},{en:"She has worked here for three consecutive years.",ja:"彼女は連続3年間ここで働いている。",wrong:["彼女は断続的に3年間ここで働いている","彼女は3年間休んでいた","彼女は3年間交代で働いた"]},{en:"The numbers 1, 2, 3, and 4 are consecutive integers.",ja:"1、2、3、4は連続した整数です。",wrong:["これらは交互の整数です","これらはランダムな整数です","これらは減少する整数です"]}]},{word:"consent",meaning:"同意する、承諾",example:"Patients must give informed consent before surgery.",category:"science",difficulty:3,examples:[{en:"The parents gave their consent for the school trip.",ja:"親たちは修学旅行の同意を与えた。",wrong:["親たちは修学旅行を禁止した","親たちは修学旅行に反対した","親たちは何も答えなかった"]},{en:"Both parties consented to the agreement before signing it.",ja:"両者は署名前に合意に同意した。",wrong:["両者は合意に反対した","両者は合意を破った","両者は合意を無視した"]},{en:"You cannot proceed without the patient's informed consent.",ja:"患者の十分な説明に基づく同意なしに進められません。",wrong:["患者の反対がなければ進められる","患者の許可なしに進める","患者の拒否でも進める"]}]},{word:"conservation",meaning:"保全、保存",example:"Wildlife conservation requires international cooperation.",category:"current",difficulty:3,examples:[{en:"Wildlife conservation is essential to protect endangered species.",ja:"野生動物保全は絶滅危惧種を保護するために不可欠です。",wrong:["野生動物の破壊は保護に必要です","野生動物の乱獲は保全です","野生動物の絶滅は保全です"]},{en:"The organization works on forest conservation projects.",ja:"その組織は森林保全プロジェクトに取り組んでいます。",wrong:["その組織は森林破壊プロジェクトに取り組んでいる","その組織は森林伐採を推進している","その組織は森林を燃やしている"]},{en:"Energy conservation helps reduce electricity bills.",ja:"エネルギー保全は電気代を削減するのに役立ちます。",wrong:["エネルギー浪費が電気代を削減する","エネルギー消費が電気代を下げる","電気の無駄使いが節約になる"]}]},{word:"conspicuous",meaning:"目立つ",example:"His absence was conspicuous at the meeting.",category:"society",difficulty:5,examples:[{en:"Her bright red dress made her conspicuous at the party.",ja:"彼女の真っ赤なドレスはパーティーで彼女を目立たせた。",wrong:["彼女のドレスは彼女を隠した","彼女のドレスは誰も気づかなかった","彼女のドレスは目立たなかった"]},{en:"The building's modern architecture is conspicuous among old structures.",ja:"その建物のモダンアーキテクチャは古い建造物の中で目立っている。",wrong:["その建物は古い建造物と同じように見える","その建物は隠れている","その建物は目立たない"]},{en:"His absence from the meeting was conspicuous.",ja:"彼の会議からの欠席は目立っていた。",wrong:["彼の出席は目立っていた","誰も彼がいないことに気づかなかった","彼の欠席は隠れていた"]}]},{word:"contempt",meaning:"軽蔑",example:"She looked at him with contempt.",category:"society",difficulty:4,examples:[{en:"She showed contempt for his rude behavior.",ja:"彼女は彼の無礼な行動に軽蔑を示した。",wrong:["彼女は彼の行動を敬った","彼女は彼の行動を褒めた","彼女は彼の行動に感謝した"]},{en:"The judge held the defendant in contempt of court.",ja:"裁判官は被告人を法廷侮辱罪で責任に問うた。",wrong:["裁判官は被告人を尊敬した","裁判官は被告人を褒めた","裁判官は被告人を釈放した"]},{en:"He spoke with contempt about the opposing team.",ja:"彼は対抗チームについて軽蔑を込めて話した。",wrong:["彼は対抗チームを尊敬して話した","彼は対抗チームを褒めた","彼は対抗チームに賛成した"]}]},{word:"contend",meaning:"争う、主張する",example:"Several companies are contending for the contract.",category:"society",difficulty:4,examples:[{en:"The two companies contend for market leadership.",ja:"2つの企業は市場リーダーシップを争っている。",wrong:["2つの企業は協力している","2つの企業は合併している","2つの企業は提携している"]},{en:"She contends that education is the key to success.",ja:"彼女は教育が成功の鍵だと主張している。",wrong:["彼女は教育は無用だと言っている","彼女は教育に反対している","彼女は教育を否定している"]},{en:"The athletes contended fiercely in the championship.",ja:"アスリートたちはチャンピオンシップで激しく争った。",wrong:["アスリートたちは協力して競った","アスリートたちは順番に走った","アスリートたちは談笑した"]}]},{word:"convention",meaning:"慣例、大会",example:"It is a convention to shake hands when meeting.",category:"culture",difficulty:3,examples:[{en:"The political party held its annual convention in July.",ja:"その政党は7月に年次大会を開催した。",wrong:["その政党は小さな会議を開いた","その政党はイベントをキャンセルした","その政党は秘密集会を開いた"]},{en:"It is a social convention to shake hands when meeting someone.",ja:"誰かに会うときに握手することは社会的慣例です。",wrong:["握手することは違法な行為です","握手することは不作法です","握手することは珍しい行為です"]},{en:"The international convention on climate change was signed by many countries.",ja:"気候変動に関する国際条約は多くの国によって署名された。",wrong:["その条約は一国だけが署名した","その条約は誰も署名しなかった","その条約は破棄された"]}]},{word:"convert",meaning:"変換する、改宗する",example:"The factory was converted into apartments.",category:"society",difficulty:3,examples:[{en:"She converted the garage into a home office.",ja:"彼女はガレージをホームオフィスに変換した。",wrong:["彼女はガレージを壊した","彼女はガレージを売った","彼女はガレージを放置した"]},{en:"He converted to Buddhism after studying its teachings for years.",ja:"彼は数年間その教えを学んだ後、仏教に改宗した。",wrong:["彼は仏教を批判している","彼は仏教から離れた","彼は仏教の敵になった"]},{en:"The currency converter helps you convert dollars to euros.",ja:"通貨換算機はドルをユーロに変換するのに役立ちます。",wrong:["換算機は通貨を作成する","換算機は通貨を破壊する","換算機は通貨を隠す"]}]},{word:"conviction",meaning:"信念、有罪判決",example:"She spoke with deep conviction about human rights.",category:"society",difficulty:4,examples:[{en:"He was convicted of theft and received a prison sentence.",ja:"彼は窃盗罪で有罪判決を受けて懲役刑を受けた。",wrong:["彼は釈放された","彼は無罪になった","彼は罰金を払った"]},{en:"She spoke with conviction about her political beliefs.",ja:"彼女は自分の政治的信念について信念を持って話した。",wrong:["彼女は疑いながら話した","彼女は躊躇いながら話した","彼女は無関心に話した"]},{en:"His conviction that hard work pays off motivated him to study harder.",ja:"懸命な努力が報われるという彼の信念が、彼をより一生懸命勉強するよう動機付けた。",wrong:["彼の不安が彼を動機付けた","彼の疑いが彼を励ました","彼の恐怖が彼を勇気付けた"]}]},{word:"cope",meaning:"対処する",example:"He struggled to cope with the pressure.",category:"society",difficulty:3,examples:[{en:"She had to cope with stress while managing her family and work.",ja:"彼女は家族と仕事を管理しながらストレスに対処する必要がありました。",wrong:["彼女はストレスを無視した","彼女はストレスを増やした","彼女はストレスから逃げた"]},{en:"The country coped with the economic crisis by implementing new policies.",ja:"その国は新しい政策を実施することで経済危機に対処した。",wrong:["その国は危機を悪化させた","その国は何もしなかった","その国は危機を受け入れた"]},{en:"It is important to develop healthy ways to cope with depression.",ja:"うつ病に対処するための健康的な方法を開発することが重要です。",wrong:["不健康な方法がうつ病に対処するのに良い","うつ病を無視するのが最善の方法です","うつ病から逃げることが対処です"]}]},{word:"cordial",meaning:"心からの、友好的な",example:"Relations between the two leaders are cordial.",category:"society",difficulty:5,examples:[{en:"They greeted each other with a cordial handshake.",ja:"彼らはお互いを心からの握手で挨拶した。",wrong:["彼らは冷たく握手した","彼らは敵意を持って握手した","彼らは無関心に握手した"]},{en:"The host served cordial wine to her guests.",ja:"ホストは彼女のゲストに心からのワインを提供した。",wrong:["ホストは冷たいワインを提供した","ホストはゲストにアルコールを与えなかった","ホストは敵意を示した"]},{en:"Despite their disagreement, they maintained a cordial relationship.",ja:"彼らの意見の相違にもかかわらず、彼らは友好的な関係を保った。",wrong:["彼らは敵対関係を作った","彼らは冷淡になった","彼らは憎み合った"]}]},{word:"corrode",meaning:"腐食する",example:"Salt water can corrode metal surfaces.",category:"science",difficulty:4,examples:[{en:"Rust began to corrode the old iron fence.",ja:"さびが古い鉄製フェンスを腐食し始めた。",wrong:["さびがフェンスを修復した","さびがフェンスを強化した","さびがフェンスを磨いた"]},{en:"Salt water corrodes metal faster than fresh water.",ja:"塩水は淡水よりも速く金属を腐食します。",wrong:["塩水は金属を保護する","塩水は金属を強くする","塩水は金属に影響しない"]},{en:"The acid will corrode the surface of the material.",ja:"酸は材料の表面を腐食します。",wrong:["酸は材料の表面を保護する","酸は材料を強化する","酸は材料を修復する"]}]},{word:"counterpart",meaning:"対応する人・物",example:"The Japanese minister met her British counterpart.",category:"society",difficulty:4,examples:[{en:"The American ambassador met with his French counterpart to discuss trade.",ja:"アメリカの大使は貿易について議論するためにフランスの対応者と会った。",wrong:["大使は敵対者と会った","大使は部下と会った","大使は誰とも会わなかった"]},{en:"In the novel, the protagonist has a counterpart in the sequel.",ja:"小説では、主人公は続編に対応する人物を持っている。",wrong:["主人公は続編に敵がいる","主人公は続編に対手がいない","主人公は続編で死ぬ"]},{en:"The software has a counterpart version for mobile devices.",ja:"そのソフトウェアはモバイルデバイス用の対応するバージョンを持っています。",wrong:["ソフトウェアはモバイル版がない","ソフトウェアはモバイルと互換性がない","ソフトウェアはモバイルで動作しない"]}]},{word:"courteous",meaning:"礼儀正しい",example:"The staff were always courteous and helpful.",category:"society",difficulty:4,examples:[{en:"The courteous waiter made sure all customers felt welcome.",ja:"その礼儀正しいウェイターは、すべての顧客が歓迎されていると感じるようにしました。",wrong:["The rude waiter ignored the customers.","The waiter was impolite and dismissive.","The discourteous staff member was unhelpful."]},{en:"She gave a courteous reply to the difficult question.",ja:"彼女は難しい質問に礼儀正しい返答をしました。",wrong:["She gave a rude and offensive answer.","She responded in an impolite manner.","Her reply was disrespectful and harsh."]},{en:"It is courteous to hold the door for someone behind you.",ja:"自分の後ろの人のためにドアを開けておくことは礼儀正しいです。",wrong:["It is rude to slam the door in someone's face.","Ignoring others is a courteous gesture.","Being impolite is the proper way to behave."]}]},{word:"craft",meaning:"工芸、巧みに作る",example:"She crafted a persuasive argument.",category:"culture",difficulty:3,examples:[{en:"She learned the craft of pottery from her grandmother.",ja:"彼女は祖母から陶芸の工芸を学びました。",wrong:["She learned modern technology from her grandmother.","She studied the science of chemistry.","She picked up the skill of cooking."]},{en:"The artisan used traditional methods to craft the wooden chair.",ja:"その職人は伝統的な方法で木製の椅子を巧みに作りました。",wrong:["The factory mass-produced the plastic chair.","The carpenter destroyed the wooden furniture.","The builder quickly assembled the metal structure."]},{en:"They craft their jewelry with great precision and care.",ja:"彼らは大きな精密さと注意を持って宝飾品を巧みに作ります。",wrong:["They quickly manufacture jewelry without care.","They buy mass-produced pieces from factories.","They assemble cheap imitations carelessly."]}]},{word:"credentials",meaning:"資格、信任状",example:"Employers will verify your academic credentials.",category:"society",difficulty:4,examples:[{en:"The doctor presented her medical credentials to the hospital.",ja:"その医者は病院に医学資格を提出しました。",wrong:["The doctor hid her qualifications from the hospital.","The physician had no formal education or training.","The medical professional lacked any certification."]},{en:"His credentials as a software engineer impressed the company.",ja:"ソフトウェアエンジニアとしての彼の資格は会社に印象を与えました。",wrong:["His lack of experience disappointed the employer.","The company rejected his unqualified application.","His credentials as a musician were irrelevant to the job."]},{en:"Journalists must verify the credentials of their sources.",ja:"ジャーナリストは情報源の信任状を確認しなければなりません。",wrong:["Journalists should ignore the background of sources.","Reporters believe everything without checking credentials.","The media publishes unverified information from unknown people."]}]},{word:"crude",meaning:"粗野な、未加工の",example:"Crude oil prices rose sharply this week.",category:"current",difficulty:3,examples:[{en:"The crude oil needs to be refined before use.",ja:"その未加工の石油は使用前に精製する必要があります。",wrong:["The refined oil is completely processed.","The purified petroleum is ready to sell.","The processed fuel needs no further treatment."]},{en:"His crude jokes offended many people at the party.",ja:"彼の粗野なジョークはパーティーで多くの人を不快にさせました。",wrong:["His refined humor was appreciated by everyone.","His sophisticated jokes made people laugh politely.","His elegant comments impressed the refined guests."]},{en:"The crude tools were all they had to build the shelter.",ja:"その粗野な道具は彼らが避難所を建てるために持っていたすべてでした。",wrong:["The sophisticated equipment made construction easier.","The advanced machinery was available for use.","The refined tools were perfect for the job."]}]},{word:"curb",meaning:"抑制する",example:"The policy aims to curb carbon emissions.",category:"current",difficulty:4,examples:[{en:"The government tried to curb inflation with new policies.",ja:"政府は新しい政策でインフレーションを抑制しようとしました。",wrong:["The government encouraged rapid price increases.","Officials promoted uncontrolled spending.","The state increased inflation without any restrictions."]},{en:"Parents must curb their children's excessive screen time.",ja:"親は子供たちの過度なスクリーンタイムを抑制しなければなりません。",wrong:["Parents should allow unlimited device usage.","Guardians encourage all-day video game playing.","Adults promote excessive internet consumption."]},{en:"She learned to curb her anger through meditation.",ja:"彼女は瞑想を通じて怒りを抑制することを学びました。",wrong:["She encouraged her emotions to intensify.","She expressed all her anger without control.","She allowed her frustration to grow unchecked."]}]},{word:"curriculum",meaning:"教育課程",example:"The national curriculum was revised last year.",category:"society",difficulty:4,examples:[{en:"The school updated its curriculum to include coding classes.",ja:"その学校は教育課程を更新してコーディングクラスを含めました。",wrong:["The school removed all academic subjects.","The institution eliminated the course requirements.","The educational program was abolished completely."]},{en:"A strong curriculum prepares students for college.",ja:"強力な教育課程は大学のために学生を準備します。",wrong:["A weak curriculum fails to prepare students.","Poor course planning undermines learning outcomes.","Inadequate academic programs lead to failure."]},{en:"The curriculum includes subjects like math, science, and history.",ja:"教育課程には数学、科学、歴史などの科目が含まれています。",wrong:["The curriculum consists only of physical education.","The program focuses exclusively on art and music.","The coursework ignores all academic subjects."]}]},{word:"daunting",meaning:"気後れさせる",example:"Moving to a new country can be a daunting experience.",category:"society",difficulty:4,examples:[{en:"Climbing Mount Everest is a daunting challenge.",ja:"エベレスト山に登ることは気後れさせる挑戦です。",wrong:["Climbing Mount Everest is an easy task.","The mountain presents no difficulty.","The climb is a simple, trivial challenge."]},{en:"The daunting task made her feel discouraged.",ja:"その気後れさせる仕事は彼女を落ち込ませました。",wrong:["The easy assignment encouraged her enthusiasm.","The simple task motivated her greatly.","The trivial work inspired her confidence."]},{en:"Writing a thesis seemed daunting at first.",ja:"論文を書くことは最初のところ気後れさせるように見えました。",wrong:["Writing a thesis was immediately simple.","The paper seemed easy to complete.","The assignment caused no concern whatsoever."]}]},{word:"debris",meaning:"破片、残骸",example:"Rescue teams cleared the debris from the earthquake.",category:"current",difficulty:4,examples:[{en:"After the explosion, debris was scattered everywhere.",ja:"爆発の後、破片があちこちに散らばっていました。",wrong:["The explosion left everything perfectly intact.","No wreckage remained after the blast.","The area was completely clean and organized."]},{en:"The construction workers cleaned up the debris from demolition.",ja:"建設労働者は取り壊しからの残骸を片付けました。",wrong:["The workers left all the rubble untouched.","They ignored the scattered materials.","The crew left the site in complete disorder."]},{en:"Storm debris blocked the road for days.",ja:"嵐の破片は何日も道を塞ぎました。",wrong:["The road remained completely clear and passable.","No obstacles hindered traffic flow.","The street was perfectly clean immediately."]}]},{word:"deceive",meaning:"欺く",example:"He was accused of deceiving investors.",category:"society",difficulty:3,examples:[{en:"He tried to deceive his parents about his grades.",ja:"彼は成績について両親を欺こうとしました。",wrong:["He told his parents the complete truth.","He revealed his poor performance honestly.","He was transparent about his academic struggles."]},{en:"The fraudster tried to deceive investors with false promises.",ja:"その詐欺師は虚偽の約束で投資家を欺こうとしました。",wrong:["The honest businessman kept his word.","The entrepreneur provided accurate information.","The investor received transparent financial reports."]},{en:"Optical illusions can deceive your eyes.",ja:"光学的な錯覚はあなたの目を欺くことができます。",wrong:["Optical illusions show everything clearly.","Illusions provide accurate visual information.","Your eyes always perceive things correctly."]}]},{word:"decree",meaning:"法令、命令する",example:"The emperor issued a decree banning the practice.",category:"history",difficulty:5,examples:[{en:"The king issued a decree that changed the law.",ja:"その王は法律を変えた法令を発令しました。",wrong:["The king suggested a optional guideline.","The ruler offered a recommendation.","The monarch made a casual suggestion."]},{en:"The government will decree new environmental regulations.",ja:"政府は新しい環境規制を命令するでしょう。",wrong:["The officials will ignore environmental issues.","The state will make no new rules.","The administration will dismiss conservation efforts."]},{en:"A royal decree forbade hunting in the forest.",ja:"王令は森での狩猟を禁じました。",wrong:["The announcement permitted all hunting activities.","The rule allowed unlimited forest use.","The proclamation encouraged wildlife exploitation."]}]},{word:"deem",meaning:"見なす",example:"The building was deemed unsafe for occupancy.",category:"society",difficulty:4,examples:[{en:"The committee will deem the proposal acceptable.",ja:"委員会はその提案を許容可能であると見なすでしょう。",wrong:["The committee will consider it completely unacceptable.","The board will reject the entire proposal.","The group will disapprove of all suggestions."]},{en:"She was deemed the best candidate for the job.",ja:"彼女はその仕事の最良の候補者であると見なされました。",wrong:["He was considered the worst choice.","She was judged to be unqualified.","The applicant was deemed unsuitable."]},{en:"The court deemed the evidence insufficient.",ja:"裁判所はその証拠を不十分であると見なしました。",wrong:["The judge considered the proof overwhelming.","The tribunal deemed it completely adequate.","The court found it thoroughly convincing."]}]},{word:"defect",meaning:"欠陥、亡命する",example:"A defect in the engine caused the crash.",category:"technology",difficulty:4,examples:[{en:"The manufacturer recalled the car due to a serious defect.",ja:"メーカーは深刻な欠陥のためにその車をリコールしました。",wrong:["The company praised the car's perfect design.","The product was flawless in every way.","There were no problems with the vehicle."]},{en:"The soldier decided to defect to the other side.",ja:"その兵士は反対側に亡命することを決めました。",wrong:["The soldier remained loyal to his country.","He refused to betray his allegiance.","The fighter stayed committed to his cause."]},{en:"Quality control found a defect in the product.",ja:"品質管理はその製品に欠陥を見つけました。",wrong:["The inspection confirmed perfect quality.","No issues were detected in testing.","The product passed all quality standards."]}]},{word:"defer",meaning:"延期する、敬意を払う",example:"The committee deferred the decision until next month.",category:"society",difficulty:4,examples:[{en:"The company decided to defer the project until next year.",ja:"会社はプロジェクトを来年まで延期することを決めました。",wrong:["The organization started the project immediately.","They rushed to complete it today.","The firm proceeded without any delay."]},{en:"He chose to defer to his manager's judgment.",ja:"彼はマネージャーの判断に敬意を払うことを選びました。",wrong:["He ignored his manager's opinion completely.","He refused to respect his superior.","He contradicted all management decisions."]},{en:"They decided to defer payment until the next quarter.",ja:"彼らは次四半期まで支払いを延期することを決めました。",wrong:["They paid the full amount immediately.","Payment was made without delay.","The bill was settled right away."]}]},{word:"deficit",meaning:"赤字、不足",example:"The country faces a growing trade deficit.",category:"current",difficulty:4,examples:[{en:"The government's budget deficit increased this year.",ja:"政府の予算赤字は今年増加しました。",wrong:["The budget showed a large surplus.","The government had extra funds available.","The financial situation improved significantly."]},{en:"The athlete has a deficit in upper body strength.",ja:"その運動選手は上半身の強さの不足を持っています。",wrong:["The athlete has excellent upper body strength.","He is strong in all physical areas.","The competitor has no weakness whatsoever."]},{en:"Many schools face a deficit in funding.",ja:"多くの学校は資金不足に直面しています。",wrong:["Schools have abundant financial resources.","Educational institutions are fully funded.","There is sufficient money for all programs."]}]},{word:"defy",meaning:"反抗する",example:"The protesters defied the government ban.",category:"society",difficulty:3,examples:[{en:"The rebels decided to defy the government.",ja:"その反乱者は政府に反抗することを決めました。",wrong:["The revolutionaries obeyed all laws.","They submitted to authority completely.","The group followed all regulations."]},{en:"She continued to defy her parents' wishes.",ja:"彼女は両親の願いに反抗し続けました。",wrong:["She always respected her parents' decisions.","She obeyed every instruction given.","She never questioned their authority."]},{en:"The acrobat seemed to defy the laws of physics.",ja:"その曲芸師は物理学の法則に反抗しているように見えました。",wrong:["The performer followed all physical limitations.","Gravity had complete control over the movement.","The gymnast was bound by normal constraints."]}]},{word:"delegate",meaning:"代表者、委任する",example:"Managers should learn to delegate tasks effectively.",category:"society",difficulty:4,examples:[{en:"The manager decided to delegate the project to her assistant.",ja:"マネージャーはそのプロジェクトをアシスタントに委任することにした。",wrong:["マネージャーはそのプロジェクトを廃棄することにした。","マネージャーはそのプロジェクトを拒否することにした。","マネージャーはそのプロジェクトを販売することにした。"]},{en:"Each delegate at the conference represented their country.",ja:"会議の各代表者は自国を代表していた。",wrong:["会議の各廃棄物は自国を代表していた。","会議の各医者は自国を代表していた。","会議の各警察官は自国を代表していた。"]},{en:"I will delegate the responsibility to someone more experienced.",ja:"私はその責任をより経験のある人に委任する。",wrong:["私はその責任を盗む。","私はその責任を隠す。","私はその責任を燃やす。"]}]},{word:"demolish",meaning:"取り壊す",example:"The old factory was demolished to make way for a park.",category:"society",difficulty:3,examples:[{en:"The old building will be demolished next month.",ja:"その古い建物は来月取り壊される。",wrong:["その古い建物は来月修理される。","その古い建物は来月装飾される。","その古い建物は来月改築される。"]},{en:"Heavy machinery was used to demolish the factory.",ja:"重機を使って工場を取り壊した。",wrong:["重機を使って工場を建設した。","重機を使って工場を修復した。","重機を使って工場を拡張した。"]},{en:"The argument completely demolished his theory.",ja:"その議論は彼の理論を完全に破壊した。",wrong:["その議論は彼の理論を支持した。","その議論は彼の理論を改善した。","その議論は彼の理論を強化した。"]}]},{word:"denounce",meaning:"非難する、告発する",example:"Human rights groups denounced the policy.",category:"society",difficulty:5,examples:[{en:"The activist denounced the government's policies on environmental protection.",ja:"その活動家は政府の環境保護政策を非難した。",wrong:["その活動家は政府の環境保護政策を賞賛した。","その活動家は政府の環境保護政策を実行した。","その活動家は政府の環境保護政策を提案した。"]},{en:"He was denounced as a traitor by his former colleagues.",ja:"彼は元同僚に裏切り者として告発された。",wrong:["彼は元同僚に英雄として昇進された。","彼は元同僚に友人として招待された。","彼は元同僚に指導者として任命された。"]},{en:"The witness denounced the criminal to the police.",ja:"その証人は犯人を警察に告発した。",wrong:["その証人は犯人を保護した。","その証人は犯人を逃がした。","その証人は犯人を雇った。"]}]},{word:"deploy",meaning:"展開する、配置する",example:"The army deployed troops along the border.",category:"society",difficulty:4,examples:[{en:"The military deployed troops to the border region.",ja:"軍隊は国境地域に兵士を配置した。",wrong:["軍隊は国境地域に難民を避難させた。","軍隊は国境地域に物資を保管した。","軍隊は国境地域に建物を建設した。"]},{en:"The company deployed new software to improve efficiency.",ja:"会社は効率を改善するために新しいソフトウェアを展開した。",wrong:["会社は効率を改善するために古いソフトウェアを削除した。","会社は効率を改善するために機械を売却した。","会社は効率を改善するために従業員を解雇した。"]},{en:"Emergency services were deployed to the disaster area.",ja:"緊急サービスが災害地域に配置された。",wrong:["緊急サービスが災害地域から撤退した。","緊急サービスが災害地域を爆撃した。","緊急サービスが災害地域を隔離した。"]}]},{word:"deprive",meaning:"奪う",example:"The prisoners were deprived of basic human rights.",category:"society",difficulty:4,examples:[{en:"The court decided to deprive him of his citizenship.",ja:"裁判所は彼から市民権を奪うことに決めた。",wrong:["裁判所は彼に市民権を与えることに決めた。","裁判所は彼の市民権を確認することに決めた。","裁判所は彼の市民権を延長することに決めた。"]},{en:"Sleep deprivation can seriously affect your health.",ja:"睡眠不足はあなたの健康に深刻な影響を与える可能性がある。",wrong:["睡眠の改善はあなたの健康に深刻な影響を与える可能性がある。","睡眠の増加はあなたの健康に深刻な影響を与える可能性がある。","睡眠の享受はあなたの健康に深刻な影響を与える可能性がある。"]},{en:"The punishment deprived him of his freedom.",ja:"その罰は彼から自由を奪った。",wrong:["その罰は彼に自由を与えた。","その罰は彼の自由を拡大した。","その罰は彼の自由を回復した。"]}]},{word:"desolate",meaning:"荒涼とした",example:"The landscape was desolate and windswept.",category:"science",difficulty:5,examples:[{en:"The abandoned town had a desolate appearance.",ja:"その放棄された町は荒涼とした外観をしていた。",wrong:["その放棄された町は活気に満ちた外観をしていた。","その放棄された町は繁栄した外観をしていた。","その放棄された町は華やかな外観をしていた。"]},{en:"The desolate landscape stretched for miles.",ja:"荒涼とした風景は何マイルも広がっていた。",wrong:["緑豊かな風景は何マイルも広がっていた。","活気に満ちた風景は何マイルも広がっていた。","美しい風景は何マイルも広がっていた。"]},{en:"After the disaster, the city was left desolate and empty.",ja:"災害後、その都市は荒涼として空っぽのままだった。",wrong:["災害後、その都市は繁栄して満員のままだった。","災害後、その都市は再建されて活気づいていた。","災害後、その都市は装飾されて美しくなった。"]}]},{word:"detain",meaning:"拘留する",example:"Police detained the suspect for questioning.",category:"society",difficulty:4,examples:[{en:"The police detained the suspect for questioning.",ja:"警察は容疑者を尋問のために拘留した。",wrong:["警察は容疑者を解放した。","警察は容疑者を採用した。","警察は容疑者を昇進させた。"]},{en:"I apologize for detaining you so long.",ja:"長い間あなたを引き止めてしまい申し訳ない。",wrong:["あなたを急いで解放してしまい申し訳ない。","あなたを忘れてしまい申し訳ない。","あなたを無視してしまい申し訳ない。"]},{en:"Customs detained the shipment for inspection.",ja:"税関は検査のために荷物を拘留した。",wrong:["税関は検査のために荷物を配送した。","税関は検査のために荷物を販売した。","税関は検査のために荷物を破棄した。"]}]},{word:"deter",meaning:"阻止する",example:"High fines deter people from speeding.",category:"society",difficulty:4,examples:[{en:"The high price deters many potential customers.",ja:"その高い価格は多くの潜在的な顧客を阻止する。",wrong:["その高い価格は多くの潜在的な顧客を魅了する。","その高い価格は多くの潜在的な顧客を招く。","その高い価格は多くの潜在的な顧客を増やす。"]},{en:"The warning signs were designed to deter trespassers.",ja:"その警告標識は不法侵入者を阻止するために設計された。",wrong:["その警告標識は不法侵入者を歓迎するために設計された。","その警告標識は不法侵入者を招待するために設計された。","その警告標識は不法侵入者を支援するために設計された。"]},{en:"Nothing could deter him from his goal.",ja:"何も彼を目標から阻止できなかった。",wrong:["何も彼を目標へ促進できなかった。","何も彼を目標に近づけなかった。","何も彼を目標で成功させなかった。"]}]},{word:"devastate",meaning:"壊滅させる",example:"The tsunami devastated coastal communities.",category:"current",difficulty:3,examples:[{en:"The hurricane devastated the coastal region.",ja:"ハリケーンは沿岸地域を壊滅させた。",wrong:["ハリケーンは沿岸地域を修復した。","ハリケーンは沿岸地域を保護した。","ハリケーンは沿岸地域を改善した。"]},{en:"The news devastated the entire family.",ja:"そのニュースは家族全体に大きなショックを与えた。",wrong:["そのニュースは家族全体を喜ばせた。","そのニュースは家族全体を元気づけた。","そのニュースは家族全体を祝福した。"]},{en:"The economic crisis devastated small businesses.",ja:"経済危機は中小企業を壊滅させた。",wrong:["経済危機は中小企業を支援した。","経済危機は中小企業を成長させた。","経済危機は中小企業を繁栄させた。"]}]},{word:"deviate",meaning:"逸脱する",example:"The pilot deviated from the planned route.",category:"technology",difficulty:5,examples:[{en:"The road deviates from the original route.",ja:"その道は元のルートから逸脱している。",wrong:["その道は元のルートに従っている。","その道は元のルートと一致している。","その道は元のルートを改善している。"]},{en:"He refused to deviate from his principles.",ja:"彼は自分の原則から逸脱することを拒否した。",wrong:["彼は自分の原則に従うことを拒否した。","彼は自分の原則を支持することを拒否した。","彼は自分の原則を守ることを拒否した。"]},{en:"Don't deviate from the instructions.",ja:"指示から逸脱しないでください。",wrong:["指示に従ってください。","指示を改善してください。","指示を無視してください。"]}]},{word:"devote",meaning:"捧げる",example:"She devoted her life to medical research.",category:"science",difficulty:3,examples:[{en:"She devoted her life to helping others.",ja:"彼女は他者を助けることに人生を捧げた。",wrong:["彼女は他者から目を背けることに人生を捧げた。","彼女は自分自身に人生を捧げた。","彼女は富を集めることに人生を捧げた。"]},{en:"The company devotes significant resources to research and development.",ja:"その会社は研究開発に多大なリソースを捧げている。",wrong:["その会社は研究開発からリソースを削減している。","その会社は研究開発を停止している。","その会社は研究開発を売却している。"]},{en:"He devoted himself entirely to his studies.",ja:"彼は完全に勉強に自分自身を捧げた。",wrong:["彼は完全に勉強から逃げた。","彼は完全に勉強を避けた。","彼は完全に勉強を放棄した。"]}]},{word:"diagnose",meaning:"診断する",example:"The disease was diagnosed at an early stage.",category:"science",difficulty:3,examples:[{en:"The doctor diagnosed the patient with diabetes.",ja:"医者は患者を糖尿病と診断した。",wrong:["医者は患者を治した。","医者は患者を退院させた。","医者は患者を予防した。"]},{en:"The mechanic diagnosed the car's problem.",ja:"整備士は車の問題を診断した。",wrong:["整備士は車の問題を無視した。","整備士は車の問題を隠した。","整備士は車の問題を作成した。"]},{en:"Tests were performed to diagnose the illness.",ja:"その病気を診断するためにテストが実施された。",wrong:["その病気を治すためにテストが実施された。","その病気を予防するためにテストが実施された。","その病気を忘れるためにテストが実施された。"]}]},{word:"dictate",meaning:"命令する、口述する",example:"Market conditions dictate the price of goods.",category:"current",difficulty:4,examples:[{en:"The boss dictates the company's policies.",ja:"ボスは会社の方針を指示する。",wrong:["ボスは会社の方針を相談する。","ボスは会社の方針を提案する。","ボスは会社の方針を推奨する。"]},{en:"She dictated the letter to her secretary.",ja:"彼女は秘書に手紙を口述した。",wrong:["彼女は秘書に手紙を盗んだ。","彼女は秘書に手紙を焼いた。","彼女は秘書に手紙を隠した。"]},{en:"Don't let circumstances dictate your decisions.",ja:"状況があなたの決定を指示させないでください。",wrong:["状況があなたの決定を支援させてください。","状況があなたの決定を改善させてください。","状況があなたの決定を促進させてください。"]}]},{word:"diffuse",meaning:"拡散する、広まる",example:"The scent diffused throughout the room.",category:"science",difficulty:5,examples:[{en:"The smoke diffused throughout the room.",ja:"煙は部屋中に拡散した。",wrong:["煙は部屋の隅に集中した。","煙は部屋から消えた。","煙は部屋に濃くなった。"]},{en:"Information diffuses quickly through social media.",ja:"情報はソーシャルメディアを通じて素早く広まる。",wrong:["情報はソーシャルメディアを通じて遅く隠される。","情報はソーシャルメディアを通じて削除される。","情報はソーシャルメディアを通じて検閲される。"]},{en:"The light was diffuse and soft.",ja:"その光は拡散していて柔らかかった。",wrong:["その光は集中していて厳しかった。","その光は明るすぎて耀いていた。","その光は暗すぎて見えなかった。"]}]},{word:"diligent",meaning:"勤勉な",example:"She is a diligent student who always meets deadlines.",category:"society",difficulty:3,examples:[{en:"She is a diligent student who always completes her assignments.",ja:"彼女は常に課題を完了する勤勉な学生だ。",wrong:["彼女は怠惰な学生で課題を放棄する。","彼女は不注意な学生で課題を失う。","彼女は怠け者な学生で課題を避ける。"]},{en:"The researcher conducted diligent work to gather all the data.",ja:"その研究者はすべてのデータを収集するために勤勉に仕事をした。",wrong:["その研究者は怠惰に仕事をしてデータを失った。","その研究者は不注意に仕事をしてデータを盗んだ。","その研究者は雑に仕事をしてデータを破壊した。"]},{en:"Through diligent effort, he achieved his goals.",ja:"勤勉な努力を通じて、彼は目標を達成した。",wrong:["怠惰な努力を通じて、彼は目標を放棄した。","不注意な努力を通じて、彼は目標を失った。","雑な努力を通じて、彼は目標を破壊した。"]}]},{word:"diplomacy",meaning:"外交",example:"Diplomacy resolved the border dispute peacefully.",category:"history",difficulty:4,examples:[{en:"The ambassador used skillful diplomacy to negotiate the peace treaty.",ja:"大使は巧妙な外交を用いて平和条約を交渉した。",wrong:["The ambassador used aggressive warfare to negotiate the peace treaty.","The ambassador used harsh criticism to negotiate the peace treaty.","The ambassador used military force to negotiate the peace treaty."]},{en:"Diplomacy requires patience and understanding between nations.",ja:"外交は国家間の忍耐と理解を必要とする。",wrong:["Warfare requires patience and understanding between nations.","Diplomacy requires immediate action and confrontation between nations.","Diplomacy requires weapons and soldiers between nations."]},{en:"Through careful diplomacy, the two countries resolved their differences.",ja:"注意深い外交を通じて、2つの国は違いを解決した。",wrong:["Through military conquest, the two countries resolved their differences.","Through trade wars, the two countries resolved their differences.","Through violence, the two countries resolved their differences."]}]},{word:"discard",meaning:"捨てる",example:"Old batteries should be discarded responsibly.",category:"current",difficulty:3,examples:[{en:"I decided to discard the old newspapers and recycle them.",ja:"私は古い新聞を捨ててリサイクルすることにした。",wrong:["I decided to preserve the old newspapers forever.","I decided to treasure the old newspapers as collectibles.","I decided to sell the old newspapers as valuable items."]},{en:"She discarded her worn-out shoes and bought new ones.",ja:"彼女はボロボロの靴を捨てて新しいものを買った。",wrong:["She carefully stored her worn-out shoes in a safe place.","She donated her new shoes to charity.","She repaired her shoes instead of replacing them."]},{en:"The company decided to discard the failed project and start fresh.",ja:"会社は失敗したプロジェクトを廃棄して新しく始めることにした。",wrong:["The company decided to invest more money in the failed project.","The company decided to continue the failed project indefinitely.","The company decided to expand the failed project."]}]},{word:"discretion",meaning:"裁量、慎重さ",example:"The matter was handled with great discretion.",category:"society",difficulty:5,examples:[{en:"The doctor handled the sensitive patient information with great discretion.",ja:"医者は敏感な患者情報を大変な慎重さで扱った。",wrong:["The doctor shared the patient information on social media carelessly.","The doctor disclosed the patient information to strangers.","The doctor published the patient information in newspapers."]},{en:"Use your discretion when deciding how to spend the budget.",ja:"予算の使い方を決めるときに裁量を使いなさい。",wrong:["Use only the instructions given without any independent judgment.","Follow the rules strictly without any flexibility.","Ask permission for every single decision."]},{en:"The judge had discretion in sentencing the defendant.",ja:"裁判官は被告人に判決を下す際に裁量権があった。",wrong:["The judge had no choice but to follow a fixed sentence.","The judge was not allowed to make any decisions.","The judge had to ask the defendant how to sentence them."]}]},{word:"discriminate",meaning:"差別する、区別する",example:"It is illegal to discriminate on the basis of gender.",category:"society",difficulty:3,examples:[{en:"It is illegal to discriminate against people based on their race.",ja:"人種に基づいて人々を差別することは違法である。",wrong:["It is legal to treat all people equally regardless of background.","It is encouraged to give everyone fair opportunities.","It is required to respect everyone's rights."]},{en:"She can discriminate between high-quality and low-quality products.",ja:"彼女は高品質と低品質の製品を区別することができる。",wrong:["She cannot tell the difference between any products.","She thinks all products are identical.","She is unable to make comparisons between items."]},{en:"The company was accused of discriminating against female employees.",ja:"その企業は女性従業員を差別したと非難された。",wrong:["The company was praised for treating all employees equally.","The company provided equal opportunities to everyone.","The company ensured fair treatment for all staff members."]}]},{word:"dismiss",meaning:"却下する、解雇する",example:"The judge dismissed the case for lack of evidence.",category:"society",difficulty:3,examples:[{en:"The manager decided to dismiss the employee for misconduct.",ja:"マネージャーは不正行為のため従業員を解雇することにした。",wrong:["The manager decided to promote the employee for excellent work.","The manager decided to give the employee a raise.","The manager decided to reward the employee with a bonus."]},{en:"The judge dismissed the case due to lack of evidence.",ja:"裁判官は証拠不足のため事件を却下した。",wrong:["The judge upheld the case and convicted the defendant.","The judge decided to increase the charges.","The judge ordered a longer investigation."]},{en:"She dismissed his concerns without listening to his explanation.",ja:"彼女は彼の説明を聞かずに彼の懸念を却下した。",wrong:["She carefully considered all of his concerns.","She took his worries very seriously.","She gave him her full attention and support."]}]},{word:"disperse",meaning:"散らす",example:"Police used water cannons to disperse the crowd.",category:"society",difficulty:4,examples:[{en:"The police dispersed the crowd that had gathered in the square.",ja:"警察は広場に集まった群衆を散らした。",wrong:["The police brought the crowd together.","The police gathered more people in the square.","The police encouraged the crowd to stay."]},{en:"The wind dispersed the seeds across the field.",ja:"風は野原に種子を散らした。",wrong:["The wind collected the seeds in one place.","The wind planted the seeds in straight rows.","The wind buried the seeds underground."]},{en:"After the announcement, the audience dispersed and left the hall.",ja:"発表の後、観客は散って会場を去った。",wrong:["After the announcement, the audience gathered more closely.","After the announcement, the audience remained seated.","After the announcement, the audience crowded toward the stage."]}]},{word:"displace",meaning:"追い出す、取って代わる",example:"Millions of people were displaced by the conflict.",category:"current",difficulty:4,examples:[{en:"The flood displaced thousands of people from their homes.",ja:"洪水は数千人を彼らの家から追い出した。",wrong:["The flood helped people stay in their homes.","The flood repaired damaged homes.","The flood provided shelter for people."]},{en:"New technology has displaced many traditional workers.",ja:"新しい技術は多くの伝統的な労働者に取って代わった。",wrong:["New technology has created jobs for traditional workers.","New technology has supported traditional industries.","New technology has enhanced traditional methods."]},{en:"The new shopping center displaced several local businesses.",ja:"新しいショッピングセンターはいくつかの地元企業に取って代わった。",wrong:["The new shopping center helped local businesses thrive.","The new shopping center partnered with local shops.","The new shopping center supported the local economy."]}]},{word:"dispose",meaning:"処分する",example:"Toxic waste must be disposed of safely.",category:"current",difficulty:3,examples:[{en:"You need to dispose of the chemical waste properly.",ja:"化学廃棄物を適切に処分する必要がある。",wrong:["You should dump the chemical waste anywhere.","You can leave the waste in the environment.","You should pour the waste into the river."]},{en:"The company disposed of the defective products.",ja:"会社は不良製品を処分した。",wrong:["The company sold all defective products to customers.","The company kept the defective products in storage.","The company redistributed the defective products."]},{en:"After the party, we disposed of all the garbage.",ja:"パーティーの後、すべてのゴミを処分した。",wrong:["After the party, we collected garbage in a pile.","After the party, we scattered garbage everywhere.","After the party, we left garbage on the floor."]}]},{word:"dissolve",meaning:"溶かす、解散する",example:"Salt dissolves easily in warm water.",category:"science",difficulty:3,examples:[{en:"Sugar dissolves quickly in hot water.",ja:"砂糖は熱湯に素早く溶ける。",wrong:["Sugar hardens in hot water.","Sugar becomes solid in hot water.","Sugar floats on top of hot water."]},{en:"The government decided to dissolve the parliament.",ja:"政府は議会を解散することを決めた。",wrong:["The government decided to strengthen the parliament.","The government decided to expand the parliament.","The government decided to make the parliament permanent."]},{en:"Salt dissolves in water to create a solution.",ja:"塩は水に溶けて溶液を作る。",wrong:["Salt mixes with water but remains solid.","Salt separates from water immediately.","Salt sinks to the bottom unchanged."]}]},{word:"distinct",meaning:"明確な、異なる",example:"There are two distinct approaches to the problem.",category:"science",difficulty:3,examples:[{en:"There are distinct differences between the two cultures.",ja:"2つの文化の間に明確な違いがある。",wrong:["The two cultures are almost identical.","The cultures have no differences.","The cultures are very similar in every way."]},{en:"Each student has a distinct learning style.",ja:"各生徒は異なる学習スタイルを持っている。",wrong:["All students learn in exactly the same way.","Students have identical learning preferences.","There is only one correct way for everyone to learn."]},{en:"The flavor of this wine is distinct and memorable.",ja:"このワインの味は明確で印象的だ。",wrong:["The flavor is bland and forgettable.","The taste is the same as all other wines.","The flavor is unclear and confusing."]}]},{word:"distort",meaning:"歪める",example:"The media distorted the facts of the case.",category:"current",difficulty:4,examples:[{en:"The funhouse mirror distorts your reflection.",ja:"楽しい家のミラーはあなたの反射を歪める。",wrong:["The funhouse mirror reflects you perfectly.","The mirror shows your true appearance.","The mirror keeps everything in its proper shape."]},{en:"He distorted the facts to make his case stronger.",ja:"彼は事実を歪めて彼の場合をより強くした。",wrong:["He presented the facts honestly and accurately.","He told the complete truth without exaggeration.","He provided accurate information."]},{en:"The report distorted the data to support their argument.",ja:"レポートは彼らの議論をサポートするためにデータを歪めた。",wrong:["The report presented unbiased data.","The report showed accurate information.","The report was completely objective."]}]},{word:"distribute",meaning:"分配する",example:"Aid was distributed to the affected areas.",category:"society",difficulty:3,examples:[{en:"The organization distributed food to the homeless.",ja:"組織はホームレスに食料を配布した。",wrong:["The organization kept all food for themselves.","The organization discarded the food.","The organization sold the food privately."]},{en:"She distributed the award equally among the winners.",ja:"彼女は賞を勝者に均等に配分した。",wrong:["She gave all the award to one person.","She kept the award for herself.","She threw away the prize money."]},{en:"The teacher distributed the worksheets to all students.",ja:"先生はすべての生徒にワークシートを配布した。",wrong:["The teacher kept all worksheets on her desk.","The teacher gave worksheets to only some students.","The teacher collected the worksheets without sharing."]}]},{word:"diversity",meaning:"多様性",example:"Cultural diversity enriches our society.",category:"society",difficulty:3,examples:[{en:"The university celebrates diversity among its student body.",ja:"大学は学生集団の多様性を祝う。",wrong:["The university excludes people from different backgrounds.","The university prefers students from a single culture.","The university discourages diversity."]},{en:"There is great diversity in the types of animals in the rainforest.",ja:"熱帯雨林には様々な種類の動物の大きな多様性がある。",wrong:["The rainforest has only one type of animal.","The rainforest lacks variety.","All animals in the rainforest are identical."]},{en:"The company values diversity and inclusion in hiring.",ja:"会社は採用の多様性と包括性を大切にしている。",wrong:["The company only hires people from the same background.","The company excludes certain groups.","The company discriminates in its hiring practices."]}]},{word:"domestic",meaning:"国内の、家庭の",example:"Domestic demand for electric vehicles is rising.",category:"current",difficulty:3,examples:[{en:"Domestic flights are shorter than international flights.",ja:"国内線は国際線より短い。",wrong:["Domestic flights go to foreign countries.","Domestic flights are international flights.","Domestic flights cross multiple borders."]},{en:"She prefers domestic wines produced in her own country.",ja:"彼女は自国で生産された国内ワインを好む。",wrong:["She only drinks wines from other countries.","She avoids wines produced at home.","She prefers imported wines exclusively."]},{en:"Domestic violence is a serious social problem.",ja:"家庭内暴力は深刻な社会問題である。",wrong:["Family relationships are always peaceful.","Domestic violence doesn't really exist.","All home environments are safe."]}]},{word:"dominate",meaning:"支配する",example:"A few large firms dominate the market.",category:"current",difficulty:3,examples:[{en:"The larger team dominated the game and won easily.",ja:"より大きなチームがゲームを支配して簡単に勝った。",wrong:["The larger team lost the game.","The larger team was defeated badly.","The larger team had no control over the game."]},{en:"Her personality dominates every conversation.",ja:"彼女の個性はすべての会話を支配する。",wrong:["Her personality is timid and quiet.","She never speaks in conversations.","Others easily take charge in her presence."]},{en:"Spain's empire dominated many regions during the colonial period.",ja:"スペイン帝国は植民地時代に多くの地域を支配した。",wrong:["Spain's empire was weak and powerless.","Spain was conquered by other nations.","Spain had no influence over other regions."]}]},{word:"drastic",meaning:"抜本的な",example:"Drastic measures are needed to reduce emissions.",category:"current",difficulty:3,examples:[{en:"The company made drastic changes to its business strategy.",ja:"その会社はビジネス戦略に抜本的な変更を加えた。",wrong:["その会社は戦略に些細な変更を加えた。","その会社は戦略を徐々に改善した。","その会社は戦略を完全に放棄した。"]},{en:"We need drastic measures to reduce pollution.",ja:"汚染を減らすために抜本的な対策が必要だ。",wrong:["汚染を少し改善するための対策が必要だ。","汚染を無視するための対策が必要だ。","汚染を増やすための対策が必要だ。"]},{en:"The drastic temperature drop caught everyone by surprise.",ja:"抜本的な気温低下は皆を驚かせた。",wrong:["わずかな気温上昇は皆を驚かせた。","気温は安定していて皆を驚かせた。","気温の上昇は予測されていた。"]}]},{word:"drought",meaning:"干ばつ",example:"The region suffered its worst drought in decades.",category:"current",difficulty:3,examples:[{en:"The severe drought destroyed crops across the region.",ja:"ひどい干ばつは地域全体の作物を破壊した。",wrong:["大洪水は地域全体の作物を破壊した。","大雪は地域全体の作物を破壊した。","豊かな降雨は地域全体の作物を破壊した。"]},{en:"California experienced a prolonged drought lasting several years.",ja:"カリフォルニアは数年間続く干ばつを経験した。",wrong:["カリフォルニアは豊富な降水を経験した。","カリフォルニアは短期間の干ばつを経験した。","カリフォルニアは洪水を経験した。"]},{en:"Many animals died during the drought due to lack of water.",ja:"干ばつの間に多くの動物が水不足で死んだ。",wrong:["干ばつの間に多くの動物が水が多すぎて死んだ。","干ばつの間に多くの動物が生まれた。","干ばつの間に多くの動物が栄えた。"]}]},{word:"dubious",meaning:"疑わしい",example:"His claims seemed dubious at best.",category:"society",difficulty:4,examples:[{en:"The witness's testimony seemed dubious to the judge.",ja:"その証人の証言は裁判官には疑わしく思えた。",wrong:["その証人の証言は裁判官には明らかに正しく思えた。","その証人の証言は裁判官には完全に信頼できると思えた。","その証人の証言は裁判官には確実に真実と思えた。"]},{en:"His dubious claims about winning the lottery raised suspicion.",ja:"彼の宝くじに勝ったという疑わしい主張は疑惑を生じさせた。",wrong:["彼の宝くじに勝ったという明白な主張は確認された。","彼の宝くじに勝ったという信頼できる主張は証明された。","彼の宝くじに勝ったという明らかに真実の主張は検証された。"]},{en:"The quality of the product was dubious at best.",ja:"その製品の品質は最高でも疑わしかった。",wrong:["その製品の品質は明らかに優れていた。","その製品の品質は完全に信頼できた。","その製品の品質は確実に最高だった。"]}]},{word:"dwell",meaning:"住む、くよくよ考える",example:"It is unhealthy to dwell on past mistakes.",category:"society",difficulty:4,examples:[{en:"They dwell in a small cottage near the forest.",ja:"彼らは森の近くの小さな小屋に住んでいる。",wrong:["彼らは大都市の高層ビルに住んでいる。","彼らは森の中心部に住んでいる。","彼らは海岸の大きな家に住んでいる。"]},{en:"Don't dwell on your past mistakes; focus on the future.",ja:"過去の失敗にくよくよ考えないで、将来に焦点を当てなさい。",wrong:["過去の失敗を忘れなさい。","過去の失敗を無視しなさい。","過去の失敗を祝いなさい。"]},{en:"She tends to dwell on negative thoughts.",ja:"彼女はネガティブな思考にくよくよ考える傾向がある。",wrong:["彼女はポジティブな思考を無視する傾向がある。","彼女はすべての思考を忘れる傾向がある。","彼女は思考することを避ける傾向がある。"]}]},{word:"eclipse",meaning:"食、凌駕する",example:"The new product eclipsed its predecessor in sales.",category:"science",difficulty:4,examples:[{en:"A solar eclipse will occur next month.",ja:"来月に日食が起こるでしょう。",wrong:["来月に月食が起こるでしょう。","来月に流星が起こるでしょう。","来月に虹が起こるでしょう。"]},{en:"The younger athlete's performance began to eclipse the champion's record.",ja:"若い選手のパフォーマンスはチャンピオンの記録を凌駕し始めた。",wrong:["若い選手のパフォーマンスはチャンピオンの記録を支持し始めた。","若い選手のパフォーマンスはチャンピオンの記録を追従し始めた。","若い選手のパフォーマンスはチャンピオンの記録を模倣し始めた。"]},{en:"Her talent will eclipse all her competitors.",ja:"彼女の才能はすべての競争相手を凌駕するでしょう。",wrong:["彼女の才能はすべての競争相手を支援するでしょう。","彼女の才能はすべての競争相手と同等でしょう。","彼女の才能はすべての競争相手を助けるでしょう。"]}]},{word:"ecosystem",meaning:"生態系",example:"Coral reefs are vital marine ecosystems.",category:"science",difficulty:3,examples:[{en:"The rainforest ecosystem is incredibly diverse.",ja:"熱帯雨林の生態系は非常に多様である。",wrong:["砂漠の単純な生態系は多様である。","都市の人工環境は自然の生態系である。","人間が作った世界は生態系ではない。"]},{en:"Pollution threatens the entire ocean ecosystem.",ja:"汚染は海全体の生態系を脅かしている。",wrong:["汚染は海の生態系を改善している。","汚染は海の生態系を強化している。","汚染は海の生態系に良い影響を与えている。"]},{en:"We must protect fragile ecosystems from human interference.",ja:"人間の干渉から壊れやすい生態系を保護しなければならない。",wrong:["人間の干渉から頑丈な生態系を保護する必要がある。","人間の干渉で壊れやすい生態系を改善する必要がある。","人間の開発で壊れやすい生態系を強化する必要がある。"]}]},{word:"eligible",meaning:"資格がある",example:"Only residents over 18 are eligible to vote.",category:"society",difficulty:3,examples:[{en:"You are eligible to apply for this scholarship if you meet the requirements.",ja:"要件を満たしていれば、この奨学金に応募する資格があります。",wrong:["あなたはこの奨学金の要件を満たしていないので申請できません。","あなたはこの奨学金の資格がありません。","あなたはこの奨学金には不適切です。"]},{en:"Only eligible candidates will be interviewed for the position.",ja:"この職位のインタビューに呼ばれるのは資格のある候補者だけです。",wrong:["不適格な候補者のみがこの職位のインタビューに呼ばれます。","誰もが資格のないこの職位のインタビューに呼ばれます。","このポジションには誰も適切ではありません。"]},{en:"All eligible voters must register before the election.",ja:"すべての投票資格のある有権者は選挙前に登録する必要があります。",wrong:["不適格な投票者は選挙前に登録する必要があります。","誰もが登録する必要がないわけではありません。","すべての国民が投票する資格があります。"]}]},{word:"eliminate",meaning:"排除する",example:"We need to eliminate unnecessary costs.",category:"society",difficulty:3,examples:[{en:"The coach decided to eliminate three players from the team.",ja:"コーチはチームから3人の選手を排除することにした。",wrong:["コーチはチームに3人の選手を追加することにした。","コーチはチームの3人の選手を昇進させることにした。","コーチはチームの3人の選手を報酬することにした。"]},{en:"We need to eliminate waste to reduce costs.",ja:"費用を削減するために廃棄物を排除する必要があります。",wrong:["費用を増やすために廃棄物を増加させる必要があります。","費用を削減するために廃棄物を保持する必要があります。","費用を削減するために廃棄物を保護する必要があります。"]},{en:"The new policy aims to eliminate discrimination in the workplace.",ja:"新しい政策は職場での差別を排除することを目指しています。",wrong:["新しい政策は職場での差別を増やすことを目指しています。","新しい政策は職場での差別を奨励することを目指しています。","新しい政策は職場での差別を強化することを目指しています。"]}]},{word:"eloquent",meaning:"雄弁な",example:"She gave an eloquent speech at the ceremony.",category:"culture",difficulty:5,examples:[{en:"The speaker delivered an eloquent speech that moved the audience.",ja:"スピーカーは聴衆を感動させた雄弁なスピーチをした。",wrong:["スピーカーは聴衆を退屈させた不明確なスピーチをした。","スピーカーは聴衆を困惑させた不器用なスピーチをした。","スピーカーは聴衆を失望させた無言のスピーチをした。"]},{en:"Her eloquent writing style captivated many readers.",ja:"彼女の雄弁な文体は多くの読者を魅了した。",wrong:["彼女の不明確な文体は多くの読者を混乱させた。","彼女の素朴な文体は多くの読者を退屈させた。","彼女の拙い文体は多くの読者を失望させた。"]},{en:"The eloquent diplomat successfully negotiated the peace agreement.",ja:"雄弁な外交官は平和協定をうまく交渉した。",wrong:["無言の外交官は平和協定を交渉できなかった。","不器用な外交官は紛争を悪化させた。","沈黙する外交官は何も達成できなかった。"]}]},{word:"embrace",meaning:"受け入れる、抱擁",example:"The company embraced new technology early.",category:"technology",difficulty:3,examples:[{en:"She embraced her friend warmly at the airport.",ja:"彼女は空港で友人を温かく抱擁した。",wrong:["彼女は空港で友人を突き放した。","彼女は空港で友人を避けた。","彼女は空港で友人を無視した。"]},{en:"The company decided to embrace new technology.",ja:"その会社は新しい技術を受け入れることにした。",wrong:["その会社は新しい技術を拒否することにした。","その会社は新しい技術を避けることにした。","その会社は新しい技術を廃止することにした。"]},{en:"We should embrace diversity in our community.",ja:"私たちは私たちのコミュニティで多様性を受け入れるべきです。",wrong:["私たちは私たちのコミュニティで多様性を排除すべきです。","私たちは私たちのコミュニティで多様性を拒否すべきです。","私たちは私たちのコミュニティで均一性を強制すべきです。"]}]},{word:"emerging",meaning:"新興の",example:"Emerging economies are growing rapidly.",category:"current",difficulty:3,examples:[{en:"Several emerging technologies are changing the industry.",ja:"いくつかの新興技術が業界を変えている。",wrong:["いくつかの衰退している技術が業界を変えている。","いくつかの確立された古い技術が業界を変えている。","いくつかの消滅している技術が業界を変えている。"]},{en:"The emerging market offers great investment opportunities.",ja:"新興市場は素晴らしい投資機会を提供している。",wrong:["衰退市場は素晴らしい投資機会を提供している。","成熟した確立市場は素晴らしい新しい機会を提供している。","消滅市場は投資の機会を提供している。"]},{en:"Emerging economies are growing faster than developed ones.",ja:"新興経済は発展した経済よりも速く成長している。",wrong:["衰退経済は発展した経済よりも速く成長している。","確立経済は衰退経済よりも速く成長している。","消滅経済は存在する経済よりも速く成長している。"]}]},{word:"emit",meaning:"放出する",example:"The factory emits large amounts of carbon dioxide.",category:"current",difficulty:4,examples:[{en:"The factory emits harmful gases into the atmosphere.",ja:"その工場は有害なガスを大気中に放出している。",wrong:["その工場は有益なガスを吸収している。","その工場は大気を浄化している。","その工場は汚染を減らしている。"]},{en:"The sun emits light and heat.",ja:"太陽は光と熱を放出している。",wrong:["太陽は光と熱を吸収している。","太陽は光と熱を反射している。","太陽は光と熱を隠している。"]},{en:"The car emits carbon dioxide when it burns fuel.",ja:"その車は燃料を燃やすときに二酸化炭素を放出している。",wrong:["その車は燃料を燃やすときに酸素を放出している。","その車は燃料を燃やすときにガスを吸収している。","その車は燃料を燃やすときに水を放出している。"]}]},{word:"empathy",meaning:"共感",example:"Good leaders show empathy towards their team.",category:"society",difficulty:3,examples:[{en:"The counselor showed great empathy towards her clients.",ja:"カウンセラーはクライアントに対して大きな共感を示した。",wrong:["カウンセラーはクライアントに対して無関心を示した。","カウンセラーはクライアントに対して同情ではなく共感を示さなかった。","カウンセラーはクライアントに対して批判を示した。"]},{en:"To be a good teacher, you need empathy for your students.",ja:"良い先生になるには、生徒に対する共感が必要です。",wrong:["良い先生になるには、生徒への無関心が必要です。","良い先生になるには、生徒への批判が必要です。","良い先生になるには、生徒への厳しさが必要です。"]},{en:"Empathy helps us understand others' perspectives and feelings.",ja:"共感は他の人の視点と感情を理解するのに役立ちます。",wrong:["無関心は他の人の視点と感情を理解するのに役立ちます。","批判は他の人の視点と感情を理解するのに役立ちます。","判断は他の人の視点と感情を理解するのに役立ちます。"]}]},{word:"empirical",meaning:"実証的な",example:"The theory is supported by empirical evidence.",category:"science",difficulty:5,examples:[{en:"The study was based on empirical evidence collected over five years.",ja:"その研究は5年間に渡って収集された実証的な証拠に基づいていた。",wrong:["その研究は推測に基づいていた。","その研究は個人的な意見に基づいていた。","その研究は神話に基づいていた。"]},{en:"Empirical research requires careful observation and measurement.",ja:"実証的な研究は慎重な観察と測定を必要とします。",wrong:["理論的な推測は慎重な観察と測定を必要とします。","空想的な研究は証拠を必要とします。","投機的な研究は観察を必要とします。"]},{en:"The team relied on empirical data to make their conclusions.",ja:"チームは結論を出すために実証的なデータに頼った。",wrong:["チームは結論を出すために推測に頼った。","チームは結論を出すために個人的な感覚に頼った。","チームは結論を出すために仮説に頼った。"]}]},{word:"endeavour",meaning:"努力する",example:"We must endeavour to find a peaceful solution.",category:"society",difficulty:4,examples:[{en:"The team made every endeavour to win the championship.",ja:"チームはチャンピオンシップを獲得するためにあらゆる努力をした。",wrong:["チームは何もしないことを努力した。","チームは試合に負けるために努力した。","チームは参加しないことを努力した。"]},{en:"She continues to endeavour to improve her skills.",ja:"彼女はスキルを向上させるために努力し続けている。",wrong:["彼女はスキルを悪化させるために努力し続けている。","彼女はスキルを学習することを避けている。","彼女は改善を放棄した。"]},{en:"The company endeavours to provide excellent customer service.",ja:"その会社は優れた顧客サービスを提供するために努力している。",wrong:["その会社は悪い顧客サービスを提供するために努力している。","その会社は顧客を無視するために努力している。","その会社は顧客満足度を減らすために努力している。"]}]},{word:"endorse",meaning:"支持する、推薦する",example:"The celebrity endorsed the new product.",category:"current",difficulty:3,examples:[{en:"The celebrity decided to endorse the new smartphone brand.",ja:"その有名人は新しいスマートフォンブランドを推薦することにした。",wrong:["その有名人はスマートフォンブランドを禁止した。","その有名人はスマートフォンを批判した。","その有名人はスマートフォンを修理した。"]},{en:"I fully endorse your proposal for the project.",ja:"私はあなたのプロジェクト提案を完全に支持します。",wrong:["私はあなたの提案を拒否します。","私はあなたの提案に反対です。","私はあなたの提案を無視します。"]},{en:"The organization will not endorse any political candidate.",ja:"その組織はいかなる政治候補者も推薦しない。",wrong:["その組織はすべての候補者を選出する。","その組織は政治家を雇う。","その組織は選挙を開催する。"]}]},{word:"enforce",meaning:"施行する",example:"Police enforce traffic laws strictly.",category:"society",difficulty:3,examples:[{en:"The government will enforce the new traffic laws starting next month.",ja:"政府は来月から新しい交通法を施行する。",wrong:["政府は交通法を廃止する。","政府は交通ルールを削除する。","政府は運転を禁止する。"]},{en:"Teachers must enforce classroom rules consistently.",ja:"教師は教室のルールを一貫して施行しなければならない。",wrong:["教師はルールを無視する必要がある。","教師はルールを変更する必要がある。","教師はルールをなくす必要がある。"]},{en:"The police will enforce the curfew throughout the city.",ja:"警察は都市全体でカーフューを施行する。",wrong:["警察はカーフューを廃止する。","警察は夜間外出を許可する。","警察は規則を忘れる。"]}]},{word:"enhance",meaning:"高める",example:"Regular exercise enhances physical and mental health.",category:"science",difficulty:3,examples:[{en:"This software will enhance your productivity significantly.",ja:"このソフトウェアはあなたの生産性を大幅に高める。",wrong:["このソフトウェアはあなたの生産性を低下させる。","このソフトウェアはあなたの効率を減らす。","このソフトウェアは仕事を遅くする。"]},{en:"The new lighting design will enhance the beauty of the building.",ja:"新しい照明デザインは建物の美しさを高める。",wrong:["新しい照明は建物を醜くする。","新しい照明は暗くする。","新しい照明は価値を下げる。"]},{en:"Adding spices will enhance the flavor of the dish.",ja:"スパイスを加えることは料理の味を高める。",wrong:["スパイスは味を悪くする。","スパイスは食べ物を台無しにする。","スパイスは味を消す。"]}]},{word:"enlighten",meaning:"啓発する",example:"The documentary enlightened viewers about climate change.",category:"culture",difficulty:4,examples:[{en:"The professor's lecture will enlighten students about quantum physics.",ja:"教授の講義は学生を量子物理学について啓発する。",wrong:["教授の講義は学生を混乱させる。","教授の講義は学生に何も教えない。","教授の講義は知識を減らす。"]},{en:"Can you enlighten me on this complicated topic?",ja:"この複雑なトピックについて私を啓発してくれますか？",wrong:["私を混乱させてくれますか？","この話題を隠してくれますか？","私を誤解させてくれますか？"]},{en:"The documentary aims to enlighten viewers about environmental issues.",ja:"そのドキュメンタリーは視聴者を環境問題について啓発することを目指している。",wrong:["ドキュメンタリーは視聴者を無視する。","ドキュメンタリーは真実を隠す。","ドキュメンタリーは視聴者を欺く。"]}]},{word:"entity",meaning:"実体、存在",example:"Each subsidiary operates as a separate legal entity.",category:"society",difficulty:5,examples:[{en:"The company is a legal entity that can sign contracts.",ja:"その会社は契約に署名できる法的実体です。",wrong:["その会社は人間ではない。","その会社は契約できない。","その会社は存在しない。"]},{en:"Each entity in the database has a unique identifier.",ja:"データベース内の各実体は一意の識別子を持っている。",wrong:["データベース内の各項目は同じである。","データベースに実体はない。","識別子は不要である。"]},{en:"The government recognized the organization as an independent entity.",ja:"政府はその組織を独立した実体として認識した。",wrong:["政府はそれを実体として認めなかった。","政府はそれを依存していると言った。","政府はそれを存在しないと言った。"]}]},{word:"entrepreneur",meaning:"起業家",example:"She became a successful entrepreneur at age 25.",category:"current",difficulty:3,examples:[{en:"Steve Jobs was an entrepreneur who founded Apple.",ja:"スティーブ・ジョブズはAppleを設立した起業家だった。",wrong:["スティーブ・ジョブズはAppleで働く従業員だった。","スティーブ・ジョブズはAppleを破壊した。","スティーブ・ジョブズは大企業の社長だった。"]},{en:"The entrepreneur invested her own money to start the business.",ja:"その起業家は事業を始めるために自分の金を投資した。",wrong:["起業家は他人の金を盗んだ。","起業家はお金を投資しなかった。","起業家は従業員だった。"]},{en:"Many entrepreneurs fail in their first business attempt.",ja:"多くの起業家は最初の事業で失敗する。",wrong:["起業家は常に成功する。","起業家は失敗しない。","起業家は事業を始めない。"]}]},{word:"envisage",meaning:"想定する",example:"It is hard to envisage a world without smartphones.",category:"technology",difficulty:5,examples:[{en:"The architect envisaged a modern building with sustainable features.",ja:"その建築家は持続可能な機能を備えた近代的な建物を想定した。",wrong:["建築家は古い建物を想定した。","建築家は何も計画しなかった。","建築家は伝統的な建物を想定した。"]},{en:"I cannot envisage a future without technological advancement.",ja:"私は技術進歩なしの未来を想定することはできない。",wrong:["私は技術なしの未来を簡単に想定できる。","私は過去を想定している。","私は現在を計画している。"]},{en:"The company envisages expanding to five new markets within two years.",ja:"その会社は2年以内に5つの新しい市場に拡大することを想定している。",wrong:["会社は縮小を計画している。","会社は拡大しない。","会社は市場を離れる。"]}]},{word:"epidemic",meaning:"流行病",example:"The epidemic spread rapidly across the continent.",category:"science",difficulty:3,examples:[{en:"The disease spread rapidly, creating an epidemic in the region.",ja:"その病気は急速に広がり、その地域に流行病を引き起こした。",wrong:["病気は広がらなかった。","流行病は起こらなかった。","病気は減少した。"]},{en:"Health officials declared an epidemic after hundreds of cases were reported.",ja:"数百件の症例が報告された後、保健当局は流行病を宣言した。",wrong:["保健当局は安全を宣言した。","誰も病気にならなかった。","症例は報告されなかった。"]},{en:"The government took emergency measures to control the epidemic.",ja:"政府は流行病を抑制するために緊急措置を講じた。",wrong:["政府は何もしなかった。","政府は流行病を無視した。","政府は拡大を助けた。"]}]},{word:"erode",meaning:"浸食する",example:"Coastal cliffs are being eroded by the sea.",category:"science",difficulty:4,examples:[{en:"Constant water flow will erode the stone over time.",ja:"継続的な水の流れは時間とともに石を浸食する。",wrong:["水は石を強くする。","水は石を硬くする。","石は水に耐える。"]},{en:"The scandal began to erode public trust in the government.",ja:"そのスキャンダルは政府に対する国民の信頼を浸食し始めた。",wrong:["スキャンダルは信頼を増やした。","スキャンダルは人気を高めた。","スキャンダルは支持を強めた。"]},{en:"Years of neglect will erode the foundation of the building.",ja:"何年もの放置は建物の基礎を浸食する。",wrong:["放置は建物を改善する。","放置は基礎を強化する。","放置は構造を保護する。"]}]},{word:"essence",meaning:"本質",example:"Trust is the essence of a good relationship.",category:"society",difficulty:3,examples:[{en:"The essence of good leadership is the ability to inspire others.",ja:"優れたリーダーシップの本質は他者を鼓舞する能力である。",wrong:["リーダーシップの本質は権力である。","リーダーシップの本質は富である。","リーダーシップの本質は知識である。"]},{en:"The essence of the problem lies in poor communication.",ja:"その問題の本質はコミュニケーション不足にある。",wrong:["問題はお金にある。","問題は技術にある。","問題は人数にある。"]},{en:"Understanding the essence of the text is more important than memorizing details.",ja:"テキストの本質を理解することは細部を記憶することより重要である。",wrong:["細部を記憶する方がより重要である。","テキストに本質はない。","本質を理解する必要はない。"]}]},{word:"ethnic",meaning:"民族の",example:"The country has a rich ethnic diversity.",category:"society",difficulty:3,examples:[{en:"The city has a diverse ethnic population from many different countries.",ja:"その都市は多くの異なる国からの多様な民族人口を持っている。",wrong:["都市は単一の民族だけである。","都市に異なる民族はいない。","すべて同じ文化である。"]},{en:"The museum displays ethnic artifacts from around the world.",ja:"その博物館は世界中の民族工芸品を展示している。",wrong:["博物館は現代美術のみを展示している。","博物館は1つの国の工芸品のみを持っている。","博物館に民族工芸品はない。"]},{en:"She is studying ethnic traditions and customs in her anthropology class.",ja:"彼女は人類学のクラスで民族の伝統と習慣を研究している。",wrong:["彼女は科学を学んでいる。","彼女は数学を研究している。","彼女は民族について学んでいない。"]}]},{word:"evacuate",meaning:"避難させる",example:"Residents were evacuated before the hurricane.",category:"current",difficulty:3,examples:[{en:"The residents were evacuated from the building due to the fire alarm.",ja:"火災警報のため、住民は建物から避難させられた。",wrong:["住民は建物に留まった。","誰も避難しなかった。","住民は火を消した。"]},{en:"The government ordered to evacuate the coastal areas before the hurricane arrives.",ja:"政府はハリケーン到着前に沿岸地域を避難させるよう命じた。",wrong:["政府は人々を留まらせた。","政府は避難を禁止した。","政府は何もしなかった。"]},{en:"Hospital staff helped evacuate the patients to safer locations.",ja:"病院スタッフは患者をより安全な場所に避難させるのを手伝った。",wrong:["スタッフは患者を危険な場所に移動させた。","患者は避難しなかった。","スタッフは何もしなかった。"]}]},{word:"evade",meaning:"逃れる、回避する",example:"He was charged with evading taxes.",category:"society",difficulty:4,examples:[{en:"The criminal tried to evade the police by hiding in the forest.",ja:"その犯人は森に隠れることで警察から逃れようとした。",wrong:["犯人は警察に会った。","犯人は逮捕を助けた。","犯人は警察に近づいた。"]},{en:"The company was accused of trying to evade taxes.",ja:"その会社は税金を回避しようとしていると非難された。",wrong:["会社は税金を完全に支払った。","会社は税金を増やした。","会社は正直に報告した。"]},{en:"He evaded answering the difficult question during the interview.",ja:"彼はインタビュー中に難しい質問に答えることを回避した。",wrong:["彼は質問に直接答えた。","彼は正直に返答した。","彼は詳しく説明した。"]}]},{word:"evolve",meaning:"進化する",example:"Technology continues to evolve at a rapid pace.",category:"science",difficulty:3,examples:[{en:"Species evolve over millions of years through natural selection.",ja:"種は自然選択を通じて数百万年にわたって進化する。",wrong:["種は進化しない。","種は瞬間的に変わる。","自然選択は存在しない。"]},{en:"Technology continues to evolve at a rapid pace.",ja:"技術は急速なペースで進化し続けている。",wrong:["技術は停止している。","技術は後退している。","技術は変わらない。"]},{en:"The company's strategy will evolve based on market feedback.",ja:"その会社の戦略は市場フィードバックに基づいて進化する。",wrong:["会社の戦略は変わらない。","戦略は市場を無視する。","フィードバックは無視される。"]}]},{word:"exaggerate",meaning:"誇張する",example:"The media tends to exaggerate risks.",category:"current",difficulty:3,examples:[{en:"He tends to exaggerate his accomplishments when talking to others.",ja:"彼は他の人と話すときに自分の成果を誇張する傾向がある。",wrong:["彼は自分の成果を控えめに述べる。","彼は嘘をつかない。","彼は正確に説明する。"]},{en:"The advertisement exaggerates the benefits of the product.",ja:"その広告は製品の利点を誇張している。",wrong:["広告は正確である。","広告は利点を控えめに述べている。","広告は欠点を強調している。"]},{en:"Don't exaggerate the importance of this minor issue.",ja:"このささいな問題の重要性を誇張しないでください。",wrong:["この問題を過小評価してください。","この問題は重要ではない。","この問題を簡単に扱ってください。"]}]},{word:"exceed",meaning:"超える",example:"Sales exceeded expectations by 20 percent.",category:"current",difficulty:3,examples:[{en:"The speed of the car exceeded the limit.",ja:"その車の速度は制限速度を超えました。",wrong:["その車の速度は制限速度を下回りました。","その車の速度は制限速度と同じでした。","その車の速度は制限速度より遅かった。"]},{en:"Her performance exceeded all expectations.",ja:"彼女のパフォーマンスはすべての期待を超えました。",wrong:["彼女のパフォーマンスはすべての期待に達しませんでした。","彼女のパフォーマンスは期待通りでした。","彼女のパフォーマンスは期待以下でした。"]},{en:"The expenses will not exceed the budget.",ja:"費用は予算を超えることはありません。",wrong:["費用は予算より少なくなります。","費用は予算と等しいです。","費用は予算以下です。"]}]},{word:"excerpt",meaning:"抜粋",example:"The teacher read an excerpt from the novel.",category:"culture",difficulty:4,examples:[{en:"I read an excerpt from the novel.",ja:"その小説の抜粋を読みました。",wrong:["その小説全体を読みました。","その小説の要約を読みました。","その小説の結末を読みました。"]},{en:"The newspaper published an excerpt of the speech.",ja:"新聞はその演説の抜粋を掲載しました。",wrong:["新聞はその演説の全文を掲載しました。","新聞はその演説の批評を掲載しました。","新聞はその演説を削除しました。"]},{en:"This excerpt shows the main theme of the book.",ja:"この抜粋はその本の主なテーマを示しています。",wrong:["この全文はその本の副次的なテーマを示しています。","この要約はその本の背景を示しています。","この省略版はその本の結論を示しています。"]}]},{word:"exclusive",meaning:"独占的な、排他的な",example:"The club has an exclusive membership policy.",category:"society",difficulty:3,examples:[{en:"This club is exclusive and only members can enter.",ja:"このクラブは排他的であり、メンバーだけが入会できます。",wrong:["このクラブは公開されており、誰でも入会できます。","このクラブは誰でも自由に出入りできます。","このクラブは一般向けです。"]},{en:"She has an exclusive interview with the celebrity.",ja:"彼女はその有名人との独占的なインタビューを持っています。",wrong:["彼女はその有名人との公開インタビューを持っています。","彼女はその有名人と一般的なインタビューを持っています。","彼女はその有名人との共有インタビューを持っています。"]},{en:"The price is exclusive of tax.",ja:"その価格は税金を除いたものです。",wrong:["その価格は税金を含んでいます。","その価格は税金と一緒です。","その価格は税金を加えたものです。"]}]},{word:"exempt",meaning:"免除された",example:"Charities are exempt from certain taxes.",category:"society",difficulty:4,examples:[{en:"Students are exempt from paying the fee.",ja:"学生はその料金の支払いが免除されています。",wrong:["学生はその料金を全額支払う必要があります。","学生はその料金を二倍支払う必要があります。","学生はその料金の追加支払いが必要です。"]},{en:"Religious organizations are exempt from taxes.",ja:"宗教団体は税金が免除されています。",wrong:["宗教団体は通常の税金を支払う必要があります。","宗教団体はより高い税金を支払う必要があります。","宗教団体は追加税金を支払う必要があります。"]},{en:"You are exempt from the exam if you pass the midterm.",ja:"中間試験に合格すれば、最終試験が免除されます。",wrong:["中間試験に合格すれば、最終試験を受ける必要があります。","中間試験に合格すれば、追加試験が必要です。","中間試験に合格すれば、試験がさらに増えます。"]}]},{word:"exhaust",meaning:"使い果たす、排気",example:"Car exhaust contributes to air pollution.",category:"current",difficulty:3,examples:[{en:"The long hike exhausted me completely.",ja:"その長いハイキングは私を完全に疲れさせました。",wrong:["その長いハイキングは私を元気にしました。","その長いハイキングは私をリラックスさせました。","その長いハイキングは私を活気づけました。"]},{en:"We exhausted all possible solutions to the problem.",ja:"その問題のあらゆる可能な解決策を使い果たしました。",wrong:["その問題の解決策をまだ試していません。","その問題の解決策を避けました。","その問題の解決策を無視しました。"]},{en:"The car's exhaust produces harmful emissions.",ja:"その車の排気は有害な排出物を生成します。",wrong:["その車の排気は清潔な空気を生成します。","その車の排気は無害です。","その車の排気は空気を浄化します。"]}]},{word:"exile",meaning:"追放、亡命",example:"The writer lived in exile for twenty years.",category:"history",difficulty:4,examples:[{en:"The political dissident was sent into exile.",ja:"その政治的反体制派は亡命に送られました。",wrong:["その政治的反体制派は国で権力を得ました。","その政治的反体制派は国務大臣に任命されました。","その政治的反体制派は国で栄誉を受けました。"]},{en:"He lived in exile for twenty years.",ja:"彼は20年間亡命生活をしました。",wrong:["彼は20年間国で普通に生活しました。","彼は20年間権力を持っていました。","彼は20年間国の指導者でした。"]},{en:"The king exiled his enemies from the kingdom.",ja:"その王は敵を王国から追放しました。",wrong:["その王は敵を王国に迎え入れました。","その王は敵に高い地位を与えました。","その王は敵を信頼の厚い顧問にしました。"]}]},{word:"explicit",meaning:"明示的な",example:"The instructions were clear and explicit.",category:"society",difficulty:4,examples:[{en:"The instructions were explicit and easy to follow.",ja:"その指示は明示的で従いやすかった。",wrong:["その指示は曖昧で理解しにくかった。","その指示は暗黙的でした。","その指示は不明確でした。"]},{en:"He gave explicit permission for the use of his image.",ja:"彼は自分の画像の使用を明示的に許可しました。",wrong:["彼は暗黙的に許可を拒否しました。","彼は許可なく画像を使用させました。","彼は曖昧な返事をしました。"]},{en:"The contract contains explicit terms and conditions.",ja:"その契約には明示的な条件と条項が含まれています。",wrong:["その契約には隠れた条件と条項が含まれています。","その契約には暗黙的な合意が含まれています。","その契約には不明確な条項が含まれています。"]}]},{word:"expose",meaning:"暴露する、さらす",example:"The journalist exposed the corruption scandal.",category:"current",difficulty:3,examples:[{en:"The journalist exposed the corruption in the government.",ja:"そのジャーナリストは政府の腐敗を暴露しました。",wrong:["そのジャーナリストは政府の腐敗を隠蔽しました。","そのジャーナリストは政府の腐敗を擁護しました。","そのジャーナリストは政府の腐敗を無視しました。"]},{en:"Don't expose your skin to the sun for too long.",ja:"太陽に肌をさらしすぎないでください。",wrong:["太陽から肌を完全に保護してください。","太陽光を避けるべきです。","太陽の下では肌を覆うべきではありません。"]},{en:"The scandal exposed his true character.",ja:"そのスキャンダルは彼の真の性格を明らかにしました。",wrong:["そのスキャンダルは彼の評判を守りました。","そのスキャンダルは彼の秘密を隠しました。","そのスキャンダルは彼のイメージを改善しました。"]}]},{word:"extend",meaning:"延長する、広げる",example:"The deadline was extended by two weeks.",category:"society",difficulty:3,examples:[{en:"Can you extend the deadline for the project?",ja:"そのプロジェクトの期限を延長してもらえますか？",wrong:["そのプロジェクトの期限を短縮してもらえますか？","そのプロジェクトの期限を廃止してもらえますか？","そのプロジェクトを中止してもらえますか？"]},{en:"The road extends for miles across the desert.",ja:"その道は砂漠を何マイルも横切って延びています。",wrong:["その道は短く限定されています。","その道は終わりに達しています。","その道は収縮しています。"]},{en:"She extended her hand in greeting.",ja:"彼女は挨拶のために手を差し伸べました。",wrong:["彼女は手を引っ込めました。","彼女は手を隠しました。","彼女は手を縮めました。"]}]},{word:"extract",meaning:"抽出する",example:"Oil is extracted from deep underground.",category:"technology",difficulty:3,examples:[{en:"The dentist had to extract the damaged tooth.",ja:"歯科医は損傷した歯を抽出する必要がありました。",wrong:["歯科医はその歯を修復しました。","歯科医はその歯を植え込みました。","歯科医はその歯を強化しました。"]},{en:"Scientists extract DNA from cells for analysis.",ja:"科学者は分析のために細胞からDNAを抽出します。",wrong:["科学者は細胞にDNAを注入します。","科学者は細胞を合成します。","科学者は細胞を破壊します。"]},{en:"They extracted oil from the ground.",ja:"彼らは地面から石油を採掘しました。",wrong:["彼らは地面に石油を埋蔵しました。","彼らは石油を地中に深く埋めました。","彼らは地表に石油を堆積させました。"]}]},{word:"extravagant",meaning:"贅沢な",example:"The wedding was an extravagant affair.",category:"society",difficulty:4,examples:[{en:"The wedding was extravagant with flowers and decorations.",ja:"その結婚式は花と装飾で贅沢でした。",wrong:["その結婚式は質素でした。","その結婚式は簡潔でした。","その結婚式は節約的でした。"]},{en:"He has extravagant tastes in fashion.",ja:"彼はファッションに贅沢な好みを持っています。",wrong:["彼はファッションに質素な好みを持っています。","彼はファッションに節約的な好みを持っています。","彼はファッションに控えめな好みを持っています。"]},{en:"The extravagant price of the restaurant shocked me.",ja:"そのレストランの法外な価格は私を驚かせました。",wrong:["そのレストランの手頃な価格は私を驚かせました。","そのレストランの割安な価格は私を驚かせました。","そのレストランの安い価格は私を驚かせました。"]}]},{word:"fabricate",meaning:"捏造する、製造する",example:"The defendant fabricated an alibi.",category:"society",difficulty:4,examples:[{en:"He fabricated a story to excuse his absence.",ja:"彼は欠席の言い訳として話を捏造しました。",wrong:["彼は真実を話しました。","彼は正直な理由を述べました。","彼は正当な言い訳をしました。"]},{en:"The factory fabricates car parts.",ja:"その工場は自動車部品を製造しています。",wrong:["その工場は自動車部品を販売しています。","その工場は自動車部品を輸入しています。","その工場は自動車部品を破壊しています。"]},{en:"The defendant fabricated evidence to win the case.",ja:"被告は裁判に勝つために証拠を捏造しました。",wrong:["被告は正当な証拠を提出しました。","被告は本物の証拠を隠しました。","被告は証拠を改ざんしました。"]}]},{word:"facilitate",meaning:"促進する",example:"The internet facilitates global communication.",category:"technology",difficulty:4,examples:[{en:"Good communication facilitates teamwork.",ja:"良いコミュニケーションはチームワークを促進します。",wrong:["良いコミュニケーションはチームワークを妨害します。","良いコミュニケーションはチームワークを阻止します。","良いコミュニケーションはチームワークを複雑にします。"]},{en:"The new software facilitates faster data processing.",ja:"新しいソフトウェアはより速いデータ処理を容易にします。",wrong:["新しいソフトウェアはデータ処理を遅くします。","新しいソフトウェアはデータ処理を困難にします。","新しいソフトウェアはデータ処理を複雑にします。"]},{en:"The teacher facilitated the discussion between students.",ja:"その先生は学生間の議論を進行させました。",wrong:["その先生は学生間の議論を禁止しました。","その先生は学生間の議論を中断しました。","その先生は学生間の議論を妨害しました。"]}]},{word:"famine",meaning:"飢饉",example:"The famine claimed thousands of lives.",category:"history",difficulty:3,examples:[{en:"The country faced a severe famine due to drought.",ja:"その国は干ばつにより深刻な飢饉に直面しました。",wrong:["その国は豊作の時期を経験しました。","その国は食料が豊富でした。","その国は飢えの問題がありませんでした。"]},{en:"Many people died during the famine.",ja:"飢饉中に多くの人が亡くなりました。",wrong:["飢饉中に人口が増加しました。","飢饉中に生活は改善されました。","飢饉中に誰も苦しまなかった。"]},{en:"The famine caused widespread hunger and disease.",ja:"飢饉は広範な飢えと病気を引き起こしました。",wrong:["飢饉は豊かさと繁栄をもたらしました。","飢饉は健康と幸福を増加させました。","飢饉は食料の過剰をもたらしました。"]}]},{word:"feasible",meaning:"実行可能な",example:"Is it feasible to complete the project by March?",category:"society",difficulty:4,examples:[{en:"The project seems feasible with the available resources.",ja:"利用可能なリソースを使えば、そのプロジェクトは実行可能に見えます。",wrong:["そのプロジェクトは不可能です。","そのプロジェクトは実現不可能です。","そのプロジェクトは実行できません。"]},{en:"Is it feasible to complete the work by Friday?",ja:"金曜日までに仕事を完了することは実行可能ですか？",wrong:["金曜日までに仕事を完了することは不可能ですか？","金曜日までに仕事を完了することは実現不可能ですか？","金曜日までに仕事を完了することは難しすぎますか？"]},{en:"The plan is feasible but requires careful planning.",ja:"その計画は実行可能ですが、慎重な計画が必要です。",wrong:["その計画は不可能で計画も不要です。","その計画は実現不可能です。","その計画を実行することはできません。"]}]},{word:"flaw",meaning:"欠点、欠陥",example:"A flaw in the design caused the system to fail.",category:"technology",difficulty:3,examples:[{en:"The diamond had a small flaw that reduced its value.",ja:"そのダイヤモンドは価値を減らす小さな欠陥がありました。",wrong:["その宝石は完璧な欠点を持っていました。","ダイヤモンドは大きな利点がありました。","その石は美しい傷を持っていました。"]},{en:"Every person has some character flaw.",ja:"すべての人には何らかの性格的欠点があります。",wrong:["すべての人は完璧な欠陥を持っています。","人格は利点のみです。","誰もが良い欠陥があります。"]},{en:"The flaw in his argument was obvious to everyone.",ja:"彼の議論の欠陥は誰の目にも明らかでした。",wrong:["彼の論理には強みの欠陥がありました。","議論は完璧な利点を持っていました。","その欠陥は隠されていました。"]}]},{word:"flee",meaning:"逃げる",example:"Thousands of refugees fled the country.",category:"current",difficulty:3,examples:[{en:"The refugees had to flee their homeland during the war.",ja:"難民は戦争中に故郷から逃げなければなりませんでした。",wrong:["難民は故郷に留まることを逃げました。","彼らは戦争に向かって逃げました。","難民は帰国することを選択しました。"]},{en:"When the police arrived, the suspect tried to flee the scene.",ja:"警察が到着したとき、容疑者は現場から逃げようとしました。",wrong:["容疑者は警察に向かって逃げました。","彼は現場に留まることを逃げました。","犯人は警察を待つために逃げました。"]},{en:"Birds flee to warmer climates in winter.",ja:"鳥は冬に暖かい気候に逃げます。",wrong:["鳥は冷たい気候に逃げます。","彼らは移動することを避けました。","鳥は北に向かって飛びました。"]}]},{word:"flourish",meaning:"繁栄する",example:"The arts flourished during the Renaissance.",category:"history",difficulty:3,examples:[{en:"The business began to flourish after implementing new strategies.",ja:"新しい戦略を実施した後、ビジネスは繁栄し始めました。",wrong:["ビジネスは衰退することで繁栄しました。","新しい戦略の後、会社は失敗しました。","事業は停滞しながら繁栄しました。"]},{en:"Tropical plants flourish in humid environments.",ja:"熱帯植物は湿った環境で繁栄します。",wrong:["植物は乾燥した環境で繁栄します。","湿度は植物の成長を殺します。","熱帯植物は北極で繁栄します。"]},{en:"The arts flourished during the Renaissance period.",ja:"ルネサンス期間中、芸術は繁栄しました。",wrong:["ルネサンス中、芸術は衰えました。","その時代は文化的な停滞を見ました。","芸術は中世に最も繁栄しました。"]}]},{word:"folklore",meaning:"民間伝承",example:"Dragons feature prominently in European folklore.",category:"culture",difficulty:4,examples:[{en:"The folklore of the region includes many ghost stories.",ja:"その地域の民間伝承には多くの幽霊物語が含まれています。",wrong:["民間伝承は科学的事実のみです。","その地域の民間伝承には現代的な物語だけがあります。","民間伝承は真実の歴史です。"]},{en:"Folklore has been passed down through generations.",ja:"民間伝承は世代を通じて受け継がれてきました。",wrong:["民間伝承は最近発明されました。","昔の人々は民間伝承を記録しませんでした。","民間伝承は一人の人が作りました。"]},{en:"Dragons appear frequently in Asian folklore.",ja:"龍はアジアの民間伝承に頻繁に登場します。",wrong:["アジアの民間伝承には龍はいません。","龍は現代のアジア文化です。","民間伝承は実在する動物についてのみです。"]}]},{word:"forbid",meaning:"禁じる",example:"The law forbids the sale of alcohol to minors.",category:"society",difficulty:3,examples:[{en:"The school forbids students from using mobile phones in class.",ja:"学校は生徒が授業中に携帯電話を使用することを禁じています。",wrong:["学校は生徒が携帯電話を使うことを許可しています。","携帯電話の使用は学校で必須です。","学校は携帯電話の所持を奨励しています。"]},{en:"The law forbids discrimination based on race or gender.",ja:"法律は人種または性別に基づく差別を禁じています。",wrong:["法律は差別を奨励しています。","差別は法律によって許可されています。","法律は平等を禁じています。"]},{en:"My parents forbid me from staying out late.",ja:"両親は私が遅くまで出かけることを禁じています。",wrong:["両親は私が遅く帰宅することを許可しています。","両親は夜更かしを奨励しています。","親は夜間の外出を強制しています。"]}]},{word:"forecast",meaning:"予測する",example:"Economists forecast steady growth next year.",category:"current",difficulty:3,examples:[{en:"The weather forecast predicts rain tomorrow.",ja:"天気予報は明日の雨を予測しています。",wrong:["天気予報は晴天を約束しています。","予報は天気を実際に制御します。","天気予報は100%正確です。"]},{en:"Economists forecast economic growth for next year.",ja:"経済学者は来年の経済成長を予測しています。",wrong:["経済学者は経済の衰退を確実に知っています。","予測は必ず正確です。","経済学者は経済を制御できます。"]},{en:"The forecast shows a 30% chance of snow.",ja:"予報は30%の雪の確率を示しています。",wrong:["予報は雪が確実に降ることを意味します。","30%の確率は降らないことを意味します。","予報は天気を変えることができます。"]}]},{word:"forge",meaning:"偽造する、築く",example:"The two companies forged a strong partnership.",category:"society",difficulty:4,examples:[{en:"The blacksmith will forge a new sword from metal.",ja:"鍛冶屋は金属から新しい剣を鍛造します。",wrong:["鍛冶屋は金属を燃やします。","鍛造は壊すことです。","金属は何も作ることができません。"]},{en:"They forged a strong partnership over many years.",ja:"彼らは多くの年にわたって強い連携を築きました。",wrong:["彼らは弱い関係を壊しました。","パートナーシップは簡単に失われました。","彼らは敵になりました。"]},{en:"He was arrested for forging documents.",ja:"彼は文書を偽造したために逮捕されました。",wrong:["彼は本物の文書を作りました。","偽造は法律です。","彼は誠実に文書を記述しました。"]}]},{word:"formidable",meaning:"手ごわい",example:"She is a formidable opponent in debate.",category:"society",difficulty:5,examples:[{en:"The team faced a formidable opponent in the championship.",ja:"チームは選手権で手ごわい相手に直面しました。",wrong:["相手は非常に弱かったです。","チームは簡単に勝ちました。","相手は脅威ではありませんでした。"]},{en:"She has a formidable intellect and knowledge.",ja:"彼女は手ごわい知性と知識を持っています。",wrong:["彼女は知識がありません。","彼女は簡単に倒せます。","彼女は非常に愚かです。"]},{en:"The mountain climber faced formidable challenges.",ja:"登山家は手ごわい課題に直面しました。",wrong:["山登りは簡単でした。","彼は障害に遭遇しませんでした。","登山は誰でもできます。"]}]},{word:"forthcoming",meaning:"近づいている、率直な",example:"Details will be published in the forthcoming report.",category:"society",difficulty:4,examples:[{en:"The forthcoming election will be held next month.",ja:"近づいている選挙は来月開催されます。",wrong:["選挙は昨年でした。","選挙はもう終わりました。","選挙は過去の出来事です。"]},{en:"He was very forthcoming about his mistakes.",ja:"彼は自分の間違いについて非常に率直でした。",wrong:["彼は自分の過ちを隠しました。","彼は誠実ではありませんでした。","彼は真実を言いませんでした。"]},{en:"The forthcoming movie will be released in December.",ja:"公開予定の映画は12月にリリースされます。",wrong:["映画はすでに公開されました。","映画は二度と出ません。","映画は去年のものです。"]}]},{word:"foster",meaning:"育成する、里親の",example:"The programme fosters creativity in young people.",category:"society",difficulty:4,examples:[{en:"The organization fosters creativity in children.",ja:"その組織は子どもたちの創造性を育成します。",wrong:["その組織は創造性を抑制します。","彼らは想像力を壊します。","その組織は子どもを教育しません。"]},{en:"She grew up in a foster family.",ja:"彼女は里親の家族で育ちました。",wrong:["彼女は生みの親と暮らしていました。","彼女は施設にいました。","彼女は両親の家にいました。"]},{en:"The program fosters international cooperation.",ja:"プログラムは国際協力を育成します。",wrong:["プログラムは対立を作ります。","それは国を分裂させます。","協力を阻止します。"]}]},{word:"fraction",meaning:"一部、分数",example:"Only a fraction of applicants are accepted.",category:"science",difficulty:3,examples:[{en:"Only a fraction of the population speaks fluent English.",ja:"人口の一部だけが流暢な英語を話します。",wrong:["ほぼ全員が英語を話します。","大多数が英語を話します。","ほとんど誰もが英語を話しません。"]},{en:"In mathematics, 1/4 is a fraction.",ja:"数学では、1/4は分数です。",wrong:["分数は整数です。","1/4は整数です。","分数は計算に使われません。"]},{en:"A fraction of the cost went to advertising.",ja:"費用の一部は広告に使われました。",wrong:["すべての費用が広告に使われました。","広告には費用がかかりませんでした。","ほぼすべてが広告費です。"]}]},{word:"fragile",meaning:"壊れやすい",example:"The ecosystem is extremely fragile.",category:"science",difficulty:3,examples:[{en:"The fragile vase was carefully wrapped for shipping.",ja:"壊れやすい花瓶は配送のために慎重に梱包されました。",wrong:["その花瓶は丈夫でした。","壊れやすいものは包装が必要ありません。","その花瓶は投げることができます。"]},{en:"The patient's health is fragile and requires constant care.",ja:"患者の健康は脆弱で絶え間ないケアが必要です。",wrong:["患者は非常に健康です。","彼の状態は強いです。","ケアは必要ありません。"]},{en:"The peace agreement is fragile and could break easily.",ja:"平和協定は脆弱で簡単に破裂する可能性があります。",wrong:["平和は非常に強いです。","協定は永遠に続きます。","平和は保証されています。"]}]},{word:"fragment",meaning:"断片",example:"Fragments of pottery were found at the site.",category:"history",difficulty:4,examples:[{en:"Archaeologists found fragments of ancient pottery.",ja:"考古学者は古い陶器の断片を見つけました。",wrong:["彼らは完全な食器を見つけました。","陶器は壊れていません。","断片は考古学的に重要ではありません。"]},{en:"The book was only a fragment of his complete work.",ja:"その本は彼の完全な作品の一部に過ぎませんでした。",wrong:["本は彼の完全な作品でした。","他に作品はありません。","これはすべての仕事です。"]},{en:"A fragment of memory remained from childhood.",ja:"子ども時代からの記憶の断片が残っていました。",wrong:["すべての記憶が戻ってきました。","彼は何も覚えていません。","記憶は完全です。"]}]},{word:"friction",meaning:"摩擦、不和",example:"There has been friction between the two departments.",category:"science",difficulty:3,examples:[{en:"Friction between the two managers created workplace tension.",ja:"2人のマネージャー間の不和は職場の緊張を生じさせました。",wrong:["マネージャーは完全に同意しました。","不和は問題を解決しました。","彼らは友達でした。"]},{en:"Friction on the road surface helps prevent skidding.",ja:"道路表面の摩擦はスキッドを防ぐのに役立ちます。",wrong:["摩擦は車がスリップするのを促進します。","スムーズな表面は最も安全です。","摩擦は有害です。"]},{en:"There is growing friction between the two countries.",ja:"2つの国の間の不和が増加しています。",wrong:["国々は友好的です。","関係は改善しています。","対立はありません。"]}]},{word:"frontier",meaning:"辺境、最前線",example:"Space exploration is the next frontier.",category:"technology",difficulty:3,examples:[{en:"The pioneers moved westward to the frontier.",ja:"開拓者は辺境に向かって西に移動しました。",wrong:["開拓者は東に移動しました。","彼らは文明地域に留まりました。","辺境は存在しません。"]},{en:"Technology is pushing the frontier of human knowledge.",ja:"技術は人間の知識の最前線を押し進めています。",wrong:["技術は知識を減らしています。","私たちは知識の拡大を停止しました。","イノベーションは不可能です。"]},{en:"The space program represents the new frontier.",ja:"宇宙プログラムは新しい最前線を表しています。",wrong:["宇宙探検は終わりました。","宇宙はもう興味がありません。","探索は終了しました。"]}]},{word:"fruitful",meaning:"実りある",example:"The meeting was fruitful and productive.",category:"society",difficulty:3,examples:[{en:"The meeting was fruitful and resulted in several new ideas.",ja:"その会議は実りあるもので、いくつかの新しいアイデアが生まれた。",wrong:["会議は果実が多かった","その会議は美味しい結果になった","会議は実際のフルーツを生産した"]},{en:"Her research has been fruitful, leading to important discoveries.",ja:"彼女の研究は実りあるもので、重要な発見につながった。",wrong:["彼女の研究は果物を見つけた","その研究は甘い成果を上げた","彼女の研究は実際の実をつけた"]},{en:"We had a fruitful conversation about the future of the company.",ja:"会社の将来について実りある対話ができた。",wrong:["私たちはフルーツについて話し合った","その会話は果実的だった","私たちは実のなる話をした"]}]},{word:"fulfil",meaning:"果たす、満たす",example:"She fulfilled her dream of becoming a doctor.",category:"society",difficulty:3,examples:[{en:"He promised to fulfil all his responsibilities.",ja:"彼はすべての責任を果たすことを約束した。",wrong:["彼は完全に満杯になることを約束した","彼は責任を満たすつもりだ","彼は責任を完成させた"]},{en:"She worked hard to fulfil her dreams of becoming a doctor.",ja:"彼女は医者になるという夢を果たすために一生懸命働いた。",wrong:["彼女は医者の夢を満杯にした","彼女の夢は満たされて完全になった","彼女は医者の夢を埋めた"]},{en:"The company fulfilled its promise to deliver on time.",ja:"その会社は期間内に配達するという約束を果たした。",wrong:["その会社は約束を満たした","その会社は配達を完全にした","その会社は約束を埋めた"]}]},{word:"fundamental",meaning:"基本的な",example:"Freedom of speech is a fundamental right.",category:"society",difficulty:3,examples:[{en:"Mathematics is fundamental to science.",ja:"数学は科学の基本的な要素である。",wrong:["数学は科学的に基礎がある","数学は科学の基礎を建てた","数学は科学に根付いている"]},{en:"Understanding the fundamental principles is essential for success.",ja:"基本的な原則を理解することは成功に不可欠である。",wrong:["基本的な原則を把握することは本質的である","その基礎的な原則は成功に根ざしている","基本的な原則を理解することは実質的である"]},{en:"The fundamental right to education should be protected.",ja:"教育を受ける基本的な権利は保護されるべきである。",wrong:["教育の基礎的な権利は本質的である","教育の根本的な権利は保護されている","教育の基本的な権利は基礎的に保護された"]}]},{word:"furious",meaning:"激怒した",example:"The fans were furious about the referee's decision.",category:"society",difficulty:3},{word:"gaze",meaning:"じっと見る",example:"She gazed out of the window at the mountains.",category:"culture",difficulty:3,examples:[{en:"She gazed at the stars for hours.",ja:"彼女は数時間星をじっと見つめていた。",wrong:["彼女は星を見つめて見た","彼女は星を見る目で見つめた","彼女は星をじっと眺めていた"]},{en:"He held her gaze and smiled.",ja:"彼は彼女のじっとした視線を受け止めて微笑んだ。",wrong:["彼は彼女の視線をじっと見つめた","彼は彼女を見て微笑んだ","彼は彼女のまなざしを保った"]},{en:"The child's gaze was fixed on the colorful toys.",ja:"子どもの視線はカラフルなおもちゃに固定されていた。",wrong:["子どもはカラフルなおもちゃをじっと見た","子どもの目はおもちゃに見つめられていた","子どもは視線をおもちゃに定めた"]}]},{word:"generous",meaning:"寛大な、気前のよい",example:"She made a generous donation to the charity.",category:"society",difficulty:3,examples:[{en:"He is a generous person who always helps those in need.",ja:"彼は寛大な人で、いつも困っている人を助ける。",wrong:["彼は気前よく人を助ける","彼は寛容に人を支援する","彼は惜しみなく人に援助する"]},{en:"The generous donation helped the charity achieve its goals.",ja:"気前のよい寄付は慈善団体が目標を達成するのに役立った。",wrong:["寛大な寄付が慈善団体を助けた","その大量の寄付は慈善団体を支援した","気前よい献金は目標を達成させた"]},{en:"She gave a generous portion of dessert to everyone.",ja:"彼女は誰もが食べられるようにたっぷりのデザートを配った。",wrong:["彼女は寛大にデザートを配った","彼女は気前よくデザート部分を与えた","彼女は大量のデザートをみんなに与えた"]}]},{word:"genocide",meaning:"大量虐殺",example:"The United Nations condemned the genocide.",category:"history",difficulty:5,examples:[{en:"The genocide during World War II was one of history's greatest atrocities.",ja:"第二次世界大戦中の大量虐殺は歴史上最大の残虐行為の一つだった。",wrong:["その大量殺害は歴史上最大の暴力だった","戦争中の虐殺は歴史上最悪の悪行だった","その民族浄化は歴史上最大の犯罪だった"]},{en:"International law was established to prevent future genocides.",ja:"今後の大量虐殺を防ぐために国際法が制定された。",wrong:["国際法は虐殺を阻止するために作られた","国際法は民族浄化を防ぐために設立された","世界法は将来の大量殺害を防ぐために制定された"]},{en:"The UN condemned the genocide and called for intervention.",ja:"国連は大量虐殺を非難し、介入を呼びかけた。",wrong:["国連は虐殺を非難した","国連は民族浄化を非難し、支援を求めた","国連は大量殺害を非難し、行動を要求した"]}]},{word:"genre",meaning:"ジャンル",example:"Science fiction is a popular literary genre.",category:"culture",difficulty:3,examples:[{en:"Science fiction is my favorite genre of books.",ja:"SFは私が好きな本のジャンルです。",wrong:["科学小説は私が好きなジャンルの本だ","サイエンスフィクションは本の種類として好きだ","SF小説は私の好きな本の形式だ"]},{en:"The movie belongs to the horror genre.",ja:"その映画はホラーというジャンルに属している。",wrong:["その映画はホラーという種類に入っている","その映画はホラーというカテゴリに分類される","その映画はホラーという形式である"]},{en:"Different genres of music appeal to different audiences.",ja:"異なる音楽ジャンルは異なる聴衆にアピールします。",wrong:["異なる音楽の種類は異なる観客に訴える","様々な音楽ジャンルは様々な人々に魅力的だ","異なる音楽形式は異なる人々を引きつける"]}]},{word:"gesture",meaning:"身振り、意思表示",example:"It was a kind gesture of goodwill.",category:"culture",difficulty:3,examples:[{en:"She made a gesture to welcome the guests.",ja:"彼女はゲストを迎えるための身振りをした。",wrong:["彼女はゲストを歓迎する動きをした","彼女はゲストを迎えるための手振りをした","彼女は客人を迎える合図をした"]},{en:"His kind gesture of helping an elderly person was appreciated.",ja:"お年寄りを助けるという親切な意思表示は感謝された。",wrong:["彼の親切な動作は感謝された","高齢者を助ける彼の親切な身振りは認められた","彼の優しい行為は感謝された"]},{en:"The peace gesture between the two nations was significant.",ja:"2つの国家間の平和のジェスチャーは重要だった。",wrong:["2国間の平和の動きは意味があった","2つの国の平和的な身振りは重要だった","2国間の平和の合図は大切だった"]}]},{word:"gigantic",meaning:"巨大な",example:"A gigantic wave crashed against the cliffs.",category:"science",difficulty:3,examples:[{en:"The gigantic building dominated the city skyline.",ja:"巨大な建物は都市のスカイラインを支配していた。",wrong:["その大きな建物は街を支配した","その巨大な構造物は景観を占めた","その巨体の建物は都市の輪郭を支配した"]},{en:"She overcame a gigantic obstacle to achieve her goal.",ja:"彼女は目標を達成するために巨大な障害を乗り越えた。",wrong:["彼女は大きな困難を克服した","彼女は巨大な問題を解決した","彼女は大きな課題を乗り越えた"]},{en:"The gigantic waves crashed against the shore.",ja:"巨大な波が岸に激しくぶつかった。",wrong:["その大きな波は岸にぶつかった","巨大な水の波が海岸に打ちつけた","その巨体の波は岸を襲った"]}]},{word:"glimpse",meaning:"ちらりと見る、一目",example:"I caught a glimpse of the celebrity.",category:"society",difficulty:3,examples:[{en:"I caught a glimpse of the famous actor at the airport.",ja:"私は空港で有名な俳優をちらりと見かけた。",wrong:["私は空港で有名な俳優を見た","私は有名な俳優の一目を空港で目撃した","私は空港で俳優を少し見えた"]},{en:"The documentary provided a glimpse into the lives of ancient people.",ja:"そのドキュメンタリーは古代の人々の生活を一目うかがわせた。",wrong:["そのドキュメンタリーは古代人の生活を見せた","そのドキュメンタリーは古代の人々の生活を少し見た","そのドキュメンタリーは古代人の人生を垣間見えた"]},{en:"She had only a brief glimpse of the sunset before the clouds covered it.",ja:"彼女は雲が覆う前に夕日をちらりと見ただけだった。",wrong:["彼女は雲が覆う前に夕焼けを見た","彼女は夕日を少し見ることができた","彼女は雲が来る前に夕焼けを一目見た"]}]},{word:"govern",meaning:"統治する",example:"The country is governed by a democratically elected parliament.",category:"society",difficulty:3,examples:[{en:"The president governs the country with the help of the cabinet.",ja:"大統領は内閣の助けを借りて国を統治している。",wrong:["大統領は国を支配している","大統領は内閣と一緒に国を管理している","大統領は国を司っている"]},{en:"Laws govern how people behave in society.",ja:"法律は人々が社会でどのように行動するかを統治する。",wrong:["法律は人々の社会的行動を支配する","法律は社会での行動を管理する","法律は人々がどう行動するかを決める"]},{en:"The board of directors governs the company's decisions.",ja:"取締役会は会社の決定を統治する。",wrong:["取締役会は会社の決定を支配する","取締役会は会社の決定を管理している","取締役会は会社の判断を司っている"]}]},{word:"grace",meaning:"優雅さ、恵み",example:"The dancer moved with incredible grace.",category:"culture",difficulty:3,examples:[{en:"The ballerina danced with grace and elegance.",ja:"バレエダンサーは優雅さと優雅さで踊った。",wrong:["バレエダンサーは優雅に踊った","バレエダンサーはしなやかに踊った","バレエダンサーは美しく踊った"]},{en:"She showed grace under pressure during the difficult situation.",ja:"彼女は困難な状況の中で圧力の中でも優雅さを示した。",wrong:["彼女は困難な状況で上品さを示した","彼女は難しい状況で優雅に行動した","彼女は苦労しながらも落ち着きを保った"]},{en:"By the grace of God, they survived the accident.",ja:"神の恵みにより、彼らはその事故から生き残った。",wrong:["神の優雅さのおかげで生き残った","神の助けで彼らは事故を生き残った","神の祝福により生き残った"]}]},{word:"gradual",meaning:"徐々の",example:"There has been a gradual improvement in air quality.",category:"current",difficulty:3,examples:[{en:"The gradual increase in temperature caused concern among scientists.",ja:"気温の徐々の上昇は科学者の懸念を引き起こした。",wrong:["気温が徐々に上昇することは懸念を招いた","段階的な温度上昇は科学者の心配を引き起こした","徐々の気温上昇は懸念事項だった"]},{en:"His gradual improvement in health was encouraging.",ja:"彼の健康の徐々の改善は励みになった。",wrong:["彼の段階的な健康改善は励みになった","彼の健康が徐々に改善したことは励みになった","彼の緩やかな回復は励ましになった"]},{en:"Learning a new language requires gradual practice.",ja:"新しい言語を学ぶには徐々の練習が必要である。",wrong:["新しい言語を学ぶには段階的な練習が必要だ","新しい言語は徐々に学ぶ必要がある","言語学習には段階的な取り組みが必要である"]}]},{word:"grant",meaning:"与える、助成金",example:"The university received a research grant.",category:"science",difficulty:3,examples:[{en:"The government granted permission for the new construction project.",ja:"政府は新しい建設プロジェクトの許可を与えた。",wrong:["政府は新しい建設プロジェクトを認可した","政府は新しい建設を許可した","政府は建設プロジェクトを承認した"]},{en:"The foundation granted a large sum of money to the research team.",ja:"その財団は研究チームに大金の助成金を与えた。",wrong:["その財団は研究チームにお金を与えた","その財団は研究チームに大きな融資を行った","その財団は研究チームに資金を供与した"]},{en:"I take my freedom for granted sometimes.",ja:"時々、私は自分の自由を当たり前だと思っている。",wrong:["私は自分の自由を与えられたと思う","私は自由を認めている","私は自分の自由を許可されたと考える"]}]},{word:"grasp",meaning:"握る、理解する",example:"Students struggled to grasp the concept.",category:"science",difficulty:3,examples:[{en:"She grasped the concept of quantum physics after studying for months.",ja:"彼女は数ヶ月間勉強した後、量子物理学の概念を理解した。",wrong:["彼女は量子物理学を握った。","彼女は数ヶ月間量子物理学を保持した。","彼女は量子物理学の概念を捕まえた。"]},{en:"The child grasped the toy tightly in both hands.",ja:"子どもはおもちゃを両手でしっかり握った。",wrong:["子どもはおもちゃを理解した。","子どもはおもちゃの意味を握った。","子どもはおもちゃを把握する必要があった。"]},{en:"I cannot grasp why he made such a decision.",ja:"私は彼がなぜそのような決定をしたのか理解できない。",wrong:["私は彼の決定を握ることができない。","私は彼を理解できない。","私は決定を握ることができない。"]}]},{word:"grieve",meaning:"嘆き悲しむ",example:"The community grieved for the victims.",category:"society",difficulty:4,examples:[{en:"The family grieved the loss of their beloved grandmother.",ja:"家族は愛する祖母の死を嘆き悲しんだ。",wrong:["家族は祖母を怒った。","家族は祖母を喜んだ。","家族は祖母を許した。"]},{en:"She grieved for weeks after hearing the tragic news.",ja:"彼女はその悲劇的なニュースを聞いた後、数週間嘆き悲しんだ。",wrong:["彼女は数週間喜んだ。","彼女は数週間怒った。","彼女は数週間祝った。"]},{en:"The nation grieved together following the disaster.",ja:"その災害に続いて、国民は一緒に嘆き悲しんだ。",wrong:["国民は災害を祝った。","国民は災害に喜んだ。","国民は災害を楽しんだ。"]}]},{word:"gross",meaning:"総計の、ひどい",example:"Gross domestic product grew by three percent.",category:"current",difficulty:3,examples:[{en:"The gross income before taxes was $50,000.",ja:"税引前の総所得は50,000ドルだった。",wrong:["純所得は50,000ドルだった。","ひどい所得は50,000ドルだった。","不潔な収入は50,000ドルだった。"]},{en:"That behavior is absolutely gross and unacceptable.",ja:"その振る舞いは本当にひどく受け入れられない。",wrong:["その振る舞いは総計でひどい。","その振る舞いは総額で不適切だ。","その振る舞いは全体的に良い。"]},{en:"The gross weight of the package is 10 kilograms.",ja:"その小包の総重量は10キログラムである。",wrong:["その小包のひどい重量は10キログラムだ。","その小包の不潔な重量は10キログラムだ。","その小包の悪い重量は10キログラムだ。"]}]},{word:"groundbreaking",meaning:"画期的な",example:"The research led to a groundbreaking discovery.",category:"science",difficulty:4,examples:[{en:"Her groundbreaking research changed the field of medicine forever.",ja:"彼女の画期的な研究は医学の分野を永遠に変えた。",wrong:["彼女の地面を破る研究は医学を変えた。","彼女の革新的でない研究は医学を変えた。","彼女の古い研究は医学を変えた。"]},{en:"The groundbreaking ceremony for the new hospital was held yesterday.",ja:"新しい病院の起工式は昨日行われた。",wrong:["地面を破る式典は昨日行われた。","病院の完成式は昨日行われた。","病院の解体式は昨日行われた。"]},{en:"This groundbreaking technology will revolutionize the industry.",ja:"この画期的な技術は業界に革命をもたらすだろう。",wrong:["この地面を割く技術は業界を変えるだろう。","この古い技術は業界を変えるだろう。","この一般的な技術は業界を変えるだろう。"]}]},{word:"halt",meaning:"停止する",example:"Construction was halted due to safety concerns.",category:"society",difficulty:3,examples:[{en:"The train came to a halt at the station.",ja:"その電車は駅で停止した。",wrong:["その電車は駅で始まった。","その電車は駅で加速した。","その電車は駅で移動した。"]},{en:"The company decided to halt production due to low sales.",ja:"その会社は売上が少ないため生産を中止することにした。",wrong:["その会社は生産を増やすことにした。","その会社は生産を続けることにした。","その会社は生産を開始することにした。"]},{en:"The government ordered a halt to all construction work.",ja:"政府はすべての建設工事の中止を命じた。",wrong:["政府はすべての建設工事の開始を命じた。","政府はすべての建設工事の加速を命じた。","政府はすべての建設工事の再開を命じた。"]}]},{word:"hamper",meaning:"妨げる",example:"Bad weather hampered the rescue efforts.",category:"current",difficulty:4,examples:[{en:"Bad weather hampered our outdoor activities.",ja:"悪い天気が私たちの屋外活動を妨げた。",wrong:["悪い天気が私たちの屋外活動を助けた。","悪い天気が私たちの屋外活動を促進した。","悪い天気が私たちの屋外活動を改善した。"]},{en:"The lack of funding hampers the research project.",ja:"資金不足がその研究プロジェクトを妨げている。",wrong:["資金不足がその研究プロジェクトを支援している。","資金不足がその研究プロジェクトを加速している。","資金不足がその研究プロジェクトを完成させている。"]},{en:"Language barriers hamper communication between the teams.",ja:"言語の障壁がチーム間のコミュニケーションを妨げている。",wrong:["言語の障壁がチーム間のコミュニケーションを促進している。","言語の障壁がチーム間の理解を深めている。","言語の障壁がチーム間の協力を助けている。"]}]},{word:"harbor",meaning:"港、抱く",example:"She harbored doubts about the plan.",category:"society",difficulty:4,examples:[{en:"The ships sailed into the harbor for protection.",ja:"船舶は保護を求めて港に入った。",wrong:["船舶は沖合に向かった。","船舶は陸地に向かった。","船舶は空を飛んだ。"]},{en:"She harbored feelings of resentment toward her brother.",ja:"彼女は兄に対して恨みの感情を抱いていた。",wrong:["彼女は兄に対して愛情を抱いていた。","彼女は兄に対して喜びを感じていた。","彼女は兄に対して港を建設していた。"]},{en:"The country harbors a desire for peace.",ja:"その国は平和への願いを抱いている。",wrong:["その国は戦争への願いを抱いている。","その国は港を建設したい。","その国は分裂を望んでいる。"]}]},{word:"harsh",meaning:"厳しい",example:"The winters are harsh in northern regions.",category:"science",difficulty:3,examples:[{en:"The harsh winter conditions made travel difficult.",ja:"厳しい冬の状況が旅行を困難にした。",wrong:["穏やかな冬の状況が旅行を困難にした。","温かい冬の状況が旅行を困難にした。","快適な冬の状況が旅行を困難にした。"]},{en:"The teacher gave harsh criticism of the student's work.",ja:"その先生は学生の仕事に対して厳しい批判を与えた。",wrong:["その先生は学生の仕事に対して温かい批判を与えた。","その先生は学生の仕事に対して褒める批判を与えた。","その先生は学生の仕事に対して優しい批判を与えた。"]},{en:"His harsh words hurt her feelings deeply.",ja:"彼の厳しい言葉は彼女の気持ちを深く傷つけた。",wrong:["彼の優しい言葉は彼女の気持ちを傷つけた。","彼の甘い言葉は彼女の気持ちを傷つけた。","彼の褒める言葉は彼女の気持ちを傷つけた。"]}]},{word:"hazard",meaning:"危険",example:"Smoking is a serious health hazard.",category:"science",difficulty:3,examples:[{en:"The wet floor is a hazard to pedestrians.",ja:"濡れた床は歩行者に対する危険である。",wrong:["濡れた床は歩行者にとって安全である。","濡れた床は歩行者にとって便利である。","濡れた床は歩行者を助ける。"]},{en:"I would hazard a guess that he won't come.",ja:"彼は来ないだろうと推測してもいいだろう。",wrong:["私は彼が来るだろうと確実に言える。","私は彼が来るだろうと知っている。","私は彼が来ることは危険だと思う。"]},{en:"The construction site presents many hazards.",ja:"その建設現場には多くの危険がある。",wrong:["その建設現場には多くの安全性がある。","その建設現場には多くの利点がある。","その建設現場には多くの良いことがある。"]}]},{word:"heritage",meaning:"遺産",example:"The temple is part of our cultural heritage.",category:"history",difficulty:3,examples:[{en:"The ancient temple is part of the nation's cultural heritage.",ja:"その古い寺院は国の文化遺産の一部である。",wrong:["その古い寺院は国の負債の一部である。","その古い寺院は国の負担の一部である。","その古い寺院は国の問題の一部である。"]},{en:"She inherited her grandmother's jewelry as a family heritage.",ja:"彼女は祖母のジュエリーを家族の遺産として相続した。",wrong:["彼女は祖母のジュエリーを借りた。","彼女は祖母のジュエリーを盗んだ。","彼女は祖母のジュエリーを失った。"]},{en:"Our artistic heritage is reflected in our museums.",ja:"私たちの芸術的遺産は私たちの博物館に反映されている。",wrong:["私たちの負債は私たちの博物館に反映されている。","私たちの負担は私たちの博物館に反映されている。","私たちの問題は私たちの博物館に反映されている。"]}]},{word:"hierarchy",meaning:"階層",example:"There is a strict hierarchy within the organisation.",category:"society",difficulty:4,examples:[{en:"The company has a strict hierarchy of authority.",ja:"その会社は権威の厳しい階層を持っている。",wrong:["その会社は平等な構造を持っている。","その会社は無秩序な組織を持っている。","その会社は民主的な構造を持っている。"]},{en:"In the social hierarchy, education plays a crucial role.",ja:"社会的階層では、教育が重要な役割を果たしている。",wrong:["社会的平等では、教育が重要な役割を果たしている。","社会的無秩序では、教育が重要な役割を果たしている。","社会的混乱では、教育が重要な役割を果たしている。"]},{en:"Animals follow a clear hierarchy within their pack.",ja:"動物は自分たちの群れの中で明確な階層に従う。",wrong:["動物は自分たちの群れの中で平等に従う。","動物は自分たちの群れの中で無秩序に従う。","動物は自分たちの群れの中で混乱に従う。"]}]},{word:"hinder",meaning:"妨げる",example:"Lack of funding hindered the project.",category:"society",difficulty:4,examples:[{en:"The strike hindered the company's productivity.",ja:"その罷業がその会社の生産性を妨げた。",wrong:["その罷業がその会社の生産性を促進した。","その罷業がその会社の生産性を改善した。","その罷業がその会社の生産性を加速した。"]},{en:"Physical limitations do not hinder her determination.",ja:"肉体的な制限は彼女の決意を妨げない。",wrong:["肉体的な制限は彼女の決意を助ける。","肉体的な制限は彼女の決意を強める。","肉体的な制限は彼女の決意を支える。"]},{en:"Poor communication hindered the project's success.",ja:"不十分なコミュニケーションがそのプロジェクトの成功を妨げた。",wrong:["良好なコミュニケーションがそのプロジェクトの成功を妨げた。","明確なコミュニケーションがそのプロジェクトを妨げた。","効果的なコミュニケーションがそのプロジェクトを妨げた。"]}]},{word:"hollow",meaning:"空洞の、うつろな",example:"His promises rang hollow.",category:"society",difficulty:3,examples:[{en:"The tree trunk was hollow inside.",ja:"その木の幹の中は空洞だった。",wrong:["その木の幹の中は詰まっていた。","その木の幹の中は実が詰まっていた。","その木の幹の中は固かった。"]},{en:"His promises rang hollow after his repeated failures.",ja:"彼の繰り返される失敗の後、彼の約束は空虚に聞こえた。",wrong:["彼の約束は誠実に聞こえた。","彼の約束は深く聞こえた。","彼の約束は満ちていた。"]},{en:"She felt a hollow sensation in her chest.",ja:"彼女は胸に空虚感を感じた。",wrong:["彼女は胸に満足感を感じた。","彼女は胸に充実感を感じた。","彼女は胸に温かさを感じた。"]}]},{word:"hostile",meaning:"敵意のある",example:"The crowd turned hostile after the announcement.",category:"society",difficulty:3,examples:[{en:"The two nations have maintained hostile relations for decades.",ja:"その二つの国は数十年間敵意のある関係を保ってきた。",wrong:["その二つの国は友好的な関係を保ってきた。","その二つの国は中立的な関係を保ってきた。","その二つの国は親密な関係を保ってきた。"]},{en:"He received a hostile response to his proposal.",ja:"彼は彼の提案に対して敵意のある応答を受けた。",wrong:["彼は彼の提案に対して好意的な応答を受けた。","彼は彼の提案に対して歓迎する応答を受けた。","彼は彼の提案に対して優しい応答を受けた。"]},{en:"The hostile environment made survival difficult.",ja:"敵意のある環境が生存を困難にした。",wrong:["友好的な環境が生存を困難にした。","親切な環境が生存を困難にした。","助けになる環境が生存を困難にした。"]}]},{word:"humanitarian",meaning:"人道主義の",example:"Humanitarian aid was sent to the disaster zone.",category:"current",difficulty:3,examples:[{en:"The organization provides humanitarian aid to disaster victims.",ja:"その組織は災害被害者に人道支援を提供している。",wrong:["その組織は災害被害者に敵意を示している。","その組織は災害被害者に害をもたらしている。","その組織は災害被害者を無視している。"]},{en:"She has a humanitarian concern for all people.",ja:"彼女はすべての人々に対する人道的関心を持っている。",wrong:["彼女はすべての人々に対する無関心を持っている。","彼女はすべての人々に対する敵意を持っている。","彼女はすべての人々に対する嫌悪を持っている。"]},{en:"The humanitarian crisis requires immediate international response.",ja:"その人道危機は即座の国際的対応を必要とする。",wrong:["その人道危機は無視を必要とする。","その人道危機は遅延を必要とする。","その人道危機は害をもたらす必要がある。"]}]},{word:"humiliate",meaning:"屈辱を与える",example:"He was humiliated in front of his colleagues.",category:"society",difficulty:4,examples:[{en:"The coach did not want to humiliate his players in front of the crowd.",ja:"そのコーチは群衆の前で選手たちを屈辱的な思いにさせたくなかった。",wrong:["The coach wanted to encourage his players publicly.","The coach decided to praise his players loudly.","The coach aimed to celebrate his players' achievements."]},{en:"She felt humiliated after failing the exam in front of her classmates.",ja:"彼女はクラスメートの前で試験に失敗して屈辱を感じた。",wrong:["She felt proud after passing the exam.","She felt excited about her exam results.","She felt confident after the test."]},{en:"Making fun of someone's appearance can humiliate them deeply.",ja:"誰かの外見をからかうことは彼らに深い屈辱を与える可能性がある。",wrong:["Making fun of someone's appearance can cheer them up.","Joking about someone's looks can boost their confidence.","Teasing about appearance can strengthen friendships."]}]},{word:"hybrid",meaning:"混合の、ハイブリッド",example:"Hybrid cars use both petrol and electricity.",category:"technology",difficulty:3,examples:[{en:"The car manufacturer released a new hybrid vehicle that uses both electric and gasoline power.",ja:"その自動車メーカーは電気とガソリンの両方を使う新しいハイブリッド車を発売した。",wrong:["The car is powered only by gasoline.","The vehicle uses only electric power.","The car relies exclusively on solar energy."]},{en:"A hybrid approach combines traditional teaching methods with modern technology.",ja:"ハイブリッドなアプローチは従来の教育方法と現代技術を組み合わせている。",wrong:["A hybrid approach uses only traditional methods.","A hybrid method focuses solely on technology.","A hybrid system abandons all traditional practices."]},{en:"The restaurant serves a hybrid cuisine that blends Asian and European flavors.",ja:"そのレストランはアジアとヨーロッパの味を融合させたハイブリッド料理を提供している。",wrong:["The restaurant serves purely Asian cuisine.","The menu features only European dishes.","The food is exclusively traditional Japanese."]}]},{word:"identical",meaning:"同一の",example:"The two paintings are virtually identical.",category:"culture",difficulty:3,examples:[{en:"The twin sisters looked identical, making it difficult for people to tell them apart.",ja:"その双子の姉妹は同一に見えて、人々が彼らを区別することが難しかった。",wrong:["The sisters looked completely different.","The twins had distinct appearances.","The sisters were easy to distinguish."]},{en:"Both documents contain identical information and should not be filed separately.",ja:"両方の書類は同一の情報を含んでおり、別々に保存するべきではない。",wrong:["The documents contain different information.","The papers have unique content each.","The files are completely dissimilar."]},{en:"The two cars are identical in design but different in color.",ja:"その2台の車はデザインが同一だが色が異なっている。",wrong:["The cars have completely different designs.","The vehicles are uniquely styled.","The cars differ significantly in shape."]}]},{word:"ideology",meaning:"思想体系",example:"The movement was driven by a political ideology.",category:"history",difficulty:5,examples:[{en:"Political ideology shapes how citizens view government policies and social issues.",ja:"政治思想体系は市民がどのように政府政策と社会問題を見るかを形作る。",wrong:["Ideology has no effect on political views.","Political beliefs don't influence policy opinions.","Ideology is irrelevant to society."]},{en:"The company's ideology emphasizes sustainability and environmental responsibility.",ja:"その企業の思想体系は持続可能性と環境責任を強調している。",wrong:["The company ignores environmental concerns.","The business ideology promotes wasteful practices.","The organization disregards sustainability."]},{en:"Different ideologies throughout history have influenced cultural and social developments.",ja:"歴史を通じて異なる思想体系は文化的および社会的発展に影響を与えている。",wrong:["Ideologies have never affected history.","Ideas don't influence social change.","Philosophy has no historical impact."]}]},{word:"ignorance",meaning:"無知",example:"Ignorance of the law is no defence.",category:"society",difficulty:3,examples:[{en:"His ignorance of the law did not excuse him from following it.",ja:"法律に対する彼の無知は法律に従うことから彼を免除しなかった。",wrong:["His knowledge of the law excused him.","His expertise prevented legal obligations.","His understanding freed him from rules."]},{en:"Ignorance about climate change leads many people to dismiss environmental concerns.",ja:"気候変動に関する無知は多くの人々が環境問題を軽視するように導く。",wrong:["Knowledge about climate change causes dismissal.","Understanding environmental issues increases denial.","Expertise leads to environmental neglect."]},{en:"The teacher tried to combat ignorance by providing comprehensive education to all students.",ja:"その教師はすべての学生に包括的な教育を提供することで無知と闘おうとした。",wrong:["The teacher promoted ignorance in class.","The educator increased student confusion.","The instructor discouraged learning and understanding."]}]},{word:"illuminate",meaning:"照らす、解明する",example:"The study illuminated the causes of the disease.",category:"science",difficulty:4,examples:[{en:"The bright lamp illuminated the dark corner of the room.",ja:"その明るいランプは部屋の暗い角を照らした。",wrong:["The lamp darkened the room.","The light obscured the corner.","The brightness dimmed the space."]},{en:"The documentary helped illuminate the historical events that led to the war.",ja:"そのドキュメンタリーは戦争につながった歴史的な出来事を解明するのに役立った。",wrong:["The film obscured historical facts.","The documentary confused the historical timeline.","The program made events more mysterious."]},{en:"Her research illuminated new perspectives on the scientific phenomenon.",ja:"彼女の研究はその科学現象に関する新しい視点を明らかにした。",wrong:["Her study concealed scientific findings.","The research obscured new understanding.","The investigation made things more unclear."]}]},{word:"immense",meaning:"巨大な",example:"The project required an immense amount of effort.",category:"society",difficulty:3,examples:[{en:"The immense size of the ocean makes it difficult to fully explore.",ja:"海の巨大な大きさはそれを完全に探索することを難しくしている。",wrong:["The ocean is tiny and easily explored.","The sea is small in size.","The water body is microscopic."]},{en:"She felt immense gratitude for the support her family provided during difficult times.",ja:"彼女は困難な時期に家族が提供した支援に対して莫大な感謝を感じた。",wrong:["She felt minimal appreciation for her family.","Her gratitude was insignificant.","She was slightly thankful."]},{en:"The immense wealth accumulated by the billionaire took decades to build.",ja:"その億万長者によって蓄積された巨大な富は数十年をかけて構築された。",wrong:["The billionaire had very little money.","The wealth was insignificant.","The fortune was modest in size."]}]},{word:"immigrant",meaning:"移民",example:"The city has a large immigrant community.",category:"society",difficulty:3,examples:[{en:"The immigrant family arrived at the airport with all their belongings in two suitcases.",ja:"その移民一家は2つのスーツケースに彼らの持ち物すべてを持って空港に到着した。",wrong:["The native citizen departed from their homeland.","The local resident immigrated elsewhere.","The citizen who was born there left."]},{en:"Many immigrants contribute significantly to the economy through their work and entrepreneurship.",ja:"多くの移民は彼らの仕事と起業家精神を通じて経済に大きく貢献している。",wrong:["Immigrants take resources without contributing.","Newcomers harm the local economy.","Foreign-born people diminish economic growth."]},{en:"The immigrant learned the local language to better integrate into the community.",ja:"その移民はコミュニティにより良く統合するために地域言語を学んだ。",wrong:["The immigrant refused to learn any language.","The newcomer isolated themselves.","The person avoided community involvement."]}]},{word:"immune",meaning:"免疫の",example:"Some people are immune to the common cold.",category:"science",difficulty:3,examples:[{en:"After receiving the vaccine, she became immune to the disease.",ja:"ワクチンを接種した後、彼女はその病気に免疫を獲得した。",wrong:["The vaccine made her vulnerable to disease.","After vaccination, she became susceptible.","The shot increased her infection risk."]},{en:"The politician seemed immune to criticism despite numerous scandals.",ja:"その政治家は多くのスキャンダルにもかかわらず批判に免疫があるように見えた。",wrong:["The politician was sensitive to all criticism.","The official was vulnerable to accusations.","The leader was easily affected by scandals."]},{en:"Some people appear to be naturally immune to certain allergies.",ja:"ある人々は特定のアレルギーに自然に免疫があるように見える。",wrong:["People are naturally susceptible to all allergies.","Everyone develops the same allergic reactions.","No one can be immune to allergens."]}]},{word:"impact",meaning:"影響、衝撃",example:"Climate change has a global impact.",category:"current",difficulty:3,examples:[{en:"The asteroid's impact created a massive crater on the Earth's surface.",ja:"その小惑星の衝撃は地球の表面に巨大なクレーターを作った。",wrong:["The asteroid gently landed without effect.","The impact caused no change.","The collision had minimal consequences."]},{en:"Social media has had a profound impact on how people communicate and share information.",ja:"ソーシャルメディアは人々がどのように通信し情報を共有するかに深刻な影響を与えた。",wrong:["Social media has no effect on communication.","Online platforms don't influence information sharing.","Technology doesn't change how people interact."]},{en:"The teacher's encouraging words had a positive impact on the student's confidence.",ja:"その先生の励ましの言葉は学生の自信に肯定的な影響を与えた。",wrong:["The encouraging words had no effect.","Positive feedback diminishes confidence.","Kind words have negative consequences."]}]},{word:"implement",meaning:"実施する",example:"The school implemented a new attendance policy.",category:"society",difficulty:3,examples:[{en:"The company decided to implement new safety measures in all factories.",ja:"その企業はすべての工場で新しい安全対策を実施することを決定した。",wrong:["The company refused to apply safety measures.","The organization ignored new protocols.","The business rejected all improvements."]},{en:"The government plans to implement stricter environmental regulations next year.",ja:"政府は来年より厳しい環境規制を実施する予定である。",wrong:["The government won't enforce any regulations.","The state plans to remove all rules.","The administration will loosen restrictions."]},{en:"Teachers implement various teaching strategies to help students learn more effectively.",ja:"教師は学生がより効果的に学べるように様々な教育戦略を実施している。",wrong:["Teachers avoid using any strategies.","Educators don't employ teaching methods.","Instructors refuse to implement anything new."]}]},{word:"implicit",meaning:"暗黙の",example:"There was an implicit agreement between them.",category:"society",difficulty:5,examples:[{en:"There was an implicit agreement between the two parties that neither would discuss the meeting.",ja:"その二者の間に誰も会議について議論しないという暗黙の合意があった。",wrong:["There was an explicit written contract.","The agreement was clearly stated.","The understanding was openly declared."]},{en:"Her implicit trust in him was evident from her actions, even though she never said it aloud.",ja:"彼女が声に出して言わなかったにもかかわらず、彼に対する彼女の暗黙の信頼は彼女の行動から明らかだった。",wrong:["Her explicit distrust was shown.","She openly questioned his reliability.","Her expressed doubt was apparent."]},{en:"The implicit meaning of the poem required careful analysis to fully understand.",ja:"その詩の暗黙の意味は完全に理解するために慎重な分析が必要だった。",wrong:["The poem's explicit message was clear.","The obvious meaning was straightforward.","The stated purpose was obvious."]}]},{word:"impose",meaning:"課す",example:"The government imposed new tariffs on imports.",category:"current",difficulty:3,examples:[{en:"The government imposed new taxes on imported goods to protect local businesses.",ja:"政府は地域企業を保護するために輸入品に新しい税金を課した。",wrong:["The government removed all taxes.","The state eliminated import duties.","The administration reduced tariffs."]},{en:"The strict principal imposed strict rules on student behavior and dress code.",ja:"その厳格な校長は学生の行動と服装規定に厳格なルールを課した。",wrong:["The principal allowed complete freedom.","The headmaster removed all restrictions.","The administrator abolished discipline."]},{en:"She did not want to impose her opinions on others during the discussion.",ja:"彼女は議論中に他の人に自分の意見を課したくなかった。",wrong:["She wanted to force her views.","She attempted to push her beliefs.","She tried to dominate the conversation."]}]},{word:"impulse",meaning:"衝動",example:"She bought the dress on impulse.",category:"society",difficulty:3,examples:[{en:"Acting on an impulse, he bought the expensive camera without thinking about the cost.",ja:"衝動で行動して、彼はコストについて考えずに高価なカメラを買った。",wrong:["He carefully planned his purchase.","He considered all options thoroughly.","He made a deliberate decision."]},{en:"The child had an impulse to run into the street, but the parent quickly stopped her.",ja:"その子どもは通りに走り込む衝動があったが、親がすぐに彼女を止めた。",wrong:["The child calmly decided to stay.","The girl carefully considered walking.","The child thought rationally."]},{en:"Learning to resist the impulse to spend money helps develop financial discipline.",ja:"お金を使う衝動に抵抗することを学ぶことは財政的規律を発展させるのに役立つ。",wrong:["Giving in to spending urges builds discipline.","Following impulses improves finances.","Resisting urges wastes money."]}]},{word:"inaugurate",meaning:"就任させる、開始する",example:"The president was inaugurated in January.",category:"history",difficulty:5,examples:[{en:"The president will be inaugurated on January 20th in a formal ceremony.",ja:"その大統領は1月20日に正式な式典で就任する。",wrong:["The president was removed from office.","The leader resigned from power.","The official stepped down."]},{en:"The museum will inaugurate its new wing with a grand opening celebration.",ja:"その博物館は盛大なオープニングセレモニーで新しい棟を開始する。",wrong:["The museum closed its new section.","The facility sealed off the wing.","The building abandoned the expansion."]},{en:"The company decided to inaugurate a new era of innovation with the product launch.",ja:"その企業は製品発表で革新の新しい時代を開始することを決定した。",wrong:["The company ended innovation efforts.","The organization stopped development.","The business halted all new initiatives."]}]},{word:"incidence",meaning:"発生率",example:"The incidence of diabetes is rising globally.",category:"science",difficulty:4,examples:[{en:"The incidence of diabetes has increased significantly in recent years.",ja:"近年、糖尿病の発生率が大幅に増加しています。",wrong:["糖尿病の入射が最近増加した","糖尿病の傾きが著しく上昇した","糖尿病の衝突がこの頃増えた"]},{en:"Scientists are studying the incidence of cancer in different populations.",ja:"科学者たちは異なる集団におけるがんの発生率を研究しています。",wrong:["科学者たちはがんの傾斜を研究している","がんの照射が異なる人口で研究されている","がんの接続率を調べている"]},{en:"The incidence of car accidents decreased after the new traffic law.",ja:"新しい交通法の後、交通事故の発生率は減少しました。",wrong:["新しい法律の後、車の傾きが減った","交通事故の入場が法律の後に低下した","車の相互作用が交通法の後に減少した"]}]},{word:"incline",meaning:"傾く、〜する気にさせる",example:"He is inclined to agree with the proposal.",category:"society",difficulty:4,examples:[{en:"The road inclines steeply towards the mountain.",ja:"その道は山に向かって急に傾いています。",wrong:["その道は山に含まれている","その道は山に促進する","その道は山に相続する"]},{en:"Success in sports inclines young people to pursue athletics.",ja:"スポーツでの成功は若い人々に運動を追求する気にさせます。",wrong:["スポーツの成功は若者を傾斜させる","スポーツの勝利は若い人をインフラにする","スポーツの成功は若者を組み込む"]},{en:"I incline towards the opinion that we should wait longer.",ja:"私はもっと長く待つべきだという意見に傾いています。",wrong:["私はより長く待つ発生率に傾いている","私はもっと長く待つことを吸収する","私は待つことを受け継ぐ傾向がある"]}]},{word:"incorporate",meaning:"組み込む",example:"The design incorporates solar panels.",category:"technology",difficulty:4,examples:[{en:"The company will incorporate new technology into its products.",ja:"その会社は新しいテクノロジーを製品に組み込みます。",wrong:["その会社は新しい技術を傾ける","その会社は新しい技術を相続する","その会社は新しい技術を誘発する"]},{en:"Teachers incorporate feedback from students into their lessons.",ja:"教師たちは生徒からのフィードバックをレッスンに組み込みます。",wrong:["教師たちは学生の反応を展開する","教師たちは生徒の意見を抑制する","教師たちは学生の反応を甘やかす"]},{en:"The new law incorporates several amendments from previous legislation.",ja:"新しい法律は以前の法律からいくつかの修正案を組み込んでいます。",wrong:["新しい法律は以前の修正案を傾ける","新しい法律は以前の立法を吸収する","新しい法律は以前の法律を検査する"]}]},{word:"index",meaning:"指標、索引",example:"The consumer price index rose by two percent.",category:"current",difficulty:3,examples:[{en:"The book has a detailed index at the back.",ja:"その本は背後に詳細な索引があります。",wrong:["その本は背後に詳細な傾斜がある","その本は背後に詳細な発生率がある","その本は背後に詳細なインフラがある"]},{en:"The stock market index rose by 2% this week.",ja:"株式市場指標は今週2%上昇しました。",wrong:["株式市場の傾きが今週2%上昇した","株式市場の組み込みが2%上がった","株価の相続が今週2%増加した"]},{en:"Economists use the consumer price index to measure inflation.",ja:"経済学者たちは消費者物価指数を使ってインフレを測定しています。",wrong:["経済学者たちは消費者価格の傾きでインフレを測定する","経済学者たちはインフレを相続する指標を使う","経済学者たちは消費者価格を甘やかす"]}]},{word:"induce",meaning:"誘発する、促す",example:"Stress can induce various health problems.",category:"science",difficulty:4,examples:[{en:"The medication can induce drowsiness as a side effect.",ja:"その薬は副作用として眠気を誘発することができます。",wrong:["その薬は眠気を組み込むことができる","その薬は眠気を甘やかすことができる","その薬は眠気を抑制することができる"]},{en:"The advertisement induces consumers to buy the product.",ja:"その広告は消費者にその製品を買わせます。",wrong:["その広告は消費者を傾かせる","その広告は消費者を受け継がせる","その広告は消費者を検査する"]},{en:"Heavy exercise can induce muscle soreness the next day.",ja:"激しい運動は次の日に筋肉痛を誘発することができます。",wrong:["激しい運動は筋肉痛を甘やかす","激しい運動は筋肉痛を索引する","激しい運動は筋肉痛を住ませる"]}]},{word:"indulge",meaning:"ふける、甘やかす",example:"She indulged in a piece of chocolate cake.",category:"society",difficulty:3,examples:[{en:"She indulges in chocolate every weekend.",ja:"彼女は毎週末チョコレートにふけります。",wrong:["彼女は毎週末チョコレートを誘発する","彼女は毎週末チョコレートを検査する","彼女は毎週末チョコレートを組み込む"]},{en:"Parents sometimes indulge their children with too many gifts.",ja:"両親たちは時々子どもたちをおもちゃで甘やかします。",wrong:["両親たちは時々子どもたちをおもちゃで誘発する","両親たちは時々子どもたちをおもちゃで抑制する","両親たちは時々子どもたちをおもちゃで検査する"]},{en:"He indulges himself with expensive wines and fine dining.",ja:"彼は高級ワインと高級レストランで自分をふけります。",wrong:["彼は高級ワインで自分を傾かせる","彼は高級ワインで自分を相続させる","彼は高級ワインで自分を抑制する"]}]},{word:"infant",meaning:"幼児",example:"Infant mortality rates have decreased significantly.",category:"science",difficulty:3,examples:[{en:"The infant is sleeping peacefully in the crib.",ja:"その幼児はベビーベッドで静かに寝ています。",wrong:["その幼児は傾いて眠っている","その幼児は発生率で寝ている","その幼児は索引の中で寝ている"]},{en:"Parents need to provide proper nutrition for infants.",ja:"両親たちは幼児に適切な栄養を提供する必要があります。",wrong:["両親たちは傾斜に栄養を提供する必要がある","両親たちは相続者に栄養を与える必要がある","両親たちは抑制物に栄養を提供する必要がある"]},{en:"Infant mortality rates have decreased significantly in developed countries.",ja:"先進国における幼児死亡率は大幅に低下しました。",wrong:["傾斜死亡率は先進国で低下した","組み込み死亡率が先進国で減少した","相続死亡率が発達国で低下した"]}]},{word:"infrastructure",meaning:"インフラ",example:"The country needs to invest in infrastructure.",category:"society",difficulty:3,examples:[{en:"A country needs good infrastructure for economic development.",ja:"国の経済発展のためには良いインフラが必要です。",wrong:["国の経済発展には良い傾斜が必要である","国の発展には良い索引が必要である","国の成長には良い相続が必要である"]},{en:"The government invested billions in infrastructure improvements.",ja:"政府はインフラの改善に数十億ドルを投資しました。",wrong:["政府は傾斜改善に数十億ドルを投資した","政府は相続改善に数十億ドルを投資した","政府は誘発改善に投資した"]},{en:"Modern infrastructure includes roads, airports, and utilities.",ja:"現代のインフラには道路、空港、公共サービスが含まれます。",wrong:["現代の傾斜は道路を含む","現代の発生率は道路を含む","現代の組み込みは道路を含む"]}]},{word:"inhabit",meaning:"住む",example:"Many species inhabit the rainforest.",category:"science",difficulty:3,examples:[{en:"Many species inhabit the tropical rainforest.",ja:"多くの種が熱帯雨林に住んでいます。",wrong:["多くの種が熱帯雨林を誘発している","多くの種が熱帯雨林を傾けている","多くの種が熱帯雨林を甘やかしている"]},{en:"The village is inhabited by farmers and fishermen.",ja:"その村は農民と漁師たちが住んでいます。",wrong:["その村は農民によって誘発されている","その村は農民によって組み込まれている","その村は農民によって検査されている"]},{en:"Polar bears inhabit the Arctic regions.",ja:"ホッキョクグマは北極地域に住んでいます。",wrong:["ホッキョクグマは北極地域を誘発する","ホッキョクグマは北極地域を相続する","ホッキョクグマは北極地域を甘やかす"]}]},{word:"inherit",meaning:"相続する、受け継ぐ",example:"She inherited a fortune from her grandmother.",category:"society",difficulty:3,examples:[{en:"She will inherit her father's property after his death.",ja:"彼女は父親の死後、彼の財産を相続します。",wrong:["彼女は父親の死後、彼の財産を誘発する","彼女は父親の死後、彼の財産を甘やかす","彼女は父親の死後、彼の財産を検査する"]},{en:"Children inherit genetic traits from their parents.",ja:"子どもたちは両親から遺伝的特性を受け継ぎます。",wrong:["子どもたちは両親から遺伝的特性を傾ける","子どもたちは両親から遺伝的特性を組み込む","子どもたちは両親から遺伝的特性を抑制する"]},{en:"He inherited his mother's talent for music.",ja:"彼は母親の音楽の才能を受け継ぎました。",wrong:["彼は母親の音楽の才能を誘発した","彼は母親の音楽の才能を甘やかした","彼は母親の音楽の才能を検査した"]}]},{word:"inhibit",meaning:"抑制する",example:"Shyness can inhibit social interaction.",category:"science",difficulty:4,examples:[{en:"Fear inhibits people from taking risks.",ja:"恐怖は人々がリスクを取ることを抑制します。",wrong:["恐怖は人々がリスクを取ることを誘発する","恐怖は人々がリスクを取ることを甘やかす","恐怖は人々がリスクを取ることを組み込む"]},{en:"The medication inhibits the growth of bacteria.",ja:"その薬は細菌の成長を抑制します。",wrong:["その薬は細菌の成長を誘発する","その薬は細菌の成長を組み込む","その薬は細菌の成長を受け継がせる"]},{en:"Cold weather inhibits plant growth.",ja:"寒い天候は植物の成長を抑制します。",wrong:["寒い天候は植物の成長を誘発する","寒い天候は植物の成長を甘やかす","寒い天候は植物の成長を検査する"]}]},{word:"initiate",meaning:"開始する",example:"The company initiated a review of its policies.",category:"society",difficulty:4,examples:[{en:"The company will initiate a new project next month.",ja:"その会社は来月新しいプロジェクトを開始します。",wrong:["その会社は来月新しいプロジェクトを誘発する","その会社は来月新しいプロジェクトを甘やかす","その会社は来月新しいプロジェクトを抑制する"]},{en:"She initiated a conversation with her new colleague.",ja:"彼女は新しい同僚との会話を始めました。",wrong:["彼女は新しい同僚との会話を誘発した","彼女は新しい同僚との会話を検査した","彼女は新しい同僚との会話を相続した"]},{en:"The government initiated reforms to improve education.",ja:"政府は教育を改善するための改革を開始しました。",wrong:["政府は教育を改善する傾斜を開始した","政府は教育を改善する発生率を開始した","政府は教育を改善する甘やかしを開始した"]}]},{word:"innovative",meaning:"革新的な",example:"The firm is known for its innovative products.",category:"technology",difficulty:3,examples:[{en:"The company is known for its innovative products.",ja:"その会社は革新的な製品で知られています。",wrong:["その会社は傾斜製品で知られている","その会社は相続製品で知られている","その会社は誘発製品で知られている"]},{en:"Innovative thinking led to the discovery of new technologies.",ja:"革新的な考え方は新しい技術の発見につながりました。",wrong:["傾斜した考え方は新しい技術を誘発した","相続的な考え方は新しい技術を発見した","甘やかし的な思考は新しい技術を見つけた"]},{en:"The team came up with an innovative solution to the problem.",ja:"チームはその問題に対する革新的な解決策を思いつきました。",wrong:["チームは問題に対して傾斜した解決策を思いついた","チームは問題に対して相続的な解決策を思いついた","チームは問題に対して誘発的な解決策を思いついた"]}]},{word:"insight",meaning:"洞察",example:"The report provides valuable insights into consumer behaviour.",category:"society",difficulty:3,examples:[{en:"The expert provided valuable insight into the market trends.",ja:"その専門家は市場動向に対する貴重な洞察を提供しました。",wrong:["その専門家は市場動向に対する傾斜を提供した","その専門家は市場動向に対する誘発を提供した","その専門家は市場動向に対する相続を提供した"]},{en:"Her insight into human behavior helped solve the problem.",ja:"人間の行動に対する彼女の洞察は問題を解決するのに役立ちました。",wrong:["人間の行動への彼女の傾斜が問題を解決した","人間の行動への彼女の誘発が問題を解決した","人間の行動への彼女の甘やかしが問題を解決した"]},{en:"The researcher gained insight from analyzing the data.",ja:"研究者はデータを分析することから洞察を得ました。",wrong:["研究者はデータを分析することから傾斜を得た","研究者はデータを分析することから相続を得た","研究者はデータを分析することから誘発を得た"]}]},{word:"inspect",meaning:"検査する",example:"Officials inspected the factory for safety violations.",category:"society",difficulty:3,examples:[{en:"The inspector will inspect the building for safety hazards.",ja:"検査官は安全上の危険がないか建物を検査します。",wrong:["検査官は安全上の危険がないか建物を誘発する","検査官は安全上の危険がないか建物を甘やかす","検査官は安全上の危険がないか建物を相続する"]},{en:"Quality control inspects every product before shipment.",ja:"品質管理は出荷前にすべての製品を検査します。",wrong:["品質管理は出荷前にすべての製品を誘発する","品質管理は出荷前にすべての製品を組み込む","品質管理は出荷前にすべての製品を抑制する"]},{en:"The doctor inspected the patient's throat carefully.",ja:"医者は患者の喉を注意深く検査しました。",wrong:["医者は患者の喉を注意深く誘発した","医者は患者の喉を注意深く甘やかした","医者は患者の喉を注意深く相続した"]}]},{word:"instinct",meaning:"本能",example:"Birds migrate by instinct.",category:"science",difficulty:3,examples:[{en:"The mother's instinct to protect her child is very strong.",ja:"子どもを守るという母親の本能は非常に強い。",wrong:["母親の指示は子どもを守ることが非常に強い。","子どもを守る母親の習慣は非常に強い。","子どもを守るという母親の計画は非常に強い。"]},{en:"He followed his instinct and decided to trust her.",ja:"彼は自分の本能に従って、彼女を信じることにした。",wrong:["彼は自分の指示に従って、彼女を信じることにした。","彼は自分の感情に従って、彼女に指示を与えた。","彼は自分の教えに従って、彼女を信じることを避けた。"]},{en:"Animals rely on instinct for survival.",ja:"動物は生き残るために本能に頼っている。",wrong:["動物は生き残るために教育に頼っている。","動物は生き残るために指示に頼っている。","動物は生き残るために技能に頼っている。"]}]},{word:"institute",meaning:"設立する、機関",example:"The government instituted new healthcare reforms.",category:"society",difficulty:4,examples:[{en:"The government will institute new policies next year.",ja:"政府は来年新しい政策を設立する。",wrong:["政府は来年新しい政策を廃止する。","政府は来年新しい政策を否定する。","政府は来年新しい政策を延期する。"]},{en:"She works at a research institute.",ja:"彼女は研究機関で働いている。",wrong:["彼女は研究機関を廃止している。","彼女は研究機関を設立している。","彼女は研究機関を破壊している。"]},{en:"The institute was founded in 1990.",ja:"その機関は1990年に設立された。",wrong:["その機関は1990年に閉鎖された。","その機関は1990年に廃止された。","その機関は1990年に移動された。"]}]},{word:"intact",meaning:"無傷の、そのままの",example:"The ancient ruins remained largely intact.",category:"history",difficulty:4,examples:[{en:"The package arrived intact despite rough handling.",ja:"荷物は乱雑に扱われたにもかかわらず、無傷で到着した。",wrong:["荷物は乱雑に扱われたので、破損して到着した。","荷物は無傷だったので、丁寧に扱われた。","荷物は乱雑に扱われて、完全に壊れた。"]},{en:"We must keep the ecosystem intact.",ja:"私たちは生態系をそのままに保つ必要がある。",wrong:["私たちは生態系を破壊する必要がある。","私たちは生態系を変更する必要がある。","私たちは生態系を変えるべきだ。"]},{en:"His reputation remained intact after the scandal.",ja:"スキャンダルの後も彼の評判は傷つかなかった。",wrong:["スキャンダルの後、彼の評判は完全に破壊された。","スキャンダルの後、彼の評判は低下した。","スキャンダルの後、彼の評判は失われた。"]}]},{word:"integral",meaning:"不可欠な",example:"Teamwork is an integral part of success.",category:"society",difficulty:4,examples:[{en:"Trust is an integral part of any relationship.",ja:"信頼はどんな関係においても不可欠な部分である。",wrong:["信頼はどんな関係においても不必要な部分である。","信頼はどんな関係においても邪魔な部分である。","信頼はどんな関係においても補助的な部分である。"]},{en:"Education is integral to our society's progress.",ja:"教育は私たちの社会の進歩に不可欠である。",wrong:["教育は私たちの社会の進歩を妨げている。","教育は私たちの社会の進歩とは関係がない。","教育は私たちの社会にとって有害である。"]},{en:"The engine is an integral component of the car.",ja:"エンジンは車の不可欠な部品である。",wrong:["エンジンは車の不要な部品である。","エンジンは車から外すことができる。","エンジンは車の装飾的な部品である。"]}]},{word:"integrate",meaning:"統合する",example:"The school integrates students of all abilities.",category:"society",difficulty:3,examples:[{en:"We need to integrate new technologies into our workflow.",ja:"新しい技術をワークフローに統合する必要がある。",wrong:["新しい技術をワークフローから除外する必要がある。","新しい技術をワークフローで分離する必要がある。","新しい技術をワークフローと別にする必要がある。"]},{en:"The school integrated students from different backgrounds.",ja:"学校は異なる背景を持つ学生を統合した。",wrong:["学校は異なる背景を持つ学生を分離した。","学校は異なる背景を持つ学生を排除した。","学校は異なる背景を持つ学生を隔離した。"]},{en:"The two companies integrated their operations.",ja:"2つの会社は彼らの事業を統合した。",wrong:["2つの会社は彼らの事業を分割した。","2つの会社は彼らの事業を分離した。","2つの会社は彼らの事業を中止した。"]}]},{word:"integrity",meaning:"誠実さ、完全性",example:"She is a woman of great integrity.",category:"society",difficulty:4,examples:[{en:"She is known for her integrity and honesty.",ja:"彼女は誠実さと正直さで知られている。",wrong:["彼女は不正と嘘で知られている。","彼女は欺瞞と詐欺で知られている。","彼女は不真実さで知られている。"]},{en:"The integrity of the building structure is questionable.",ja:"建物の構造の完全性は疑わしい。",wrong:["建物の構造の欠陥はない。","建物の構造は完全に壊れている。","建物の構造は非常に新しい。"]},{en:"Maintaining integrity in business is essential.",ja:"ビジネスで誠実さを保つことは本質的である。",wrong:["ビジネスで欺くことは本質的である。","ビジネスで嘘をつくことは重要である。","ビジネスで不正を行うことは必要である。"]}]},{word:"intensify",meaning:"強まる",example:"The storm is expected to intensify overnight.",category:"current",difficulty:4,examples:[{en:"The conflict continued to intensify over time.",ja:"紛争は時間とともに強まり続けた。",wrong:["紛争は時間とともに減少し続けた。","紛争は時間とともに消滅した。","紛争は時間とともに緩和した。"]},{en:"She intensified her efforts to complete the project.",ja:"彼女はプロジェクトを完了するために努力を強めた。",wrong:["彼女はプロジェクトを完了するために努力を減らした。","彼女はプロジェクトを放棄するために努力を減らした。","彼女はプロジェクトを中止するために努力を弱めた。"]},{en:"The heat will intensify during the afternoon.",ja:"午後は気温が強まる。",wrong:["午後は気温が低下する。","午後は気温が同じままである。","午後は気温が冷える。"]}]},{word:"interfere",meaning:"干渉する",example:"Parents should not interfere too much.",category:"society",difficulty:3,examples:[{en:"Please do not interfere with my work.",ja:"私の仕事に干渉しないでください。",wrong:["私の仕事を手伝ってください。","私の仕事をサポートしてください。","私の仕事を改善してください。"]},{en:"The noise interfered with our concentration.",ja:"ノイズは私たちの集中力を妨げた。",wrong:["ノイズは私たちの集中力を助けた。","ノイズは私たちの集中力を向上させた。","ノイズは私たちの集中力を強化した。"]},{en:"He tends to interfere in other people's affairs.",ja:"彼は他人の事柄に干渉する傾向がある。",wrong:["彼は他人の事柄を尊重する傾向がある。","彼は他人の事柄に関与しない傾向がある。","彼は他人の事柄を支持する傾向がある。"]}]},{word:"interim",meaning:"暫定の",example:"An interim report will be published next week.",category:"society",difficulty:5,examples:[{en:"An interim government was established after the revolution.",ja:"革命の後、暫定政府が樹立された。",wrong:["革命の後、永続的な政府が樹立された。","革命の後、独裁政権が樹立された。","革命の後、正規政府が樹立された。"]},{en:"In the interim, we will continue with the old system.",ja:"その間、私たちは古いシステムで継続する。",wrong:["その後、私たちは古いシステムで継続する。","一方、私たちは新しいシステムに変更する。","その結果、私たちは古いシステムを廃止する。"]},{en:"She served as interim director for three months.",ja:"彼女は3ヶ月間暫定ディレクターを務めた。",wrong:["彼女は3ヶ月間常任ディレクターを務めた。","彼女は3年間暫定ディレクターを務めた。","彼女は永遠に暫定ディレクターを務めた。"]}]},{word:"intervene",meaning:"介入する",example:"The government intervened to stabilise the economy.",category:"society",difficulty:4,examples:[{en:"The government decided to intervene in the crisis.",ja:"政府は危機に介入することを決定した。",wrong:["政府は危機を無視することを決定した。","政府は危機を傍観することを決定した。","政府は危機から逃げることを決定した。"]},{en:"A mediator intervened to resolve the dispute.",ja:"仲介者は紛争を解決するために介入した。",wrong:["仲介者は紛争を無視した。","仲介者は紛争を悪化させた。","仲介者は紛争から逃げた。"]},{en:"We should not intervene in their personal matters.",ja:"彼らの個人的な事柄に介入するべきではない。",wrong:["彼らの個人的な事柄を手伝うべきである。","彼らの個人的な事柄を支援すべきである。","彼らの個人的な事柄を監視すべきである。"]}]},{word:"intimate",meaning:"親密な、ほのめかす",example:"Only intimate friends were invited to the party.",category:"society",difficulty:3,examples:[{en:"They shared an intimate conversation over dinner.",ja:"彼らはディナーの間に親密な会話をした。",wrong:["彼らはディナーの間に形式的な会話をした。","彼らはディナーの間に気の進まない会話をした。","彼らはディナーの間に疎遠な会話をした。"]},{en:"She intimated that she might resign soon.",ja:"彼女は間もなく辞任するかもしれないとほのめかした。",wrong:["彼女は間もなく昇進することを約束した。","彼女は間もなく辞任しないことを宣言した。","彼女は永遠に働き続けることを約束した。"]},{en:"They have an intimate relationship.",ja:"彼らは親密な関係を持っている。",wrong:["彼らは距離のある関係を持っている。","彼らは形式的な関係を持っている。","彼らは疎遠な関係を持っている。"]}]},{word:"intricate",meaning:"複雑な、精巧な",example:"The watch has an intricate mechanical movement.",category:"technology",difficulty:4,examples:[{en:"The intricate design of the jewelry was stunning.",ja:"ジュエリーの複雑な設計は素晴らしかった。",wrong:["ジュエリーのシンプルな設計は素晴らしかった。","ジュエリーの粗い設計は素晴らしかった。","ジュエリーの単純な設計は素晴らしかった。"]},{en:"The plot of the novel is quite intricate.",ja:"小説のプロットはかなり複雑である。",wrong:["小説のプロットはかなりシンプルである。","小説のプロットはかなり退屈である。","小説のプロットはかなり直線的である。"]},{en:"Understanding the intricate details requires patience.",ja:"複雑な詳細を理解するには忍耐が必要である。",wrong:["シンプルな詳細を理解するには忍耐が必要である。","複雑な詳細を理解するのは簡単である。","複雑な詳細は無視できる。"]}]},{word:"intrinsic",meaning:"本質的な",example:"Curiosity is intrinsic to human nature.",category:"science",difficulty:5,examples:[{en:"The intrinsic value of gold is very high.",ja:"金の本質的な価値は非常に高い。",wrong:["金の外的な価値は非常に高い。","金の一時的な価値は非常に高い。","金の相対的な価値は非常に低い。"]},{en:"Learning has intrinsic motivation for many students.",ja:"多くの学生にとって学習は本質的な動機づけを持っている。",wrong:["多くの学生にとって学習は外的な報酬である。","多くの学生にとって学習は強制である。","多くの学生にとって学習は退屈である。"]},{en:"The intrinsic nature of the problem cannot be ignored.",ja:"問題の本質的な性質は無視できない。",wrong:["問題の外的な性質は無視できない。","問題の一時的な性質は無視できない。","問題の表面的な側面は本質的である。"]}]},{word:"invade",meaning:"侵入する",example:"Foreign troops invaded the country in 1940.",category:"history",difficulty:3,examples:[{en:"The army will invade the neighboring country.",ja:"軍隊は隣国に侵入するだろう。",wrong:["軍隊は隣国を訪問するだろう。","軍隊は隣国を支援するだろう。","軍隊は隣国と友好関係を結ぶだろう。"]},{en:"Privacy invaders constantly monitor social media.",ja:"プライバシー侵害者は絶えずソーシャルメディアを監視している。",wrong:["プライバシー保護者は絶えずソーシャルメディアを監視している。","プライバシー支援者は絶えずソーシャルメディアを無視している。","プライバシー尊重者は絶えずソーシャルメディアを利用している。"]},{en:"Darkness invaded the room as the sun set.",ja:"太陽が沈むにつれて、暗闇が部屋に侵入した。",wrong:["太陽が沈むにつれて、光が部屋に侵入した。","太陽が沈むにつれて、明るさが部屋に広がった。","太陽が沈むにつれて、光線が部屋を照らした。"]}]},{word:"invoke",meaning:"呼び出す、援用する",example:"The lawyer invoked the right to privacy.",category:"society",difficulty:5,examples:[{en:"She invoked the law to protect her rights.",ja:"彼女は自分の権利を守るために法律を援用した。",wrong:["彼女は自分の権利を放棄するために法律を無視した。","彼女は自分の権利に対して法律に反対した。","彼女は自分の権利を失うために法律を避けた。"]},{en:"The programmer invoked the function to process data.",ja:"プログラマーはデータを処理するためにその関数を呼び出した。",wrong:["プログラマーはデータを処理するためにその関数を削除した。","プログラマーはデータを処理するためにその関数を無視した。","プログラマーはデータを処理するためにその関数を停止した。"]},{en:"He invoked his right to remain silent.",ja:"彼は黙秘権を行使した。",wrong:["彼は黙秘権を放棄した。","彼は黙秘権に反対した。","彼は発言する義務を引き受けた。"]}]},{word:"irony",meaning:"皮肉",example:"The irony is that he became what he criticised.",category:"culture",difficulty:3,examples:[{en:"The irony of the situation is that he became rich after winning the lottery, only to lose it all in bad investments.",ja:"その状況の皮肉なことに、彼は宝くじで金持ちになった後、悪い投資ですべてを失った。",wrong:["彼は宝くじに当たったので確実に金持ちになった","皮肉とは必ず笑える冗談のことである","状況が複雑であることを皮肉と呼ぶ"]},{en:"It's ironic that a fire station burned down.",ja:"消防署が火事で燃えてしまったのは皮肉である。",wrong:["消防署は常に火事から守られている","皮肉とは予期しない出来事のことである","消防署が火事になることは不可能である"]},{en:"She said with irony that the service was excellent, while they waited three hours for food.",ja:"彼女は皮肉を込めて、食事を3時間待っている間にサービスは素晴らしいと言った。",wrong:["彼女は本当にサービスに満足していた","皮肉は常に言葉通りの意味である","待ち時間は良いサービスの証である"]}]},{word:"irrigate",meaning:"灌漑する",example:"Farmers irrigate their fields during dry spells.",category:"science",difficulty:4,examples:[{en:"Farmers irrigate their fields during the dry season to ensure crop growth.",ja:"農民は乾季に畑に灌漑して作物の成長を確保する。",wrong:["灌漑とは雑草を取り除くことである","灌漑は水を減らすプロセスである","灌漑は肥料を添加することを意味する"]},{en:"The ancient Romans built aqueducts to irrigate the surrounding farmland.",ja:"古代ローマ人は周辺の農地に灌漑するために水道橋を建設した。",wrong:["水道橋は水を運ぶためのものではない","灌漑は古代に存在しなかった","ローマ人は灌漑システムを使わなかった"]},{en:"To properly irrigate a garden, you need to water it regularly and evenly.",ja:"庭に適切に灌漑するには、定期的かつ均等に水をやる必要がある。",wrong:["灌漑とは不規則に水をやることである","灌漑は一度だけ行う必要がある","灌漑は土を掘ることを意味する"]}]},{word:"isolate",meaning:"隔離する",example:"Scientists isolated the virus in the laboratory.",category:"science",difficulty:3,examples:[{en:"During the pandemic, health officials advised people to isolate if they tested positive for the virus.",ja:"パンデミック中、保健当局はウイルスの検査が陽性の場合、人々に隔離することをお勧めした。",wrong:["隔離とは積極的に他人と交流することである","隔離は病気の治療方法である","隔離はウイルスを殺すプロセスである"]},{en:"Scientists isolated the bacteria in a sterile laboratory to study its properties.",ja:"科学者たちは無菌研究室でバクテリアを隔離してその特性を研究した。",wrong:["隔離とは複数の物を混ぜることである","隔離は研究の速度を上げる","隔離なしで正確な実験ができる"]},{en:"The child felt isolated after moving to a new school where she didn't know anyone.",ja:"その子は誰も知らない新しい学校に引っ越した後、孤立していると感じた。",wrong:["隔離とは多くの友達を持つことである","隔離は楽しい経験である","隔離とは学校でのランキングである"]}]},{word:"jeopardise",meaning:"危険にさらす",example:"Reckless driving can jeopardise lives.",category:"society",difficulty:4,examples:[{en:"Smoking can jeopardise your health and longevity.",ja:"喫煙はあなたの健康と長寿を危険にさらす可能性がある。",wrong:["喫煙は健康に良い","喫煙は寿命を延ばす","喫煙は危険にさらすことではない"]},{en:"The scandal jeopardised the politician's career and reputation.",ja:"そのスキャンダルは政治家のキャリアと評判を危険にさらした。",wrong:["スキャンダルは人の評判を改善する","スキャンダルはキャリアを助ける","危険にさらすことは利益をもたらす"]},{en:"Poor time management could jeopardise the success of the project.",ja:"不十分な時間管理はプロジェクトの成功を危険にさらす可能性がある。",wrong:["悪い時間管理はプロジェクトを改善する","時間管理はプロジェクトに影響を与えない","危険にさらすとは支援することである"]}]},{word:"jurisdiction",meaning:"管轄権",example:"The case falls under federal jurisdiction.",category:"society",difficulty:5,examples:[{en:"The federal court has jurisdiction over interstate commerce cases.",ja:"連邦裁判所は州間通商事件に対する管轄権を持っている。",wrong:["管轄権とは法律を作ることである","州の裁判所は常に連邦事件を扱う","管轄権は国によって異なることはない"]},{en:"The local police department has jurisdiction within the city limits.",ja:"市警察局は市の境界内で管轄権を持っている。",wrong:["管轄権とは警察を雇うことである","警察は市の外でも同じ権力を持つ","管轄権は地域によって異なることはない"]},{en:"Under international law, each country has jurisdiction over its own territorial waters.",ja:"国際法の下では、各国は独自の領海に対する管轄権を持っている。",wrong:["国は他国の領海に管轄権を持つ","管轄権は地理的な場所と関係がない","国際法は管轄権を規定しない"]}]},{word:"keen",meaning:"熱心な、鋭い",example:"She has a keen interest in environmental issues.",category:"society",difficulty:3,examples:[{en:"She has a keen interest in environmental conservation and volunteers regularly.",ja:"彼女は環境保全に熱心な関心を持ち、定期的にボランティアをしている。",wrong:["熱心とは関心がないことを意味する","熱心な人はボランティアをしない","関心がないことは熱心さを示す"]},{en:"The detective has a keen eye for detail and solved the mystery quickly.",ja:"その探偵は細部に対して鋭い目を持ち、謎を素早く解いた。",wrong:["鋭いとは視力が悪いことである","鋭い観察は謎を解くのを遅くする","詳細への注意は役に立たない"]},{en:"He is keen on learning new languages and has already mastered three.",ja:"彼は新しい言語を学ぶことに熱心であり、すでに3つをマスターしている。",wrong:["熱心とは学習に興味がないことである","3つの言語をマスターすることは熱心さを示さない","学習への興味は無関心と同じである"]}]},{word:"landmark",meaning:"画期的な出来事、目印",example:"The ruling was a landmark decision for human rights.",category:"history",difficulty:3,examples:[{en:"The Statue of Liberty is a famous landmark that represents freedom and democracy.",ja:"自由の女神像は自由と民主主義を表す有名な目印である。",wrong:["目印とは隠れた場所のことである","目印は見つけるのが難しい","自由の女神像は有名ではない"]},{en:"The moon landing in 1969 was a landmark achievement in human history.",ja:"1969年の月面着陸は人類の歴史における画期的な成就であった。",wrong:["画期的な成就とは重要ではないことである","月面着陸は歴史的な出来事ではない","画期的な出来事は人類を進歩させない"]},{en:"The landmark court decision changed the legal landscape of the country.",ja:"その画期的な裁判所の決定は国の法的状況を変えた。",wrong:["画期的な決定は影響力がない","裁判所の決定は法律を変えることができない","画期的とは重要ではないことを意味する"]}]},{word:"latent",meaning:"潜在的な",example:"The disease can remain latent for years.",category:"science",difficulty:5,examples:[{en:"His latent talent for music was discovered when he took piano lessons.",ja:"彼のピアノレッスンを受けたときに、音楽への潜在的な才能が発見された。",wrong:["潜在的とは明らかに見える才能のことである","潜在的な才能は発見されることはない","潜在能力は存在しない"]},{en:"The disease remained latent for years before showing any symptoms.",ja:"その病気は症状を示す前に何年も潜在的なままであった。",wrong:["潜在的とは症状が明らかに見えることである","潜在的な病気は治療する必要がない","症状のない病気は存在しない"]},{en:"Social tensions that had been latent erupted into conflict during the election.",ja:"潜在的であった社会的緊張は選挙中に紛争に爆発した。",wrong:["潜在的な緊張は常に表面的である","潜在的な問題は発展することはない","選挙は潜在的な問題を露わにしない"]}]},{word:"lateral",meaning:"横の、側面の",example:"Lateral thinking helps solve problems creatively.",category:"science",difficulty:5,examples:[{en:"In anatomy, lateral movement refers to movement away from the body's midline.",ja:"解剖学では、側方運動は身体の中線から離れた運動を指す。",wrong:["側面とは前後の動きを意味する","側方運動は中線に向かうことである","側面運動は体の動きではない"]},{en:"The lateral pass in rugby moves the ball sideways across the field.",ja:"ラグビーの側方パスはボールをフィールド全体で横に動かす。",wrong:["側方パスとは前方に投げることである","側面パスは規則違反である","側方パスはサッカーのみで使用される"]},{en:"She received a lateral promotion, moving to a different department at the same level.",ja:"彼女は側方配置転換を受け、同じレベルで異なる部門に移った。",wrong:["側方配置転換とは昇進することである","側方異動は降格を意味する","異なる部門への移動は昇進と同じである"]}]},{word:"launch",meaning:"発売する、打ち上げる",example:"The company launched its new product line.",category:"technology",difficulty:3,examples:[{en:"The company decided to launch a new product line to attract younger customers.",ja:"その会社は若い顧客を引き付けるために新しい製品ラインを発売することを決定した。",wrong:["発売とは製品を中止することである","発売は顧客を遠ざける","新製品は発売される必要がない"]},{en:"NASA will launch the satellite into orbit next month.",ja:"NASAは来月衛星を軌道に打ち上げる予定である。",wrong:["打ち上げとは衛星を地上に保つことである","衛星は軌道に打ち上げられることはない","打ち上げは宇宙活動ではない"]},{en:"The politician launched a new campaign to increase voter support.",ja:"その政治家は投票者の支持を増やすために新しいキャンペーンを開始した。",wrong:["開始とは計画を停止することである","キャンペーンの開始は支持を減らす","政治家はキャンペーンを開始しない"]}]},{word:"legitimate",meaning:"合法的な、正当な",example:"The workers have legitimate concerns about safety.",category:"society",difficulty:4,examples:[{en:"The company's business practices are legitimate and comply with all regulations.",ja:"その会社のビジネス慣行は合法的であり、すべての規制に準拠している。",wrong:["合法的とは違法であることを意味する","合法的なビジネスは規制に従わない","正当性は法律と関係がない"]},{en:"He has a legitimate reason for being late to the meeting.",ja:"彼は会議に遅刻することについて正当な理由を持っている。",wrong:["正当とは理由がないことである","正当な理由は存在しない","遅刻は正当な理由を示さない"]},{en:"The government acknowledged the legitimacy of the citizens' concerns.",ja:"その政府は市民の懸念の正当性を認めた。",wrong:["正当性とは有効でないことである","懸念の正当性は認識されることはない","政府は市民の懸念を認めない"]}]},{word:"levy",meaning:"課税する、徴収する",example:"A new tax was levied on luxury goods.",category:"society",difficulty:5,examples:[{en:"The government plans to levy a new tax on imported goods.",ja:"その政府は輸入品に新しい税を課す予定である。",wrong:["課税とは税を廃止することである","課税は収入を減らす","政府は税を課すことができない"]},{en:"The municipality decided to levy a fee on parking to reduce congestion downtown.",ja:"その自治体は市街地の混雑を減らすために駐車料金を徴収することを決定した。",wrong:["徴収とは料金を提供することである","駐車料金は混雑を増やす","料金を徴収することは公共サービスではない"]},{en:"Insurance companies can levy additional charges for high-risk clients.",ja:"保険会社は高リスク顧客に対して追加料金を課すことができる。",wrong:["課すとは割引を提供することである","追加料金は高リスク顧客には適用されない","課すことは商業的慣行ではない"]}]},{word:"liable",meaning:"責任がある、〜しがちな",example:"The manufacturer may be liable for damages.",category:"society",difficulty:4,examples:[{en:"The company is liable for any injuries that occur on its property.",ja:"その会社は自分の敷地内で発生したすべての怪我に対して責任がある。",wrong:["責任があるとは責任がないことである","会社は顧客の怪我に対して責任がない","法的責任は存在しない"]},{en:"He is liable to make mistakes when working under pressure.",ja:"彼はプレッシャーの下で仕事をする際に間違いをしやすい。",wrong:["しやすいとは間違いをしないことである","プレッシャーは間違いを減らす","人はプレッシャーの下で完璧である"]},{en:"Parents are legally liable for the actions of their minor children.",ja:"親は未成年の子どもの行動に対して法的責任がある。",wrong:["責任があるとは責任がないことである","親は子どもの行動に責任がない","未成年の行動は親に影響を与えない"]}]},{word:"liberal",meaning:"自由主義の、寛大な",example:"The university has a liberal admissions policy.",category:"society",difficulty:3,examples:[{en:"A liberal education exposes students to a wide range of subjects and ideas.",ja:"自由主義的教育は学生を様々な科目と思想に触れさせる。",wrong:["自由主義的とは制限的であることを意味する","自由主義的教育は限定的である","様々な思想への露出は良い教育ではない"]},{en:"She is known for her liberal attitudes toward social issues.",ja:"彼女は社会問題に対して寛大な態度で知られている。",wrong:["寛大とは厳しい態度である","寛大な態度は社会問題と関係がない","社会問題への寛大さは存在しない"]},{en:"The foundation made liberal donations to various charitable organizations.",ja:"その財団は様々な慈善団体に寛大な寄付をした。",wrong:["寛大な寄付とは少量の寄付である","寛大な寄付は慈善活動ではない","財団は多額の寄付をしない"]}]},{word:"likewise",meaning:"同様に",example:"He voted in favour, and his colleagues did likewise.",category:"society",difficulty:3,examples:[{en:"She enjoys hiking, and likewise, her sister loves outdoor activities.",ja:"彼女はハイキングを楽しみ、同様に彼女の妹も屋外活動を愛している。",wrong:["同様にとは異なることを意味する","同様にとは対立を示す","同様にとは比較しないことである"]},{en:"The first chapter was interesting, and likewise, the second chapter kept me engaged.",ja:"最初の章は興味深く、同様に2番目の章も私を魅了した。",wrong:["同様にとは対比を意味する","同様にとは異なる状況を示す","同様にとは類似性を示さない"]},{en:"John is talented in mathematics, and likewise, his brother excels in science.",ja:"ジョンは数学に才能があり、同様に彼の兄は科学で優れている。",wrong:["同様にとは反対であることを意味する","同様にとは相違を示す","同様にとは類似の能力を意味しない"]}]},{word:"literacy",meaning:"読み書き能力",example:"Improving digital literacy is a priority in education.",category:"society",difficulty:3,examples:[{en:"Improving literacy rates is essential for economic development.",ja:"識字率を向上させることは経済発展に不可欠です。",wrong:["読書を楽しむ能力","本を速く読む技術","図書館を使う知識"]},{en:"Digital literacy has become as important as traditional reading and writing skills.",ja:"デジタル・リテラシーは従来の読み書き能力と同じくらい重要になっています。",wrong:["コンピュータを操作する能力","インターネットを使う技術","プログラミングの知識"]},{en:"The program focuses on adult literacy in rural communities.",ja:"このプログラムは農村地域の成人識字教育に焦点を当てています。",wrong:["大人の読書習慣の向上","農村部の図書館建設","成人教育全般"]}]},{word:"lofty",meaning:"高い、崇高な",example:"The organisation has lofty ideals.",category:"society",difficulty:4,examples:[{en:"She has lofty ambitions to become a renowned scientist.",ja:"彼女は著名な科学者になるという崇高な野心を持っています。",wrong:["背が高い野心","上空の野心","建物のような野心"]},{en:"The lofty mountains stretched across the horizon.",ja:"高い山々が地平線に沿って広がっていました。",wrong:["聖なる山々","尊敬される山々","価値のある山々"]},{en:"Despite his lofty goals, he remained humble and grounded.",ja:"崇高な目標にもかかわらず、彼は謙虚で現実的なままでした。",wrong:["高度な目標","空中の目標","上層階の目標"]}]},{word:"lucrative",meaning:"儲かる",example:"Real estate can be a lucrative investment.",category:"current",difficulty:4,examples:[{en:"Technology startups often pursue lucrative opportunities in the market.",ja:"テクノロジースタートアップはしばしば市場で儲かる機会を追求しています。",wrong:["光る機会","明るい機会","幸運な機会"]},{en:"She turned down a lucrative job offer to pursue her passion.",ja:"彼女は情熱を追求するために、儲かる仕事のオファーを断りました。",wrong:["美しい仕事のオファー","輝く仕事のオファー","人気のある仕事のオファー"]},{en:"The pharmaceutical industry is known for its lucrative contracts.",ja:"製薬業界は儲かる契約で知られています。",wrong:["光の契約","豊富な契約","有益な契約"]}]},{word:"magnitude",meaning:"規模、重大さ",example:"They underestimated the magnitude of the disaster.",category:"science",difficulty:4,examples:[{en:"The magnitude of the earthquake was measured at 7.5 on the Richter scale.",ja:"地震の規模はリヒタースケールで7.5と測定されました。",wrong:["地震の大きさ","地震の強さ","地震の深さ"]},{en:"We didn't fully understand the magnitude of the problem until it was too late.",ja:"問題の重大さを完全に理解したのは手遅れになってからでした。",wrong:["問題の原因","問題の影響","問題の理由"]},{en:"The magnitude of her achievement cannot be overstated.",ja:"彼女の成果の重大さは過大評価することはできません。",wrong:["彼女の成果の大きさ","彼女の成果の規模","彼女の成果の価値"]}]},{word:"mainstream",meaning:"主流の",example:"Electric vehicles are entering the mainstream.",category:"current",difficulty:3,examples:[{en:"Electric vehicles are becoming increasingly mainstream in developed countries.",ja:"電動車は先進国で主流になりつつあります。",wrong:["メイン川","川の流れ","主要な流れ"]},{en:"The artist's unconventional work eventually entered the mainstream.",ja:"アーティストの型破りな作品は最終的に主流に入りました。",wrong:["メイン通り","主要な通り","大きな通り"]},{en:"Mainstream media outlets reported on the scandal extensively.",ja:"主流メディアはスキャンダルについて広範に報道しました。",wrong:["流行のメディア","流れのメディア","普通のメディア"]}]},{word:"malfunction",meaning:"故障する",example:"The engine malfunctioned during the flight.",category:"technology",difficulty:3,examples:[{en:"The aircraft's engine began to malfunction during the flight.",ja:"飛行中に航空機のエンジンが故障し始めました。",wrong:["不正に動く","悪く動く","機能を失う"]},{en:"A software malfunction caused the entire system to crash.",ja:"ソフトウェアの故障がシステム全体をクラッシュさせました。",wrong:["悪いソフトウェア","間違ったソフトウェア","壊れたソフトウェア"]},{en:"If the device continues to malfunction, we will need to replace it.",ja:"デバイスが故障し続ける場合は、交換する必要があります。",wrong:["悪く機能する","正しく機能しない","動作しない"]}]},{word:"mandate",meaning:"命令する、権限",example:"The law mandates equal pay for equal work.",category:"society",difficulty:4,examples:[{en:"The government has a mandate to protect its citizens.",ja:"政府は市民を保護する権限を持っています。",wrong:["命令を与える義務","指示する力","支配する権利"]},{en:"The elected official received a clear mandate from the voters.",ja:"選ばれた公務員は有権者から明確な権限を受けました。",wrong:["投票者からの命令","有権者からの指示","国民からの義務"]},{en:"The law mandates that all children attend school until age sixteen.",ja:"法律はすべての子どもが16歳まで学校に通うことを義務付けています。",wrong:["法律が強制する","法律が要求する","法律が許可する"]}]},{word:"manifest",meaning:"明白な、表れる",example:"Symptoms may manifest weeks after infection.",category:"science",difficulty:5,examples:[{en:"Her talent was manifest from an early age.",ja:"彼女の才能は幼い頃から明白でした。",wrong:["見える","示される","現れる"]},{en:"The symptoms of the disease began to manifest within a week.",ja:"病気の症状は1週間以内に表れ始めました。",wrong:["現実になった","生じた","起こった"]},{en:"His fears were manifest in his nervous behavior.",ja:"彼の恐れは神経過敏な行動に明白に表れていました。",wrong:["彼の恐れが見える","彼の恐れが知られている","彼の恐れが感じられる"]}]},{word:"manipulate",meaning:"操る",example:"The data was manipulated to hide losses.",category:"society",difficulty:3,examples:[{en:"She tried to manipulate the situation to her advantage.",ja:"彼女は自分の有利になるように状況を操りました。",wrong:["状況を手で扱う","状況を変える","状況を管理する"]},{en:"The politician manipulated public opinion through misleading statements.",ja:"政治家は誤解を招く発言を通じて世論を操りました。",wrong:["世論を影響する","世論を導く","世論を変える"]},{en:"He learned to manipulate the controls of the machine.",ja:"彼は機械の制御を操る方法を学びました。",wrong:["機械を直す","機械を使う","機械を動かす"]}]},{word:"manuscript",meaning:"原稿",example:"The author submitted the manuscript to the publisher.",category:"culture",difficulty:4,examples:[{en:"The author submitted her manuscript to the publisher last month.",ja:"著者は先月出版社に原稿を提出しました。",wrong:["手書きの本","手書きのページ","手書きのテキスト"]},{en:"The ancient manuscript was carefully preserved in the library.",ja:"古い原稿は図書館に慎重に保存されていました。",wrong:["古い本","古い手書き","古い書類"]},{en:"He spent years researching historical manuscripts for his book.",ja:"彼は本のために何年も歴史的原稿を研究するのに費やしました。",wrong:["歴史的な本","歴史的な文書","歴史的な記録"]}]},{word:"marine",meaning:"海の",example:"Marine pollution threatens ocean ecosystems.",category:"science",difficulty:3,examples:[{en:"The marine ecosystem is threatened by pollution and climate change.",ja:"海の生態系は汚染と気候変動によって脅かされています。",wrong:["軍隊の生態系","水手の生態系","船員の生態系"]},{en:"She works as a marine biologist studying coral reefs.",ja:"彼女は珊瑚礁を研究する海洋生物学者として働いています。",wrong:["船の生物学者","軍隊の生物学者","水の生物学者"]},{en:"The country has a strong marine industry with fishing and shipping.",ja:"その国は漁業と海運を持つ強い海洋産業を持っています。",wrong:["軍隊の産業","船員の産業","水上の産業"]}]},{word:"mature",meaning:"成熟した",example:"She showed mature judgement beyond her years.",category:"society",difficulty:3,examples:[{en:"Children gradually mature as they grow older and gain more experience.",ja:"子どもたちは年を重ねて経験を積むにつれて徐々に成熟します。",wrong:["大人になる","完成する","発展する"]},{en:"The wine needs to mature for several years before it reaches its peak flavor.",ja:"ワインはピークの風味に達するまで数年間成熟する必要があります。",wrong:["古くなる","新しくなる","変わる"]},{en:"Her mature approach to the problem impressed everyone in the meeting.",ja:"問題に対する彼女の成熟したアプローチは会議の誰もが感心しました。",wrong:["大人っぽいアプローチ","完成したアプローチ","経験豊かなアプローチ"]}]},{word:"mediate",meaning:"仲介する",example:"A neutral party was called to mediate the dispute.",category:"society",difficulty:4,examples:[{en:"A neutral third party agreed to mediate the dispute between the two companies.",ja:"中立的な第三者が2つの企業間の紛争を仲介することに同意しました。",wrong:["紛争について考える","紛争を理解する","紛争に対処する"]},{en:"The UN mediates peace talks between conflicting nations.",ja:"国連は紛争中の国々の間の平和談判を仲介しています。",wrong:["平和について話し合う","平和を提案する","平和を促進する"]},{en:"She will mediate between the two groups to find a compromise.",ja:"彼女は妥協案を見つけるために2つのグループの間を仲介します。",wrong:["2つのグループを管理する","2つのグループを統制する","2つのグループを指導する"]}]},{word:"medieval",meaning:"中世の",example:"The castle dates back to medieval times.",category:"history",difficulty:3,examples:[{en:"The medieval castle still stands at the center of the old town.",ja:"中世の城は旧市街の中心にまだ立っています。",wrong:["中程度の城","中央の城","中年の城"]},{en:"Medieval scholars made significant contributions to philosophy and science.",ja:"中世の学者は哲学と科学に大きな貢献をしました。",wrong:["中程度の学者","中央の学者","真ん中の学者"]},{en:"The medieval period was characterized by feudalism and the dominance of the Church.",ja:"中世はシステムと教会の支配を特徴としていました。",wrong:["中程度の時代","中央の時代","中間の時代"]}]},{word:"memoir",meaning:"回想録",example:"She published a memoir about her childhood.",category:"culture",difficulty:4,examples:[{en:"She published a memoir describing her life during World War II.",ja:"彼女は第二次世界大戦中の彼女の人生を説明する回想録を出版しました。",wrong:["日記","伝記","自叙伝"]},{en:"The famous actor's memoir became a bestseller.",ja:"有名な俳優の回想録はベストセラーになりました。",wrong:["日記本","伝記本","物語本"]},{en:"In his memoir, he reflects on his career achievements and personal struggles.",ja:"彼の回想録の中で、彼はキャリアの成果と個人的な苦労を反映しています。",wrong:["日記で","伝記で","自叙伝で"]}]},{word:"merge",meaning:"合併する",example:"The two banks merged to form a larger institution.",category:"current",difficulty:3,examples:[{en:"The two companies decided to merge their operations.",ja:"その2つの会社は事業を合併することに決めた。",wrong:["分離する","競争する","解散する"]},{en:"The rivers merge into a single stream.",ja:"その川は1本の流れに合併する。",wrong:["分岐する","蒸発する","氾濫する"]},{en:"We need to merge these two documents into one.",ja:"これら2つの文書を1つに合併する必要がある。",wrong:["削除する","複製する","翻訳する"]}]},{word:"metabolism",meaning:"代謝",example:"Exercise boosts your metabolism.",category:"science",difficulty:4,examples:[{en:"A fast metabolism helps burn calories quickly.",ja:"速い代謝はカロリーをすばやく燃焼するのに役立つ。",wrong:["呼吸","消化","成長"]},{en:"Exercise can increase your metabolism.",ja:"運動はあなたの代謝を増加させることができる。",wrong:["筋肉","免疫力","血圧"]},{en:"Plant metabolism differs from animal metabolism.",ja:"植物の代謝は動物の代謝と異なる。",wrong:["進化","行動","寿命"]}]},{word:"metaphor",meaning:"隠喩",example:"Life is often described as a journey — a common metaphor.",category:"culture",difficulty:4,examples:[{en:"The poem uses the metaphor of a journey to describe life.",ja:"この詩は人生を説明するために旅の隠喩を使用している。",wrong:["比較","象徴","説明"]},{en:"Time is a metaphor for money in business.",ja:"ビジネスでは時間はお金の隠喩である。",wrong:["価値","資源","測定"]},{en:"Understanding metaphors helps improve reading comprehension.",ja:"隠喩を理解することは読解力の向上に役立つ。",wrong:["文法","単語","発音"]}]},{word:"migrate",meaning:"移住する",example:"Birds migrate south for the winter.",category:"science",difficulty:3,examples:[{en:"Birds migrate south for the winter.",ja:"鳥は冬のために南に移住する。",wrong:["冬眠する","産卵する","脱皮する"]},{en:"Many families migrate to the city seeking better opportunities.",ja:"多くの家族がより良い機会を求めて都市に移住する。",wrong:["旅行する","観光する","引っ越しする"]},{en:"The software data will migrate to the new server.",ja:"ソフトウェアデータは新しいサーバーに移住するでしょう。",wrong:["コピーする","削除する","圧縮する"]}]},{word:"militant",meaning:"戦闘的な",example:"Militant groups threaten stability in the region.",category:"current",difficulty:4,examples:[{en:"The activist group took a more militant approach.",ja:"その活動家グループはより戦闘的なアプローチを取った。",wrong:["友好的な","静かな","平和的な"]},{en:"Militant groups can pose a threat to national security.",ja:"戦闘的なグループは国家安全保障に脅威をもたらす可能性がある。",wrong:["商業的な","教育的な","医学的な"]},{en:"She has a militant attitude toward environmental protection.",ja:"彼女は環境保護に対して戦闘的な態度を持っている。",wrong:["無関心な","妥協的な","消極的な"]}]},{word:"mimic",meaning:"模倣する",example:"Some insects mimic the appearance of leaves.",category:"science",difficulty:3,examples:[{en:"Children often mimic the behavior of their parents.",ja:"子どもはしばしば両親の行動を模倣する。",wrong:["批判する","教える","無視する"]},{en:"The actor can mimic different accents convincingly.",ja:"その俳優は異なるアクセントを説得力をもって模倣できる。",wrong:["翻訳する","作成する","変更する"]},{en:"Some animals mimic the appearance of dangerous species.",ja:"一部の動物は危険な種の外観を模倣する。",wrong:["変身する","逃げる","隠れる"]}]},{word:"ministry",meaning:"省、省庁",example:"The Ministry of Education announced new guidelines.",category:"society",difficulty:3,examples:[{en:"The Ministry of Education sets curriculum standards.",ja:"教育省はカリキュラム基準を設定している。",wrong:["大学","学校","図書館"]},{en:"She works for the Ministry of Health.",ja:"彼女は厚生労働省で働いている。",wrong:["病院","クリニック","薬局"]},{en:"The Foreign Ministry handles diplomatic relations.",ja:"外務省は外交関係を処理する。",wrong:["大使館","航空会社","銀行"]}]},{word:"modest",meaning:"控えめな、ささやかな",example:"He comes from a modest background.",category:"society",difficulty:3,examples:[{en:"Despite his success, he remained modest and humble.",ja:"彼の成功にもかかわらず、彼は控えめで謙虚なままであった。",wrong:["傲慢な","虚栄心の強い","自慢する"]},{en:"They live in a modest house on the outskirts of town.",ja:"彼らは町の郊外にあるささやかな家に住んでいる。",wrong:["豪華な","広大な","高級な"]},{en:"The company made modest profits this quarter.",ja:"その会社は今四半期に控えめな利益を上げた。",wrong:["莫大な","破産的な","損失的な"]}]},{word:"modify",meaning:"修正する",example:"The plan was modified to reduce costs.",category:"technology",difficulty:3,examples:[{en:"We need to modify the contract before signing.",ja:"署名する前に契約を修正する必要がある。",wrong:["破棄する","署名する","承認する"]},{en:"The engineer modified the design to improve efficiency.",ja:"エンジニアは効率を改善するために設計を修正した。",wrong:["複製する","分析する","テストする"]},{en:"You can modify your diet to include more vegetables.",ja:"より多くの野菜を含めるために食事を修正できる。",wrong:["中止する","強化する","禁止する"]}]},{word:"momentum",meaning:"勢い",example:"The reform movement gained momentum.",category:"current",difficulty:4,examples:[{en:"The team has momentum after winning three games in a row.",ja:"チームは3試合連続で勝利した後、勢いを持っている。",wrong:["疲労","停滞","敗北"]},{en:"The political movement is gaining momentum.",ja:"その政治運動は勢いを増している。",wrong:["衰退している","沈静化している","分裂している"]},{en:"Once you start exercising, you build momentum.",ja:"運動を始めると、勢いがつく。",wrong:["怠け癖","無関心","停止"]}]},{word:"monopoly",meaning:"独占",example:"The company has a monopoly on the market.",category:"current",difficulty:4,examples:[{en:"The company holds a monopoly on the market.",ja:"その会社は市場を独占している。",wrong:["共有","競争","分散"]},{en:"Governments often regulate monopolies to protect consumers.",ja:"政府は消費者を保護するために独占を規制することが多い。",wrong:["促進する","支援する","奨励する"]},{en:"Breaking up the monopoly created more competition.",ja:"独占を分割することでより多くの競争が生まれた。",wrong:["統合","統一","合併"]}]},{word:"morale",meaning:"士気",example:"Team morale was boosted by the victory.",category:"society",difficulty:4,examples:[{en:"The team's morale was low after the defeat.",ja:"その敗北の後、チームの士気は低かった。",wrong:["得点","スキル","体力"]},{en:"Good management can boost employee morale.",ja:"良い管理は従業員の士気を高めることができる。",wrong:["給料","福利厚生","休暇"]},{en:"The soldiers' morale remained high despite the difficult conditions.",ja:"困難な条件にもかかわらず、兵士の士気は高いままであった。",wrong:["装備","訓練","武器"]}]},{word:"mortgage",meaning:"住宅ローン",example:"They took out a mortgage to buy their first home.",category:"society",difficulty:3,examples:[{en:"They took out a 30-year mortgage to buy the house.",ja:"彼らは家を購入するために30年の住宅ローンを組んだ。",wrong:["給料","奨学金","ビジネスローン"]},{en:"The mortgage interest rates have increased.",ja:"住宅ローン金利が上昇した。",wrong:["家賃","税金","保険料"]},{en:"It took 20 years to pay off the mortgage.",ja:"住宅ローンを返済するのに20年かかった。",wrong:["給与","債務","クレジットカード"]}]},{word:"municipal",meaning:"市の",example:"The municipal government approved the plan.",category:"society",difficulty:4,examples:[{en:"The municipal government is responsible for local services.",ja:"市政府はローカルサービスの責任がある。",wrong:["国家的な","州の","連邦の"]},{en:"The municipal election will be held next month.",ja:"市選挙は来月開催される。",wrong:["大統領選挙","州選挙","国民投票"]},{en:"Municipal bonds are often used to fund city projects.",ja:"市債は都市プロジェクトの資金に使用されることが多い。",wrong:["国債","株式","預金"]}]},{word:"mutual",meaning:"相互の",example:"The agreement was based on mutual respect.",category:"society",difficulty:3,examples:[{en:"They have mutual respect for each other.",ja:"彼らは互いに相互の尊重を持っている。",wrong:["一方的な","競争的な","敵対的な"]},{en:"The agreement was mutually beneficial for both parties.",ja:"その協定は両者にとって相互に有益であった。",wrong:["片方だけに有利","不均等な","不公正な"]},{en:"Mutual understanding is important in relationships.",ja:"相互の理解は関係において重要である。",wrong:["誤解","無関心","隠蔽"]}]},{word:"negotiate",meaning:"交渉する",example:"The unions negotiated a pay rise.",category:"society",difficulty:3,examples:[{en:"The two countries will negotiate a peace treaty.",ja:"2つの国は平和条約について交渉するでしょう。",wrong:["2つの国は平和条約を否定するでしょう。","2つの国は平和条約を無視するでしょう。","2つの国は平和条約を破棄するでしょう。"]},{en:"She negotiated a better salary with her employer.",ja:"彼女は雇用主と給料についてより良い条件で交渉した。",wrong:["彼女は雇用主から給料を盗んだ。","彼女は雇用主に給料を要求した。","彼女は雇用主と給料について議論した。"]},{en:"The driver had to negotiate the mountain pass carefully.",ja:"運転手は慎重に山道を通過しなければならなかった。",wrong:["運転手は山道を爆発させなければならなかった。","運転手は山道を建設しなければならなかった。","運転手は山道を販売しなければならなかった。"]}]},{word:"neutral",meaning:"中立の",example:"Switzerland remained neutral during the war.",category:"history",difficulty:3,examples:[{en:"Switzerland remained neutral during the war.",ja:"スイスは戦争中中立を保った。",wrong:["スイスは戦争中に参加した。","スイスは戦争中に敵対した。","スイスは戦争中に味方した。"]},{en:"He took a neutral stance on the controversial issue.",ja:"彼は論争の多い問題について中立的な立場を取った。",wrong:["彼は論争の多い問題について攻撃的な立場を取った。","彼は論争の多い問題について支持的な立場を取った。","彼は論争の多い問題について反対の立場を取った。"]},{en:"The neutral color of the walls makes the room feel calm.",ja:"壁の中立的な色は部屋を落ち着いた感じにする。",wrong:["壁の明るい色は部屋を落ち着いた感じにする。","壁の暗い色は部屋を興奮させる。","壁の派手な色は部屋を静かにする。"]}]},{word:"nominal",meaning:"名目上の",example:"The fee is purely nominal.",category:"society",difficulty:5,examples:[{en:"He was the nominal head of the company but had no real power.",ja:"彼は会社の名目上の責任者でしたが、実際の権力はありませんでした。",wrong:["彼は会社の実際の責任者でしたが、名目上の権力はありませんでした。","彼は会社の完全な責任者でした。","彼は会社に全く関係がありませんでした。"]},{en:"The nominal value of the stock is $10 per share.",ja:"その株の名目値は1株あたり10ドルです。",wrong:["その株の実際の価値は1株あたり10ドルです。","その株の最高値は1株あたり10ドルです。","その株の最低値は1株あたり10ドルです。"]},{en:"There is a nominal fee of $5 for the service.",ja:"そのサービスには名目上5ドルの料金があります。",wrong:["そのサービスには非常に高い5ドルの料金があります。","そのサービスは完全に無料です。","そのサービスには隠れた5ドルの料金があります。"]}]},{word:"norm",meaning:"基準、規範",example:"Working from home has become the new norm.",category:"current",difficulty:3,examples:[{en:"It is the norm in Japanese culture to remove shoes when entering a home.",ja:"日本文化では家に入るときに靴を脱ぐことは一般的な規範です。",wrong:["日本文化では家に入るときに靴を脱がないことは一般的な規範です。","日本文化では靴を脱ぐことは禁止されています。","日本文化では靴を脱ぐことは不敬です。"]},{en:"Working 8 hours a day is the accepted norm in most companies.",ja:"1日8時間働くことはほとんどの会社で受け入れられている規範です。",wrong:["1日12時間働くことはほとんどの会社で受け入れられている規範です。","1日8時間働くことはほとんどの会社で禁止されています。","1日8時間働くことはほとんどの会社で異常です。"]},{en:"The norm in this office is to arrive by 9 AM.",ja:"このオフィスの規範は午前9時までに到着することです。",wrong:["このオフィスの規範は午前10時までに到着することです。","このオフィスの規範は遅刻することです。","このオフィスの規範は欠席することです。"]}]},{word:"notable",meaning:"注目すべき",example:"There has been a notable increase in sales.",category:"current",difficulty:3,examples:[{en:"Her notable achievement was winning the Nobel Prize.",ja:"彼女の注目すべき成果はノーベル賞を受賞したことです。",wrong:["彼女の注目すべき失敗はノーベル賞を受賞したことです。","彼女の取るに足らない成果はノーベル賞を受賞したことです。","彼女の隠れた成果はノーベル賞を受賞しなかったことです。"]},{en:"There are several notable differences between the two products.",ja:"2つの製品の間にはいくつかの注目すべき違いがあります。",wrong:["2つの製品の間には違いはありません。","2つの製品の間には隠れた違いがあります。","2つの製品の間には共通点があります。"]},{en:"The most notable feature of this car is its fuel efficiency.",ja:"この車の最も注目すべき特徴は燃料効率です。",wrong:["この車の最も注目すべき欠陥は燃料効率です。","この車の最も些細な特徴は燃料効率です。","この車の最も隠れた特徴は重さです。"]}]},{word:"notion",meaning:"概念、考え",example:"The notion of equality has evolved over time.",category:"society",difficulty:4,examples:[{en:"He had a vague notion that something was wrong.",ja:"彼は何か間違っているという漠然とした概念を持っていました。",wrong:["彼は何か間違っているという明確な知識を持っていました。","彼は何か間違っているという確実な証拠を持っていました。","彼は何か間違っているということを知りませんでした。"]},{en:"The notion of equality is fundamental to democracy.",ja:"平等の概念は民主主義の基本です。",wrong:["差別の概念は民主主義の基本です。","不平等の概念は民主主義の基本です。","支配の概念は民主主義の基本です。"]},{en:"I dismissed the notion that he was guilty.",ja:"彼が有罪であるという考えを私は棄却しました。",wrong:["彼が無罪であるという考えを私は棄却しました。","彼が有罪であるという考えを私は受け入れました。","彼が有罪であるという考えを私は完全に信じました。"]}]},{word:"notorious",meaning:"悪名高い",example:"The road is notorious for accidents.",category:"society",difficulty:3,examples:[{en:"He became notorious for his criminal activities.",ja:"彼は犯罪活動で悪名高くなりました。",wrong:["彼は犯罪活動で有名になりました。","彼は善行で悪名高くなりました。","彼は社会貢献で悪名高くなりました。"]},{en:"The city is notorious for its pollution problem.",ja:"その都市は汚染問題で悪名高いです。",wrong:["その都市は清潔さで悪名高いです。","その都市は汚染問題で有名です。","その都市は環境保全で悪名高いです。"]},{en:"The restaurant is notorious for its slow service.",ja:"そのレストランは遅いサービスで悪名高いです。",wrong:["そのレストランは速いサービスで悪名高いです。","そのレストランは遅いサービスで有名です。","そのレストランは効率的なサービスで悪名高いです。"]}]},{word:"nourish",meaning:"栄養を与える",example:"A balanced diet nourishes the body.",category:"science",difficulty:3,examples:[{en:"A healthy diet nourishes the body.",ja:"健康的な食事は体に栄養を与えます。",wrong:["健康的な食事は体に害を与えます。","不健康な食事は体に栄養を与えます。","健康的な食事は体を弱くします。"]},{en:"She nourished her friendship by spending time together.",ja:"彼女は一緒に時間を過ごすことで友情に栄養を与えました。",wrong:["彼女は一緒に時間を過ごすことで友情を壊しました。","彼女は友達を避けることで友情に栄養を与えました。","彼女は口論することで友情に栄養を与えました。"]},{en:"Reading nourishes the mind with knowledge.",ja:"読書は心に知識という栄養を与えます。",wrong:["読書は心を無知にさせます。","テレビ視聴は心に知識という栄養を与えます。","読書は心を退化させます。"]}]},{word:"novel",meaning:"斬新な",example:"The researcher proposed a novel approach.",category:"science",difficulty:3,examples:[{en:"Her novel approach to problem-solving impressed everyone.",ja:"彼女の問題解決への斬新なアプローチは誰もが感心しました。",wrong:["彼女の古い方法は誰もが感心しました。","彼女の問題解決への斬新なアプローチは誰も気付きませんでした。","彼女の奇抜な方法は失敗しました。"]},{en:"The technology represents a novel breakthrough in medical research.",ja:"この技術は医学研究における斬新な突破口を表しています。",wrong:["この技術は医学研究における古い方法を表しています。","この技術は医学研究における障害を表しています。","この技術は医学研究において何もしていません。"]},{en:"I enjoyed reading that novel about ancient Rome.",ja:"古代ローマについてのその小説を読むことが楽しかったです。",wrong:["現代についてのその小説を読むことが楽しかったです。","私はその歴史書を読むことが楽しかったです。","その小説はつまらなかったです。"]}]},{word:"numerous",meaning:"多数の",example:"Numerous studies confirm the benefits of exercise.",category:"science",difficulty:3,examples:[{en:"There are numerous reasons to visit Japan.",ja:"日本を訪問する多数の理由があります。",wrong:["日本を訪問する理由はほとんどありません。","日本を訪問する唯一の理由があります。","日本を訪問する理由はありません。"]},{en:"The company faced numerous challenges during the expansion.",ja:"その会社は拡張期間中に多数の課題に直面しました。",wrong:["その会社は拡張期間中に課題はありませんでした。","その会社は拡張期間中に1つの課題に直面しました。","その会社は拡張期間中に困難がありませんでした。"]},{en:"She received numerous compliments on her presentation.",ja:"彼女はプレゼンテーションについて多数の褒め言葉を受けました。",wrong:["彼女はプレゼンテーションについて批判を受けました。","彼女はプレゼンテーションについて褒め言葉を受けませんでした。","彼女はプレゼンテーションについて1つだけ褒め言葉を受けました。"]}]},{word:"oblige",meaning:"義務づける",example:"Employees are obliged to follow safety procedures.",category:"society",difficulty:4,examples:[{en:"The law obliges employers to provide safe working conditions.",ja:"法律は雇用主に安全な労働条件を提供することを義務づけます。",wrong:["法律は雇用主に危険な労働条件を提供することを許可します。","法律は雇用主に安全な労働条件を提供することを禁止します。","法律は雇用主に何もする必要はありません。"]},{en:"I would be happy to oblige your request.",ja:"あなたのリクエストに応じることができてうれしいです。",wrong:["あなたのリクエストを拒否することができてうれしいです。","あなたのリクエストに反対することができてうれしいです。","あなたのリクエストを無視することができてうれしいです。"]},{en:"She obliged by helping us move the furniture.",ja:"彼女は家具の移動を手伝うことで応じました。",wrong:["彼女は家具の移動を拒否することで応じました。","彼女は家具の移動を手伝わないことで応じました。","彼女は私たちを邪魔することで応じました。"]}]},{word:"obscure",meaning:"不明瞭な、隠す",example:"The meaning of the poem is deliberately obscure.",category:"culture",difficulty:4,examples:[{en:"The meaning of the ancient text is obscure.",ja:"古代のテキストの意味は不明瞭です。",wrong:["古代のテキストの意味は非常に明確です。","古代のテキストの意味は簡単に理解できます。","古代のテキストの意味は有名です。"]},{en:"The trees obscured our view of the mountains.",ja:"木々は山への私たちの景色を隠しました。",wrong:["木々は山をより見えやすくしました。","木々は山へのアクセスを提供しました。","木々は山を明確に見せました。"]},{en:"He is an obscure artist from the 19th century.",ja:"彼は19世紀の無名の芸術家です。",wrong:["彼は19世紀の非常に有名な芸術家です。","彼は19世紀の有名な詩人です。","彼は現代の有名な芸術家です。"]}]},{word:"obsess",meaning:"取り憑く",example:"He is obsessed with perfection.",category:"society",difficulty:3,examples:[{en:"He became obsessed with collecting vintage cars.",ja:"彼はクラシックカーの収集に取り憑かれました。",wrong:["彼はクラシックカーの販売に取り憑かれました。","彼はクラシックカーに興味がありません。","彼はクラシックカーを無視しました。"]},{en:"She obsesses over the details of her work.",ja:"彼女は自分の仕事の詳細に取り憑かれています。",wrong:["彼女は自分の仕事を無視しています。","彼女は詳細を気にしていません。","彼女は仕事を完全に忘れています。"]},{en:"The fans obsessed over every detail of the celebrity's life.",ja:"ファンは有名人の人生のあらゆる詳細に取り憑かれました。",wrong:["ファンは有名人に全く興味がありません。","ファンは有名人の詳細を無視しました。","ファンは有名人を嫌いました。"]}]},{word:"obsolete",meaning:"時代遅れの",example:"Floppy disks have become obsolete.",category:"technology",difficulty:3,examples:[{en:"Floppy disks are now obsolete.",ja:"フロッピーディスクは今や時代遅れです。",wrong:["フロッピーディスクは今や最先端です。","フロッピーディスクは今や非常に一般的です。","フロッピーディスクはまだ広く使われています。"]},{en:"The old factory equipment has become obsolete.",ja:"古い工場設備は時代遅れになりました。",wrong:["古い工場設備は最新です。","古い工場設備は非常に効率的です。","古い工場設備はまだ使われています。"]},{en:"Many traditional skills are becoming obsolete.",ja:"多くの伝統的なスキルは時代遅れになりつつあります。",wrong:["多くの伝統的なスキルは非常に必要とされています。","多くの伝統的なスキルは価値が増しています。","多くの伝統的なスキルは流行しています。"]}]},{word:"obstacle",meaning:"障害",example:"Poverty remains a major obstacle to education.",category:"society",difficulty:3,examples:[{en:"Lack of funding is a major obstacle to our project.",ja:"資金不足は私たちのプロジェクトへの大きな障害です。",wrong:["資金の充分さは私たちのプロジェクトへの大きな障害です。","資金は私たちのプロジェクトを助けています。","十分な資金は問題です。"]},{en:"She overcame every obstacle to achieve her dreams.",ja:"彼女は彼女の夢を達成するためにあらゆる障害を克服しました。",wrong:["彼女は障害によって止められました。","彼女は障害を無視しました。","彼女は障害の前に諦めました。"]},{en:"The obstacle course tested the participants' physical abilities.",ja:"障害物競走は参加者の身体能力をテストしました。",wrong:["スムーズなコースは参加者の身体能力をテストしました。","障害物競走は何もテストしていません。","障害物競走は知識をテストしました。"]}]},{word:"offset",meaning:"相殺する",example:"Higher wages offset the rise in living costs.",category:"current",difficulty:4,examples:[{en:"The company offset its carbon emissions by planting trees.",ja:"その企業は木を植えることで炭素排出量を相殺した。",wrong:["その企業は炭素排出量を増やすために木を植えた。","その企業は木を植えることで炭素排出量を倍にした。","その企業は炭素排出量を相殺するために工場を閉鎖した。"]},{en:"Higher sales offset the increased production costs.",ja:"販売額の増加が生産コストの増加を相殺した。",wrong:["販売額の減少が生産コストを増やした。","生産コストの増加が販売額を相殺した。","販売額と生産コストが両方増加した。"]},{en:"The tax credit will offset your tax liability.",ja:"その税額控除はあなたの税務申告額を相殺するだろう。",wrong:["その税額控除はあなたの税務申告額を増やすだろう。","その税額控除はあなたの給料を相殺するだろう。","その税額控除は完全に無効である。"]}]},{word:"ongoing",meaning:"進行中の",example:"Negotiations are ongoing and progress is being made.",category:"society",difficulty:3,examples:[{en:"The investigation is ongoing and should be completed next month.",ja:"その調査は進行中であり、来月完了するはずだ。",wrong:["その調査は完全に終了した。","その調査はまだ開始していない。","その調査は来月開始される。"]},{en:"We have ongoing discussions with our partners about future projects.",ja:"私たちはパートナーとの間で将来のプロジェクトについて進行中の議論を持っている。",wrong:["私たちはパートナーとの議論をすべて終了した。","私たちはパートナーと議論したことがない。","私たちは新しい議論を来週開始する予定だ。"]},{en:"Ongoing maintenance is required to keep the equipment functioning properly.",ja:"機器が適切に機能し続けるには、継続的なメンテナンスが必要です。",wrong:["機器は一度のメンテナンスで永久に動作する。","機器はメンテナンスを必要としない。","機器のメンテナンスはもう完了した。"]}]},{word:"oppress",meaning:"弾圧する",example:"The regime oppressed political opponents.",category:"history",difficulty:4,examples:[{en:"The authoritarian regime oppressed the local population for decades.",ja:"その独裁政権は何十年もの間、地元住民を弾圧した。",wrong:["その独裁政権は地元住民を支援した。","その独裁政権は地元住民に自由を与えた。","その独裁政権は民主的に統治した。"]},{en:"Heavy responsibilities oppressed him emotionally.",ja:"重い責任は彼を感情的に圧迫した。",wrong:["重い責任は彼を幸せにした。","重い責任は彼を解放した。","重い責任は彼を励ました。"]},{en:"The government was accused of oppressing freedom of speech.",ja:"その政府は言論の自由を弾圧していると非難された。",wrong:["その政府は言論の自由を推進していると非難された。","その政府は言論の自由を保護したと非難された。","その政府は民主主義を支援していると非難された。"]}]},{word:"opt",meaning:"選ぶ",example:"More students are opting for online courses.",category:"society",difficulty:3,examples:[{en:"Many employees opted to work from home after the pandemic.",ja:"パンデミック後、多くの従業員は在宅勤務を選ぶことにした。",wrong:["多くの従業員は在宅勤務を拒否した。","多くの従業員は在宅勤務を強制された。","多くの従業員は在宅勤務について決定を下さなかった。"]},{en:"She opted for the cheaper option instead of the premium package.",ja:"彼女はプレミアムパッケージではなく、より安い選択肢を選んだ。",wrong:["彼女はプレミアムパッケージを選んだ。","彼女は最も高い選択肢を選んだ。","彼女は選択について決定を下さなかった。"]},{en:"The student opted out of the field trip.",ja:"その学生は遠足から脱退することを選んだ。",wrong:["その学生は遠足に参加することを選んだ。","その学生は遠足に強制的に参加した。","その学生は遠足に関して決定を下さなかった。"]}]},{word:"optimal",meaning:"最適な",example:"The experiment was conducted under optimal conditions.",category:"science",difficulty:4,examples:[{en:"The optimal temperature for storing wine is around 45 degrees Fahrenheit.",ja:"ワイン保管の最適な温度は華氏約45度である。",wrong:["ワイン保管の最適な温度は華氏100度である。","ワイン保管の最適な温度は華氏0度である。","ワイン保管には特定の温度が必要ない。"]},{en:"We need to find the optimal solution that satisfies all requirements.",ja:"すべての要件を満たす最適なソリューションを見つける必要があります。",wrong:["私たちは最悪のソリューションを見つける必要があります。","私たちは不完全なソリューションを見つける必要があります。","私たちはソリューションについて心配する必要はありません。"]},{en:"Exercise is optimal for maintaining good health.",ja:"運動は良好な健康を維持するために最適である。",wrong:["運動は健康に悪い。","運動は健康の維持には不要である。","運動は最悪の選択肢である。"]}]},{word:"orient",meaning:"方向づける",example:"The programme is oriented towards practical skills.",category:"society",difficulty:4,examples:[{en:"The compass helped orient the hikers in the right direction.",ja:"コンパスはハイカーを正しい方向に方向づけるのに役立った。",wrong:["コンパスはハイカーを間違った方向に方向づけた。","コンパスはハイカーを迷わせた。","コンパスは方向を示さなかった。"]},{en:"The new employee needs time to orient herself with company procedures.",ja:"新しい従業員は会社の手順に慣れるために時間が必要です。",wrong:["新しい従業員はすぐに会社について完全に理解している。","新しい従業員は会社の手順を学ぶ必要がない。","新しい従業員は会社に不適応である。"]},{en:"The building is oriented towards the south to maximize sunlight.",ja:"その建物は日光を最大化するために南向きに方向づけられている。",wrong:["その建物は日光を避けるために北向きに方向づけられている。","その建物は向きの影響を受けない。","その建物は東向きに固定されている。"]}]},{word:"outbreak",meaning:"発生、勃発",example:"An outbreak of flu affected thousands.",category:"science",difficulty:3,examples:[{en:"The outbreak of COVID-19 changed the world in 2020.",ja:"2020年のCOVID-19の発生は世界を変えた。",wrong:["COVID-19の発生は世界に影響を与えなかった。","COVID-19は2021年に発生した。","COVID-19は完全に予防されていた。"]},{en:"Health officials warned of a potential outbreak of flu this winter.",ja:"保健当局はこの冬のインフルエンザの潜在的な勃発について警告した。",wrong:["保健当局はインフルエンザについて警告しなかった。","保健当局はインフルエンザが発生しないと言った。","保健当局はインフルエンザを心配していない。"]},{en:"The sudden outbreak of violence forced the government to declare an emergency.",ja:"暴力の突然の勃発は政府に緊急事態を宣言するよう強制した。",wrong:["暴力の勃発は平和をもたらした。","政府は警告なしに緊急事態を宣言した。","暴力は計画的かつ段階的に発生した。"]}]},{word:"outcome",meaning:"結果",example:"The outcome of the election was unexpected.",category:"society",difficulty:3,examples:[{en:"The outcome of the election surprised everyone.",ja:"選挙の結果は誰もが驚いた。",wrong:["選挙の結果は予想通りだった。","選挙は何も決定しなかった。","選挙の結果は不明である。"]},{en:"The outcome of the negotiation was mutually beneficial.",ja:"交渉の結果は相互に有益だった。",wrong:["交渉の結果は片方に有利だった。","交渉は失敗した。","交渉は決定を下さなかった。"]},{en:"We cannot predict the outcome of this experiment with certainty.",ja:"この実験の結果を確実に予測することはできません。",wrong:["この実験の結果は確実に予測できます。","この実験は結果を生み出さない。","この実験の結果はすでに確定している。"]}]},{word:"outweigh",meaning:"上回る",example:"The benefits outweigh the risks.",category:"society",difficulty:4,examples:[{en:"The benefits of the new policy outweigh the drawbacks.",ja:"新しいポリシーの利点は欠点を上回っています。",wrong:["新しいポリシーの欠点が利点を上回っている。","新しいポリシーは利点と欠点が同等である。","新しいポリシーは完全に負の影響を持つ。"]},{en:"Health considerations outweigh cost concerns in this decision.",ja:"この決定では健康上の考慮がコスト上の懸念を上回っています。",wrong:["コスト上の懸念が健康上の考慮を上回っている。","健康上の考慮とコスト上の懸念は同等である。","この決定ではコストだけが重要である。"]},{en:"The advantages of relocating outweigh the inconvenience.",ja:"移転の利点は不便さを上回っています。",wrong:["移転の不便さが利点を上回っている。","移転は完全に不利である。","移転には利点がない。"]}]},{word:"overwhelm",meaning:"圧倒する",example:"She was overwhelmed by the support she received.",category:"society",difficulty:3,examples:[{en:"The large number of emails overwhelmed the new intern.",ja:"大量のメールは新しいインターンを圧倒した。",wrong:["大量のメールは新しいインターンを励ました。","新しいインターンはメールに対応するのに問題がなかった。","メールは新しいインターンに影響を与えなかった。"]},{en:"The team was overwhelmed by unexpected challenges.",ja:"チームは予期しない課題に圧倒された。",wrong:["チームは課題に簡単に対処した。","チームは課題の準備ができていた。","課題はチームに影響を与えなかった。"]},{en:"Emotions overwhelmed her during the sad movie.",ja:"その悲しい映画の間、感情は彼女を圧倒した。",wrong:["彼女は映画を見て冷静だった。","彼女は映画に感情的に反応しなかった。","映画は彼女を幸せにした。"]}]},{word:"paradox",meaning:"逆説",example:"It is a paradox that richer countries are not always happier.",category:"society",difficulty:4,examples:[{en:"It's a paradox that the more we have, the less satisfied we feel.",ja:"持っているものが多いほど、満足感を感じるのが少なくなるというのは逆説です。",wrong:["より多く持つことは常により多くの満足をもたらします。","この関係は因果関係です。","より多く持つことは満足に影響を与えません。"]},{en:"The time traveler faced a paradox when meeting his younger self.",ja:"タイムトラベラーは彼の若い時代の自分に会ったときに逆説に直面した。",wrong:["過去を訪問することは完全に可能で論理的です。","パラドックスは存在しません。","彼は彼の若い時代の自分に会うことができませんでした。"]},{en:"The paradox of choice suggests that too many options can lead to dissatisfaction.",ja:"選択のパラドックスは、あまりにも多くの選択肢が不満につながる可能性があることを示唆しています。",wrong:["より多くの選択肢は常にはより多くの満足をもたらします。","選択肢の数は満足に影響を与えません。","より少ない選択肢は常により良い結果をもたらします。"]}]},{word:"paralyse",meaning:"麻痺させる",example:"Fear paralysed him when he saw the snake.",category:"science",difficulty:4,examples:[{en:"The accident paralysed him from the waist down.",ja:"その事故は彼の腰から下を麻痺させた。",wrong:["その事故は彼の体を癒した。","その事故は彼を動かすことができるようにした。","その事故は彼に影響を与えなかった。"]},{en:"Fear paralysed her ability to make a decision.",ja:"恐怖は彼女の決定を下す能力を麻痺させた。",wrong:["恐怖は彼女が決定を下すのに役立った。","恐怖は彼女を元気づけた。","恐怖は彼女の判断力に影響を与えなかった。"]},{en:"The economic crisis paralysed the entire industry.",ja:"経済危機は業界全体を麻痺させた。",wrong:["経済危機は業界を成長させた。","危機は業界に影響を与えなかった。","業界は危機の準備ができていた。"]}]},{word:"parameter",meaning:"指標、範囲",example:"The study defined strict parameters for the experiment.",category:"science",difficulty:5,examples:[{en:"The scientist set specific parameters for the experiment.",ja:"科学者は実験の特定の指標を設定した。",wrong:["科学者は実験の指標を設定しなかった。","科学者は無限の変数を許可した。","実験には制約がなかった。"]},{en:"The software allows you to adjust parameters to suit your needs.",ja:"そのソフトウェアはあなたのニーズに合わせて指標を調整することを許可します。",wrong:["そのソフトウェアは固定設定のみを許可します。","そのソフトウェアは調整を許可しません。","パラメータは変更できません。"]},{en:"Within the parameters of the budget, we can hire two new employees.",ja:"予算の範囲内で、私たちは2人の新しい従業員を雇うことができます。",wrong:["予算に制限はありません。","私たちは無限の新しい従業員を雇うことができます。","予算は決定に影響を与えません。"]}]},{word:"parliament",meaning:"議会",example:"Parliament debated the new education bill.",category:"society",difficulty:3,examples:[{en:"Parliament passed a new law regarding environmental protection.",ja:"議会は環境保護に関する新しい法律を可決した。",wrong:["議会は法律を否決した。","議会は立法権を持たない。","個人が単独で法律を作ることができます。"]},{en:"The members of parliament debated the controversial bill for hours.",ja:"議会のメンバーは数時間、物議を醸す法案について議論した。",wrong:["議会のメンバーは議論に参加しません。","議会は立法について決定を下しません。","法案は一瞬で可決されました。"]},{en:"Parliament is responsible for making national decisions on behalf of the people.",ja:"議会は国民に代わって国家的決定を下す責任があります。",wrong:["議会は権力を持たない。","個人が政府を統治している。","国の法律は議会なしで作成されます。"]}]},{word:"partial",meaning:"部分的な、偏った",example:"The renovation is only partially complete.",category:"society",difficulty:3,examples:[{en:"The report provides only a partial understanding of the problem.",ja:"その報告書は問題の部分的な理解のみを提供しています。",wrong:["報告書は完全な理解を提供しています。","報告書は問題について何も説明していません。","報告書は正確です。"]},{en:"The judge was accused of being partial towards the defendant.",ja:"その裁判官は被告人に対して偏った判断をしていると非難された。",wrong:["その裁判官は公正だった。","その裁判官は原告を支持していた。","その裁判官は偏見を持たなかった。"]},{en:"We received a partial refund for the damaged goods.",ja:"傷ついた商品に対して部分的な払い戻しを受けました。",wrong:["私たちは完全な払い戻しを受けました。","私たちは払い戻しを受けませんでした。","会社は払い戻しを拒否しました。"]}]},{word:"patron",meaning:"後援者、常連客",example:"The arts depend on generous patrons.",category:"culture",difficulty:4,examples:[{en:"The wealthy patron donated a large sum to the art museum.",ja:"その裕福な後援者は美術館に大金を寄付した。",wrong:["その裕福な常連客は美術館を訪問した。","その裕福なパトロンは警察官だった。","その裕福な後援者は美術館で絵を盗んだ。"]},{en:"As a regular patron of this restaurant, I know all the staff.",ja:"このレストランの常連客として、私はすべてのスタッフを知っている。",wrong:["このレストランのオーナーとして、私はすべてのスタッフを知っている。","このレストランの料理人として、私はすべてのスタッフを知っている。","このレストランの食材の提供者として、私はすべてのスタッフを知っている。"]},{en:"The patron saint of the city is celebrated annually.",ja:"その都市の守護聖人は毎年祝われている。",wrong:["その都市のオーナーは毎年祝われている。","その都市の市長は毎年祝われている。","その都市の後援者は毎年祝われている。"]}]},{word:"peculiar",meaning:"独特の、奇妙な",example:"The island has a peculiar ecosystem.",category:"science",difficulty:3,examples:[{en:"That peculiar smell coming from the kitchen was quite unusual.",ja:"台所から漂ってくるその奇妙な匂いはかなり珍しかった。",wrong:["台所から漂ってくるその普通の匂いはかなり珍しかった。","台所から漂ってくるその美しい匂いはかなり珍しかった。","台所から漂ってくるその強い匂いはかなり珍しかった。"]},{en:"She has a peculiar way of speaking that makes her stand out.",ja:"彼女は目立つようにさせる独特の話し方を持っている。",wrong:["彼女は普通の話し方を持っている。","彼女は美しい話し方を持っている。","彼女は静かな話し方を持っている。"]},{en:"The peculiar behavior of the animals suggested they were sick.",ja:"その動物たちの奇妙な振る舞いは彼らが病気であることを示唆していた。",wrong:["その動物たちの正常な振る舞いは彼らが病気であることを示唆していた。","その動物たちの怠惰な振る舞いは彼らが病気であることを示唆していた。","その動物たちの活発な振る舞いは彼らが病気であることを示唆していた。"]}]},{word:"peer",meaning:"同僚、同等の人",example:"Peer review is essential in academic publishing.",category:"science",difficulty:3,examples:[{en:"I discussed the project with my peers in the department.",ja:"私は部門の同僚とそのプロジェクトについて議論した。",wrong:["私は部門の上司とそのプロジェクトについて議論した。","私は部門の部下とそのプロジェクトについて議論した。","私は部門の顧客とそのプロジェクトについて議論した。"]},{en:"She peered through the window to see what was happening outside.",ja:"彼女は外で何が起こっているのかを見るために窓をのぞいた。",wrong:["彼女は外で何が起こっているのかを理解するために窓を壊した。","彼女は外で何が起こっているのかを見るために扉を開けた。","彼女は外で何が起こっているのかを聞くために耳を傾けた。"]},{en:"Among his peers, he is considered an equal in knowledge and skill.",ja:"彼の同等の人々の中で、彼は知識とスキルの同等者と見なされている。",wrong:["彼の上司の中で、彼は知識とスキルの同等者と見なされている。","彼の敵の中で、彼は知識とスキルの同等者と見なされている。","彼の友達の中で、彼は知識とスキルの劣った者と見なされている。"]}]},{word:"penalty",meaning:"罰則、ペナルティ",example:"Heavy penalties apply for tax evasion.",category:"society",difficulty:3,examples:[{en:"The player received a penalty for breaking the rules.",ja:"そのプレイヤーはルールを破ったためにペナルティを受けた。",wrong:["そのプレイヤーはルールを守ったためにペナルティを受けた。","そのプレイヤーは素晴らしいプレーをしたためにペナルティを受けた。","そのプレイヤーはゴールを決めたためにペナルティを受けた。"]},{en:"There is a penalty for late payment of taxes.",ja:"税金の支払いが遅れるとペナルティがある。",wrong:["税金の支払いが早いとペナルティがある。","税金を支払わないとボーナスがある。","税金を支払うと減税される。"]},{en:"The penalty for speeding includes a fine and points on your license.",ja:"スピード違反のペナルティには罰金と免許への加点が含まれる。",wrong:["スピード違反の報酬には罰金と免許への加点が含まれる。","遅く運転することのペナルティには報酬と免許の削除が含まれる。","安全運転のペナルティには罰金と免許への減点が含まれる。"]}]},{word:"penetrate",meaning:"貫通する、浸透する",example:"The company aims to penetrate new markets.",category:"current",difficulty:4,examples:[{en:"The bullet penetrated through the wall.",ja:"その弾は壁を貫通した。",wrong:["その弾は壁に跳ね返った。","その弾は壁の上を飛んだ。","その弾は壁を修理した。"]},{en:"The company is trying to penetrate new markets in Asia.",ja:"その会社はアジアの新しい市場に浸透しようとしている。",wrong:["その会社はアジアの市場から撤退しようとしている。","その会社はアジアの市場を避けようとしている。","その会社はアジアの市場を破壊しようとしている。"]},{en:"Light penetrates through the glass.",ja:"光はガラスを通して浸透する。",wrong:["光はガラスによって反射される。","光はガラスに吸収される。","光はガラスを曇らせる。"]}]},{word:"perceive",meaning:"知覚する、認識する",example:"People perceive risk differently.",category:"science",difficulty:4,examples:[{en:"I perceive a change in her attitude.",ja:"私は彼女の態度の変化を認識している。",wrong:["私は彼女の態度の変化を無視している。","私は彼女の態度の変化を望んでいない。","私は彼女の態度を信頼していない。"]},{en:"How do you perceive the situation?",ja:"あなたはこの状況をどのように知覚していますか？",wrong:["あなたはこの状況をどのように作成していますか？","あなたはこの状況をどのように無視していますか？","あなたはこの状況をどのように変えていますか？"]},{en:"The audience perceived the film as a masterpiece.",ja:"観客はその映画を傑作として認識した。",wrong:["観客はその映画を失敗として認識した。","観客はその映画を退屈として認識した。","観客はその映画を難しすぎると認識した。"]}]},{word:"peril",meaning:"危険",example:"The explorers faced many perils on their journey.",category:"history",difficulty:4,examples:[{en:"The ship was in great peril during the storm.",ja:"その船は嵐の中で大きな危険にさらされていた。",wrong:["その船は嵐の中で安全だった。","その船は嵐の中で利益を得ていた。","その船は嵐の中で静かに進んでいた。"]},{en:"The hikers were warned of the peril of avalanches.",ja:"ハイカーたちは雪崩の危険について警告されていた。",wrong:["ハイカーたちは雪崩の美しさについて警告されていた。","ハイカーたちは雪崩の利益について警告されていた。","ハイカーたちは雪崩の楽しさについて警告されていた。"]},{en:"Citizens were in peril of losing their homes.",ja:"市民たちは家を失う危険にさらされていた。",wrong:["市民たちは家を得る危険にさらされていた。","市民たちは家を修理する利益を得ていた。","市民たちは家を改築する機会を得ていた。"]}]},{word:"peripheral",meaning:"周辺の",example:"The issue was of peripheral importance.",category:"society",difficulty:5,examples:[{en:"The peripheral vision is important for driving safely.",ja:"周辺視野は安全な運転のために重要である。",wrong:["中心視野は安全な運転のために重要である。","夜間視野は安全な運転のために重要である。","色覚は安全な運転のために重要である。"]},{en:"The peripheral devices are connected to the main computer.",ja:"周辺機器はメインコンピュータに接続されている。",wrong:["中央処理装置はメインコンピュータに接続されている。","マザーボードはメインコンピュータに接続されている。","CPU はメインコンピュータに接続されている。"]},{en:"The issue is peripheral to our main discussion.",ja:"その問題は私たちの主な議論の周辺にある。",wrong:["その問題は私たちの主な議論の中心にある。","その問題は私たちの主な議論と同じくらい重要である。","その問題は私たちの主な議論よりも重要である。"]}]},{word:"permanent",meaning:"永続的な",example:"The damage to the environment may be permanent.",category:"current",difficulty:3,examples:[{en:"She got a permanent job after working as a temporary employee.",ja:"彼女は一時的な従業員として働いた後に永続的な職を得た。",wrong:["彼女は一時的な従業員として働いた後に一時的な職を得た。","彼女は永続的な従業員として働いた後に一時的な職を得た。","彼女は一時的な従業員として働いた後に失業した。"]},{en:"The damage to the building was permanent.",ja:"その建物へのダメージは永続的であった。",wrong:["その建物へのダメージは一時的であった。","その建物へのダメージは修復可能であった。","その建物へのダメージは見えない。"]},{en:"He decided to make a permanent move to another country.",ja:"彼は別の国への永続的な引越を決めた。",wrong:["彼は別の国への一時的な訪問を決めた。","彼は現在の国に留まることを決めた。","彼は仕事のために旅行することを決めた。"]}]},{word:"perpetuate",meaning:"永続させる",example:"Stereotypes perpetuate inequality.",category:"society",difficulty:5,examples:[{en:"The tradition was perpetuated through generations.",ja:"その伝統は世代を通して永続された。",wrong:["その伝統は世代によって廃止された。","その伝統は誰もが忘れた。","その伝統は現代では無関係である。"]},{en:"The cycle of poverty perpetuates itself without intervention.",ja:"貧困のサイクルは干渉なしに自らを永続させている。",wrong:["貧困のサイクルは自動的に終わる。","貧困のサイクルは時間とともに改善する。","貧困のサイクルは政府によって作られている。"]},{en:"The media perpetuates stereotypes through biased reporting.",ja:"メディアは偏った報道を通してステレオタイプを永続させている。",wrong:["メディアはステレオタイプを排除している。","メディアはステレオタイプを作成している。","メディアはステレオタイプを無視している。"]}]},{word:"persist",meaning:"持続する、固執する",example:"The symptoms persisted despite treatment.",category:"science",difficulty:3,examples:[{en:"Despite the challenges, she persisted in her efforts.",ja:"課題があるにもかかわらず、彼女は彼女の努力に固執した。",wrong:["課題があるため、彼女は彼女の努力をやめた。","課題があるため、彼女は諦めた。","課題があるため、彼女は別のことを試みた。"]},{en:"The pain persisted for several weeks.",ja:"その痛みは数週間続いた。",wrong:["その痛みはすぐに消えた。","その痛みは治療で治った。","その痛みは1日で消えた。"]},{en:"He persisted with his questions until he got an answer.",ja:"彼は答えを得るまで彼の質問に固執した。",wrong:["彼は1つの質問の後に諦めた。","彼は質問をしなかった。","彼は答えを聞かずに去った。"]}]},{word:"perspective",meaning:"見方、視点",example:"Try to see the issue from a different perspective.",category:"society",difficulty:3,examples:[{en:"From her perspective, the decision was unfair.",ja:"彼女の視点からは、その決定は不公正であった。",wrong:["彼の視点からは、その決定は不公正であった。","誰もの視点からは、その決定は公正であった。","会社の視点からは、その決定は良かった。"]},{en:"The artist used perspective to create depth in the painting.",ja:"その芸術家は絵に奥行きを作るために遠近法を使用した。",wrong:["その芸術家は明るさを作るために色を使用した。","その芸術家は動きを作るために線を使用した。","その芸術家は影を作るために照明を使用した。"]},{en:"We need to gain some perspective on this issue.",ja:"私たちはこの問題について何らかの見方を得る必要がある。",wrong:["私たちはこの問題について詳細を忘れる必要がある。","私たちはこの問題について判断を下す必要がない。","私たちはこの問題について何も考える必要がない。"]}]},{word:"petition",meaning:"請願書、嘆願する",example:"Citizens signed a petition against the new law.",category:"society",difficulty:4,examples:[{en:"The students signed a petition to extend the library hours.",ja:"学生たちは図書館の営業時間を延長するための請願書に署名した。",wrong:["学生たちは図書館を閉じるための請願書に署名した。","学生たちは図書館の営業時間を短くするための請願書に署名した。","学生たちは図書館を新しい場所に移動するための請願書に署名した。"]},{en:"She petitioned the court for a divorce.",ja:"彼女は離婚のために裁判所に嘆願した。",wrong:["彼女は結婚継続のために裁判所に嘆願した。","彼女は子どもの権利のために裁判所に嘆願した。","彼女は財産分割のために裁判所に嘆願した。"]},{en:"A petition with thousands of signatures was delivered to the government.",ja:"数千の署名がある請願書が政府に提出された。",wrong:["少数の署名がある請願書が政府に提出された。","署名がない請願書が政府に提出された。","一つの署名がある請願書が政府に提出された。"]}]},{word:"phenomenon",meaning:"現象",example:"Global warming is a well-documented phenomenon.",category:"science",difficulty:3,examples:[{en:"The aurora borealis is a natural phenomenon that occurs in polar regions.",ja:"オーロラは極地地域で起こる自然現象である。",wrong:["オーロラは赤道地域で起こる人工現象である。","オーロラは季節に関係なく起こる現象である。","オーロラは北半球でのみ起こる現象である。"]},{en:"The phenomenon of globalization has changed the world economy.",ja:"グローバル化の現象は世界経済を変えた。",wrong:["グローバル化の現象は世界経済を変えなかった。","グローバル化の現象は世界経済を衰退させた。","グローバル化の現象は新しく起こった。"]},{en:"Scientists are studying the phenomenon of climate change.",ja:"科学者たちは気候変動の現象を研究している。",wrong:["科学者たちは気候変動の解決策を発明している。","科学者たちは気候変動が存在しないと証明している。","科学者たちは気候変動について無関心である。"]}]},{word:"pioneer",meaning:"先駆者、開拓する",example:"She pioneered research in gene therapy.",category:"science",difficulty:3,examples:[{en:"She was a pioneer in the field of computer science.",ja:"彼女はコンピュータ科学の分野の先駆者だった。",wrong:["彼女はコンピュータ科学の分野の後発者だった。","彼女はコンピュータ科学の分野の反対者だった。","彼女はコンピュータ科学について知らなかった。"]},{en:"The pioneers settled in the western territories.",ja:"開拓者たちは西部領土に定住した。",wrong:["定住者たちは東部領土を放棄した。","移民たちは南部領土を探索した。","旅人たちは北部領土を避けた。"]},{en:"He pioneered a new method of teaching mathematics.",ja:"彼は数学教育の新しい方法を開拓した。",wrong:["彼は数学教育の古い方法を復活させた。","彼は数学教育の標準的な方法を使用した。","彼は数学教育の効果的な方法を廃止した。"]}]},{word:"plausible",meaning:"もっともらしい",example:"His excuse sounded plausible but was untrue.",category:"society",difficulty:5,examples:[{en:"His explanation sounds plausible, but I need more evidence.",ja:"彼の説明はもっともらしく聞こえるが、もっと証拠が必要だ。",wrong:["彼の説明は完全に真実である。","彼の説明は全く信じられない。","彼の説明は証拠によって証明されている。"]},{en:"The theory is plausible enough to warrant further investigation.",ja:"その理論はもっともらしく、さらなる調査に値する。",wrong:["その理論は完全に間違っている。","その理論は調査する必要がない。","その理論は科学的に証明されている。"]},{en:"While not proven, the suspect's alibi is plausible.",ja:"証明されていないが、容疑者のアリバイはもっともらしい。",wrong:["容疑者のアリバイは明らかに嘘である。","容疑者のアリバイは完全に証明されている。","容疑者のアリバイは不可能である。"]}]},{word:"pledge",meaning:"誓約する",example:"The government pledged to reduce carbon emissions.",category:"current",difficulty:3,examples:[{en:"The president pledged to reduce poverty by 50 percent.",ja:"大統領は貧困を50パーセント削減することを誓約した。",wrong:["大統領は貧困を増やすことを約束した。","大統領は貧困について何も言わなかった。","大統領は貧困を完全に終わらせた。"]},{en:"She pledged her loyalty to the organization.",ja:"彼女は組織への忠誠を誓約した。",wrong:["彼女は組織から離れることを約束した。","彼女は組織を裏切ることを宣言した。","彼女は組織に無関心だと言った。"]},{en:"All members pledge to follow the code of conduct.",ja:"すべてのメンバーは行動規範に従うことを誓約する。",wrong:["すべてのメンバーは行動規範を無視する。","すべてのメンバーは規則を破ることに同意する。","すべてのメンバーは行動規範に反対する。"]}]},{word:"plunge",meaning:"急落する、飛び込む",example:"Share prices plunged after the announcement.",category:"current",difficulty:3,examples:[{en:"Stock prices plunged after the announcement.",ja:"発表後、株価は急落した。",wrong:["株価は徐々に上昇した。","株価は安定したままだった。","株価は少し下がった。"]},{en:"He plunged into the pool without hesitation.",ja:"彼は躊躇することなくプールに飛び込んだ。",wrong:["彼はプールに慎重に入った。","彼はプールの近くに立っていた。","彼はプールに入らなかった。"]},{en:"The economy plunged into recession.",ja:"経済は不況に陥った。",wrong:["経済は繁栄に向かった。","経済は変わらなかった。","経済は徐々に悪化した。"]}]},{word:"portray",meaning:"描写する",example:"The film portrays life in wartime London.",category:"culture",difficulty:4,examples:[{en:"The film portrays the life of a famous scientist.",ja:"その映画は有名な科学者の人生を描写している。",wrong:["その映画は科学者について何も説明していない。","その映画はまったく異なる主題について述べている。","その映画は虚構の物語だけを扱っている。"]},{en:"The artist portrayed her emotions through abstract painting.",ja:"芸術家は抽象画を通じて彼女の感情を描写した。",wrong:["芸術家は彼女の感情を隠した。","芸術家は具体的な描写だけを使った。","芸術家は感情を表現しなかった。"]},{en:"The character is portrayed as a hero in the novel.",ja:"その人物は小説で英雄として描写されている。",wrong:["その人物は悪役として描写されている。","その人物は小説に登場しない。","その人物の性格は説明されていない。"]}]},{word:"postpone",meaning:"延期する",example:"The concert was postponed due to rain.",category:"society",difficulty:3,examples:[{en:"The meeting has been postponed until next week.",ja:"会議は来週まで延期された。",wrong:["会議はすぐに開催された。","会議は今日開催された。","会議はキャンセルされた。"]},{en:"We decided to postpone the project deadline.",ja:"プロジェクトの期限を延期することに決めた。",wrong:["期限を前倒しにした。","期限を厳しくした。","期限を撤廃した。"]},{en:"She postponed her vacation due to work commitments.",ja:"彼女は仕事の都合で休暇を延期した。",wrong:["彼女は休暇に出かけた。","彼女は仕事を辞めた。","彼女は休暇を取り消した。"]}]},{word:"potential",meaning:"潜在的な、可能性",example:"The technology has enormous potential.",category:"technology",difficulty:3,examples:[{en:"This young athlete has great potential.",ja:"この若い選手には大きな可能性がある。",wrong:["この選手には才能がない。","この選手は既に全力を尽くしている。","この選手には成長の余地がない。"]},{en:"The potential benefits of this technology are enormous.",ja:"この技術の潜在的な利益は莫大である。",wrong:["この技術は利益をもたらさない。","この技術は既に最大限活用されている。","この技術には欠点しかない。"]},{en:"We need to unlock the potential of our team.",ja:"チームの潜在能力を引き出す必要がある。",wrong:["チームの能力は既に最大限だ。","チームには能力がない。","チームの成長は不可能だ。"]}]},{word:"practitioner",meaning:"実践者、開業者",example:"She is a qualified medical practitioner.",category:"science",difficulty:4,examples:[{en:"She is an experienced practitioner of traditional medicine.",ja:"彼女は伝統医学の経験豊かな実践者である。",wrong:["彼女は伝統医学について何も知らない。","彼女は医学を学んだことがない。","彼女は医療に関わっていない。"]},{en:"The law firm employs many skilled legal practitioners.",ja:"その法律事務所は多くの熟練した法律実践者を雇用している。",wrong:["その法律事務所に弁護士がいない。","その法律事務所は未熟な人しか雇っていない。","その法律事務所は経験者を避けている。"]},{en:"A yoga practitioner must practice regularly.",ja:"ヨガの実践者は定期的に練習する必要がある。",wrong:["ヨガの実践者は練習する必要がない。","ヨガをしている人は初心者ではない。","ヨガは実践を必要としない。"]}]},{word:"precede",meaning:"先行する",example:"A brief introduction preceded the main speech.",category:"society",difficulty:4,examples:[{en:"Dinner will be preceded by a cocktail hour.",ja:"ディナーはカクテルアワーに先行される。",wrong:["ディナーはカクテルアワーの後に始まる。","カクテルアワーはディナーの後だ。","ディナーはカクテルアワーと同時に始まる。"]},{en:"Hard work precedes success.",ja:"成功は努力に先行される。",wrong:["成功は努力なしに起こる。","努力は成功の後だ。","成功と努力は関係がない。"]},{en:"The introduction precedes the main content.",ja:"導入は主要な内容に先行する。",wrong:["導入は主要な内容の後にある。","導入と内容は同時だ。","導入は主要な内容と無関係だ。"]}]},{word:"precedent",meaning:"前例",example:"The court ruling set a legal precedent.",category:"society",difficulty:4,examples:[{en:"This court ruling sets a precedent for future cases.",ja:"この判決は今後の事件の前例を設定する。",wrong:["この判決は将来に影響しない。","この判決は過去の判決だけに影響する。","この判決は異例である。"]},{en:"There is no precedent for this situation.",ja:"この状況には前例がない。",wrong:["この状況は以前あったことがある。","この状況は一般的だ。","この状況は昔から存在する。"]},{en:"We should follow the precedent established by our predecessors.",ja:"前任者によって確立された前例に従うべきだ。",wrong:["前例に反対すべきだ。","前例は存在しない。","前例は無視すべきだ。"]}]},{word:"precise",meaning:"正確な",example:"The measurements need to be very precise.",category:"science",difficulty:3,examples:[{en:"The measurements must be precise to avoid errors.",ja:"誤りを避けるために測定は正確である必要がある。",wrong:["測定は不正確でも大丈夫だ。","正確さは重要ではない。","誤りは避けられない。"]},{en:"He gave a precise explanation of the process.",ja:"彼はプロセスの正確な説明を与えた。",wrong:["彼の説明は曖昧だった。","彼は詳細を省略した。","彼の説明は不完全だった。"]},{en:"We need precise data to make informed decisions.",ja:"情報に基づいた決定をするには正確なデータが必要だ。",wrong:["不正確なデータで十分だ。","データの精度は重要ではない。","推測だけで決定できる。"]}]},{word:"predator",meaning:"捕食者",example:"Lions are apex predators in the savanna.",category:"science",difficulty:3,examples:[{en:"The lion is a fierce predator in the African savanna.",ja:"ライオンはアフリカのサバンナの凶暴な捕食者である。",wrong:["ライオンは草食動物だ。","ライオンは狩りをしない。","ライオンは獲物だ。"]},{en:"Many sea birds are predators of small fish.",ja:"多くの海鳥は小魚の捕食者である。",wrong:["海鳥は植物だけを食べる。","海鳥は獲物ではなく狩人だ。","海鳥は魚を食べない。"]},{en:"The hawk is a skilled predator that hunts from the sky.",ja:"鷹は空から狩りをする熟練した捕食者である。",wrong:["鷹は地上でしか狩りをしない。","鷹は獲物だ。","鷹は狩りをしない。"]}]},{word:"predecessor",meaning:"前任者",example:"The new CEO differed from her predecessor.",category:"society",difficulty:4,examples:[{en:"The new manager is more innovative than his predecessor.",ja:"新しいマネージャーは前任者より革新的だ。",wrong:["新しいマネージャーの前に誰もいなかった。","前任者はまだ職務に就いている。","前任者が現在のマネージャーだ。"]},{en:"This model improves upon the design of its predecessor.",ja:"このモデルは前任者のデザインを改善している。",wrong:["このモデルは前のモデルと同じだ。","このモデルは前のモデルより悪い。","前任者は現在のモデルだ。"]},{en:"She inherited many policies from her predecessor.",ja:"彼女は前任者から多くの方針を受け継いだ。",wrong:["彼女は独自の方針を創設した。","前任者は彼女の後に来た。","彼女には前任者がいなかった。"]}]},{word:"predominant",meaning:"支配的な",example:"Rice is the predominant crop in the region.",category:"science",difficulty:4,examples:[{en:"English is the predominant language in international business.",ja:"英語は国際ビジネスにおける支配的な言語である。",wrong:["英語は国際ビジネスではあまり使われていない。","多くの言語が英語と同等に使われている。","英語は少数派の言語だ。"]},{en:"The predominant color in the painting is blue.",ja:"その絵画の支配的な色は青である。",wrong:["その絵画の主な色は赤だ。","その絵画には支配的な色がない。","青はその絵画にはない。"]},{en:"Technology has become the predominant force in modern society.",ja:"技術は現代社会の支配的な力になった。",wrong:["技術は社会ではあまり役割を果たしていない。","技術は衰退している。","技術の影響力は限定的だ。"]}]},{word:"prejudice",meaning:"偏見",example:"Education helps overcome racial prejudice.",category:"society",difficulty:3,examples:[{en:"Prejudice against minorities is a serious social problem.",ja:"少数派に対する偏見は深刻な社会問題だ。",wrong:["少数派への差別は問題ではない。","偏見は存在しない。","少数派は平等に扱われている。"]},{en:"We must try to overcome our own prejudices.",ja:"自分たちの偏見を克服しようと努力する必要がある。",wrong:["偏見を持つことは良いことだ。","偏見は変えられない。","偏見を克服する必要はない。"]},{en:"His prejudice against the proposal prevented fair consideration.",ja:"その提案に対する彼の偏見は公正な検討を妨げた。",wrong:["彼は公平に提案を検討した。","彼は提案に賛成した。","彼は偏見を持っていなかった。"]}]},{word:"preliminary",meaning:"予備的な",example:"Preliminary results suggest the treatment works.",category:"science",difficulty:4,examples:[{en:"The preliminary results suggest the treatment is effective.",ja:"予備的な結果は治療が効果的であることを示唆している。",wrong:["最終的な結果は判明している。","結果は決定的である。","治療の効果は確認されていない。"]},{en:"We held a preliminary meeting to discuss the project.",ja:"プロジェクトについて議論するための予備的な会議を開いた。",wrong:["それは最後の会議だった。","会議はプロジェクトの完了後だった。","それは次の段階の会議だった。"]},{en:"Preliminary investigations revealed no evidence of foul play.",ja:"予備的な調査は不正の証拠を明かさなかった。",wrong:["最終的な調査は完了している。","調査は深刻な不正を発見した。","調査はまだ始まっていない。"]}]},{word:"premise",meaning:"前提",example:"The argument is based on a false premise.",category:"science",difficulty:5,examples:[{en:"The argument is based on a false premise.",ja:"その議論は誤った前提に基づいている。",wrong:["その議論は誤った建物に基づいている。","その議論は誤った敷地に結論づけられている。","その議論は誤った結果に起因している。"]},{en:"We must accept the premise before proceeding.",ja:"先に進む前に、その前提を受け入れなければならない。",wrong:["進む前に、その建物を受け入れなければならない。","進む前に、その約束を認めなければならない。","進む前に、その場所を承認しなければならない。"]},{en:"The premise of the theory needs to be verified.",ja:"その理論の前提は検証される必要がある。",wrong:["その理論の敷地は証明される必要がある。","その理論の基礎となる建物は確認される必要がある。","その理論の所有物は検査される必要がある。"]}]},{word:"prescribe",meaning:"処方する、規定する",example:"The doctor prescribed antibiotics for the infection.",category:"science",difficulty:3,examples:[{en:"The doctor prescribed antibiotics for the infection.",ja:"医者は感染症に対して抗生物質を処方した。",wrong:["医者は感染症に対して薬を禁止した。","医者は感染症に対して治療法を提案した。","医者は感染症に対して医学を説く手段を与えた。"]},{en:"The law prescribes strict penalties for theft.",ja:"法律は窃盗に対して厳しい罰を規定している。",wrong:["法律は窃盗に対して罰を禁止している。","法律は窃盗に対して罰を提案している。","法律は窃盗に対して罰を推奨している。"]},{en:"The regulations prescribe how to handle hazardous materials.",ja:"規則は危険物の取り扱い方を規定している。",wrong:["規則は危険物の取り扱い方を禁止している。","規則は危険物の取り扱い方を説明している。","規則は危険物の取り扱い方を命じている。"]}]},{word:"preserve",meaning:"保存する",example:"Efforts are being made to preserve the rainforest.",category:"current",difficulty:3,examples:[{en:"We must preserve the historical artifacts for future generations.",ja:"私たちは将来の世代のために歴史的遺物を保存しなければならない。",wrong:["私たちは将来の世代のために歴史的遺物を破壊しなければならない。","私たちは将来の世代のために歴史的遺物を変更しなければならない。","私たちは将来の世代のために歴史的遺物を展示しなければならない。"]},{en:"Salt is used to preserve meat.",ja:"肉を保存するために塩が使用される。",wrong:["肉を腐らせるために塩が使用される。","肉を調理するために塩が使用される。","肉を乾燥させるために塩が使用される。"]},{en:"We should preserve the environment for our children.",ja:"私たちは子どもたちのために環境を保全すべきである。",wrong:["私たちは子どもたちのために環境を汚染すべきである。","私たちは子どもたちのために環境を破壊すべきである。","私たちは子どもたちのために環境を変えるべきである。"]}]},{word:"prestige",meaning:"威信",example:"The award carries great prestige.",category:"society",difficulty:4,examples:[{en:"The university has great prestige in the academic world.",ja:"その大学は学術界で大きな威信を持っている。",wrong:["その大学は学術界で大きな利益を持っている。","その大学は学術界で大きな名声を持っている。","その大学は学術界で大きな富を持っている。"]},{en:"Winning the award enhanced her prestige.",ja:"その賞を獲得することで、彼女の威信が高まった。",wrong:["その賞を獲得することで、彼女の評判が落ちた。","その賞を獲得することで、彼女の信用が失われた。","その賞を獲得することで、彼女の地位が低下した。"]},{en:"He lost prestige after the scandal.",ja:"スキャンダルの後、彼は威信を失った。",wrong:["スキャンダルの後、彼は名誉を失った。","スキャンダルの後、彼は評価を失った。","スキャンダルの後、彼は信頼を失った。"]}]},{word:"presume",meaning:"推定する",example:"The missing climber is presumed dead.",category:"society",difficulty:4,examples:[{en:"I presume you have finished your work.",ja:"あなたが仕事を終わらせたと推定しています。",wrong:["あなたが仕事を終わらせたと知っています。","あなたが仕事を終わらせたと見ています。","あなたが仕事を終わらせたと確認しています。"]},{en:"We can presume that he will arrive on time.",ja:"彼が時間通りに到着するだろうと推定できます。",wrong:["彼が時間通りに到着するだろうと確信しています。","彼が時間通りに到着するだろうと承知しています。","彼が時間通りに到着するだろうと決定しています。"]},{en:"It is presumed that the accident was caused by human error.",ja:"事故は人的ミスが原因であると推定されている。",wrong:["事故は人的ミスが原因であると明らかである。","事故は人的ミスが原因であると立証されている。","事故は人的ミスが原因であると確実である。"]}]},{word:"prevail",meaning:"広まる、打ち勝つ",example:"Common sense must prevail in this debate.",category:"society",difficulty:4,examples:[{en:"Justice prevailed in the end.",ja:"正義は結局勝利した。",wrong:["正義は結局敗北した。","正義は結局失敗した。","正義は結局消滅した。"]},{en:"The new fashion trend will prevail next season.",ja:"新しいファッショントレンドは来シーズン流行するだろう。",wrong:["新しいファッショントレンドは来シーズン廃止されるだろう。","新しいファッショントレンドは来シーズン消えるだろう。","新しいファッショントレンドは来シーズン忘れられるだろう。"]},{en:"Common sense should prevail in decision-making.",ja:"意思決定において常識が支配すべきである。",wrong:["意思決定において常識が失敗すべきである。","意思決定において常識が排除されるべきである。","意思決定において常識が無視されるべきである。"]}]},{word:"prevalent",meaning:"流行している",example:"Obesity is increasingly prevalent among children.",category:"science",difficulty:4,examples:[{en:"Smoking was prevalent in the 1950s.",ja:"喫煙は1950年代に流行していた。",wrong:["喫煙は1950年代に禁止されていた。","喫煙は1950年代に廃止されていた。","喫煙は1950年代に衰退していた。"]},{en:"Obesity is prevalent in developed countries.",ja:"肥満は先進国で流行している。",wrong:["肥満は先進国で減少している。","肥満は先進国で治療されている。","肥満は先進国で消滅している。"]},{en:"The prevalent opinion is that climate change is real.",ja:"気候変動が現実であるという見解が一般的である。",wrong:["気候変動が現実であるという見解が少数派である。","気候変動が現実であるという見解が議論の余地がある。","気候変動が現実であるという見解が否定されている。"]}]},{word:"prior",meaning:"以前の",example:"No prior experience is required for this role.",category:"society",difficulty:3,examples:[{en:"Prior to the meeting, please review the documents.",ja:"会議の前に、ドキュメントを確認してください。",wrong:["会議の後に、ドキュメントを確認してください。","会議の間に、ドキュメントを確認してください。","会議の代わりに、ドキュメントを確認してください。"]},{en:"He has prior experience in management.",ja:"彼は経営についての以前の経験を持っている。",wrong:["彼は経営についての将来の経験を持っている。","彼は経営についての現在の経験を持っている。","彼は経営についての同時の経験を持っている。"]},{en:"Without prior notice, the meeting was cancelled.",ja:"事前の通知なしに、会議はキャンセルされた。",wrong:["事後の通知なしに、会議はキャンセルされた。","同時の通知なしに、会議はキャンセルされた。","予定された通知なしに、会議はキャンセルされた。"]}]},{word:"privilege",meaning:"特権",example:"Access to clean water should not be a privilege.",category:"society",difficulty:3,examples:[{en:"It is a privilege to meet you.",ja:"あなたにお会いするのは特権です。",wrong:["あなたにお会いするのは義務です。","あなたにお会いするのは負担です。","あなたにお会いするのは罰です。"]},{en:"The wealthy enjoy certain privileges.",ja:"富裕層は特定の特権を享受している。",wrong:["富裕層は特定の責任を享受している。","富裕層は特定の義務を享受している。","富裕層は特定の制限を享受している。"]},{en:"Voting is a privilege, not a right.",ja:"投票は権利ではなく特権である。",wrong:["投票は義務ではなく特権である。","投票は恩恵ではなく特権である。","投票は制限ではなく特権である。"]}]},{word:"probe",meaning:"調査する、探査機",example:"Investigators are probing the cause of the crash.",category:"science",difficulty:4,examples:[{en:"The police are probing the crime scene for evidence.",ja:"警察は証拠について犯罪現場を調査している。",wrong:["警察は証拠について犯罪現場を無視している。","警察は証拠について犯罪現場を隠蔽している。","警察は証拠について犯罪現場を破壊している。"]},{en:"The space probe traveled beyond our solar system.",ja:"その探査機は私たちの太陽系を超えて旅行した。",wrong:["その探査機は私たちの太陽系に落ちた。","その探査機は私たちの太陽系で停止した。","その探査機は私たちの太陽系に帰った。"]},{en:"Journalists are probing into the minister's finances.",ja:"ジャーナリストは大臣の財政を調査している。",wrong:["ジャーナリストは大臣の財政を隠している。","ジャーナリストは大臣の財政を許している。","ジャーナリストは大臣の財政を賞賛している。"]}]},{word:"proclaim",meaning:"宣言する",example:"The country proclaimed independence in 1960.",category:"history",difficulty:4,examples:[{en:"The king proclaimed a new law.",ja:"王は新しい法律を宣言した。",wrong:["王は新しい法律を撤回した。","王は新しい法律を否定した。","王は新しい法律を破棄した。"]},{en:"She proclaimed her innocence loudly.",ja:"彼女は大声で自分の無実を宣言した。",wrong:["彼女は大声で自分の有罪を宣言した。","彼女は大声で自分の過失を宣言した。","彼女は大声で自分の責任を宣言した。"]},{en:"The government proclaimed a state of emergency.",ja:"政府は緊急事態を宣言した。",wrong:["政府は平和な状態を宣言した。","政府は通常の状態を宣言した。","政府は安全な状態を宣言した。"]}]},{word:"profound",meaning:"深い、重大な",example:"The discovery had a profound impact on medicine.",category:"science",difficulty:4,examples:[{en:"His profound knowledge impressed everyone.",ja:"彼の深い知識は誰もを感動させた。",wrong:["彼の浅い知識は誰もを感動させた。","彼の不十分な知識は誰もを感動させた。","彼の基本的な知識は誰もを感動させた。"]},{en:"The book had a profound impact on her life.",ja:"その本は彼女の人生に重大な影響を与えた。",wrong:["その本は彼女の人生に軽微な影響を与えた。","その本は彼女の人生に無視できる影響を与えた。","その本は彼女の人生に表面的な影響を与えた。"]},{en:"He made a profound discovery in physics.",ja:"彼は物理学で重大な発見をした。",wrong:["彼は物理学で取るに足らない発見をした。","彼は物理学で些細な発見をした。","彼は物理学で明白な発見をした。"]}]},{word:"prohibit",meaning:"禁止する",example:"Smoking is prohibited in public buildings.",category:"society",difficulty:3,examples:[{en:"The law prohibits smoking in public places.",ja:"法律は公共の場での喫煙を禁止している。",wrong:["法律は公共の場での喫煙を奨励している。","法律は公共の場での喫煙を許可している。","法律は公共の場での喫煙を推奨している。"]},{en:"Parents prohibit their children from playing outside at night.",ja:"親は子どもたちが夜間に外で遊ぶことを禁止している。",wrong:["親は子どもたちが夜間に外で遊ぶことを許可している。","親は子どもたちが夜間に外で遊ぶことを奨励している。","親は子どもたちが夜間に外で遊ぶことを推奨している。"]},{en:"The school prohibits students from using mobile phones.",ja:"学校は学生が携帯電話を使用することを禁止している。",wrong:["学校は学生が携帯電話を使用することを許可している。","学校は学生が携帯電話を使用することを要求している。","学校は学生が携帯電話を使用することを促進している。"]}]},{word:"prominent",meaning:"著名な、目立つ",example:"She is a prominent figure in the tech industry.",category:"current",difficulty:3,examples:[{en:"He is a prominent figure in the political world.",ja:"彼は政治の世界で著名な人物である。",wrong:["彼は政治の世界で無名な人物である。","彼は政治の世界で隠れた人物である。","彼は政治の世界で目立たない人物である。"]},{en:"The building has a prominent location on the main street.",ja:"その建物はメインストリートで目立つ場所にある。",wrong:["その建物はメインストリートで目立たない場所にある。","その建物はメインストリートで隠れた場所にある。","その建物はメインストリートで奥まった場所にある。"]},{en:"She played a prominent role in the project.",ja:"彼女はプロジェクトで重要な役割を果たした。",wrong:["彼女はプロジェクトで軽微な役割を果たした。","彼女はプロジェクトで目立たない役割を果たした。","彼女はプロジェクトで脇役を果たした。"]}]},{word:"prone",meaning:"〜しがちな",example:"The area is prone to flooding.",category:"current",difficulty:3,examples:[{en:"Some people are prone to allergies.",ja:"アレルギーになりやすい人もいます。",wrong:["アレルギーに抵抗しやすい人もいます。","アレルギーを避けやすい人もいます。","アレルギーを治しやすい人もいます。"]},{en:"He is prone to making careless mistakes.",ja:"彼はうっかりミスをしやすい傾向がある。",wrong:["彼はうっかりミスをしにくい傾向がある。","彼はうっかりミスを避けやすい傾向がある。","彼はうっかりミスを防ぎやすい傾向がある。"]},{en:"The area is prone to flooding during the rainy season.",ja:"その地域は雨季に洪水になりやすい。",wrong:["その地域は雨季に乾燥しやすい。","その地域は雨季に干ばつになりやすい。","その地域は雨季に乾いやすい。"]}]},{word:"propaganda",meaning:"政治宣伝",example:"The regime spread propaganda through state media.",category:"history",difficulty:4,examples:[{en:"The government used propaganda to influence public opinion.",ja:"政府は世論に影響を与えるために政治宣伝を使用した。",wrong:["政府は事実を広める広告を使用した。","政府は教育プログラムを宣伝した。","政府はニュースメディアを購入した。"]},{en:"Propaganda during the war spread misleading information.",ja:"戦争中の政治宣伝は誤った情報を広めた。",wrong:["戦争中の広告は正確な情報を広めた。","戦争中の宣伝は兵士を募集した。","戦争中の放送は娯楽を提供した。"]},{en:"Students learned to identify propaganda in media.",ja:"学生たちはメディアの政治宣伝を識別することを学んだ。",wrong:["学生たちはメディアの広告を作成することを学んだ。","学生たちはメディアの真実を広めることを学んだ。","学生たちはメディアの娯楽を理解することを学んだ。"]}]},{word:"proportion",meaning:"割合、比率",example:"A large proportion of the budget goes to defence.",category:"society",difficulty:3,examples:[{en:"The proportion of women in the company increased to 40%.",ja:"会社における女性の割合は40%に増加した。",wrong:["会社における女性の人数は40人に増加した。","会社における女性の給与は40%増加した。","会社における女性の昇進率は40%だった。"]},{en:"The painting's proportions were perfectly balanced.",ja:"絵画の比率は完璧にバランスしていた。",wrong:["絵画の色のバランスが完璧だった。","絵画のサイズが均等だった。","絵画のテーマの比率が完璧だった。"]},{en:"A large proportion of the budget was spent on marketing.",ja:"予算の大きな割合がマーケティングに費やされた。",wrong:["予算の大部分は人件費に費やされた。","予算の大部分は従業員に配分された。","予算の大部分は設備投資に使われた。"]}]},{word:"prosecute",meaning:"起訴する",example:"The company was prosecuted for environmental violations.",category:"society",difficulty:4,examples:[{en:"The attorney decided to prosecute the suspect for theft.",ja:"弁護士は容疑者を窃盗罪で起訴することを決めた。",wrong:["弁護士は容疑者を逮捕することを決めた。","弁護士は容疑者を調査することを決めた。","弁護士は容疑者を釈放することを決めた。"]},{en:"The government will prosecute all cases of fraud.",ja:"政府はすべての詐欺事件を起訴する。",wrong:["政府はすべての詐欺事件を調査する。","政府はすべての詐欺事件を防止する。","政府はすべての詐欺事件を報告する。"]},{en:"They prosecuted the war criminal for crimes against humanity.",ja:"彼らは戦争犯罪人を人道に対する罪で起訴した。",wrong:["彼らは戦争犯罪人を逮捕した。","彼らは戦争犯罪人を裁判にかけた。","彼らは戦争犯罪人を投獄した。"]}]},{word:"prosperity",meaning:"繁栄",example:"The country enjoyed a period of economic prosperity.",category:"current",difficulty:3,examples:[{en:"The country experienced economic prosperity in the 1990s.",ja:"その国は1990年代に経済繁栄を経験した。",wrong:["その国は1990年代に経済成長を経験した。","その国は1990年代に経済復興を経験した。","その国は1990年代に経済発展を経験した。"]},{en:"Prosperity brought wealth to many families.",ja:"繁栄は多くの家族に富をもたらした。",wrong:["成功は多くの家族に富をもたらした。","幸運は多くの家族に富をもたらした。","成長は多くの家族に富をもたらした。"]},{en:"The business sought prosperity through innovation.",ja:"企業はイノベーションを通じて繁栄を求めた。",wrong:["企業は競争を通じて繁栄を求めた。","企業は投資を通じて繁栄を求めた。","企業は営業を通じて繁栄を求めた。"]}]},{word:"provoke",meaning:"挑発する、引き起こす",example:"The remark provoked an angry response.",category:"society",difficulty:3,examples:[{en:"His comments provoked an angry response from the audience.",ja:"彼のコメントは観客から怒った反応を引き起こした。",wrong:["彼のコメントは観客を感動させた。","彼のコメントは観客を喜ばせた。","彼のコメントは観客に質問させた。"]},{en:"The incident provoked a diplomatic crisis between the nations.",ja:"その事件は国家間の外交危機を引き起こした。",wrong:["その事件は国家間の協力を促進した。","その事件は国家間の友好関係を深めた。","その事件は国家間の交渉を開始した。"]},{en:"They deliberately tried to provoke a fight.",ja:"彼らは意図的に喧嘩を挑発しようとした。",wrong:["彼らは意図的に平和を求めた。","彼らは意図的に議論を避けた。","彼らは意図的に和解を提案した。"]}]},{word:"proximity",meaning:"近接",example:"The hotel is valued for its proximity to the station.",category:"society",difficulty:5,examples:[{en:"The proximity of the school to the park was convenient for students.",ja:"学校から公園への近接は学生にとって便利だった。",wrong:["学校から公園への距離は学生にとって便利だった。","学校から公園への位置は学生にとって便利だった。","学校から公園への接続は学生にとって便利だった。"]},{en:"Due to proximity, the two cities have similar cultures.",ja:"近接のため、2つの都市は同様の文化を持つ。",wrong:["接触のため、2つの都市は同様の文化を持つ。","関係のため、2つの都市は同様の文化を持つ。","交易のため、2つの都市は同様の文化を持つ。"]},{en:"The proximity alarm warned of danger nearby.",ja:"近接アラームは近くの危険を警告した。",wrong:["距離警報は遠くの危険を警告した。","感知アラームは周囲の危険を警告した。","警戒警報は外部の危険を警告した。"]}]},{word:"pursuit",meaning:"追求",example:"She dedicated her life to the pursuit of knowledge.",category:"society",difficulty:3,examples:[{en:"He dedicated his life to the pursuit of knowledge.",ja:"彼は知識の追求に人生を捧げた。",wrong:["彼は知識の習得に人生を捧げた。","彼は知識の学習に人生を捧げた。","彼は知識の研究に人生を捧げた。"]},{en:"The police started a pursuit of the fleeing suspect.",ja:"警察は逃げ去る容疑者の追求を開始した。",wrong:["警察は逃げ去る容疑者の追跡を開始した。","警察は逃げ去る容疑者の逮捕を開始した。","警察は逃げ去る容疑者の捜査を開始した。"]},{en:"The pursuit of happiness is a common goal.",ja:"幸福の追求は一般的な目標である。",wrong:["幸福の探求は一般的な目標である。","幸福の達成は一般的な目標である。","幸福の実現は一般的な目標である。"]}]},{word:"quota",meaning:"割当量",example:"Fishing quotas were introduced to protect stocks.",category:"current",difficulty:4,examples:[{en:"The company set a sales quota of $1 million per quarter.",ja:"会社は四半期ごとに100万ドルの販売割当量を設定した。",wrong:["会社は四半期ごとに100万ドルの販売目標を設定した。","会社は四半期ごとに100万ドルの販売予算を設定した。","会社は四半期ごとに100万ドルの販売計画を設定した。"]},{en:"Each department has a production quota.",ja:"各部門には生産割当量がある。",wrong:["各部門には生産目標がある。","各部門には生産計画がある。","各部門には生産基準がある。"]},{en:"The government implemented an immigration quota.",ja:"政府は移民割当量を実施した。",wrong:["政府は移民制限を実施した。","政府は移民政策を実施した。","政府は移民規制を実施した。"]}]},{word:"radical",meaning:"急進的な、根本的な",example:"Radical reforms are needed to fix the system.",category:"society",difficulty:3,examples:[{en:"The radical reform changed the entire system.",ja:"根本的な改革はシステム全体を変えた。",wrong:["急進的な改革はシステムの一部を変えた。","急速な改革はシステム全体を改善した。","革新的な改革はシステムの構造を変えた。"]},{en:"His radical ideas were considered controversial.",ja:"彼の急進的な考えは物議を醸すと考えられていた。",wrong:["彼の根本的な考えは物議を醸すと考えられていた。","彼の革新的な考えは物議を醸すと考えられていた。","彼の進歩的な考えは物議を醸すと考えられていた。"]},{en:"The organization took a radical approach to problem-solving.",ja:"その組織は問題解決に対する根本的なアプローチを取った。",wrong:["その組織は問題解決に対する創造的なアプローチを取った。","その組織は問題解決に対する新しいアプローチを取った。","その組織は問題解決に対する効果的なアプローチを取った。"]}]},{word:"ratify",meaning:"批准する",example:"All member states must ratify the treaty.",category:"society",difficulty:5,examples:[{en:"The senate will ratify the treaty next month.",ja:"上院は来月条約を批准するだろう。",wrong:["上院は来月条約に署名するだろう。","上院は来月条約を提案するだろう。","上院は来月条約を交渉するだろう。"]},{en:"The country ratified the international agreement.",ja:"その国は国際協定を批准した。",wrong:["その国は国際協定に署名した。","その国は国際協定を提案した。","その国は国際協定を承認した。"]},{en:"All states must ratify the amendment for it to become law.",ja:"すべての州が法律として有効になるために修正案を批准しなければならない。",wrong:["すべての州が法律として有効になるために修正案に投票しなければならない。","すべての州が法律として有効になるために修正案を投票しなければならない。","すべての州が法律として有効になるために修正案を討論しなければならない。"]}]},{word:"rational",meaning:"合理的な",example:"We need a rational approach to the problem.",category:"science",difficulty:3,examples:[{en:"She made a rational decision based on facts.",ja:"彼女は事実に基づいて合理的な決定をした。",wrong:["彼女は感情に基づいて合理的な決定をした。","彼女は直感に基づいて合理的な決定をした。","彼女は経験に基づいて合理的な決定をした。"]},{en:"His rational explanation convinced everyone.",ja:"彼の合理的な説明はみんなを納得させた。",wrong:["彼の感情的な説明はみんなを納得させた。","彼の詳細な説明はみんなを納得させた。","彼の論理的な説明はみんなを納得させた。"]},{en:"The company used rational thinking to solve the problem.",ja:"会社は問題を解決するために合理的な思考を使用した。",wrong:["会社は問題を解決するために創造的な思考を使用した。","会社は問題を解決するために批判的な思考を使用した。","会社は問題を解決するために戦略的な思考を使用した。"]}]},{word:"realm",meaning:"領域、王国",example:"This falls outside the realm of science.",category:"society",difficulty:4,examples:[{en:"The king ruled over his realm with wisdom.",ja:"王は知恵を持って彼の王国を統治した。",wrong:["王は力で彼の領土を統治した。","王は法律で彼の領域を統治した。","王は軍隊で彼の支配地を統治した。"]},{en:"In the realm of science, new discoveries are made daily.",ja:"科学の領域では、新しい発見が毎日なされている。",wrong:["科学の分野では、新しい発見が毎日なされている。","科学の領土では、新しい発見が毎日なされている。","科学の界では、新しい発見が毎日なされている。"]},{en:"The realm of possibilities is endless.",ja:"可能性の領域は無限である。",wrong:["可能性の世界は無限である。","可能性の範囲は無限である。","可能性の領土は無限である。"]}]},{word:"reckon",meaning:"推測する",example:"Experts reckon the economy will grow by two percent.",category:"current",difficulty:3,examples:[{en:"I reckon that the project will take three months.",ja:"私はそのプロジェクトに3ヶ月かかると推測する。",wrong:["私はそのプロジェクトに3ヶ月かかると計算する。","私はそのプロジェクトに3ヶ月かかると予測する。","私はそのプロジェクトに3ヶ月かかると見積もる。"]},{en:"She reckons that he is the best candidate.",ja:"彼女は彼が最適な候補者だと推測する。",wrong:["彼女は彼が最適な候補者だと決定する。","彼女は彼が最適な候補者だと信じる。","彼女は彼が最適な候補者だと判断する。"]},{en:"They reckon the cost will be around $5000.",ja:"彼らはコストが約5000ドルになると推測する。",wrong:["彼らはコストが約5000ドルになると計算する。","彼らはコストが約5000ドルになると見積もる。","彼らはコストが約5000ドルになると確認する。"]}]},{word:"reconcile",meaning:"和解する、一致させる",example:"It is difficult to reconcile these conflicting views.",category:"society",difficulty:5,examples:[{en:"The two countries reconciled their differences.",ja:"2つの国は彼らの違いを和解した。",wrong:["2つの国は彼らの違いを解決した。","2つの国は彼らの違いを話し合った。","2つの国は彼らの違いを理解した。"]},{en:"I need to reconcile my bank account with my records.",ja:"私は銀行口座を記録と一致させる必要がある。",wrong:["私は銀行口座を検査する必要がある。","私は銀行口座を確認する必要がある。","私は銀行口座を更新する必要がある。"]},{en:"They finally reconciled after years of conflict.",ja:"彼らは長年の対立の後ついに和解した。",wrong:["彼らは長年の対立の後ついに合意した。","彼らは長年の対立の後ついに協力した。","彼らは長年の対立の後ついに仲直りした。"]}]},{word:"reform",meaning:"改革する",example:"The president promised to reform the tax system.",category:"society",difficulty:3,examples:[{en:"The government implemented educational reform.",ja:"政府は教育改革を実施した。",wrong:["政府は教育改善を実施した。","政府は教育改定を実施した。","政府は教育変更を実施した。"]},{en:"The criminal was reformed through rehabilitation programs.",ja:"犯罪者は更生プログラムを通じて改革された。",wrong:["犯罪者は更生プログラムを通じて矯正された。","犯罪者は更生プログラムを通じて改善された。","犯罪者は更生プログラムを通じて変化した。"]},{en:"The company decided to reform its management structure.",ja:"会社は経営構造を改革することを決定した。",wrong:["会社は経営構造を変更することを決定した。","会社は経営構造を改善することを決定した。","会社は経営構造を修正することを決定した。"]}]},{word:"refrain",meaning:"控える",example:"Please refrain from using mobile phones.",category:"society",difficulty:4,examples:[{en:"I will refrain from eating dessert to stay healthy.",ja:"健康のためにデザートを食べるのを控える。",wrong:["私はデザートを食べることを強制する","デザートを食べることを忘れる","デザートを拒否する"]},{en:"Please refrain from smoking in this area.",ja:"この区域での喫煙をご遠慮ください。",wrong:["このエリアでタバコを吸ってください","喫煙を推奨します","タバコの匂いを嗅ぐ"]},{en:"She refrained from commenting on the controversial topic.",ja:"彼女は物議をかもしている話題についてのコメントを控えた。",wrong:["彼女は話題について詳しく議論した","彼女は批判を浴びせた","彼女は意見を強制した"]}]},{word:"regime",meaning:"政権、体制",example:"The authoritarian regime suppressed dissent.",category:"history",difficulty:4,examples:[{en:"The authoritarian regime was overthrown by the people.",ja:"独裁政権は国民によって打倒された。",wrong:["独裁政権は強化された","政権は民主的だった","政権は人気があった"]},{en:"She follows a strict exercise regime to maintain fitness.",ja:"彼女は体を維持するために厳しい運動体制を守っている。",wrong:["彼女は運動をしない","彼女はランダムに運動する","体制は緩い"]},{en:"The new regime implemented reforms in the healthcare system.",ja:"新しい体制は医療制度に改革を実施した。",wrong:["体制は何も変わらなかった","医療システムは廃止された","改革は反対された"]}]},{word:"reinforce",meaning:"強化する",example:"The training reinforced what they learned in class.",category:"society",difficulty:3,examples:[{en:"We need to reinforce the walls to make the building safer.",ja:"建物をより安全にするために壁を補強する必要がある。",wrong:["壁を弱くする","建物を破壊する","安全性を減らす"]},{en:"The teacher reinforced the lesson by repeating the key concepts.",ja:"先生は重要な概念を繰り返すことで、レッスンを強化した。",wrong:["先生は概念を忘れた","レッスンは簡単にされた","先生は説明をやめた"]},{en:"Positive feedback reinforces good behavior in children.",ja:"ポジティブなフィードバックは子どもの良い行動を強化する。",wrong:["ネガティブなフィードバックは良い行動を増やす","子どもの行動は無視される","フィードバックは無関係だ"]}]},{word:"relevance",meaning:"関連性",example:"The study questions the relevance of the findings.",category:"science",difficulty:4,examples:[{en:"The relevance of this research to modern medicine is undeniable.",ja:"この研究の現代医学への関連性は否定できない。",wrong:["この研究は無関係だ","医学への接続がない","研究は古い"]},{en:"Social media has increased in relevance for marketing strategies.",ja:"ソーシャルメディアはマーケティング戦略において関連性が増した。",wrong:["ソーシャルメディアはマーケティングに無関係だ","関連性は減少した","マーケティングには影響がない"]},{en:"The relevance of classical literature to today's students is debated.",ja:"古典文学の今日の学生への関連性は議論されている。",wrong:["古典文学は時代遅れだ","学生には無関係だ","議論は必要ない"]}]},{word:"reliance",meaning:"依存",example:"Our reliance on fossil fuels must decrease.",category:"current",difficulty:4,examples:[{en:"Many developing countries have a heavy reliance on foreign aid.",ja:"多くの開発途上国は海外援助に大きく依存している。",wrong:["開発途上国は援助を必要としない","依存は軽い","海外援助は不要だ"]},{en:"The company's reliance on a single supplier is risky.",ja:"その企業は単一のサプライヤーへの依存が危険だ。",wrong:["複数のサプライヤーに依存する","リスクはない","供給は安定している"]},{en:"I'm trying to reduce my reliance on caffeine.",ja:"カフェインへの依存を減らそうとしている。",wrong:["カフェインに依存を増やす","カフェインは不要だ","依存は重要ではない"]}]},{word:"reluctant",meaning:"気が進まない",example:"He was reluctant to accept the offer.",category:"society",difficulty:3,examples:[{en:"He was reluctant to admit his mistake to the manager.",ja:"彼はマネージャーに自分の過ちを認めることに気が進まなかった。",wrong:["彼は喜んで過ちを認めた","彼は積極的だった","彼は急いで話した"]},{en:"The students were reluctant to participate in the group project.",ja:"学生たちはグループプロジェクトに参加することに気が進まなかった。",wrong:["学生たちは熱心に参加した","参加に興奮していた","躊躇がなかった"]},{en:"She gave a reluctant smile at the joke.",ja:"彼女はそのジョークに気の進まない笑顔を浮かべた。",wrong:["彼女は心から笑った","彼女は大笑いした","彼女は喜んで笑った"]}]},{word:"remedy",meaning:"治療法、改善策",example:"There is no simple remedy for the problem.",category:"society",difficulty:3,examples:[{en:"A good night's sleep is often the best remedy for fatigue.",ja:"よく寝ることは疲労の最良の治療法であることが多い。",wrong:["睡眠は疲労を増やす","治療法ではない","疲労を悪化させる"]},{en:"The government is working to remedy the housing shortage.",ja:"政府は住宅不足を改善するために取り組んでいる。",wrong:["政府は問題を無視している","改善策はない","状況は悪くなっている"]},{en:"There is a legal remedy available for breach of contract.",ja:"契約違反に対する法的救済がある。",wrong:["法的救済はない","契約は保護されない","救済は不可能だ"]}]},{word:"render",meaning:"〜にする、提供する",example:"The new regulation rendered the old one obsolete.",category:"society",difficulty:4,examples:[{en:"The artist will render the design in three dimensions.",ja:"アーティストはデザインを3次元で表現する。",wrong:["デザインは平らなままだ","表現されない","削除される"]},{en:"The accident rendered him unable to work for months.",ja:"その事故により、彼は数ヶ月間働けなくなった。",wrong:["事故後、彼はすぐに仕事に戻った","能力は失われなかった","彼は元気だった"]},{en:"The company will render its services to the client.",ja:"その企業はクライアントにサービスを提供する。",wrong:["サービスは提供されない","企業は拒否する","クライアントは必要ない"]}]},{word:"repeal",meaning:"廃止する",example:"The law was repealed after widespread protests.",category:"society",difficulty:5,examples:[{en:"The government decided to repeal the controversial law.",ja:"政府は物議をかもしている法律を廃止することを決めた。",wrong:["法律は強化された","廃止されなかった","法律は新しくされた"]},{en:"Many activists are calling for the repeal of outdated regulations.",ja:"多くの活動家は時代遅れの規制の廃止を求めている。",wrong:["規制は強化されている","廃止は不可能だ","規制は現代的だ"]},{en:"The previous administration's policies were repealed by the new government.",ja:"前政権の政策は新しい政府によって廃止された。",wrong:["政策は維持された","新政府は同意した","政策は強化された"]}]},{word:"replenish",meaning:"補充する",example:"We need to replenish our food supplies.",category:"society",difficulty:4,examples:[{en:"We need to replenish our water supply before the dry season.",ja:"乾季の前に水の供給を補充する必要がある。",wrong:["水を減らす","補充は不要だ","乾季は来ない"]},{en:"The store replenished its shelves with new inventory.",ja:"その店は新しい在庫で棚を補充した。",wrong:["棚は空のままだ","在庫は売られた","補充されなかった"]},{en:"Athletes replenish their energy with sports drinks after exercise.",ja:"運動後、選手たちはスポーツドリンクでエネルギーを補充する。",wrong:["エネルギーは減ったままだ","飲料は役に立たない","補充は必要ない"]}]},{word:"reproduce",meaning:"再現する、繁殖する",example:"Bacteria reproduce rapidly in warm conditions.",category:"science",difficulty:3,examples:[{en:"The artist tried to reproduce the original painting exactly.",ja:"アーティストは元の絵画を正確に再現しようとした。",wrong:["絵画は変更された","再現されなかった","オリジナルは無視された"]},{en:"Rabbits reproduce quickly in ideal conditions.",ja:"理想的な条件ではウサギは急速に繁殖する。",wrong:["ウサギは繁殖しない","増殖は遅い","条件は関係ない"]},{en:"The study reproduced the results of the previous experiment.",ja:"その研究は前の実験の結果を再現した。",wrong:["結果は異なっていた","再現は失敗した","実験は無関係だ"]}]},{word:"resemble",meaning:"似ている",example:"The child resembles her mother closely.",category:"society",difficulty:3,examples:[{en:"The daughter resembles her mother in appearance.",ja:"娘は外見で母親に似ている。",wrong:["娘は母親と異なる","似ていない","外見は関係ない"]},{en:"This cake resembles the one I ate in Paris.",ja:"このケーキはパリで食べたものに似ている。",wrong:["ケーキは異なる","パリのものと関連がない","似ていない"]},{en:"The new office building resembles a modern art sculpture.",ja:"新しいオフィスビルは現代美術彫刻に似ている。",wrong:["建物は古い","彫刻と異なる","外観は無関係だ"]}]},{word:"reside",meaning:"居住する",example:"They reside in a suburb of Tokyo.",category:"society",difficulty:4,examples:[{en:"My grandparents reside in a small village in the countryside.",ja:"祖父母は田舎の小さな村に住んでいる。",wrong:["祖父母は都市に住んでいる","村を離れた","住んでいない"]},{en:"The president resides in the official government residence.",ja:"大統領は公式な政府官邸に居住している。",wrong:["大統領は官邸に住んでいない","別の場所に住んでいる","居住地は不明だ"]},{en:"Many international students reside in university dormitories.",ja:"多くの留学生は大学の寮に居住している。",wrong:["学生は寮にいない","居住地は大学外だ","寮は使用されていない"]}]},{word:"resilient",meaning:"回復力のある",example:"Children are remarkably resilient.",category:"science",difficulty:4,examples:[{en:"The resilient community rebuilt after the natural disaster.",ja:"回復力のあるコミュニティは自然災害後に再建した。",wrong:["コミュニティは脆弱だった","再建されなかった","災害から回復しなかった"]},{en:"Resilient materials can withstand repeated stress without breaking.",ja:"回復力のある材料は繰り返されるストレスに耐えることができる。",wrong:["材料は脆い","ストレスに耐えられない","壊れやすい"]},{en:"A resilient mindset helps people overcome difficult challenges.",ja:"回復力のある心構えは人々が困難な課題を乗り越えるのに役立つ。",wrong:["心構えは脆い","困難に対処できない","強さは必要ない"]}]},{word:"resolve",meaning:"解決する、決意する",example:"The committee resolved the dispute amicably.",category:"society",difficulty:3,examples:[{en:"The mediator helped resolve the conflict between the two parties.",ja:"仲介者は2つの当事者間の紛争を解決するのを助けた。",wrong:["紛争は解決されなかった","対立は続いた","仲介は失敗した"]},{en:"She resolved to exercise regularly and eat healthier.",ja:"彼女は定期的に運動し、より健康的に食べることを決意した。",wrong:["彼女は何も決めなかった","決意は弱かった","目標はない"]},{en:"The company resolved the technical issue within hours.",ja:"その企業は技術的な問題を数時間以内に解決した。",wrong:["問題は解決されなかった","時間がかかった","技術者は何もしなかった"]}]},{word:"resort",meaning:"訴える、リゾート",example:"We must resolve this without resorting to violence.",category:"society",difficulty:3,examples:[{en:"We decided to resort to drastic measures when all other options failed.",ja:"他のすべての選択肢が失敗したとき、私たちは抜本的な対策に訴えることにしました。",wrong:["私たちはビーチリゾートに行くことに決めました。","彼は最後の手段として逃げることにしました。","その政策はリゾート地で実施されました。"]},{en:"The luxury resort offers spectacular ocean views and world-class amenities.",ja:"その豪華なリゾートは素晴らしい海の景色と世界水準の設備を提供しています。",wrong:["彼は困ったときに訴えることを選びました。","その会社は強い対策に頼りました。","リゾートは法的に認可されました。"]},{en:"If negotiations fail, we may have to resort to legal action.",ja:"交渉が失敗した場合、法的措置に訴えなければならないかもしれません。",wrong:["私たちはリゾート地に法律を適用しました。","交渉はリゾートで行われました。","彼らは観光地に逃げました。"]}]},{word:"restrain",meaning:"抑制する",example:"Police restrained the aggressive protestor.",category:"society",difficulty:3,examples:[{en:"The police officer had to restrain the aggressive suspect.",ja:"警察官は攻撃的な容疑者を抑制しなければなりませんでした。",wrong:["警察官は容疑者に訓練を与えました。","警察官は容疑者を解放しました。","警察官は容疑者を励ましました。"]},{en:"She had to restrain her emotions during the funeral.",ja:"彼女は葬式の間、自分の感情を抑制しなければなりませんでした。",wrong:["彼女は葬式で感情を表現しました。","彼女は感情を増幅させました。","彼女は感情に従いました。"]},{en:"The budget constraints will restrain our spending this year.",ja:"予算の制約は今年の支出を抑制するでしょう。",wrong:["予算は支出を増やすでしょう。","予算は支出を許可するでしょう。","予算は支出を促進するでしょう。"]}]},{word:"restrict",meaning:"制限する",example:"Access to the building is restricted to staff.",category:"society",difficulty:3,examples:[{en:"The government will restrict access to certain classified documents.",ja:"政府は特定の機密文書へのアクセスを制限するでしょう。",wrong:["政府は文書へのアクセスを許可するでしょう。","政府は文書を公開するでしょう。","政府は文書へのアクセスを促進するでしょう。"]},{en:"The doctor told him to restrict his salt intake.",ja:"医者は彼に塩分摂取を制限するよう言いました。",wrong:["医者は彼に塩分をもっと摂取するよう言いました。","医者は彼に塩分について訓練するよう言いました。","医者は彼に塩分を逃げるよう言いました。"]},{en:"This membership restricts your access to premium features only.",ja:"このメンバーシップはあなたのアクセスをプレミアム機能のみに制限します。",wrong:["このメンバーシップはあなたにすべての機能へのアクセスを許可します。","このメンバーシップはあなたのアクセスを拡大します。","このメンバーシップはあなたのアクセスを無制限にします。"]}]},{word:"retain",meaning:"保持する",example:"The company retained its market share.",category:"current",difficulty:3,examples:[{en:"The company decided to retain all of its current employees.",ja:"その会社は現在のすべての従業員を保持することに決めました。",wrong:["その会社はすべての従業員を解雇することに決めました。","その会社は従業員を失うことに決めました。","その会社は従業員を制限することに決めました。"]},{en:"The sponge retained water even after being squeezed.",ja:"スポンジは絞られた後でも水を保持していました。",wrong:["スポンジは水を失いました。","スポンジは水を放出しました。","スポンジは水を制限しました。"]},{en:"She tried to retain her dignity throughout the scandal.",ja:"彼女はスキャンダル全体を通じて自分の尊厳を保持しようとしました。",wrong:["彼女は尊厳を失いました。","彼女は尊厳を破壊しました。","彼女は尊厳を制限しました。"]}]},{word:"retrieve",meaning:"取り戻す",example:"Divers retrieved the wreckage from the seabed.",category:"technology",difficulty:4,examples:[{en:"I need to retrieve my phone from my car.",ja:"私は車から携帯電話を取り戻す必要があります。",wrong:["私は車に携帯電話を置きました。","私は携帯電話を失いました。","私は携帯電話を捨てました。"]},{en:"The rescue team retrieved the survivors from the wreckage.",ja:"救助隊は瓦礫から生存者を取り戻しました。",wrong:["救助隊は生存者を瓦礫に置きました。","救助隊は生存者を見つけることができませんでした。","救助隊は生存者を制限しました。"]},{en:"The dog was trained to retrieve the newspaper from the driveway.",ja:"その犬は車道から新聞を取り戻すように訓練されていました。",wrong:["その犬は新聞を破壊するように訓練されていました。","その犬は新聞を隠すように訓練されていました。","その犬は新聞を失うように訓練されていました。"]}]},{word:"reveal",meaning:"明らかにする",example:"The investigation revealed widespread fraud.",category:"society",difficulty:3,examples:[{en:"The investigation will reveal the truth about the incident.",ja:"その調査は事件の真実を明らかにするでしょう。",wrong:["その調査は真実を隠すでしょう。","その調査は真実を制限するでしょう。","その調査は真実を曇らすでしょう。"]},{en:"She decided to reveal her secret identity at the climax of the movie.",ja:"彼女は映画のクライマックスで自分の秘密のアイデンティティを明らかにすることに決めました。",wrong:["彼女はアイデンティティをさらに隠すことに決めました。","彼女はアイデンティティを保護することに決めました。","彼女はアイデンティティを制限することに決めました。"]},{en:"The X-ray will reveal any fractures in the bone.",ja:"X線は骨のすべての骨折を明らかにするでしょう。",wrong:["X線は骨折を隠すでしょう。","X線は骨折を見つけられないでしょう。","X線は骨折を制限するでしょう。"]}]},{word:"revenue",meaning:"歳入、収益",example:"Tax revenue funds public services.",category:"society",difficulty:3,examples:[{en:"The company's annual revenue increased by 20% this year.",ja:"その会社の年間収益は今年20%増加しました。",wrong:["その会社の支出は20%増加しました。","その会社の利益は減少しました。","その会社の収益は制限されました。"]},{en:"Tourism is a major source of revenue for the country.",ja:"観光はその国の収益の主な源です。",wrong:["観光はその国の支出です。","観光はその国の損失です。","観光はその国の制限です。"]},{en:"The tax revenue collected this quarter was lower than expected.",ja:"この四半期に徴収された税収は予想より低かった。",wrong:["税収は予想より高かった。","税収は制限されました。","税収は失われました。"]}]},{word:"rhetoric",meaning:"修辞学、弁論術",example:"His speech was full of political rhetoric.",category:"society",difficulty:5,examples:[{en:"The politician's rhetoric was more focused on emotions than facts.",ja:"その政治家の修辞学は事実よりも感情に焦点を当てていました。",wrong:["その政治家の修辞学は事実に焦点を当てていました。","その政治家の修辞学は論理に焦点を当てていました。","その政治家の修辞学は真実に焦点を当てていました。"]},{en:"The professor teaches rhetoric and public speaking to her students.",ja:"その教授は学生に修辞学と公開演説を教えています。",wrong:["その教授は学生に沈黙を教えています。","その教授は学生に嘘を教えています。","その教授は学生に隠蔽を教えています。"]},{en:"Effective rhetoric can persuade people to support your cause.",ja:"効果的な修辞学は人々をあなたの大義を支持するよう説得することができます。",wrong:["修辞学は人々を混乱させます。","修辞学は事実を不明確にします。","修辞学は人々を制限します。"]}]},{word:"rigid",meaning:"硬い、厳格な",example:"The school enforces rigid discipline.",category:"society",difficulty:3,examples:[{en:"The rigid structure of the building can withstand earthquakes.",ja:"その建物の厳格な構造は地震に耐えることができます。",wrong:["その建物の柔軟な構造は地震に耐えます。","その建物は柔らかいです。","その建物は制限されています。"]},{en:"His rigid rules left no room for flexibility or creativity.",ja:"彼の厳格なルールは柔軟性または創造性の余地を残しませんでした。",wrong:["彼の規則は非常に柔軟でした。","彼の規則は創造性を促進しました。","彼の規則は制限を除去しました。"]},{en:"The rigid material is difficult to bend or shape.",ja:"その硬い材料は曲げたり形作ったりするのが難しいです。",wrong:["その材料は非常に柔軟です。","その材料は簡単に曲がります。","その材料は流動的です。"]}]},{word:"robust",meaning:"頑丈な、堅固な",example:"The economy showed robust growth last quarter.",category:"current",difficulty:4,examples:[{en:"The software is designed to be robust and reliable.",ja:"そのソフトウェアは堅固で信頼できるように設計されています。",wrong:["そのソフトウェアは脆弱です。","そのソフトウェアは不安定です。","そのソフトウェアは信頼できません。"]},{en:"He has a robust constitution and rarely gets sick.",ja:"彼は丈夫な体をしており、めったに病気になりません。",wrong:["彼は病弱です。","彼はいつも病気です。","彼の健康は制限されています。"]},{en:"The company has a robust business model that can adapt to market changes.",ja:"その会社は市場の変化に適応できる堅固なビジネスモデルを持っています。",wrong:["その会社のビジネスモデルは脆弱です。","その会社のビジネスモデルは柔軟性がありません。","その会社のビジネスモデルは失敗しやすいです。"]}]},{word:"ruthless",meaning:"冷酷な",example:"The dictator was ruthless in suppressing opposition.",category:"history",difficulty:4,examples:[{en:"The ruthless dictator showed no mercy to his political opponents.",ja:"その冷酷な独裁者は政敵に慈悲を示しませんでした。",wrong:["その独裁者は非常に同情的でした。","その独裁者は慈悲深かった。","その独裁者は優しかった。"]},{en:"In business, she is known for her ruthless pursuit of profits.",ja:"ビジネスでは、彼女は利益の冷酷な追求で知られています。",wrong:["ビジネスでは、彼女は同情的です。","彼女は利益を無視しています。","彼女は人道的なビジネスに専念しています。"]},{en:"The ruthless criminal showed no remorse for his crimes.",ja:"その冷酷な犯人は自分の犯罪に対して後悔の念を示しませんでした。",wrong:["その犯人は深く後悔していました。","その犯人は同情を示しました。","その犯人は慈悲を願いました。"]}]},{word:"sabotage",meaning:"妨害工作",example:"The factory was shut down by an act of sabotage.",category:"society",difficulty:4,examples:[{en:"The competitor tried to sabotage our project by stealing our designs.",ja:"その競合他社は私たちの設計を盗むことで私たちのプロジェクトを妨害しようとしました。",wrong:["その競合他社は私たちのプロジェクトを支援しました。","その競合他社は私たちと協力しました。","その競合他社は私たちの設計を保護しました。"]},{en:"During the war, resistance fighters were trained in sabotage operations.",ja:"戦争中、抵抗勢力は妨害工作作戦の訓練を受けました。",wrong:["抵抗勢力は平和的な交渉を訓練されました。","抵抗勢力は支援活動を訓練されました。","抵抗勢力は協力を訓練されました。"]},{en:"She accidentally discovered evidence of sabotage in the machinery.",ja:"彼女は機械の妨害工作の証拠を偶然発見しました。",wrong:["彼女は機械の修理の証拠を発見しました。","彼女は機械の改善の証拠を発見しました。","彼女は機械の保護の証拠を発見しました。"]}]},{word:"safeguard",meaning:"保護する",example:"Laws safeguard the rights of consumers.",category:"society",difficulty:3,examples:[{en:"Strong passwords are essential to safeguard your personal information.",ja:"強力なパスワードは個人情報を保護するために不可欠です。",wrong:["パスワードは個人情報を危険にさらします。","パスワードは情報を公開します。","パスワードは情報を盗みやすくします。"]},{en:"The government implemented new laws to safeguard the rights of citizens.",ja:"政府は市民の権利を保護するために新しい法律を実施しました。",wrong:["政府は市民の権利を侵害する法律を実施しました。","政府は市民の権利を制限しました。","政府は市民の権利を削除しました。"]},{en:"Medical staff must safeguard patient confidentiality at all times.",ja:"医療スタッフは常に患者の機密性を保護する必要があります。",wrong:["医療スタッフは患者の情報を公開できます。","医療スタッフは患者の秘密を暴露する必要があります。","医療スタッフは患者の情報を危険にさらします。"]}]},{word:"sanction",meaning:"制裁、認可",example:"Economic sanctions were imposed on the country.",category:"current",difficulty:4,examples:[{en:"The international community imposed economic sanctions on the country.",ja:"国際社会はその国に経済的制裁を課しました。",wrong:["国際社会は経済的サポートを提供しました。","国際社会は支援を認可しました。","国際社会は協力を促進しました。"]},{en:"The coach refused to sanction the player's aggressive behavior.",ja:"コーチは選手の攻撃的な行動を認可することを拒否しました。",wrong:["コーチは行動を許可しました。","コーチは行動を支援しました。","コーチは行動を奨励しました。"]},{en:"The university will sanction students who violate the academic integrity code.",ja:"大学は学問的誠実さのコードに違反する学生に制裁を課すでしょう。",wrong:["大学は違反を許可するでしょう。","大学は違反を奨励するでしょう。","大学は違反に報酬を与えるでしょう。"]}]},{word:"saturate",meaning:"飽和させる",example:"The market is saturated with cheap imports.",category:"current",difficulty:5,examples:[{en:"The heavy rain will saturate the soil.",ja:"大雨は土壌を飽和させるでしょう。",wrong:["大雨は土壌を乾燥させるでしょう。","大雨は土壌を枯らすでしょう。","大雨は土壌の水分を減らすでしょう。"]},{en:"The market is saturated with similar products from competing brands.",ja:"市場は競合ブランドからの類似製品で飽和しています。",wrong:["市場は製品が不足しています。","市場は製品の需要が高いです。","市場は製品で枯れています。"]},{en:"The sponge was completely saturated with water.",ja:"スポンジは完全に水で飽和していました。",wrong:["スポンジは乾燥していました。","スポンジは水を失いました。","スポンジは空でした。"]}]},{word:"scaffold",meaning:"足場、骨組み",example:"Scaffolding was erected around the building.",category:"technology",difficulty:4,examples:[{en:"The workers built a metal scaffold around the building for repairs.",ja:"作業員は建物の修理のために周りに金属製の足場を組んだ。",wrong:["The workers destroyed a metal scaffold around the building.","The workers painted a metal scaffold inside the building.","The workers removed all scaffolds before starting repairs."]},{en:"The novel's plot provided a scaffold for exploring complex themes.",ja:"この小説のプロットは複雑なテーマを探索するための骨組みを提供した。",wrong:["The novel's plot destroyed a scaffold for exploring themes.","The novel's character was a scaffold that appeared once.","The scaffold prevented any themes from being explored."]},{en:"Educational scaffolding helps students build their knowledge gradually.",ja:"教育的な足場がけは学生が段階的に知識を構築するのを助ける。",wrong:["Educational scaffolding prevents students from learning gradually.","Scaffolding removes all knowledge from students.","Students build scaffolds instead of learning."]}]},{word:"scarce",meaning:"乏しい",example:"Clean water is scarce in many parts of the world.",category:"current",difficulty:3,examples:[{en:"Water is scarce in desert regions, making it precious.",ja:"砂漠地域では水が乏しく、非常に貴重である。",wrong:["Water is abundant in desert regions.","Water is scarce in ocean regions.","Desert regions have plenty of water."]},{en:"Skilled workers are scarce in this industry right now.",ja:"この業界では熟練した労働者が乏しい。",wrong:["Skilled workers are abundant in this industry.","Unskilled workers are scarce in this industry.","This industry has too many skilled workers."]},{en:"During the pandemic, face masks became scarce and expensive.",ja:"パンデミック中、マスクは乏しくなり、高くなった。",wrong:["During the pandemic, face masks became abundant.","Face masks were scarce before the pandemic.","Masks became cheaper and more available."]}]},{word:"scenario",meaning:"シナリオ",example:"In the worst-case scenario, the dam could break.",category:"science",difficulty:3,examples:[{en:"In the worst-case scenario, the company could lose its entire investment.",ja:"最悪のシナリオでは、企業全体の投資が失われる可能性がある。",wrong:["In the worst-case scenario, the company would gain profit.","Scenarios are not used in business planning.","The best-case scenario is the worst outcome."]},{en:"The disaster recovery plan outlines several scenarios for different emergencies.",ja:"災害復旧計画は、異なる緊急事態のためのいくつかのシナリオを概説している。",wrong:["The disaster recovery plan has no scenarios.","Scenarios are only for entertainment purposes.","Emergency situations don't need scenarios."]},{en:"Let me describe a hypothetical scenario where you win the lottery.",ja:"あなたが宝くじに当たる架空のシナリオを説明させてください。",wrong:["Hypothetical scenarios are based on real events.","A scenario cannot be imaginary.","Lottery winnings are not part of any scenario."]}]},{word:"scope",meaning:"範囲",example:"The scope of the investigation was expanded.",category:"society",difficulty:3,examples:[{en:"The scope of this project includes marketing, design, and development.",ja:"このプロジェクトの範囲は、マーケティング、デザイン、開発を含む。",wrong:["The scope of this project excludes all tasks.","Marketing is outside the scope of the project.","The project has no defined scope."]},{en:"The investigation's scope was limited to the accounting department.",ja:"調査の範囲は会計部門に限定された。",wrong:["The investigation's scope included all departments.","There was no limit to the investigation's scope.","The accounting department was excluded from scope."]},{en:"This research has a global scope and involves multiple countries.",ja:"この研究は世界的な範囲を持ち、複数の国を含む。",wrong:["This research has a local scope only.","The scope excludes international countries.","Global research has a narrow scope."]}]},{word:"scrutiny",meaning:"精査",example:"The accounts were subjected to close scrutiny.",category:"society",difficulty:5,examples:[{en:"The financial records underwent careful scrutiny by the auditors.",ja:"財務記録は監査人による慎重な精査を受けた。",wrong:["The financial records avoided scrutiny.","Auditors don't scrutinize records carefully.","The records were not examined at all."]},{en:"Under public scrutiny, the politician had to explain her decisions.",ja:"公開の精査の下で、政治家は彼女の決定を説明しなければならなかった。",wrong:["Public scrutiny allows hiding decisions.","Politicians don't face public examination.","Scrutiny prevents explanation of decisions."]},{en:"Every detail of the contract came under scrutiny before signing.",ja:"契約の細部はすべて署名前に精査された。",wrong:["No details were examined before signing.","Scrutiny prevents contract review.","Details are signed without examination."]}]},{word:"secular",meaning:"世俗の",example:"The country adopted a secular constitution.",category:"society",difficulty:5,examples:[{en:"The government promotes secular education that is independent of religion.",ja:"政府は宗教から独立した世俗的な教育を推進している。",wrong:["Secular education is based on religion.","Government prevents secular education.","Religious education is secular."]},{en:"Secular music and entertainment appeal to a broad audience.",ja:"世俗的な音楽とエンターテインメントは幅広い視聴者に訴える。",wrong:["Secular entertainment is exclusively religious.","Only religious music is secular.","Secular means limited to one religion."]},{en:"In a secular society, religious beliefs are separated from government policy.",ja:"世俗的な社会では、宗教的信念は政府政策から分離されている。",wrong:["Secular society merges religion and government.","Government ignores religious beliefs in secular societies.","Secular means all government policies are religious."]}]},{word:"segment",meaning:"部分、区分",example:"The youth segment is the fastest growing market.",category:"current",difficulty:3,examples:[{en:"The market segment for luxury cars is much smaller than for economy cars.",ja:"高級車の市場区分は、経済車よりもはるかに小さい。",wrong:["Luxury cars and economy cars are in the same segment.","Market segments don't exist.","All car segments have equal size."]},{en:"We divided the orange into eight equal segments.",ja:"私たちはオレンジを8つの等しい部分に分けた。",wrong:["We combined the orange into one piece.","Segments are not parts of fruit.","The orange was not divided."]},{en:"The business report includes a segment analyzing customer demographics.",ja:"ビジネスレポートには、顧客の人口統計を分析する部分が含まれている。",wrong:["The report has no analysis of customers.","Demographic segments are not in business reports.","Customer analysis is excluded from the report."]}]},{word:"seize",meaning:"つかむ、没収する",example:"Customs officers seized the contraband goods.",category:"society",difficulty:3,examples:[{en:"The police seized the stolen goods from the suspect's house.",ja:"警察は容疑者の家から盗まれた品を没収した。",wrong:["The police returned the stolen goods.","Stolen items cannot be seized.","The police released the goods."]},{en:"She seized the opportunity to travel abroad when she received the scholarship.",ja:"彼女は奨学金を受け取ったとき、海外旅行の機会をつかんだ。",wrong:["She ignored the opportunity to travel.","The opportunity seized her.","She missed the chance to travel."]},{en:"The government will seize all illegal weapons from the streets.",ja:"政府は路上からすべての違法な武器を没収する。",wrong:["The government will distribute illegal weapons.","Weapons cannot be seized.","The government ignores illegal weapons."]}]},{word:"sentiment",meaning:"感情、意見",example:"Public sentiment turned against the government.",category:"society",difficulty:4,examples:[{en:"The survey measured public sentiment about the new policy.",ja:"調査は新しい政策についての公共の意見を測定した。",wrong:["The survey ignored public opinion.","Sentiment cannot be measured.","Public sentiment is irrelevant to policy."]},{en:"Her words expressed genuine sentiment and deep emotion.",ja:"彼女の言葉は本当の感情と深い感動を表現した。",wrong:["Her words showed no emotion.","Sentiment and emotion are different things.","Genuine sentiment is not expressed through words."]},{en:"The market sentiment turned negative after the company's poor earnings report.",ja:"企業の悪い決算報告の後、市場の雰囲気がネガティブになった。",wrong:["Market sentiment became positive after bad news.","Bad earnings reports improve sentiment.","Sentiment doesn't change with reports."]}]},{word:"setback",meaning:"挫折",example:"The project suffered a major setback.",category:"society",difficulty:3,examples:[{en:"The project faced a major setback when the funding was cut.",ja:"資金がカットされたとき、プロジェクトは大きな挫折に直面した。",wrong:["Cutting funding helps the project progress.","Setbacks advance project goals.","The project benefited from the funding cut."]},{en:"Despite the setback, the team remained determined to succeed.",ja:"挫折にもかかわらず、チームは成功する決意を保った。",wrong:["The team gave up after the setback.","Setbacks guarantee failure.","Determination decreases after setbacks."]},{en:"The athlete overcame a serious injury setback to return to competition.",ja:"その選手は深刻な怪我の挫折を乗り越えて競技に復帰した。",wrong:["The athlete never recovered from the injury.","Injuries help athletes compete.","Setbacks prevent return to sport."]}]},{word:"shed",meaning:"流す、取り除く",example:"The report sheds light on the causes of poverty.",category:"society",difficulty:3,examples:[{en:"The dog sheds its fur during the summer months.",ja:"犬は夏の間に毛を流す。",wrong:["The dog gains fur during summer.","Shedding means keeping all fur.","Dogs don't shed seasonally."]},{en:"The company shed 500 jobs to reduce operating costs.",ja:"企業は営業費用を削減するために500の職を取り除いた。",wrong:["The company hired 500 new employees.","Shedding jobs increases costs.","Jobs cannot be removed."]},{en:"She stored her gardening tools in the old shed behind the house.",ja:"彼女は家の裏の古い小屋に庭園工具を保管した。",wrong:["The shed was inside the house.","Tools were not stored in the shed.","The shed was brand new."]}]},{word:"siege",meaning:"包囲",example:"The castle was under siege for three months.",category:"history",difficulty:4,examples:[{en:"The medieval castle withstood a three-month siege by enemy forces.",ja:"中世の城は敵軍による3ヶ月間の包囲に耐えた。",wrong:["The castle was not surrounded.","Siege means open battle in the field.","The enemy did not attempt to surround it."]},{en:"The city was under siege, with food and supplies running dangerously low.",ja:"都市は包囲下にあり、食料と補給品が危険なほど枯渇していた。",wrong:["The city had free access to supplies.","Siege means the city is open to trade.","Food was abundant during the siege."]},{en:"After weeks of siege, the fortress finally surrendered to the invading army.",ja:"数週間の包囲の後、要塞は最終的に侵略軍に降伏した。",wrong:["The fortress won the battle.","The siege lasted only one day.","The invading army retreated."]}]},{word:"signify",meaning:"意味する",example:"A red light signifies danger.",category:"society",difficulty:4,examples:[{en:"The red light signifies that the system is in standby mode.",ja:"赤いライトはシステムがスタンバイモードにあることを意味する。",wrong:["The red light means the system is off.","Red lights don't signify anything.","Standby mode is indicated by green."]},{en:"This graduation ceremony signifies the end of an important chapter in their lives.",ja:"この卒業式は彼らの人生の重要な章の終わりを意味する。",wrong:["The ceremony signifies the beginning of school.","Graduation doesn't mean anything.","Ceremonies have no significance."]},{en:"The signing of the treaty signified the peace agreement between the two nations.",ja:"条約の署名は2つの国家間の平和協定を意味した。",wrong:["Treaty signing means war is starting.","Treaties don't signify agreements.","Peace agreements are not signified by signing."]}]},{word:"simulate",meaning:"模擬実験する",example:"The software can simulate flight conditions.",category:"technology",difficulty:4,examples:[{en:"The pilots simulate emergency landings in a flight simulator before flying real aircraft.",ja:"パイロットは実際の航空機を飛ぶ前にフライトシミュレーターで緊急着陸を模擬実験する。",wrong:["Pilots practice emergency landings in real planes only.","Simulators are not used for training.","Simulation prevents real practice."]},{en:"Scientists simulate climate change scenarios to predict future environmental impacts.",ja:"科学者は将来の環境への影響を予測するために気候変動シナリオを模擬実験する。",wrong:["Scientists don't use simulations for predictions.","Simulations cannot predict climate.","Climate change doesn't need modeling."]},{en:"The software can simulate how a building will look after renovation.",ja:"そのソフトウェアは改装後の建物がどのように見えるかをシミュレートできる。",wrong:["Software cannot show building designs.","Simulations show real buildings.","Renovation results cannot be predicted."]}]},{word:"skeptical",meaning:"懐疑的な",example:"Scientists remain skeptical about the claim.",category:"science",difficulty:3,examples:[{en:"The scientist was skeptical of the new theory until she saw the experimental evidence.",ja:"その科学者は実験的な証拠を見るまで新しい理論に懐疑的だった。",wrong:["The scientist believed the theory without evidence.","Skepticism means accepting everything.","Scientists are never doubtful."]},{en:"Many investors remain skeptical about the company's ability to generate profits.",ja:"多くの投資家は企業の利益を生み出す能力について懐疑的である。",wrong:["Investors trust all companies completely.","Skepticism prevents investment.","All companies are equally trusted."]},{en:"She cast a skeptical eye on his promises, having heard them before.",ja:"彼女は以前聞いたことがあるので、彼の約束に懐疑的な目を向けた。",wrong:["She trusted his promises immediately.","Skepticism means believing everything.","Past experience doesn't create doubt."]}]},{word:"soar",meaning:"急上昇する",example:"House prices soared during the boom.",category:"current",difficulty:3,examples:[{en:"The eagle soared high above the mountains.",ja:"鷲は山々の上高く舞い上がった。",wrong:["鷲は山々の下に沈んだ。","鷲は山々の中を歩いた。","鷲は山々に落ちた。"]},{en:"After the good news, her spirits soared.",ja:"良いニュースの後、彼女の気分は高揚した。",wrong:["良いニュースの後、彼女の気分は落ち込んだ。","良いニュースの後、彼女は寝た。","良いニュースの後、彼女は泣いた。"]},{en:"Stock prices soared during the bull market.",ja:"強気市場の間、株価は急上昇した。",wrong:["強気市場の間、株価は暴落した。","強気市場の間、株価は変わらなかった。","強気市場の間、株価は消えた。"]}]},{word:"sole",meaning:"唯一の",example:"She was the sole survivor of the accident.",category:"society",difficulty:3,examples:[{en:"She is the sole owner of the company.",ja:"彼女はその会社の唯一の所有者である。",wrong:["彼女はその会社の複数の所有者である。","彼女はその会社の従業員である。","彼女はその会社と関係がない。"]},{en:"The sole survivor of the crash was found three days later.",ja:"その墜落事故の唯一の生存者は3日後に発見された。",wrong:["その墜落事故の複数の生存者が発見された。","その墜落事故の犯人が発見された。","その墜落事故の証拠が発見された。"]},{en:"He walked barefoot on the sole of his foot.",ja:"彼は足の裏で裸足で歩いた。",wrong:["彼は足の上部で歩いた。","彼は靴で歩いた。","彼は腕で歩いた。"]}]},{word:"solidarity",meaning:"連帯",example:"Workers showed solidarity by joining the strike.",category:"society",difficulty:4,examples:[{en:"The workers showed solidarity by striking together.",ja:"労働者たちは一緒にストライキをすることで連帯を示した。",wrong:["労働者たちは分裂することで連帯を示した。","労働者たちは働くことで連帯を示した。","労働者たちは逃げることで連帯を示した。"]},{en:"In solidarity with the victims, we donated to charity.",ja:"被害者たちとの連帯として、私たちは慈善団体に寄付した。",wrong:["被害者たちに反対して、私たちは寄付した。","被害者たちを無視して、私たちは寄付した。","被害者たちを傷つけるために、私たちは寄付した。"]},{en:"The international community expressed solidarity with the affected nation.",ja:"国際社会は影響を受けた国との連帯を表明した。",wrong:["国際社会は影響を受けた国を放棄した。","国際社会は影響を受けた国と戦った。","国際社会は影響を受けた国を無視した。"]}]},{word:"sophisticated",meaning:"洗練された、高度な",example:"The software uses sophisticated algorithms.",category:"technology",difficulty:3,examples:[{en:"The restaurant serves sophisticated French cuisine.",ja:"そのレストランは洗練されたフランス料理を提供している。",wrong:["そのレストランは単純なフランス料理を提供している。","そのレストランは粗雑な食べ物を提供している。","そのレストランは日本料理を提供している。"]},{en:"The software uses a sophisticated algorithm to process data.",ja:"そのソフトウェアはデータを処理するために高度なアルゴリズムを使用している。",wrong:["そのソフトウェアは単純なアルゴリズムを使用している。","そのソフトウェアはアルゴリズムを使用していない。","そのソフトウェアは壊れている。"]},{en:"She has a sophisticated taste in art and music.",ja:"彼女は美術と音楽について洗練された趣味を持っている。",wrong:["彼女は美術と音楽について単純な趣味を持っている。","彼女は美術と音楽を嫌っている。","彼女は何も理解していない。"]}]},{word:"sovereign",meaning:"主権を持つ",example:"Each nation has the right to sovereign self-governance.",category:"history",difficulty:5,examples:[{en:"The nation is a sovereign state with its own government.",ja:"その国は独自の政府を持つ主権国家である。",wrong:["その国は主権を持たない。","その国は他国に支配されている。","その国は政府がない。"]},{en:"The king has sovereign power over his realm.",ja:"その王は彼の領域に対して主権を持っている。",wrong:["その王は何の力も持っていない。","その王は市民に支配されている。","その王は奴隷である。"]},{en:"In a sovereign nation, people have the right to self-determination.",ja:"主権国家では、人々は自己決定の権利を持っている。",wrong:["主権国家では、人々は権利がない。","主権国家では、他国が支配している。","主権国家では、独裁者が全てを決める。"]}]},{word:"span",meaning:"期間、及ぶ",example:"Her career spanned three decades.",category:"society",difficulty:3,examples:[{en:"The bridge spans across the river.",ja:"その橋は川を横切る。",wrong:["その橋は川を遮断する。","その橋は川の上に落ちる。","その橋は川を埋める。"]},{en:"His career spanned over fifty years.",ja:"彼のキャリアは50年以上続いた。",wrong:["彼のキャリアは1日だった。","彼のキャリアは存在しなかった。","彼のキャリアは50分間だった。"]},{en:"The entire project spans three departments.",ja:"プロジェクト全体は3つの部門にまたがっている。",wrong:["プロジェクトは1つの部門だけである。","プロジェクトは10個の部門がある。","プロジェクトは存在しない。"]}]},{word:"speculate",meaning:"推測する、投機する",example:"Analysts speculate that prices will fall.",category:"current",difficulty:3,examples:[{en:"The media speculates about the cause of the accident.",ja:"メディアは事故の原因について推測している。",wrong:["メディアは知られた事実を報告している。","メディアは事故について沈黙している。","メディアは嘘をついている。"]},{en:"He speculated on the stock market and made a profit.",ja:"彼は株式市場に投機して利益を上げた。",wrong:["彼は株式市場で損失を被った。","彼は株式市場と関係がない。","彼は銀行に預金した。"]},{en:"Scientists speculate that life may exist on other planets.",ja:"科学者たちは他の惑星に生命が存在する可能性があると推測している。",wrong:["科学者たちは確実に他の惑星に生命がないと知っている。","科学者たちはこれについて考えていない。","科学者たちはこれについて話すことを禁止されている。"]}]},{word:"sphere",meaning:"球体、領域",example:"She has influence in the political sphere.",category:"society",difficulty:4,examples:[{en:"The Earth is a sphere that rotates on its axis.",ja:"地球はその軸上を回転する球体である。",wrong:["地球は平らな円板である。","地球は立方体である。","地球は回転していない。"]},{en:"Education falls within the sphere of responsibility of the government.",ja:"教育は政府の責任の範囲内に入る。",wrong:["教育は政府の責任の範囲外である。","教育は民間企業の唯一の責任である。","教育は誰も責任を持たない。"]},{en:"He operates in the sphere of international business.",ja:"彼は国際ビジネスの領域で活動している。",wrong:["彼はビジネスと関係がない。","彼は地元のみで活動している。","彼は無職である。"]}]},{word:"spontaneous",meaning:"自発的な",example:"The audience broke into spontaneous applause.",category:"society",difficulty:4,examples:[{en:"The crowd's applause was spontaneous and genuine.",ja:"群衆の拍手は自発的で心からのものだった。",wrong:["群衆の拍手は強制されていた。","群衆は拍手しなかった。","群衆の拍手は偽物だった。"]},{en:"She made a spontaneous decision to travel around the world.",ja:"彼女は世界中を旅行することについて自発的な決定をした。",wrong:["彼女は長年計画した。","彼女は誰かに命じられた。","彼女は旅行することを決めなかった。"]},{en:"The children's spontaneous laughter filled the room.",ja:"子どもたちの自発的な笑いが部屋を満たした。",wrong:["子どもたちは泣いていた。","子どもたちは黙っていた。","子どもたちは強制的に笑わされていた。"]}]},{word:"stake",meaning:"利害関係、賭け",example:"Millions of jobs are at stake.",category:"current",difficulty:3,examples:[{en:"He has a financial stake in the company's success.",ja:"彼は会社の成功に対して経済的な利害関係を持っている。",wrong:["彼は会社の失敗に利害関係を持っている。","彼は会社と関係がない。","彼は会社を所有していない。"]},{en:"She put her reputation at stake by supporting the controversial project.",ja:"彼女は物議を醸すプロジェクトを支持することで彼女の評判を危険にさらした。",wrong:["彼女はプロジェクトに反対した。","彼女は何もしなかった。","彼女の評判は向上した。"]},{en:"The stakes are high in this poker game.",ja:"このポーカーゲームでは賭けが大きい。",wrong:["このポーカーゲームでは賭けが小さい。","このポーカーゲームはお金を使わない。","このゲームはポーカーではない。"]}]},{word:"stall",meaning:"失速する、引き延ばす",example:"Negotiations stalled over territorial disputes.",category:"society",difficulty:3,examples:[{en:"The engine stalled in the middle of traffic.",ja:"エンジンは交通の中で失速した。",wrong:["エンジンはスムーズに走った。","エンジンは停止していなかった。","エンジンは加速した。"]},{en:"The government stalled the project to gather more information.",ja:"政府はより多くの情報を集めるためにプロジェクトを引き延ばした。",wrong:["政府はプロジェクトをすぐに始めた。","政府はプロジェクトを中止した。","政府は何もしなかった。"]},{en:"The market stall sells fresh vegetables every morning.",ja:"その市場の露店は毎朝新鮮な野菜を売っている。",wrong:["その露店は肉を売っている。","その露店は夜に営業している。","その露店は何も売っていない。"]}]},{word:"stance",meaning:"立場、姿勢",example:"The government took a firm stance on immigration.",category:"society",difficulty:4,examples:[{en:"The politician took a strong stance against corruption.",ja:"その政治家は腐敗に対して強い立場をとった。",wrong:["その政治家は腐敗を支持している。","その政治家は何の立場も持たない。","その政治家は腐敗している。"]},{en:"In martial arts, a proper stance is essential for balance.",ja:"武道では、適切な姿勢はバランスに不可欠である。",wrong:["武道では姿勢は重要ではない。","武道では姿勢は禁止されている。","武道では立つ必要がない。"]},{en:"The team maintained a defensive stance throughout the match.",ja:"チームはマッチ全体を通じて守備的な姿勢を維持した。",wrong:["チームは攻撃的な姿勢を取った。","チームは何の計画もなかった。","チームは試合を放棄した。"]}]},{word:"static",meaning:"静的な、変化のない",example:"Wages have remained largely static this year.",category:"current",difficulty:3,examples:[{en:"The prices have remained static for the past year.",ja:"価格は過去1年間変わらないままである。",wrong:["価格は毎日変わっている。","価格は上昇している。","価格は消えた。"]},{en:"The radio signal was filled with static noise.",ja:"ラジオ信号は静的なノイズで満ちていた。",wrong:["ラジオ信号は明確だった。","ラジオ信号は音声がなかった。","ラジオ信号は流動的だった。"]},{en:"The website contains static content that rarely changes.",ja:"そのウェブサイトはめったに変わらない静的なコンテンツを含んでいる。",wrong:["そのウェブサイトは毎秒変わる。","そのウェブサイトは動的なコンテンツのみである。","そのウェブサイトはコンテンツがない。"]}]},{word:"stem",meaning:"由来する、食い止める",example:"The problem stems from a lack of investment.",category:"society",difficulty:4,examples:[{en:"Many of our problems stem from poor planning.",ja:"私たちの多くの問題は不十分な計画から生じている。",wrong:["私たちの問題は良い計画から生じている。","私たちは問題を持っていない。","私たちの問題は外部から来ている。"]},{en:"We must stem the tide of climate change.",ja:"私たちは気候変動の潮流を食い止めなければならない。",wrong:["私たちは気候変動を促進すべきである。","私たちは気候変動について何もできない。","気候変動は存在しない。"]},{en:"The flower's stem is long and green.",ja:"その花の茎は長く緑色である。",wrong:["その花には茎がない。","その花の茎は赤い。","その花の茎は下を向いている。"]}]},{word:"stereotype",meaning:"固定観念",example:"We should challenge gender stereotypes.",category:"society",difficulty:3,examples:[{en:"The movie reinforces harmful stereotypes about minorities.",ja:"その映画は少数民族についての有害な固定観念を強化している。",wrong:["その映画は固定観念を破壊している。","その映画は誰も傷つけない。","その映画は教育的である。"]},{en:"We should avoid stereotyping people based on their appearance.",ja:"私たちは外見に基づいて人々を固定観念で判断することを避けるべきである。",wrong:["私たちは外見に基づいて人々を判断すべきである。","外見は人格を決める。","固定観念は正確である。"]},{en:"The character in the book is a stereotype of the wealthy businessman.",ja:"その本のキャラクターは富裕なビジネスマンの固定観念である。",wrong:["そのキャラクターはユニークである。","そのキャラクターは典型的ではない。","そのキャラクターは貧しい。"]}]},{word:"stimulate",meaning:"刺激する",example:"Tax cuts aim to stimulate economic growth.",category:"current",difficulty:3,examples:[{en:"The new marketing campaign will stimulate sales growth.",ja:"新しいマーケティングキャンペーンは売上成長を刺激するでしょう。",wrong:["新しいマーケティングキャンペーンは売上を減少させます。","新しいマーケティングキャンペーンは市場を混乱させます。","新しいマーケティングキャンペーンは販売を停止します。"]},{en:"Exercise stimulates the release of endorphins in the brain.",ja:"運動は脳内のエンドルフィンの放出を刺激します。",wrong:["運動は脳内のエンドルフィンを破壊します。","運動は脳の機能を低下させます。","運動は神経系を鈍化させます。"]},{en:"Music can stimulate creativity and imagination.",ja:"音楽は創造性と想像力を刺激することができます。",wrong:["音楽は創造性を抑制します。","音楽は想像力を減らします。","音楽は思考を妨害します。"]}]},{word:"strain",meaning:"負担、緊張",example:"The health system is under enormous strain.",category:"current",difficulty:3,examples:[{en:"The heavy workload puts a strain on employees.",ja:"重い仕事量は従業員に負担をかけます。",wrong:["重い仕事量は従業員を楽にします。","重い仕事量は従業員の生産性を高めます。","重い仕事量は従業員を喜ばせます。"]},{en:"The financial crisis strained the company's resources.",ja:"金融危機は会社のリソースに緊張をもたらしました。",wrong:["金融危機は会社のリソースを増加させました。","金融危機は会社を強化しました。","金融危機は会社の財務を改善しました。"]},{en:"He strained his back while lifting boxes.",ja:"彼は箱を持ち上げている間に背中を痛めました。",wrong:["彼は箱を持ち上げている間に背中が治りました。","彼は箱を持ち上げている間に背中が強くなりました。","彼は箱を持ち上げている間に背中がリラックスしました。"]}]},{word:"strategy",meaning:"戦略",example:"The company revised its marketing strategy.",category:"society",difficulty:3,examples:[{en:"The company developed a strategy to enter the new market.",ja:"会社は新しい市場に進出するための戦略を開発しました。",wrong:["会社は新しい市場から撤退するための戦略を開発しました。","会社は市場から逃げるための戦略を開発しました。","会社は競争を避けるための戦略を開発しました。"]},{en:"Our marketing strategy focuses on digital channels.",ja:"私たちのマーケティング戦略はデジタルチャネルに焦点を当てています。",wrong:["私たちのマーケティング戦略は従来の方法のみに焦点を当てています。","私たちのマーケティング戦略はターゲット層を無視しています。","私たちのマーケティング戦略は計画性がありません。"]},{en:"The coach outlined a defensive strategy for the match.",ja:"コーチは試合のための守備戦略を説明しました。",wrong:["コーチは試合のための無計画な戦術を説明しました。","コーチは試合のための戦略を拒否しました。","コーチは試合の準備ができていません。"]}]},{word:"strive",meaning:"努力する",example:"We strive for excellence in everything we do.",category:"society",difficulty:3,examples:[{en:"She strives to achieve excellence in everything she does.",ja:"彼女は自分がすることすべてで優秀さを達成するために努力しています。",wrong:["彼女は失敗を目指して努力しています。","彼女は平凡さを求めています。","彼女は怠惰に生きています。"]},{en:"Athletes strive for gold medals at the Olympics.",ja:"選手たちはオリンピックで金メダルを目指して努力しています。",wrong:["選手たちは敗北を目指して努力しています。","選手たちは競争を避けています。","選手たちは参加に興味がありません。"]},{en:"We strive to provide the best customer service.",ja:"私たちは最高のカスタマーサービスを提供するために努力しています。",wrong:["私たちはカスタマーサービスを無視します。","私たちは顧客を不満足させることを目指しています。","私たちはサービスの質を低下させようとしています。"]}]},{word:"subordinate",meaning:"部下、下位の",example:"He treats his subordinates with respect.",category:"society",difficulty:4,examples:[{en:"The manager assigned tasks to her subordinates.",ja:"マネージャーは彼女の部下にタスクを割り当てました。",wrong:["マネージャーは上司に指示を求めました。","マネージャーは同僚に権力を与えました。","マネージャーは自分の権限を放棄しました。"]},{en:"Personal interests should not be subordinate to company profits.",ja:"個人の利益は会社の利益に従属すべきではありません。",wrong:["個人の利益は常に最優先されるべきです。","個人の利益と会社の利益は無関係です。","会社の利益は個人の利益より低いです。"]},{en:"The subordinate clause modifies the main clause in the sentence.",ja:"従属節は文の主節を修飾しています。",wrong:["従属節は主節と関係がありません。","従属節は文の唯一の節です。","従属節は独立しています。"]}]},{word:"subside",meaning:"沈静化する",example:"The flood waters gradually subsided.",category:"current",difficulty:4,examples:[{en:"The storm will subside by tomorrow morning.",ja:"嵐は明朝までに沈静化するでしょう。",wrong:["嵐は明日さらに激しくなります。","嵐は続くでしょう。","嵐は増加します。"]},{en:"After the initial excitement subsided, reality set in.",ja:"初期の興奮が沈静化した後、現実が始まりました。",wrong:["初期の興奮は増し続けました。","初期の興奮は高まりました。","初期の興奮は消えませんでした。"]},{en:"The flood waters began to subside after three days.",ja:"洪水は3日後に引き始めました。",wrong:["洪水はさらに増加しました。","洪水は常に同じレベルでした。","洪水は上昇し続けました。"]}]},{word:"subsidy",meaning:"補助金",example:"Farmers depend on government subsidies.",category:"society",difficulty:4,examples:[{en:"The government provides a subsidy to support renewable energy.",ja:"政府は再生可能エネルギーをサポートするための補助金を提供します。",wrong:["政府は再生可能エネルギーに税金を課します。","政府は産業を罰するための補助金を与えます。","政府は企業から資金を回収します。"]},{en:"Farmers received subsidies during the economic downturn.",ja:"農民は経済の低迷期間中に補助金を受け取りました。",wrong:["農民は経済の低迷期間中に追加の税を課されました。","農民は政府からのサポートを受けませんでした。","農民は資金を失いました。"]},{en:"The housing subsidy helps low-income families afford rent.",ja:"住宅補助金は低所得世帯が家賃を支払うのを助けます。",wrong:["住宅補助金は家賃を高くさせます。","住宅補助金は貧困を増やします。","住宅補助金は人々を家がない状態にします。"]}]},{word:"substantial",meaning:"かなりの",example:"She inherited a substantial fortune.",category:"society",difficulty:3,examples:[{en:"The project made substantial progress this quarter.",ja:"このプロジェクトは今四半期にかなりの進歩を遂げました。",wrong:["プロジェクトはほとんど進歩していません。","プロジェクトは後退しました。","プロジェクトは停止しています。"]},{en:"There was a substantial increase in sales compared to last year.",ja:"昨年比でかなりの売上増加がありました。",wrong:["昨年比で売上がわずかに減少しました。","売上は変わりませんでした。","売上は急激に減りました。"]},{en:"The meal provided substantial nutrition for the day.",ja:"その食事はその日にかなりの栄養を提供しました。",wrong:["その食事は栄養がほとんどありません。","その食事は有害です。","その食事は空腹を増やします。"]}]},{word:"substitute",meaning:"代替する、代理",example:"Honey can substitute for sugar in some recipes.",category:"science",difficulty:3,examples:[{en:"You can substitute butter with oil in this recipe.",ja:"このレシピではバターを油で代替することができます。",wrong:["このレシピではバターを水で代替する必要があります。","このレシピでは代替は許可されていません。","このレシピでは材料を変更できません。"]},{en:"The substitute teacher managed the class well.",ja:"代理教師はクラスをよく管理しました。",wrong:["代理教師はクラスを混乱させました。","代理教師は教えませんでした。","代理教師はいませんでした。"]},{en:"There is no substitute for hard work and dedication.",ja:"一生懸命働くことと献身に代わるものはありません。",wrong:["怠惰は仕事と同じくらい効果的です。","運は努力より重要です。","才能は努力を不要にします。"]}]},{word:"subtle",meaning:"微妙な",example:"There is a subtle difference between the two.",category:"society",difficulty:3,examples:[{en:"The artist used subtle colors to create a calm atmosphere.",ja:"アーティストは落ち着いた雰囲気を作るために微妙な色を使いました。",wrong:["アーティストは明るく派手な色を使いました。","アーティストは単調な色を使いました。","アーティストは色の使い方が上手ではありません。"]},{en:"There was a subtle hint of irony in her comment.",ja:"彼女のコメントには微妙な皮肉のヒントがありました。",wrong:["彼女のコメントは明白な批判でした。","彼女のコメントには意味がありませんでした。","彼女のコメントは直接的でした。"]},{en:"The perfume has a subtle fragrance that lingers.",ja:"その香水は微妙な香りが残ります。",wrong:["その香水は強い臭いがします。","その香水は香りがありません。","その香水は不快です。"]}]},{word:"successive",meaning:"連続した",example:"He won three successive championships.",category:"society",difficulty:4,examples:[{en:"The team won successive victories in the tournament.",ja:"チームはトーナメントで連続した勝利を得ました。",wrong:["チームは1つの敗北を経験しました。","チームは同時に勝利と敗北を経験しました。","チームはすべての試合に失敗しました。"]},{en:"For three successive years, sales increased.",ja:"3年連続で売上が増加しました。",wrong:["毎年売上は変わりました。","売上は最初は増加し、その後は減少しました。","売上は減少し続けました。"]},{en:"The successive presidents made different policy decisions.",ja:"連続した大統領は異なる政策決定をしました。",wrong:["1人の大統領がすべての政策を決定しました。","大統領は決定を変更しませんでした。","政策は時間とともに変わりませんでした。"]}]},{word:"supplement",meaning:"補足する",example:"Many people take vitamin supplements.",category:"science",difficulty:3,examples:[{en:"She takes vitamin supplements to improve her health.",ja:"彼女は健康を改善するためにビタミンサプリメントを摂取しています。",wrong:["彼女は健康を低下させるためにサプリメントを摂取しています。","彼女は薬を拒否しています。","彼女は医療をすべて無視しています。"]},{en:"The appendix supplements the main text with additional information.",ja:"付録は主要なテキストに追加情報で補足しています。",wrong:["付録はメインのテキストと矛盾しています。","付録は追加情報を削除します。","付録は本来の意図を変更します。"]},{en:"They supplement their income with freelance work.",ja:"彼らはフリーランスの仕事で収入を補足しています。",wrong:["彼らは収入を減らしています。","彼らは追加の仕事をしていません。","彼らはお金を失っています。"]}]},{word:"suppress",meaning:"抑圧する",example:"The government suppressed freedom of the press.",category:"history",difficulty:4,examples:[{en:"The government tried to suppress the rebellion.",ja:"政府は反乱を抑圧しようとしました。",wrong:["政府は反乱を支援しました。","政府は反乱を助長しました。","政府は反乱を無視しました。"]},{en:"He struggled to suppress his laughter during the meeting.",ja:"彼は会議中に笑いを抑えるのに苦労しました。",wrong:["彼は大声で笑いました。","彼は感情をコントロールできませんでした。","彼は笑い続けました。"]},{en:"The medication suppresses the symptoms of the disease.",ja:"その薬は病気の症状を抑制します。",wrong:["その薬は症状を悪化させます。","その薬は病気を引き起こします。","その薬は効果がありません。"]}]},{word:"surge",meaning:"急増する",example:"Demand for masks surged during the pandemic.",category:"current",difficulty:3,examples:[{en:"There was a surge in demand for the new product.",ja:"新製品への需要が急増しました。",wrong:["新製品への需要は減少しました。","新製品への需要は変わりませんでした。","新製品への需要は失われました。"]},{en:"The electricity surge damaged several appliances.",ja:"電気の急増は複数の電化製品を損傷しました。",wrong:["電気の減少は電化製品を改善しました。","電気の急増は安全でした。","電気の変動は起こりませんでした。"]},{en:"A sense of hope surged through the crowd.",ja:"希望の感覚が群衆の中で急増しました。",wrong:["絶望が群衆を圧倒しました。","感情の変化はありませんでした。","人々は無関心でした。"]}]},{word:"surplus",meaning:"余剰",example:"The country has a trade surplus.",category:"current",difficulty:4,examples:[{en:"The country has a trade surplus this year.",ja:"その国は今年は貿易黒字を持っています。",wrong:["その国は貿易赤字を持っています。","その国は貿易バランスがありません。","その国は輸出がありません。"]},{en:"The surplus food was donated to the charity.",ja:"余剰食品は慈善団体に寄付されました。",wrong:["不足食品は廃棄されました。","すべての食品が使用されました。","食品の余りはありませんでした。"]},{en:"A budget surplus allows for savings and investment.",ja:"予算黒字は貯蓄と投資を可能にします。",wrong:["予算赤字は存在しません。","予算不足は良好です。","支出超過は利益をもたらします。"]}]},{word:"surveillance",meaning:"監視",example:"The suspect was placed under surveillance.",category:"technology",difficulty:4,examples:[{en:"The security team conducted surveillance of the building all night.",ja:"セキュリティチームは夜通し建物の監視を行いました。",wrong:["セキュリティチームは夜通し建物の修理を行いました。","セキュリティチームは夜通し建物の清掃を行いました。","セキュリティチームは夜通し建物の検査を行いました。"]},{en:"The government increased surveillance on social media platforms.",ja:"政府はソーシャルメディアプラットフォームに対する監視を強化しました。",wrong:["政府はソーシャルメディアプラットフォームの宣伝を強化しました。","政府はソーシャルメディアプラットフォームの開発を強化しました。","政府はソーシャルメディアプラットフォームの規制を強化しました。"]},{en:"The detective placed the suspect under surveillance for weeks.",ja:"探偵は容疑者を数週間監視下に置きました。",wrong:["探偵は容疑者を数週間逮捕しました。","探偵は容疑者を数週間訓練しました。","探偵は容疑者を数週間治療しました。"]}]},{word:"suspend",meaning:"一時停止する",example:"The airline suspended all flights to the region.",category:"current",difficulty:3,examples:[{en:"The principal decided to suspend the student for one week.",ja:"校長は学生を1週間停学にすることに決めました。",wrong:["校長は学生を1週間昇進させることに決めました。","校長は学生を1週間卒業させることに決めました。","校長は学生を1週間雇用することに決めました。"]},{en:"They had to suspend operations due to the storm.",ja:"嵐のため彼らは操業を一時停止しなければなりませんでした。",wrong:["嵐のため彼らは操業を拡大しなければなりませんでした。","嵐のため彼らは操業を加速しなければなりませんでした。","嵐のため彼らは操業を終了しなければなりませんでした。"]},{en:"The bridge was suspended across the wide river.",ja:"橋は広い川に架けられていました。",wrong:["橋は広い川に沈められていました。","橋は広い川に埋められていました。","橋は広い川に破壊されていました。"]}]},{word:"sustain",meaning:"維持する",example:"It is hard to sustain economic growth indefinitely.",category:"current",difficulty:3,examples:[{en:"The organization works hard to sustain its mission.",ja:"その組織はその使命を維持するために懸命に働いています。",wrong:["その組織はその使命を放棄するために懸命に働いています。","その組織はその使命を変更するために懸命に働いています。","その組織はその使命を否定するために懸命に働いています。"]},{en:"A healthy diet helps sustain your energy levels throughout the day.",ja:"健康的な食事は一日を通して你のエネルギーレベルを維持するのに役立ちます。",wrong:["健康的な食事は一日を通して你のエネルギーレベルを減少させるのに役立ちます。","健康的な食事は一日を通して你のエネルギーレベルを消費するのに役立ちます。","健康的な食事は一日を通して你のエネルギーレベルを破壊するのに役立ちます。"]},{en:"The pillars sustain the entire structure of the building.",ja:"柱は建物の全体構造を支持しています。",wrong:["柱は建物の全体構造を崩壊させています。","柱は建物の全体構造を弱めています。","柱は建物の全体構造を傷つけています。"]}]},{word:"swift",meaning:"迅速な",example:"The government took swift action to contain the virus.",category:"society",difficulty:3,examples:[{en:"The company made a swift decision to invest in new technology.",ja:"その会社は新しい技術に投資することを迅速に決定しました。",wrong:["その会社は新しい技術に投資することを慎重に決定しました。","その会社は新しい技術に投資することを遅延して決定しました。","その会社は新しい技術に投資することを放棄しました。"]},{en:"The swift response from emergency services saved many lives.",ja:"緊急サービスからの迅速な対応は多くの命を救いました。",wrong:["緊急サービスからの遅い対応は多くの命を救いました。","緊急サービスからの消極的な対応は多くの命を救いました。","緊急サービスからの不十分な対応は多くの命を救いました。"]},{en:"The swift river currents made it dangerous to swim.",ja:"迅速な川の流れは泳ぐのに危険でした。",wrong:["遅い川の流れは泳ぐのに危険でした。","穏やかな川の流れは泳ぐのに危険でした。","静止した川の流れは泳ぐのに危険でした。"]}]},{word:"symmetry",meaning:"対称",example:"The building displays perfect symmetry.",category:"science",difficulty:4,examples:[{en:"The building's architecture demonstrates perfect symmetry.",ja:"その建物の建築は完全な対称性を示しています。",wrong:["その建物の建築は完全な非対称性を示しています。","その建物の建築は完全な複雑性を示しています。","その建物の建築は完全な単純性を示しています。"]},{en:"The butterfly's wings show bilateral symmetry.",ja:"蝶の羽は二側対称性を示しています。",wrong:["蝶の羽は非対称性を示しています。","蝶の羽は回転対称性を示しています。","蝶の羽は多角形を示しています。"]},{en:"The artist valued symmetry in all of their paintings.",ja:"その芸術家はすべての絵画で対称性を重視していました。",wrong:["その芸術家はすべての絵画で非対称性を重視していました。","その芸術家はすべての絵画で色彩を重視していました。","その芸術家はすべての絵画で透視図法を重視していました。"]}]}]],73493),e.s(["TOEFL_ACADEMIC_VOCAB",0,[{word:"abstraction",meaning:"抽象概念",example:"The paper discusses freedom as a philosophical abstraction.",category:"science",difficulty:6,examples:[{en:"The concept of justice is an abstraction that means different things to different people.",ja:"正義という概念は、人によって異なる意味を持つ抽象概念です。",wrong:["正義は具体的な物体である","正義は常に同じ意味を持つ","抽象概念は実生活に関係がない"]},{en:"In mathematics, abstraction allows us to solve problems without considering specific details.",ja:"数学では、抽象化により具体的な詳細を考慮せずに問題を解くことができます。",wrong:["抽象化は数学では使われない","詳細を無視することは間違っている","抽象化は問題を複雑にする"]},{en:"The artist's use of abstraction created a painting open to many interpretations.",ja:"その芸術家は抽象的な表現を用いて、多くの解釈が可能な絵画を創作しました。",wrong:["抽象的な表現は解釈ができない","芸術家は具体的な描写のみを使う","抽象的な絵画は意味がない"]}]},{word:"academia",meaning:"学界",example:"She spent her entire career in academia.",category:"society",difficulty:5,examples:[{en:"She spent twenty years in academia before moving to industry.",ja:"彼女は業界に転職する前に、20年間学界で過ごしました。",wrong:["学界は企業と同じ場所である","学界は教育に関係がない","20年は学界で働くのに短すぎる"]},{en:"Academia values rigorous research and peer review.",ja:"学界は厳密な研究と査読を重視しています。",wrong:["学界は急速な出版を重視する","査読は学界では不要である","学界は厳密さを気にしない"]},{en:"Many breakthroughs in medicine have come from academia.",ja:"医学における多くの革新的発見は学界から生まれています。",wrong:["学界は医学の発展に貢献していない","医学の進歩は企業だけから生まれる","学界での研究は実用的ではない"]}]},{word:"accord",meaning:"一致、協定",example:"The findings are in accord with previous research.",category:"science",difficulty:5,examples:[{en:"The two nations reached an accord on trade agreements.",ja:"両国は貿易協定について協定に達しました。",wrong:["協定は貿易に関係がない","両国は対立したままである","協定は口頭のみで有効ではない"]},{en:"Her actions were in accord with company policy.",ja:"彼女の行動は会社の方針と一致していました。",wrong:["一致は会社の方針と関係がない","彼女の行動は方針に違反していた","一致は重要ではない"]},{en:"The board members were in accord about the new strategy.",ja:"取締役会のメンバーは新しい戦略について一致していました。",wrong:["取締役会は意見が異なっていた","一致は不可能である","戦略には合意が必要ではない"]}]},{word:"albeit",meaning:"〜ではあるが",example:"The results were positive, albeit modest.",category:"science",difficulty:6,examples:[{en:"She succeeded in her career, albeit with considerable difficulty.",ja:"彼女はかなりの困難があったものの、キャリアで成功しました。",wrong:["困難なしで成功した","困難は成功を否定する","成功と困難は関係がない"]},{en:"The project was completed on time, albeit over budget.",ja:"プロジェクトは予算超過ではあるものの、期限内に完了しました。",wrong:["プロジェクトは期限に間に合わなかった","予算内で完了した","予算超過は完了を否定する"]},{en:"The film was entertaining, albeit somewhat predictable.",ja:"その映画はやや予測可能ではあるものの、楽しめるものでした。",wrong:["映画は退屈だった","予測可能性は楽しさを排除しない","映画は予測不可能だった"]}]},{word:"ambivalent",meaning:"相反する感情を持つ",example:"Voters remain ambivalent about the new policy.",category:"society",difficulty:6,examples:[{en:"He felt ambivalent about accepting the job offer because it meant relocating.",ja:"転居が必要になるため、彼は仕事の申し出を受けることについて相反する感情を抱いていました。",wrong:["彼は明確に承諾した","転居の必要性はない","相反する感情は存在しない"]},{en:"Many people are ambivalent about technology, valuing its benefits while fearing its risks.",ja:"多くの人々は技術に対して相反する感情を持ち、その利点を評価する一方でリスクを恐れています。",wrong:["誰もが技術を無条件に愛している","技術にはリスクがない","利点とリスクの両立は不可能である"]},{en:"She was ambivalent about the decision, unable to choose between two equally appealing options.",ja:"同等に魅力的な2つの選択肢の間で選べず、彼女はその決定について相反する感情を持っていました。",wrong:["選択肢のどちらかが明確に優れていた","決定は簡単だった","相反する感情は判断を妨げない"]}]},{word:"antecedent",meaning:"先行するもの",example:"The antecedent of the modern university was the medieval studium.",category:"history",difficulty:6,examples:[{en:"The antecedent cause of the accident was the driver's failure to check the mirrors.",ja:"事故の先行原因は、運転手が鏡を確認しなかったことです。",wrong:["先行原因は後に起こった","運転手の確認は無関係である","事故には原因がない"]},{en:"In grammar, an antecedent is the noun that a pronoun refers to.",ja:"文法では、先行詞は代名詞が指す名詞です。",wrong:["先行詞は代名詞の後に来る","先行詞は動詞である","代名詞は先行詞を必要としない"]},{en:"Understanding the antecedent events helps us predict future outcomes.",ja:"先行する出来事を理解することは、将来の結果を予測するのに役立ちます。",wrong:["先行する出来事は予測に役立たない","未来の出来事が過去を決定する","予測には過去の情報は必要ない"]}]},{word:"append",meaning:"付加する",example:"Additional notes were appended to the report.",category:"science",difficulty:5,examples:[{en:"Please append your signature to the document.",ja:"ドキュメントに署名を付加してください。",wrong:["署名を削除する","署名は不要である","署名は別の場所にある"]},{en:"The appendix appends additional information to the main text.",ja:"付録は追加情報を本文に付加しています。",wrong:["付録は本文から情報を削除する","付録は関係のない情報を含む","本文は付録を必要としない"]},{en:"She decided to append a note to her original statement.",ja:"彼女は元の陳述に注釈を付加することにしました。",wrong:["彼女は元の陳述を削除した","注釈を付加することはできない","注釈は不要である"]}]},{word:"apposition",meaning:"並置",example:"The two concepts stand in apposition within the theory.",category:"science",difficulty:6,examples:[{en:"In the sentence 'My friend John is here,' 'John' is in apposition to 'friend.'",ja:"「My friend John is here」という文では、「John」は「friend」と並置の関係にあります。",wrong:["「John」は述語である","並置は文法的でない","「friend」と「John」は無関係である"]},{en:"Apposition is a grammatical construction that places two noun phrases side by side.",ja:"並置は2つの名詞句を並べる文法的構造です。",wrong:["並置は2つの動詞を並べる","並置は修飾語に使われる","並置は名詞と関係がない"]},{en:"The phrase 'the president, a visionary leader' uses apposition to provide additional description.",ja:"「the president, a visionary leader」というフレーズは並置を使って追加の説明を提供しています。",wrong:["並置は説明を提供しない","説明は別の方法で必要である","「president」と「leader」は同じではない"]}]},{word:"assent",meaning:"同意する",example:"The committee assented to the proposed changes.",category:"society",difficulty:6,examples:[{en:"The board gave its assent to the new proposal.",ja:"取締役会は新しい提案に同意しました。",wrong:["取締役会は提案に反対した","同意は必要ない","提案は承認されなかった"]},{en:"He nodded in assent, indicating he agreed with the plan.",ja:"彼はうなずいて同意を示し、計画に同意していることを示しました。",wrong:["うなずきは反対を示す","彼は計画に同意していない","同意は言葉で表現する必要がある"]},{en:"We cannot proceed without the client's assent.",ja:"クライアントの同意がなければ、進めることはできません。",wrong:["クライアントの同意は不要である","クライアントの反対でも進められる","同意は法的に重要ではない"]}]},{word:"atrophy",meaning:"萎縮する",example:"Muscles atrophy without regular exercise.",category:"science",difficulty:6,examples:[{en:"Without exercise, muscles will atrophy over time.",ja:"運動がないと、筋肉は時間とともに萎縮します。",wrong:["運動がなくても筋肉は強くなる","筋肉は萎縮しない","萎縮は筋肉にのみ起こる"]},{en:"The patient's leg began to atrophy after months of immobility.",ja:"数ヶ月間の不動状態の後、患者の脚は萎縮し始めました。",wrong:["不動状態は萎縮を引き起こさない","脚は成長する","萎縮は可逆的ではない"]},{en:"If a language is not spoken regularly, it can atrophy in the mind.",ja:"定期的に話されない言語は、心の中で萎縮することがあります。",wrong:["言語は萎縮しない","定期的な使用は関係がない","言語は常に保存される"]}]},{word:"benign",meaning:"良性の、温和な",example:"The tumour was found to be benign.",category:"science",difficulty:5,examples:[{en:"The doctor confirmed that the tumor was benign and posed no threat.",ja:"医者は腫瘍が良性で、脅威を与えないことを確認しました。",wrong:["腫瘍は悪性である","良性の腫瘍は危険である","腫瘍は無視できない"]},{en:"Her benign smile put everyone at ease.",ja:"彼女の温厚な笑顔は皆を安心させました。",wrong:["笑顔は温厚ではない","温厚さは信頼を築かない","笑顔は不安を増す"]},{en:"The climate in that region is benign, making it ideal for agriculture.",ja:"その地域の気候は温和で、農業に最適です。",wrong:["気候は厳しい","温和な気候は農業に適さない","気候は無関係である"]}]},{word:"bifurcate",meaning:"二分する",example:"The river bifurcates at the base of the mountain.",category:"science",difficulty:6,examples:[{en:"The river bifurcates into two branches before reaching the valley.",ja:"川は谷に到達する前に2つの支流に二分します。",wrong:["川は1つのままである","支流は存在しない","川は合流している"]},{en:"The organization decided to bifurcate its operations into regional divisions.",ja:"組織は運営を地域部門に二分することにしました。",wrong:["組織は統合された","地域部門は必要ない","分割は不可能である"]},{en:"The path bifurcates at the fork, with one leading to the forest and the other to the lake.",ja:"小道は分岐点で二分し、一方は森へ、もう一方は湖へ導きます。",wrong:["小道は交差する","分岐点は存在しない","両方の道は同じ場所へ行く"]}]},{word:"bioethics",meaning:"生命倫理学",example:"Bioethics addresses moral dilemmas in medicine.",category:"science",difficulty:6,examples:[{en:"Bioethics addresses the moral issues arising from advances in biological sciences.",ja:"生命倫理学は生物科学の進歩から生じる道徳的問題を扱います。",wrong:["生命倫理学は科学と無関係である","道徳的問題は存在しない","倫理は生物科学に関係がない"]},{en:"The committee on bioethics reviewed the proposed research protocol.",ja:"生命倫理学委員会は提案された研究プロトコルをレビューしました。",wrong:["倫理委員会は研究を承認しない","プロトコルは倫理的問題と無関係である","委員会は提案を却下する"]},{en:"Bioethics is essential when considering issues like genetic engineering and organ transplants.",ja:"遺伝子工学と臓器移植などの問題を検討する際に、生命倫理学は不可欠です。",wrong:["倫理は遺伝子工学と無関係である","臓器移植は倫理的問題を起こさない","倫理学は医学的決定に影響しない"]}]},{word:"biosynthesis",meaning:"生合成",example:"Biosynthesis of amino acids occurs within cells.",category:"science",difficulty:6,examples:[{en:"Photosynthesis involves the biosynthesis of glucose from carbon dioxide and water.",ja:"光合成は二酸化炭素と水からのグルコースの生合成を含みます。",wrong:["光合成は生合成を含まない","グルコースは合成されない","生合成は生物学的でない"]},{en:"The biosynthesis of proteins involves multiple enzymatic reactions.",ja:"タンパク質の生合成は複数の酵素反応を含みます。",wrong:["タンパク質は合成されない","酵素反応は関係がない","生合成は化学的ではない"]},{en:"Understanding the biosynthesis of antibiotics has improved medical treatments.",ja:"抗生物質の生合成の理解は医学的治療を改善しました。",wrong:["抗生物質の合成は医学に関係がない","生合成は医療を改善しない","抗生物質は合成されない"]}]},{word:"causality",meaning:"因果関係",example:"Correlation does not imply causality.",category:"science",difficulty:6,examples:[{en:"The study examined the causality between smoking and lung disease.",ja:"その研究は喫煙と肺疾患の間の因果関係を調べました。",wrong:["喫煙と肺疾患の関係はない","因果関係は存在しない","相関は因果性を示さない"]},{en:"In physics, causality is the principle that every effect has a cause.",ja:"物理学では、因果関係はすべての結果に原因があるという原則です。",wrong:["結果には原因がない","因果関係は原則ではない","物理学は因果関係を否定する"]},{en:"Establishing causality is crucial in scientific research and legal proceedings.",ja:"因果関係の確立は科学的研究と法的手続きにおいて重要です。",wrong:["因果関係は研究に無関係である","法的手続きは因果性を必要としない","因果関係は重要ではない"]}]},{word:"cessation",meaning:"停止、中止",example:"The cessation of hostilities was welcomed by all parties.",category:"society",difficulty:6,examples:[{en:"The cessation of hostilities was announced after months of negotiations.",ja:"数ヶ月の交渉の後、敵対行為の中止が発表された。",wrong:["敵対行為の激化が発表された。","敵対行為の継続が合意された。","敵対行為の開始が予定された。"]},{en:"The doctor recommended cessation of smoking immediately.",ja:"医者は直ちに喫煙を中止することを勧めた。",wrong:["医者は喫煙を増やすことを勧めた。","医者は喫煙を続けることを勧めた。","医者は喫煙を開始することを勧めた。"]},{en:"The cessation of rain allowed the farmers to work in the fields.",ja:"雨が止んだおかげで、農民は畑で働くことができた。",wrong:["雨が激しく降ったので、農民は畑で働けなかった。","雨が継続したので、農民は畑で働かなかった。","雨が増加したので、農民は外出できなかった。"]}]},{word:"circumscribe",meaning:"制限する、外接する",example:"The law circumscribes the powers of the executive.",category:"society",difficulty:6,examples:[{en:"The regulations circumscribe the freedom of speech in certain contexts.",ja:"その規則は特定の文脈では言論の自由を制限している。",wrong:["その規則は言論の自由を拡大している。","その規則は言論の自由を保護している。","その規則は言論の自由を奨励している。"]},{en:"The circle circumscribes the triangle perfectly.",ja:"その円は三角形に完全に外接している。",wrong:["その円は三角形に内接している。","その円は三角形と交差している。","その円は三角形と平行である。"]},{en:"The treaty circumscribed the territorial claims of both nations.",ja:"その条約は両国の領土主張を制限した。",wrong:["その条約は両国の領土主張を拡張した。","その条約は両国の領土主張を承認した。","その条約は両国の領土主張を無視した。"]}]},{word:"coalesce",meaning:"合体する",example:"Small droplets coalesce to form larger ones.",category:"science",difficulty:6,examples:[{en:"The various political movements coalesced into a single party.",ja:"様々な政治運動が1つの政党に合体した。",wrong:["様々な政治運動が分裂した。","様々な政治運動が衰退した。","様々な政治運動が対立した。"]},{en:"Water droplets coalesce to form larger drops.",ja:"水滴が合体してより大きな滴を形成する。",wrong:["水滴が蒸発してなくなる。","水滴が分散する。","水滴が凍結する。"]},{en:"The different theories began to coalesce around a common principle.",ja:"異なる理論が共通の原理の周りで合体し始めた。",wrong:["異なる理論が互いに矛盾し始めた。","異なる理論が消滅し始めた。","異なる理論が分離し始めた。"]}]},{word:"codify",meaning:"法典化する、体系化する",example:"The committee sought to codify existing practices.",category:"society",difficulty:6,examples:[{en:"The government decided to codify the existing laws into a single document.",ja:"政府は既存の法律を1つの文書に法典化することを決定した。",wrong:["政府は既存の法律を廃止することを決定した。","政府は既存の法律を隠すことを決定した。","政府は既存の法律を削除することを決定した。"]},{en:"The company codified its business practices into a standard manual.",ja:"その会社はビジネス慣行を標準マニュアルに体系化した。",wrong:["その会社はビジネス慣行を廃棄した。","その会社はビジネス慣行を隠蔽した。","その会社はビジネス慣行を放棄した。"]},{en:"Ancient philosophers codified their ethical systems in written texts.",ja:"古代の哲学者は彼らの倫理体系を書かれたテキストに体系化した。",wrong:["古代の哲学者は彼らの倫理体系を忘れた。","古代の哲学者は彼らの倫理体系を拒否した。","古代の哲学者は彼らの倫理体系を破壊した。"]}]},{word:"cognition",meaning:"認知",example:"Sleep deprivation impairs cognition significantly.",category:"science",difficulty:5,examples:[{en:"The study of cognition helps us understand how the brain processes information.",ja:"認知の研究は脳がどのように情報を処理するかを理解するのに役立つ。",wrong:["認知の研究は脳の構造を完全に決定する。","認知の研究は思考を排除する。","認知の研究は知識を否定する。"]},{en:"Children develop cognition through play and exploration.",ja:"子供は遊びと探索を通じて認知を発達させる。",wrong:["子供は遊びと探索を通じて認知を失う。","子供は遊びと探索を通じて認知を減らす。","子供は遊びと探索を通じて認知を阻害する。"]},{en:"Advanced cognition allows humans to solve complex problems.",ja:"高度な認知により、人間は複雑な問題を解決できる。",wrong:["高度な認知により、人間は問題を避ける。","高度な認知により、人間は考えを停止する。","高度な認知により、人間は判断力を失う。"]}]},{word:"cohesion",meaning:"結合力、一体性",example:"Social cohesion is vital for community stability.",category:"society",difficulty:5,examples:[{en:"The cohesion of the team was evident in their synchronized movements.",ja:"チームの結合力は彼らの同期した動きに明らかだった。",wrong:["チームの分裂は彼らの同期した動きに明らかだった。","チームの混乱は彼らの同期した動きに見られた。","チームの衝突は彼らの動きに影響した。"]},{en:"Social cohesion is important for community development.",ja:"社会的一体性はコミュニティの発展にとって重要である。",wrong:["社会的分裂はコミュニティの発展にとって重要である。","社会的対立はコミュニティの発展を促進する。","社会的孤立はコミュニティを強化する。"]},{en:"Water's cohesion allows it to form droplets.",ja:"水の結合力により、水は液滴を形成できる。",wrong:["水の分散により、水は液滴を形成できる。","水の拡散により、水は液滴になる。","水の蒸発により、水は液滴を形成する。"]}]},{word:"collateral",meaning:"担保、付随的な",example:"The study examined collateral effects of the medication.",category:"science",difficulty:6,examples:[{en:"The bank required collateral before approving the loan.",ja:"銀行はローンを承認する前に担保を要求した。",wrong:["銀行はローンを拒否するために担保を要求した。","銀行は担保なしでローンを承認した。","銀行は担保の代わりに利息を要求した。"]},{en:"The war had collateral damage in the civilian areas.",ja:"その戦争は民間地域に付随的な被害をもたらした。",wrong:["その戦争は民間地域に意図的な利益をもたらした。","その戦争は民間地域に保護をもたらした。","その戦争は民間地域に恩恵をもたらした。"]},{en:"The collateral consequences of the policy were unexpected.",ja:"その政策の付随的な影響は予期しないものだった。",wrong:["その政策の主要な結果は予期しないものだった。","その政策の意図的な結果は予期しないものだった。","その政策の明示的な目標は予期しないものだった。"]}]},{word:"compendium",meaning:"概論、要約",example:"The textbook serves as a compendium of current knowledge.",category:"science",difficulty:6,examples:[{en:"The encyclopedia serves as a compendium of human knowledge.",ja:"その百科事典は人間の知識の要約として機能する。",wrong:["その百科事典は人間の知識の否定として機能する。","その百科事典は人間の知識を隠す。","その百科事典は人間の知識を拒否する。"]},{en:"The book is a compendium of historical facts and dates.",ja:"その本は歴史的事実と年代の概論である。",wrong:["その本は歴史的虚構の集まりである。","その本は歴史的事実の完全な否定である。","その本は歴史的データを隠している。"]},{en:"She wrote a compendium of her research findings.",ja:"彼女は彼女の研究結果の要約を書いた。",wrong:["彼女は彼女の研究結果の詳細な拡張を書いた。","彼女は彼女の研究結果を隠した。","彼女は彼女の研究結果を否定した。"]}]},{word:"concatenate",meaning:"連結する",example:"The researcher concatenated data from multiple sources.",category:"technology",difficulty:6,examples:[{en:"In programming, you concatenate strings to combine them.",ja:"プログラミングでは、文字列を連結してそれらを組み合わせる。",wrong:["プログラミングでは、文字列を分離してそれらを分割する。","プログラミングでは、文字列を削除してそれらを消去する。","プログラミングでは、文字列を逆転させてそれらを無効にする。"]},{en:"The events concatenated to form a complete narrative.",ja:"その出来事は連結して完全な物語を形成した。",wrong:["その出来事は分裂して不完全な物語を形成した。","その出来事は中断して物語を壊した。","その出来事は反転して物語を否定した。"]},{en:"The DNA sequences concatenate to form the genetic code.",ja:"DNA配列は連結して遺伝暗号を形成する。",wrong:["DNA配列は分散して遺伝暗号を破壊する。","DNA配列は分裂して遺伝情報を失う。","DNA配列は分離して遺伝機能を停止する。"]}]},{word:"concomitant",meaning:"付随する",example:"Rapid growth brought concomitant environmental challenges.",category:"science",difficulty:6,examples:[{en:"Economic growth and inflation are often concomitant phenomena.",ja:"経済成長とインフレーションはしばしば付随する現象である。",wrong:["経済成長とインフレーションは相互に排他的である。","経済成長とインフレーションは無関係である。","経済成長とインフレーションは対立する。"]},{en:"The disease brought concomitant health complications.",ja:"その病気は付随する健康上の合併症をもたらした。",wrong:["その病気は独立した健康上の利益をもたらした。","その病気は無関係な改善をもたらした。","その病気は対立する結果をもたらした。"]},{en:"Progress in technology is concomitant with social change.",ja:"技術の進歩は社会的変化と付随している。",wrong:["技術の進歩は社会的停滞と付随している。","技術の進歩は社会的固定化と関連している。","技術の進歩は社会的後退と伴う。"]}]},{word:"confound",meaning:"混同する、困惑させる",example:"Several variables confounded the experimental results.",category:"science",difficulty:6,examples:[{en:"Do not confound correlation with causation.",ja:"相関と因果関係を混同しないでください。",wrong:["相関と因果関係を区別してください。","相関と因果関係を分離してください。","相関と因果関係を分析してください。"]},{en:"The confusing instructions confounded the participants.",ja:"その混乱した指示は参加者を困惑させた。",wrong:["その明確な指示は参加者を啓発した。","その詳細な指示は参加者を安心させた。","その正確な指示は参加者を満足させた。"]},{en:"The magician confounded the audience with his tricks.",ja:"その手品師は彼のトリックで観客を困惑させた。",wrong:["その手品師は彼のトリックで観客を教育した。","その手品師は彼のトリックで観客を説得した。","その手品師は彼のトリックで観客を退屈させた。"]}]},{word:"congenital",meaning:"先天性の",example:"The condition is congenital rather than acquired.",category:"science",difficulty:6,examples:[{en:"The child was born with a congenital heart defect.",ja:"その子供は先天性の心臓欠陥で生まれた。",wrong:["その子供は後天性の心臓欠陥で生まれた。","その子供は習得した心臓疾患で生まれた。","その子供は獲得した心臓障害で生まれた。"]},{en:"Congenital blindness affects vision from birth.",ja:"先天性盲目は誕生から視力に影響を与える。",wrong:["後天性盲目は誕生から視力に影響を与える。","習得された視力喪失は誕生時に始まる。","獲得された失明は生まれたときからある。"]},{en:"Some congenital disorders can be detected during pregnancy.",ja:"いくつかの先天性疾患は妊娠中に検出できる。",wrong:["いくつかの後天性疾患は妊娠中に検出できる。","いくつかの習得された障害は妊娠中に発症する。","いくつかの獲得された欠陥は妊娠中に現れる。"]}]},{word:"conjecture",meaning:"推測",example:"The hypothesis remains a conjecture until tested.",category:"science",difficulty:5,examples:[{en:"The detective made a conjecture about the suspect's motives.",ja:"その刑事は容疑者の動機について推測を立てた。",wrong:["その刑事は容疑者の動機を証明した。","その刑事は容疑者の動機を否定した。","その刑事は容疑者の動機を見つけた。"]},{en:"His conjecture was later confirmed by scientific evidence.",ja:"彼の推測は後に科学的証拠によって確認された。",wrong:["彼の推測は後に科学的証拠によって反証された。","彼の推測は後に科学的証拠によって否定された。","彼の推測は後に科学的証拠によって無視された。"]},{en:"Without more data, we can only conjecture about the outcomes.",ja:"より多くのデータがなければ、結果についてのみ推測できる。",wrong:["より多くのデータがなければ、結果を確定できる。","より多くのデータなしに、結果を証明できる。","より多くのデータなしに、結果を決定できる。"]}]},{word:"connote",meaning:"暗示する",example:"The word connotes warmth and familiarity.",category:"culture",difficulty:6,examples:[{en:"The word 'thrifty' connotes being careful with money.",ja:"「倹約的な」という言葉はお金に気をつけることを暗示している。",wrong:["「倹約的な」という言葉は浪費を暗示している。","「倹約的な」という言葉は無駄を意味する。","「倹約的な」という言葉は贅沢を表す。"]},{en:"The color black connotes darkness and mystery.",ja:"黒い色は暗さと神秘を暗示している。",wrong:["黒い色は光と明確さを暗示している。","黒い色は透明性と明白さを意味する。","黒い色は明るさと公開性を表す。"]},{en:"In literature, red connotes passion and danger.",ja:"文学では、赤は情熱と危険を暗示している。",wrong:["文学では、赤は平穏と安全を暗示している。","文学では、赤は冷淡さと穏やかさを意味する。","文学では、赤は無関心と安定を表す。"]}]},{word:"continuum",meaning:"連続体",example:"Health exists on a continuum from illness to wellness.",category:"science",difficulty:5,examples:[{en:"Color exists on a continuum from red to violet.",ja:"色は赤から紫への連続体上に存在する。",wrong:["色は赤と紫の間の離散的なカテゴリーに存在する。","色は赤と紫で完全に分離している。","色は赤と紫で区切られている。"]},{en:"There is a continuum of consciousness from wakefulness to sleep.",ja:"覚醒から睡眠への意識の連続体がある。",wrong:["覚醒から睡眠への意識は離散的な段階である。","覚醒と睡眠は完全に分離している。","覚醒と睡眠の間に段階的な違いはない。"]},{en:"Intelligence exists on a continuum rather than in discrete categories.",ja:"知能は離散的なカテゴリーではなく連続体上に存在する。",wrong:["知能は離散的なカテゴリーにはっきり分けられる。","知能は明確に分けられた段階に存在する。","知能は境界が明確に分かれている。"]}]},{word:"converge",meaning:"収束する",example:"Multiple lines of evidence converge on the same conclusion.",category:"science",difficulty:5,examples:[{en:"The two roads converge at the town center.",ja:"その2本の道は町の中心で収束する。",wrong:["2本の道が町の中心で分岐する。","その2本の道は町の中心で平行している。","2本の道が町の中心で交差して終わる。"]},{en:"Scientists from different fields converge on the same conclusion.",ja:"異なる分野の科学者たちが同じ結論に収束する。",wrong:["異なる分野の科学者たちが異なる結論に分散する。","異なる分野の科学者たちが結論を避ける。","科学者たちが互いに対立し続ける。"]},{en:"The sequence of numbers converges to zero.",ja:"その数列はゼロに収束する。",wrong:["その数列は無限大に発散する。","その数列はゼロから遠ざかる。","その数列は固定値に留まる。"]}]},{word:"convex",meaning:"凸面の",example:"A convex lens focuses light to a single point.",category:"science",difficulty:5,examples:[{en:"A convex lens bends light inward.",ja:"凸レンズは光を内側に曲げる。",wrong:["凹レンズは光を内側に曲げる。","凸レンズは光を外側に曲げる。","凸レンズは光を吸収する。"]},{en:"The surface of a sphere is convex.",ja:"球の表面は凸面である。",wrong:["球の表面は凹面である。","立方体の表面は凸面である。","球の表面は平面である。"]},{en:"A convex mirror makes objects appear smaller.",ja:"凸面鏡は物体をより小さく見える。",wrong:["凹面鏡は物体をより小さく見せる。","凸面鏡は物体を拡大する。","凸面鏡は物体の色を変える。"]}]},{word:"corroborate",meaning:"裏付ける",example:"Independent studies corroborated the original findings.",category:"science",difficulty:6,examples:[{en:"The witness testimony corroborates the defendant's alibi.",ja:"目撃者の証言が被告人のアリバイを裏付ける。",wrong:["目撃者の証言が被告人のアリバイに矛盾する。","目撃者の証言が被告人を告発する。","目撃者の証言が証拠を隠蔽する。"]},{en:"Multiple studies corroborate this scientific finding.",ja:"複数の研究がこの科学的発見を裏付ける。",wrong:["複数の研究がこの発見を否定する。","複数の研究がこの発見と矛盾する。","複数の研究がこの発見を隠蔽する。"]},{en:"The document corroborates the historical account.",ja:"その文書は歴史的記述を裏付ける。",wrong:["その文書は歴史的記述を改ざんする。","その文書は歴史的記述を反証する。","その文書は歴史的記述を消去する。"]}]},{word:"counterfactual",meaning:"反事実的な",example:"Counterfactual analysis asks what would have happened otherwise.",category:"science",difficulty:6,examples:[{en:"The counterfactual scenario explores what might have happened if World War II had ended differently.",ja:"その反事実的シナリオは、第二次世界大戦が異なる方法で終わっていたなら何が起きたかを探る。",wrong:["その実際の歴史は、第二次世界大戦の実際の結末を示す。","その反事実的シナリオは過去の事実を記録する。","その反事実的シナリオは現在の状況を説明する。"]},{en:"Counterfactual thinking helps us understand causal relationships.",ja:"反事実的思考は、因果関係の理解を助ける。",wrong:["実際の思考は因果関係を混乱させる。","反事実的思考は事実を否定する。","論理的思考は因果関係を隠す。"]},{en:"The counterfactual statement assumes a condition that is contrary to fact.",ja:"その反事実的陳述は、事実に反する条件を仮定する。",wrong:["その事実的陳述は、実際に起こったことを示す。","反事実的陳述は真実のみを述べる。","仮定的陳述は事実を証明する。"]}]},{word:"criteria",meaning:"基準（複数形）",example:"The study defined strict criteria for participant selection.",category:"science",difficulty:5,examples:[{en:"The job application was judged based on multiple criteria.",ja:"その求人応募は複数の基準に基づいて判断された。",wrong:["その求人応募は基準なしに判断された。","その求人応募は単一の基準で厳しく判断された。","その求人応募は個人的な好みのみで判断された。"]},{en:"What are the criteria for admission to this university?",ja:"この大学への入学基準は何ですか？",wrong:["この大学への入学に基準はありますか？","この大学への入学理由は何ですか？","この大学への入学費用は何ですか？"]},{en:"The selection criteria emphasize academic achievement and leadership skills.",ja:"その選抜基準は、学業成績とリーダーシップスキルを強調している。",wrong:["選抜基準は外見のみを重視する。","選抜基準は金銭的地位のみを考慮する。","選抜基準は個人的な関係に基づいている。"]}]},{word:"culminate",meaning:"最高潮に達する",example:"Years of research culminated in a breakthrough discovery.",category:"science",difficulty:5,examples:[{en:"The festival culminates in a spectacular fireworks display.",ja:"そのフェスティバルは壮観な花火で最高潮に達する。",wrong:["そのフェスティバルは静かに始まる。","そのフェスティバルは花火なしで終わる。","そのフェスティバルはゆっくり衰退する。"]},{en:"Years of hard work culminated in her winning the championship.",ja:"何年もの懸命な努力が、彼女のチャンピオンシップ獲得に最高潮に達した。",wrong:["彼女は最初からチャンピオンだった。","彼女の努力は失敗に終わった。","彼女は試合に参加しなかった。"]},{en:"The investigation culminated in several arrests.",ja:"その調査は複数の逮捕に最高潮に達した。",wrong:["その調査は何の結果ももたらさなかった。","その調査は開始前に終わった。","その調査は容疑者を釈放した。"]}]},{word:"datum",meaning:"データ（単数形）",example:"Each datum was recorded with precise timestamps.",category:"science",difficulty:5,examples:[{en:"Each datum was carefully recorded in the laboratory notebook.",ja:"各データ（単数）は実験室のノートに慎重に記録された。",wrong:["すべてのデータは記録されなかった。","そのデータは口頭で報告された。","その基準点は計算に含まれなかった。"]},{en:"A single datum is insufficient to draw a conclusion.",ja:"単一のデータでは結論を引き出すのに不十分である。",wrong:["複数のデータは結論を引き出すのに不十分である。","単一のデータは十分に信頼できる。","データなしで結論は常に有効である。"]},{en:"The datum serves as a reference point for comparison.",ja:"そのデータは比較の参照点として機能する。",wrong:["複数のデータは比較の参照点として機能する。","データは比較に使用されない。","基準点は任意に選択される。"]}]},{word:"decipher",meaning:"解読する",example:"Scientists deciphered the ancient script using statistical methods.",category:"history",difficulty:5,examples:[{en:"The archaeologist worked to decipher the ancient hieroglyphics.",ja:"その考古学者は古代の象形文字を解読するために働いた。",wrong:["考古学者は象形文字を保存した。","象形文字は簡単に読めた。","象形文字は翻訳できない。"]},{en:"I could not decipher her handwriting.",ja:"私は彼女の筆跡を解読することができなかった。",wrong:["私は彼女の筆跡をすぐに読めた。","彼女の文字は非常に明確である。","私は文字を読むことを拒否した。"]},{en:"Experts are trying to decipher the coded message.",ja:"専門家たちはその暗号化されたメッセージを解読しようとしている。",wrong:["メッセージはすぐに読める。","専門家たちはメッセージを無視している。","メッセージは解読不可能である。"]}]},{word:"deductive",meaning:"演繹的な",example:"Deductive reasoning moves from general principles to specific cases.",category:"science",difficulty:5,examples:[{en:"The deductive reasoning led to a logical conclusion.",ja:"その演繹的推論は論理的な結論に導いた。",wrong:["帰納的推論は事実に基づいている。","演繹的推論は証拠を必要としない。","演繹的推論は感情に基づいている。"]},{en:"Sherlock Holmes used deductive methods to solve crimes.",ja:"シャーロック・ホームズは演繹的方法を使用して犯罪を解決した。",wrong:["ホームズは直感のみを使用した。","ホームズは論理を無視した。","ホームズは証拠を検討しなかった。"]},{en:"In deductive logic, if the premises are true, the conclusion must be true.",ja:"演繹論理では、前提が真であれば、結論は必ず真である。",wrong:["帰納論理では、前提が常に真である。","演繹的論理では、結論は常に偽である。","演繹的推論は確率に基づいている。"]}]},{word:"delineate",meaning:"描写する、輪郭を示す",example:"The paper delineates the boundaries of the study.",category:"science",difficulty:6,examples:[{en:"The map delineates the borders of the country.",ja:"その地図は国の国境を描写する。",wrong:["その地図は国境を隠蔽する。","その地図は不正確な位置を示す。","その地図は国境に注意を払わない。"]},{en:"The contract delineates the responsibilities of each party.",ja:"その契約は各当事者の責任を描写する。",wrong:["その契約は責任を明確にしない。","その契約は曖昧である。","その契約は義務を無視する。"]},{en:"The artist delineated the figure with careful lines.",ja:"その芸術家は注意深い線で人物の輪郭を示した。",wrong:["芸術家は粗い線を使用した。","芸術家は輪郭を描かなかった。","芸術家は不注意に描いた。"]}]},{word:"demography",meaning:"人口統計学",example:"Demography reveals how populations change over time.",category:"science",difficulty:5,examples:[{en:"Demography studies population size, structure, and distribution.",ja:"人口統計学は人口のサイズ、構造、分布を研究する。",wrong:["人口統計学は経済を研究する。","人口統計学は個人の心理を研究する。","人口統計学は物理学を研究する。"]},{en:"The demography of the region shows an aging population.",ja:"その地域の人口統計は高齢化した人口を示している。",wrong:["その地域は若い人口を示している。","人口統計は出生率を測定しない。","人口統計は移動を記録しない。"]},{en:"Demographic data helps governments plan social services.",ja:"人口統計的データは政府が社会サービスを計画するのに役立つ。",wrong:["人口統計データは計画に役立たない。","人口統計は医療に使用されない。","人口統計は教育計画に無関係である。"]}]},{word:"denote",meaning:"表す、意味する",example:"In this equation, x denotes the independent variable.",category:"science",difficulty:5,examples:[{en:"The symbol '+' denotes addition in mathematics.",ja:"記号「+」は数学で加算を表す。",wrong:["記号「+」は減算を意味する。","記号「+」は乗算を示す。","記号「+」は何も表さない。"]},{en:"Red traffic lights denote stop.",ja:"赤い信号は停止を意味する。",wrong:["赤い信号は進行を表す。","赤い信号は注意を意味する。","赤い信号は意味がない。"]},{en:"The term 'literature' denotes written works of artistic value.",ja:"「文学」という用語は芸術的価値のある著作物を表す。",wrong:["文学は科学的著作物のみを示す。","文学は物理的なオブジェクトを表す。","文学という言葉は明確な意味を持たない。"]}]},{word:"depiction",meaning:"描写",example:"The artist's depiction of rural life is remarkably accurate.",category:"culture",difficulty:5},{word:"deterministic",meaning:"決定論的な",example:"The model uses a deterministic rather than probabilistic approach.",category:"science",difficulty:6,examples:[{en:"Classical physics assumes a deterministic universe where effects follow causes.",ja:"古典物理学は、結果が原因に従う決定論的宇宙を仮定する。",wrong:["古典物理学は非決定論的である。","古典物理学は因果関係を否定する。","古典物理学は不確実性を仮定する。"]},{en:"The deterministic model predicts future events based on initial conditions.",ja:"その決定論的モデルは初期条件に基づいて将来のイベントを予測する。",wrong:["確率的モデルは初期条件に基づいて予測する。","決定論的モデルは正確な予測ができない。","決定論的モデルはランダムな結果を生成する。"]},{en:"In a deterministic system, the same input always produces the same output.",ja:"決定論的システムでは、同じ入力は常に同じ出力を生成する。",wrong:["確率的システムでは同じ入力が同じ出力を生成する。","決定論的システムではランダムな結果が生じる。","決定論的システムでは出力は入力と無関係である。"]}]},{word:"dichotomy",meaning:"二分法",example:"The nature-nurture dichotomy is overly simplistic.",category:"science",difficulty:6,examples:[{en:"There is a false dichotomy between science and religion.",ja:"科学と宗教の間には誤った二分法がある。",wrong:["科学と宗教は完全に相互互換性がある。","科学と宗教の間には何の関係もない。","二分法は存在しない。"]},{en:"The dichotomy between work and leisure is becoming blurred.",ja:"仕事と余暇の二分法は曖昧になってきている。",wrong:["仕事と余暇は常に明確に分離されている。","仕事と余暇の間に区別はない。","二分法は強化されている。"]},{en:"The traditional dichotomy of male and female gender roles is being challenged.",ja:"男女の性別役割の伝統的な二分法は挑戦されている。",wrong:["性別役割の二分法は一般的に受け入れられている。","二分法は廃止された。","性別役割の区別はない。"]}]},{word:"diffusion",meaning:"拡散",example:"The diffusion of ideas across cultures shaped history.",category:"science",difficulty:5,examples:[{en:"The diffusion of new technology across the company took several months.",ja:"新しい技術が会社全体に拡散するのに数ヶ月かかりました。",wrong:["技術の集中が会社全体に広がった","技術が会社から消えた","技術が一箇所に集められた"]},{en:"Light diffusion through frosted glass creates a soft glow.",ja:"すりガラスを通した光の拡散は柔らかな光を作り出します。",wrong:["光がすりガラスで完全に遮断された","光が一点に集中した","光がガラスに吸収された"]},{en:"The diffusion of oxygen in water is essential for aquatic life.",ja:"水中への酸素の拡散は水生生物に不可欠です。",wrong:["酸素が水に吸収されない","酸素が水から逃げ出す","酸素が水中に集中する"]}]},{word:"discrepancy",meaning:"不一致",example:"There is a discrepancy between the two datasets.",category:"science",difficulty:5,examples:[{en:"There was a discrepancy between the reported sales figures and the actual revenue.",ja:"報告された売上数字と実際の収益との間に不一致がありました。",wrong:["売上数字と実際の収益が完全に一致した","売上数字が実際の収益より高かった","実際の収益が報告数字より低かった"]},{en:"The audit revealed a significant discrepancy in the accounting records.",ja:"監査は会計記録に重大な不一致を明らかにしました。",wrong:["監査は会計記録の正確性を確認した","会計記録に誤りはなかった","記録がすべて一致していた"]},{en:"A small discrepancy in measurements can lead to big problems later.",ja:"測定値の小さな不一致は後で大きな問題につながる可能性があります。",wrong:["測定値は完全に正確だった","小さな誤差は問題にならない","すべての測定値が同じだった"]}]},{word:"disseminate",meaning:"普及させる",example:"Journals disseminate research findings to the academic community.",category:"science",difficulty:5,examples:[{en:"The organization works to disseminate information about climate change.",ja:"その組織は気候変動に関する情報を普及させるために活動しています。",wrong:["組織は気候変動の情報を隠している","情報が普及されていない","情報は一箇所に留まっている"]},{en:"Social media makes it easy to disseminate news quickly.",ja:"ソーシャルメディアはニュースを素早く普及させることを容易にします。",wrong:["ソーシャルメディアはニュース配信を遅くする","ニュースが拡散しにくい","情報が一人にしか届かない"]},{en:"Teachers disseminate knowledge to their students through various methods.",ja:"教師は様々な方法で生徒に知識を普及させます。",wrong:["教師は知識を隠している","知識が生徒に届かない","教師は一人の生徒だけに教える"]}]},{word:"dissolution",meaning:"溶解、解散",example:"The dissolution of the empire occurred gradually.",category:"history",difficulty:6,examples:[{en:"The dissolution of salt in water is a common chemical process.",ja:"水への塩の溶解は一般的な化学的プロセスです。",wrong:["塩が水に溶けない","塩が水に固まる","塩が水から分離する"]},{en:"The company announced the dissolution of its partnership after ten years.",ja:"その企業は10年後にパートナーシップの解散を発表しました。",wrong:["企業がパートナーシップを継続した","パートナーシップがさらに強くなった","企業が新しいパートナーを加えた"]},{en:"The dissolution of the political party surprised many observers.",ja:"その政党の解散は多くの観察者を驚かせました。",wrong:["政党がより大きくなった","政党が統合された","政党が権力を増やした"]}]},{word:"diverge",meaning:"分岐する",example:"Opinions diverge sharply on this issue.",category:"science",difficulty:5,examples:[{en:"The two paths diverge at the fork in the road.",ja:"2つの道は道の分岐点で分岐します。",wrong:["2つの道が一本になった","2つの道が平行に走る","2つの道が同じ方向に進む"]},{en:"Their opinions began to diverge as they discussed the project.",ja:"プロジェクトについて議論するにつれて、彼らの意見は分岐し始めました。",wrong:["彼らの意見はより一致した","彼らは同じ見方を持ち始めた","意見が統一された"]},{en:"The river diverges into several smaller streams in the delta.",ja:"川はデルタでいくつかの小さな流れに分岐します。",wrong:["川が一本に合流した","川が止まった","川がより大きくなった"]}]},{word:"dormancy",meaning:"休眠",example:"Seeds can survive long periods of dormancy.",category:"science",difficulty:5,examples:[{en:"Many seeds enter a state of dormancy during winter.",ja:"多くの種は冬の間休眠状態に入ります。",wrong:["種は冬に成長する","種は冬に発芽する","種は常に活動的である"]},{en:"The dormancy of the volcano lasted for several centuries.",ja:"その火山の休眠は数百年間続きました。",wrong:["火山が常に活動していた","火山が爆発した","火山が消滅した"]},{en:"During dormancy, the organism's metabolism slows down significantly.",ja:"休眠中、生物の代謝は著しく低下します。",wrong:["休眠中、代謝が加速する","休眠中、代謝が停止する","休眠は代謝に影響しない"]}]},{word:"dualism",meaning:"二元論",example:"Mind-body dualism has been debated for centuries.",category:"science",difficulty:6,examples:[{en:"Descartes' dualism proposed a separation between mind and body.",ja:"デカルトの二元論は心と体の分離を提案しました。",wrong:["デカルトは心と体が同じだと言った","デカルトは心の存在を否定した","デカルトは物質的なものだけを信じた"]},{en:"The philosophical concept of dualism has been debated for centuries.",ja:"二元論という哲学的概念は数世紀にわたって議論されてきました。",wrong:["二元論は最近発見された","二元論は誰も議論していない","二元論は単純で議論の余地がない"]},{en:"Religious dualism often portrays good and evil as opposing forces.",ja:"宗教的二元論はしばしば善と悪を対立する力として描きます。",wrong:["宗教的二元論は善と悪を同じものと見なす","宗教的二元論には善悪の概念がない","宗教的二元論は3つ以上の力を認める"]}]},{word:"efficacy",meaning:"有効性",example:"Clinical trials measure the efficacy of new treatments.",category:"science",difficulty:5,examples:[{en:"The efficacy of the new medicine was proven through clinical trials.",ja:"新しい薬の有効性は臨床試験で証明されました。",wrong:["薬の有効性は証明されなかった","薬は効かなかった","薬は危険だった"]},{en:"The company questioned the efficacy of their competitor's product.",ja:"その企業は競合他社の製品の有効性に疑問を呈しました。",wrong:["企業は競合他社を支持した","企業は製品の有効性を認めた","企業は何も言わなかった"]},{en:"Studies have demonstrated the efficacy of exercise in reducing stress.",ja:"研究はストレスを軽減するための運動の有効性を実証しています。",wrong:["運動はストレスを増加させる","運動は効果的でない","研究が有効性を否定した"]}]},{word:"elicit",meaning:"引き出す",example:"The survey was designed to elicit honest responses.",category:"science",difficulty:5,examples:[{en:"The teacher's questions elicited thoughtful responses from the students.",ja:"教師の質問は学生から思慮深い回答を引き出しました。",wrong:["質問は学生の反応を抑圧した","学生は答えなかった","質問は無意味だった"]},{en:"The investigator worked hard to elicit the truth from the witness.",ja:"捜査官は証人から真実を引き出すために懸命に働きました。",wrong:["捜査官は真実を隠した","証人は嘘をついた","真実は引き出されなかった"]},{en:"The artist's work elicited strong emotions from the audience.",ja:"その芸術家の作品は観客から強い感情を引き出しました。",wrong:["作品は感情を起こさなかった","観客は無関心だった","作品は退屈だった"]}]},{word:"elucidate",meaning:"解明する",example:"Further research is needed to elucidate the mechanism.",category:"science",difficulty:6,examples:[{en:"The professor worked to elucidate the complex theory for her students.",ja:"教授は複雑な理論を学生のために解明するために働きました。",wrong:["教授はさらに複雑にした","学生はより混乱した","教授は説明を避けた"]},{en:"The research paper elucidates the causes of climate change.",ja:"その研究論文は気候変動の原因を解明しています。",wrong:["論文は気候変動について不明確である","論文は原因を隠している","論文は無関係である"]},{en:"The witness's testimony helped elucidate the sequence of events.",ja:"その証人の証言は事件の経過を解明するのに役立ちました。",wrong:["証言は事件をさらに不明確にした","証言は無関係だった","証言は誤解を招いた"]}]},{word:"embryonic",meaning:"胚の、初期段階の",example:"The technology is still in its embryonic stage.",category:"science",difficulty:5,examples:[{en:"The company is still in its embryonic stage of development.",ja:"その企業はまだ発展の胚段階にあります。",wrong:["企業は完全に成熟している","企業は衰退している","企業は閉鎖されている"]},{en:"Embryonic stem cells have great potential for medical research.",ja:"胚性幹細胞は医学研究における大きな可能性を持っています。",wrong:["胚性幹細胞は医学的価値がない","胚性幹細胞は危険である","胚性幹細胞は研究に使えない"]},{en:"The technology was in its embryonic form when first introduced.",ja:"その技術は最初に導入されたときは初期段階の形でした。",wrong:["技術は完全に開発されていた","技術は古すぎた","技術は使用不可能だった"]}]},{word:"empiricism",meaning:"経験主義",example:"Empiricism holds that knowledge comes from sensory experience.",category:"science",difficulty:6,examples:[{en:"Empiricism emphasizes the importance of observation and experience in gaining knowledge.",ja:"経験主義は知識を得るにおいて観察と経験の重要性を強調しています。",wrong:["経験主義は観察を否定する","経験主義は抽象理論を重視する","経験主義は経験を無視する"]},{en:"Scientific empiricism requires that hypotheses be tested through experimentation.",ja:"科学的経験主義は仮説を実験を通じてテストすることを要求します。",wrong:["科学的経験主義は実験を不要とする","仮説はテストされない","経験主義は理論を信じない"]},{en:"The philosopher argued for empiricism over pure rationalism.",ja:"その哲学者は純粋な合理主義より経験主義を主張しました。",wrong:["哲学者は合理主義を支持した","哲学者は経験を否定した","哲学者は観察を軽視した"]}]},{word:"endemic",meaning:"風土性の、固有の",example:"Malaria is endemic to tropical regions.",category:"science",difficulty:5,examples:[{en:"The disease is endemic to the tropical regions of Africa.",ja:"その病気はアフリカの熱帯地域に風土性があります。",wrong:["病気は世界中に広がっている","病気はアフリカにはない","病気はその地域から来た"]},{en:"Many endemic species are found only in Madagascar.",ja:"多くの固有種はマダガスカルにだけ見られます。",wrong:["固有種は世界中にいる","種はマダガスカルに存在しない","種は最近移入された"]},{en:"Corruption is endemic to the bureaucratic system.",ja:"汚職は官僚制度に固有のものです。",wrong:["汚職はその制度にはない","汚職は新しい現象である","汚職はどこでも同じである"]}]},{word:"entropy",meaning:"無秩序の度合い",example:"The second law of thermodynamics states that entropy tends to increase.",category:"science",difficulty:6,examples:[{en:"The second law of thermodynamics states that entropy always increases.",ja:"熱力学の第二法則は無秩序の度合いが常に増加することを述べています。",wrong:["エントロピーは常に減少する","エントロピーは一定である","エントロピーは存在しない"]},{en:"Over time, the organization's structure increased in entropy as it became disorganized.",ja:"時間とともに、組織の構造は無秩序になるにつれて無秩序の度合いが増加しました。",wrong:["組織はより整理されました","組織の構造は変わらなかった","エントロピーは減少した"]},{en:"Information entropy measures the uncertainty in a communication system.",ja:"情報エントロピーは通信システムの不確実性を測定します。",wrong:["情報エントロピーは確実性を測定する","エントロピーは通信に関係ない","エントロピーは秩序を測定する"]}]},{word:"enumerate",meaning:"列挙する",example:"The report enumerates the risk factors for the disease.",category:"science",difficulty:5,examples:[{en:"The report enumerates all the steps needed to complete the project.",ja:"その報告書はプロジェクトを完了するために必要なすべてのステップを列挙しています。",wrong:["報告書はステップを説明していない","ステップが不完全である","報告書は概要のみを提供する"]},{en:"The speaker enumerated the reasons for the company's success.",ja:"スピーカーは企業の成功の理由を列挙しました。",wrong:["スピーカーは理由について言及しなかった","理由が不明確だった","スピーカーは成功を説明しなかった"]},{en:"Please enumerate the items on the checklist before proceeding.",ja:"進める前にチェックリストの項目を列挙してください。",wrong:["チェックリストを無視する","項目を数えない","進める前に確認しない"]}]},{word:"epistemic",meaning:"認識論的な",example:"Epistemic uncertainty arises from limited knowledge.",category:"science",difficulty:6,examples:[{en:"The epistemic foundation of science relies on empirical evidence.",ja:"科学の認識論的基礎は経験的証拠に依存している。",wrong:["科学の哲学的根拠は論理的推論に基づいている。","認識論的方法は主観的な信念に頼っている。","科学の認識論的アプローチは感覚的経験を否定する。"]},{en:"There is an epistemic problem in accepting claims without verification.",ja:"検証なしに主張を受け入れることは認識論的問題である。",wrong:["確認なしに主張を受け入れることは倫理的問題である。","検証なしに主張を受け入れることは言語的問題である。","確認なしに主張を受け入れることは数学的問題である。"]},{en:"Her epistemic perspective shaped how she interpreted the data.",ja:"彼女の認識論的観点はデータの解釈方法を形作った。",wrong:["彼女の倫理的視点はデータの分析方法を決定した。","彼女の認識論的観点は統計的手法を排除した。","彼女の実証的立場はデータの信頼性を否定した。"]}]},{word:"equilibrium",meaning:"均衡",example:"The ecosystem is in a state of dynamic equilibrium.",category:"science",difficulty:5,examples:[{en:"The market reached equilibrium when supply equaled demand.",ja:"供給が需要と等しくなったとき、市場は均衡に達した。",wrong:["市場が不均衡に達したとき、供給と需要が等しくなった。","供給が需要を上回ったとき、市場は均衡状態にあった。","需要が供給の半分になったとき、市場は均衡に達した。"]},{en:"Chemical equilibrium occurs when forward and reverse reactions proceed at equal rates.",ja:"正反応と逆反応が同じ速度で進行するとき、化学均衡が生じる。",wrong:["化学反応が一方向に進む場合、化学均衡が生じる。","正反応が逆反応より速く進むとき、均衡状態が達成される。","反応が停止したとき、化学均衡が成立する。"]},{en:"The system returned to equilibrium after the external disturbance.",ja:"外部の撹乱の後、システムは均衡に戻った。",wrong:["外部の撹乱により、システムはより安定した不均衡に移行した。","システムが均衡から逸脱した後、撹乱は終わった。","外部の干渉がシステムを永遠に不均衡に保った。"]}]},{word:"erratic",meaning:"不規則な",example:"The patient exhibited erratic behaviour.",category:"science",difficulty:5,examples:[{en:"His erratic behavior made it difficult to predict his actions.",ja:"彼の不規則な行動は彼の行動を予測することを困難にした。",wrong:["彼の予測可能な行動は彼の行動の予測を不可能にした。","彼の一貫性のある行動は予測を困難にした。","彼の論理的で秩序立った行動は不確実性を生み出した。"]},{en:"The stock market showed erratic fluctuations during the financial crisis.",ja:"金融危機の間、株式市場は不規則な変動を示した。",wrong:["金融危機の間、株式市場は安定した上昇を示した。","株式市場の規則正しい変動は金融危機を引き起こした。","危機の期間中、市場は一貫した下降トレンドを示した。"]},{en:"The patient's erratic sleep schedule affected his overall health.",ja:"患者の不規則な睡眠スケジュールは彼の全体的な健康に影響を与えた。",wrong:["患者の一定の睡眠パターンは健康を害した。","不規則な睡眠スケジュールはすべての患者の健康を改善した。","規則正しい睡眠時間は睡眠障害を引き起こした。"]}]},{word:"etiology",meaning:"病因学",example:"The etiology of the disease remains poorly understood.",category:"science",difficulty:6,examples:[{en:"The etiology of the disease remains unknown despite extensive research.",ja:"広範な研究にもかかわらず、疾患の病因は未知のままである。",wrong:["疾患の症状は広範な研究によって原因が明らかになった。","病因学的研究は疾患の治療法を完全に確立した。","病因は疾患の診断後に発見される。"]},{en:"Understanding the etiology of mental illness is crucial for developing treatments.",ja:"精神疾患の病因を理解することは治療法の開発に重要である。",wrong:["精神疾患の症状を理解することは原因を無視することと同じである。","病因学は治療法の開発とは無関係である。","精神疾患の予防は病因を知ることを必要としない。"]},{en:"The etiology of diabetes includes genetic and environmental factors.",ja:"糖尿病の病因には遺伝的および環境的要因が含まれる。",wrong:["糖尿病は単一の遺伝的原因によってのみ引き起こされる。","環境的要因だけが糖尿病の原因である。","糖尿病の病因は完全に不明確である。"]}]},{word:"exacerbate",meaning:"悪化させる",example:"Climate change exacerbates food insecurity.",category:"current",difficulty:5,examples:[{en:"Stress tends to exacerbate his chronic pain condition.",ja:"ストレスは彼の慢性痛の状態を悪化させる傾向がある。",wrong:["ストレスは彼の慢性痛を完全に治す。","ストレスは慢性痛の症状を緩和する。","ストレスは痛みの感覚を完全に消す。"]},{en:"The lack of funding exacerbated the already difficult situation.",ja:"資金不足はすでに困難な状況を悪化させた。",wrong:["資金不足により状況は改善した。","資金がないことで問題は解決した。","不十分な予算投入は状況を安定させた。"]},{en:"Ignoring the problem will only exacerbate it further.",ja:"問題を無視することはそれをさらに悪化させるだけである。",wrong:["問題を無視することで問題は自動的に解決される。","何もしないことで悪化を防ぐことができる。","問題を見ないようにすることで改善される。"]}]},{word:"exemplify",meaning:"例示する",example:"This case exemplifies the challenges of modern governance.",category:"society",difficulty:5,examples:[{en:"These case studies exemplify the best practices in the industry.",ja:"これらのケーススタディは業界のベストプラクティスを例示している。",wrong:["これらのケーススタディは業界の最悪の慣行を示している。","事例研究は業界の基準を批評している。","ケーススタディは実践的な例を提供しない。"]},{en:"Her career exemplifies what dedication and hard work can achieve.",ja:"彼女のキャリアは献身と努力がもたらすことができるものを例示している。",wrong:["彼女のキャリアは怠惰と無責任さの例である。","彼女の仕事は成功の不可能性を示す。","彼女の経験は運と偶然だけに依存していることを示す。"]},{en:"This painting exemplifies the characteristics of the Impressionist movement.",ja:"この絵画は印象派運動の特徴を例示している。",wrong:["この絵画は印象派運動に反対している。","この作品は印象派の特性を無視している。","この絵画は古典主義の典型例である。"]}]},{word:"exogenous",meaning:"外因性の",example:"Exogenous factors like climate affected agricultural output.",category:"science",difficulty:6,examples:[{en:"Exogenous variables are those determined outside the model.",ja:"外因性変数はモデルの外で決定される変数である。",wrong:["外因性変数はモデルの内部で生成される。","外部から影響を受けない変数が外因性変数である。","モデルに含まれる変数が外因性変数である。"]},{en:"The economic shock was an exogenous factor that no one predicted.",ja:"経済的ショックは誰も予測しなかった外因性の要因だった。",wrong:["経済的ショックはモデル内で予測可能な内部要因だった。","外部から独立した経済ショックは発生しない。","予測不可能なショックは内因性である。"]},{en:"Environmental changes are exogenous factors in this biological study.",ja:"環境変化はこの生物学的研究の外因性要因である。",wrong:["環境変化は生物の内部で発生する。","外部から来ていない変化が外因性である。","生物が環境変化を引き起こす。"]}]},{word:"exponential",meaning:"指数関数的な",example:"The population grew at an exponential rate.",category:"science",difficulty:5,examples:[{en:"The exponential growth of the population alarmed city planners.",ja:"人口の指数関数的増加は都市計画家を懸念させた。",wrong:["人口の線形減少は都市計画家を懸念させた。","人口の指数関数的衰退が問題となった。","人口の安定は計画者の懸念事項だった。"]},{en:"The virus spread at an exponential rate during the pandemic.",ja:"パンデミック中、ウイルスは指数関数的な速度で広がった。",wrong:["ウイルスは一定の速度で一貫して広がった。","ウイルスの拡散は時間とともに遅くなった。","感染は線形的に増加した。"]},{en:"Computing power has increased exponentially over the past decades.",ja:"コンピュータの処理能力はここ数十年間に指数関数的に増加した。",wrong:["コンピュータの能力は衰退している。","処理能力は過去数十年間減少した。","技術進歩は直線的で遅い。"]}]},{word:"extrapolate",meaning:"外挿する、推定する",example:"We cannot extrapolate these results to the general population.",category:"science",difficulty:6,examples:[{en:"We can extrapolate future trends based on historical data.",ja:"歴史的データに基づいて将来のトレンドを外挿することができる。",wrong:["歴史的データはこれからの傾向を予測することを不可能にする。","過去のデータから未来を外挿することは科学的ではない。","予測は常に実現する。"]},{en:"The researcher extrapolated the findings to a larger population.",ja:"研究者はより大きな集団に対して調査結果を外挿した。",wrong:["研究者は小さなグループから大きな集団への外挿を拒否した。","外挿は常に不正確である。","サンプルの結果は一般化できない。"]},{en:"If current consumption rates continue, we can extrapolate resource depletion by 2050.",ja:"現在の消費率が続けば、2050年までに資源枯渇を外挿することができる。",wrong:["消費率の変化は予測不可能である。","資源は無限であり、外挿は無関係である。","過去の消費パターンは将来を示さない。"]}]},{word:"fallacy",meaning:"誤謬",example:"The argument contains a logical fallacy.",category:"science",difficulty:5,examples:[{en:"Assuming correlation implies causation is a common logical fallacy.",ja:"相関が因果関係を意味すると仮定することは一般的な論理的誤謬である。",wrong:["相関は常に因果関係を示す。","因果関係と相関は同じ意味である。","論理的誤謬は証明可能な事実である。"]},{en:"The ad hominem fallacy attacks the person rather than the argument.",ja:"人身攻撃の誤謬は議論ではなく人を攻撃する。",wrong:["人身攻撃は議論の有効な形式である。","人身攻撃の誤謬は主張の内容に焦点を当てている。","誤謬は常に真実に基づいている。"]},{en:"The false dilemma fallacy presents only two options when more exist.",ja:"二者択一の誤謬は、より多くのオプションが存在する場合、2つのオプションのみを提示する。",wrong:["二者択一の誤謬はすべての可能な選択肢を含む。","選択肢が2つだけの場合、それは論理的誤りではない。","誤謬は常に複数の解決策を提供する。"]}]},{word:"fidelity",meaning:"忠実度",example:"The simulation achieves high fidelity to real-world conditions.",category:"technology",difficulty:5,examples:[{en:"The high fidelity of the audio equipment reproduced sound accurately.",ja:"オーディオ機器の高い忠実度は音声を正確に再現した。",wrong:["高忠実度はひずみのある音を生成する。","低忠実度により、より正確な再現が実現する。","忠実度は音質に影響を与えない。"]},{en:"Her fidelity to her principles never wavered despite pressure.",ja:"圧力があったにもかかわらず、彼女の原則への忠実度は揺らがなかった。",wrong:["圧力の下では忠実度は重要ではない。","彼女の原則は容易に放棄された。","忠実度とは原則に反することである。"]},{en:"The fidelity of the translation preserved the original meaning.",ja:"翻訳の忠実度は原文の意味を保った。",wrong:["忠実な翻訳は原文の意味を変える。","翻訳の正確さは意味の喪失につながる。","忠実度は言語間の翻訳には関連がない。"]}]},{word:"finite",meaning:"有限の",example:"The earth has a finite supply of fossil fuels.",category:"science",difficulty:5,examples:[{en:"The planet's natural resources are finite and must be conserved.",ja:"地球の天然資源は有限であり、保全する必要がある。",wrong:["地球の資源は無限である。","有限な資源は保存の必要がない。","自然資源は決して枯渇しない。"]},{en:"Each person has a finite amount of time and energy.",ja:"各人は有限な時間とエネルギーを持っている。",wrong:["人は無限の時間とエネルギーを持っている。","時間とエネルギーは無制限である。","有限性は人間には適用されない。"]},{en:"The finite nature of life makes every moment precious.",ja:"人生の有限な性質はすべての瞬間を貴重にする。",wrong:["人生は無限である。","有限性は人生を価値がなくする。","有限な存在は重要ではない。"]}]},{word:"flux",meaning:"流動、変化",example:"The political situation remains in flux.",category:"society",difficulty:5,examples:[{en:"The situation is in a state of flux as policies continue to change.",ja:"方針が継続的に変化するにつれて、状況は流動的である。",wrong:["状況は固定されており、変化していない。","流動状態は安定性を示す。","変化の途中にあることは静止状態である。"]},{en:"The city was in constant flux during the period of rapid urbanization.",ja:"都市は急速な都市化の時期に絶え間ない変化の中にあった。",wrong:["都市化は変化を引き起こさない。","流動状態の都市は安定している。","急速な変化は安定性を示す。"]},{en:"In physics, flux refers to the flow of a field through a surface.",ja:"物理学では、束(フラックス)は表面を通る場の流れを指す。",wrong:["束は流れの反対を意味する。","フラックスは静止した場を示す。","束は流れと無関係である。"]}]},{word:"focal",meaning:"焦点の",example:"Education reform became the focal point of the debate.",category:"society",difficulty:5,examples:[{en:"The focal point of the painting draws the viewer's attention.",ja:"絵画の焦点は視聴者の注意を引く。",wrong:["焦点は視聴者の注意を逸らす。","焦点のある絵画は注意を分散させる。","焦点は視覚的重要性を低下させる。"]},{en:"Education became the focal issue in the election campaign.",ja:"教育は選挙キャンペーンの焦点的な課題となった。",wrong:["教育は選挙キャンペーンから無視された。","焦点的な問題は注目を集めない。","教育は周辺的な争点であった。"]},{en:"The focal length of the lens determines the magnification.",ja:"レンズの焦点距離は倍率を決定する。",wrong:["焦点距離は倍率に無関係である。","長い焦点距離は低倍率を生じる。","倍率は焦点距離とは別に決定される。"]}]},{word:"formulation",meaning:"策定、定式化",example:"The formulation of the hypothesis took several months.",category:"science",difficulty:5,examples:[{en:"The formulation of a new policy requires careful consideration.",ja:"新しい政策の策定には慎重な検討が必要である。",wrong:["ポリシー策定には検討は不要である。","政策は検討なしに有効である。","策定とは考えずに決定することである。"]},{en:"The pharmaceutical company developed a new drug formulation.",ja:"製薬会社は新しい医薬品配合を開発した。",wrong:["医薬品の配合は製薬会社では開発されない。","配合とは既存の物質をそのまま使用することである。","処方は化学変化を含まない。"]},{en:"The mathematical formulation of the problem allowed for systematic solution.",ja:"問題の数学的定式化は体系的な解法を可能にした。",wrong:["数学的定式化は問題を複雑にする。","定式化は解決を妨げる。","問題の定式化は解法を助けない。"]}]},{word:"fractional",meaning:"部分的な、わずかな",example:"Even a fractional change in temperature affects the ecosystem.",category:"science",difficulty:5,examples:[{en:"The company made only a fractional improvement in its sales this quarter.",ja:"その会社は今四半期の売上でわずかな改善しかできなかった。",wrong:["その会社は今四半期に大幅な改善を遂行した。","その会社の売上は完全に改善された。","その会社は売上の全部を改善した。"]},{en:"A fractional reserve banking system allows banks to lend out more money than they hold in reserves.",ja:"部分準備銀行制度により、銀行は保有している準備金よりも多くのお金を貸し出すことができる。",wrong:["銀行は準備金全体を貸し出す制度である。","この制度では銀行は準備金を貸し出すことができない。","銀行は無制限に準備金を保有する制度である。"]},{en:"The patient showed only a fractional response to the initial treatment.",ja:"患者は初期治療に対してわずかな反応しか示さなかった。",wrong:["患者は治療に完全に反応した。","患者は治療に反応しなかった。","患者の反応は非常に強かった。"]}]},{word:"fuse",meaning:"融合する",example:"The two artistic traditions fused to create a new style.",category:"culture",difficulty:5,examples:[{en:"The two companies decided to fuse their operations to become more competitive.",ja:"2つの企業は競争力を高めるために事業を融合させることに決めた。",wrong:["2つの企業は事業を分離させることに決めた。","2つの企業は統合できず、別々のままだった。","2つの企業は競争関係を続けることに決めた。"]},{en:"When you fuse hydrogen atoms, you can create tremendous energy.",ja:"水素原子を融合させると、莫大なエネルギーを生み出すことができる。",wrong:["水素原子を分裂させるとエネルギーが生まれる。","水素原子の融合ではエネルギーが消費される。","水素原子を融合させてもエネルギーは生まれない。"]},{en:"The artist decided to fuse traditional techniques with modern styles.",ja:"その芸術家は伝統的な技法と現代的なスタイルを融合させることに決めた。",wrong:["その芸術家は伝統的な技法を完全に捨てた。","その芸術家は現代的なスタイルを拒否した。","その芸術家の作品には融合の要素がない。"]}]},{word:"genealogy",meaning:"系譜学",example:"She traced her genealogy back to the 18th century.",category:"history",difficulty:5,examples:[{en:"She spent years researching her family's genealogy to trace her ancestors.",ja:"彼女は家族の系譜をたどるために何年も家族の系譜学を研究した。",wrong:["彼女は祖先を研究することなく家族の歴史を知っていた。","彼女は系譜学には興味がなかった。","彼女の家族には系譜がない。"]},{en:"The genealogy of the royal family shows a continuous line of succession for centuries.",ja:"王族の系譜は数世紀にわたって継続的な継承系統を示している。",wrong:["王族の系譜には断絶がない。","王族の系譜は数十年しかない。","王族の系譜は記録されていない。"]},{en:"Modern DNA testing has revolutionized the study of genealogy.",ja:"現代のDNA検査は系譜学の研究に革命をもたらした。",wrong:["DNA検査は系譜学に役立たない。","DNA検査が導入される前は系譜学は存在しなかった。","DNA検査は系譜学の研究を難しくした。"]}]},{word:"genesis",meaning:"起源",example:"The genesis of the theory can be traced to the 1950s.",category:"science",difficulty:5,examples:[{en:"The genesis of the project began with a simple idea in a coffee shop.",ja:"そのプロジェクトの起源はコーヒーショップでの単純な考えから始まった。",wrong:["そのプロジェクトは大企業で計画された。","そのプロジェクトは長年の計画の結果である。","そのプロジェクトの起源は明確ではない。"]},{en:"Understanding the genesis of the conflict helps us find better solutions.",ja:"紛争の起源を理解することは、より良い解決策を見つけるのに役立つ。",wrong:["紛争の起源を理解する必要はない。","紛争はいきなり発生した。","紛争の起源を知ることは解決につながらない。"]},{en:"The genesis of life on Earth remains one of science's greatest mysteries.",ja:"地球上の生命の起源は科学の最大の謎の一つである。",wrong:["地球上の生命の起源は完全に解明されている。","科学者は生命の起源に興味がない。","生命に起源はない。"]}]},{word:"geopolitical",meaning:"地政学的な",example:"Geopolitical tensions affected global trade patterns.",category:"society",difficulty:5,examples:[{en:"The geopolitical situation in the Middle East remains tense and complex.",ja:"中東の地政学的な状況は依然として緊迫していて複雑である。",wrong:["中東は地政学的に重要ではない。","中東の状況は単純で安定している。","地政学的状況は個々の国には影響しない。"]},{en:"Geopolitical considerations heavily influence international trade agreements.",ja:"地政学的考慮は国際貿易協定に大きく影響する。",wrong:["地政学は貿易協定に影響しない。","貿易協定は経済要因だけで決定される。","地政学的背景は関係国に影響しない。"]},{en:"The geopolitical strategy of major powers shapes global politics.",ja:"大国の地政学的戦略は世界政治を形作っている。",wrong:["大国は地政学的戦略を持たない。","地政学的戦略は世界政治に影響しない。","小国だけが地政学的に重要である。"]}]},{word:"gradient",meaning:"勾配",example:"The temperature gradient drives atmospheric circulation.",category:"science",difficulty:5,examples:[{en:"The hill has a steep gradient that makes it difficult to climb.",ja:"その丘は登るのが難しい急な勾配を持っている。",wrong:["その丘は平坦である。","勾配は登山の難度に影響しない。","その丘の勾配は上昇している。"]},{en:"In mathematics, the gradient represents the rate of change of a function.",ja:"数学では、勾配は関数の変化率を表す。",wrong:["勾配は関数の値そのものである。","勾配は変化率を表さない。","勾配は数学では使用されない。"]},{en:"The temperature gradient across the room indicates uneven heating.",ja:"部屋全体の温度勾配は不均一な加熱を示している。",wrong:["温度勾配は存在しない。","温度勾配は加熱を表さない。","部屋は均一に加熱されている。"]}]},{word:"hegemony",meaning:"覇権",example:"The concept of cultural hegemony was developed by Gramsci.",category:"history",difficulty:6,examples:[{en:"The hegemony of the United States in global affairs has been significant for decades.",ja:"国際関係における米国の覇権は数十年間にわたって重要であった。",wrong:["米国は世界的な覇権を持っていない。","米国の覇権は数年しか続かなかった。","覇権は現代の世界には存在しない。"]},{en:"Western hegemony has gradually shifted with the rise of emerging markets.",ja:"新興市場の台頭に伴い、西側の覇権は徐々に変わってきた。",wrong:["新興市場は西側の覇権に影響しない。","西側の覇権は変わることがない。","覇権は経済的変化に関連しない。"]},{en:"The hegemony of a single power can lead to international instability.",ja:"単一の大国の覇権は国際的な不安定性につながる可能性がある。",wrong:["単一の大国の覇権は安定をもたらす。","覇権は国際関係に影響しない。","複数の国の覇権よりも単一の覇権の方が不安定である。"]}]},{word:"heuristic",meaning:"発見的な",example:"Heuristic methods provide approximate solutions efficiently.",category:"science",difficulty:6,examples:[{en:"The teacher used a heuristic approach to help students discover solutions on their own.",ja:"その教師は学生が自分で解決策を発見するのを助けるために発見的アプローチを使用した。",wrong:["その教師は解決策を学生に直接与えた。","発見的方法は学習には役立たない。","学生は教えられることなく学習することはできない。"]},{en:"Heuristic methods in computer science provide quick but approximate solutions.",ja:"コンピュータサイエンスの発見的方法は迅速だが近似的な解決策を提供する。",wrong:["発見的方法は常に最適な解決策を提供する。","コンピュータサイエンスは発見的方法を使用しない。","発見的方法は遅い結果を生み出す。"]},{en:"A heuristic is a practical strategy for solving problems through trial and error.",ja:"発見的は試行錯誤を通じて問題を解決するための実用的な戦略である。",wrong:["発見的は科学的方法ではない。","発見的は常に正確な答えを保証する。","発見的は問題解決に使用されない。"]}]},{word:"holistic",meaning:"全体論的な",example:"A holistic approach considers the whole system.",category:"science",difficulty:5,examples:[{en:"A holistic approach to health considers both physical and mental well-being.",ja:"健康への全体論的アプローチは身体的および精神的な幸福の両方を考慮する。",wrong:["全体論的アプローチは身体の健康だけに焦点を当てる。","全体論的とは精神的なものだけを意味する。","全体論的アプローチは医学では使用されない。"]},{en:"The holistic view of the business ecosystem requires understanding all stakeholders.",ja:"ビジネスエコシステムの全体論的観点は、すべてのステークホルダーを理解する必要がある。",wrong:["全体論的観点は株主のみを考慮する。","ビジネスエコシステムは部分的にしか理解できない。","全体論的視点はビジネスに役立たない。"]},{en:"Holistic education emphasizes the development of the whole person, not just academics.",ja:"全体論的教育は学問だけでなく、人格全体の発展を強調する。",wrong:["全体論的教育は学問的成果のみに焦点を当てる。","全体論的教育では人格開発は考慮されない。","全体論的教育は有効ではない。"]}]},{word:"homogeneous",meaning:"均質な",example:"The sample was not homogeneous in composition.",category:"science",difficulty:5,examples:[{en:"The mixture became homogeneous after stirring for several minutes.",ja:"混合物は数分間かき混ぜた後、均質になった。",wrong:["混合物はかき混ぜても均質にならない。","均質とは沈殿物があることを意味する。","その混合物は不均一なままである。"]},{en:"The student population in the school is quite homogeneous, coming from similar backgrounds.",ja:"学校の学生人口は同様の背景から来ており、かなり均質である。",wrong:["学生は異なるグループに分けられている。","学生はすべて異なる背景を持っている。","均質な学生人口は存在しない。"]},{en:"A homogeneous solution has a uniform composition throughout.",ja:"均質な溶液は全体を通じて均一な組成を持っている。",wrong:["均質な溶液は異なる層を持つ。","溶液の均質性は測定不可能である。","均質な溶液は化学で一般的ではない。"]}]},{word:"immutable",meaning:"不変の",example:"The laws of physics are considered immutable.",category:"science",difficulty:6,examples:[{en:"In programming, immutable objects cannot be changed once they are created.",ja:"プログラミングでは、不変オブジェクトは作成された後、変更することができない。",wrong:["不変オブジェクトは常に変更できる。","不変はプログラミングでは使用されない用語である。","すべてのオブジェクトは不変である。"]},{en:"The laws of physics are considered immutable and universal.",ja:"物理の法則は不変であり普遍的であると考えられている。",wrong:["物理の法則は時間とともに変わる。","物理の法則は場所によって異なる。","物理の法則は変わりやすい。"]},{en:"Some believe that human nature is immutable, while others argue it can change.",ja:"人間の本性は不変であると信じる人もいれば、それが変わることができると主張する人もいる。",wrong:["人間の本性は必ず変わる。","人間の本性は完全に可変である。","不変性は人間には適用されない。"]}]},{word:"impede",meaning:"妨げる",example:"Bureaucracy can impede scientific progress.",category:"society",difficulty:5,examples:[{en:"Poor infrastructure can impede economic development in developing nations.",ja:"貧弱なインフラは発展途上国の経済発展を妨げることができる。",wrong:["貧弱なインフラは経済発展を促進する。","インフラは経済に影響しない。","妨げることは開発に役立つ。"]},{en:"The new regulations impede the company's ability to expand quickly.",ja:"新しい規制は会社の急速な拡大を妨げている。",wrong:["新しい規制は会社の成長を加速させる。","規制は企業に影響しない。","妨げることは事業にとって良いことだ。"]},{en:"Language barriers can impede effective communication in international meetings.",ja:"言語の障壁は国際会議での効果的なコミュニケーションを妨げることができる。",wrong:["言語の障壁はコミュニケーションを改善する。","言語は理解に影響しない。","すべての言語は平等に理解される。"]}]},{word:"imperative",meaning:"不可欠な、命令形",example:"It is imperative that we act on climate change now.",category:"current",difficulty:5,examples:[{en:"It is imperative that we act now to address climate change.",ja:"気候変動に対処するために今行動することは不可欠である。",wrong:["気候変動への対応は不可欠ではない。","将来の対応で十分である。","気候変動は重要ではない。"]},{en:"The imperative mood in English is used to give commands or instructions.",ja:"英語の命令形は、命令や指示を与えるために使用される。",wrong:["命令形は要求には使用されない。","命令形は英語に存在しない。","命令形は過去時制を表す。"]},{en:"Meeting customer needs is an imperative for any successful business.",ja:"顧客ニーズを満たすことは、どの成功したビジネスにとっても不可欠である。",wrong:["顧客ニーズは事業の成功に影響しない。","顧客を無視することは成功につながる。","不可欠なことは事業には関連しない。"]}]},{word:"impetus",meaning:"推進力",example:"The findings provided the impetus for further research.",category:"science",difficulty:6,examples:[{en:"The impetus for the social movement came from grassroots activists.",ja:"その社会運動の推進力は草の根活動家から来た。",wrong:["社会運動は推進力なく自然に始まった。","推進力は動きを起こさない。","活動家は社会運動に影響しない。"]},{en:"Winning the first match gave the team the impetus to continue their winning streak.",ja:"最初の試合に勝つことはチームに彼らの連勝を続けるための推進力を与えた。",wrong:["勝利は動機付けを提供しない。","推進力は成功につながらない。","最初の試合は以降の試合に影響しない。"]},{en:"The impetus for technological innovation often comes from consumer demand.",ja:"技術革新の推進力はしばしば消費者需要から来る。",wrong:["消費者需要は革新を促さない。","推進力は技術開発に影響しない。","革新は独立して発生する。"]}]},{word:"implication",meaning:"含意、影響",example:"The study discusses the implications for public policy.",category:"science",difficulty:5,examples:[{en:"The implication of the study is that regular exercise improves mental health.",ja:"その研究の含意は、定期的な運動が精神的な健康を改善するということである。",wrong:["その研究は結論を示さない。","含意とは明確に述べられたことだけを意味する。","研究は医療に影響しない。"]},{en:"The political implications of the election results will reshape the country's future.",ja:"選挙結果の政治的影響は国の将来を変えるでしょう。",wrong:["選挙結果は政治に影響しない。","含意は存在しない。","選挙は将来を決定しない。"]},{en:"Although she didn't say it directly, the implication was clear that she disagreed.",ja:"彼女は直接言わなかったが、彼女が反対していることの含意は明白だった。",wrong:["含意とは明確に述べられたことだけである。","暗示は理解できない。","その文脈には含意がない。"]}]},{word:"incur",meaning:"被る、招く",example:"The project incurred significant additional costs.",category:"society",difficulty:5,examples:[{en:"If you don't pay your bills on time, you will incur late fees.",ja:"時間内に請求書を支払わないと、延滞料金を被ることになります。",wrong:["You will avoid late fees.","The bank will forgive the charges.","You will receive a discount."]},{en:"The company incurred significant losses due to the economic downturn.",ja:"経済的な景気後退により、その企業は大きな損失を被りました。",wrong:["The company made huge profits.","The company avoided all expenses.","The company gained financial benefits."]},{en:"By speaking out against the government, he incurred the wrath of the authorities.",ja:"政府に対して意見を述べることで、彼は当局の怒りを招きました。",wrong:["He received praise from the authorities.","He avoided all consequences.","He gained the government's support."]}]},{word:"inductive",meaning:"帰納的な",example:"Inductive reasoning draws general conclusions from specific observations.",category:"science",difficulty:5,examples:[{en:"The scientist used inductive reasoning to form a general theory from specific observations.",ja:"その科学者は具体的な観察から一般的な理論を形成するために帰納的推論を使用しました。",wrong:["The scientist used deductive reasoning from specific cases.","The scientist rejected all observations.","The scientist ignored experimental data."]},{en:"Inductive logic involves drawing conclusions from multiple examples.",ja:"帰納的論理は複数の例から結論を導き出すことを含みます。",wrong:["Inductive logic rejects all examples.","Inductive logic starts with general principles.","Inductive logic avoids pattern recognition."]},{en:"The inductive method is commonly used in scientific research to build theories.",ja:"帰納的方法は理論を構築するために科学的研究で一般的に使用されます。",wrong:["The inductive method rejects empirical evidence.","The inductive method avoids scientific testing.","The inductive method ignores observations."]}]},{word:"inert",meaning:"不活性の",example:"Noble gases are chemically inert.",category:"science",difficulty:5,examples:[{en:"Helium is an inert gas that does not react with other elements.",ja:"ヘリウムは他の要素と反応しない不活性ガスです。",wrong:["Helium is highly reactive with other gases.","Helium reacts explosively with oxygen.","Helium combines readily with other elements."]},{en:"The patient remained inert and unresponsive during the examination.",ja:"患者は検査中、動かず反応しない状態のままでした。",wrong:["The patient was very active and energetic.","The patient responded enthusiastically.","The patient moved around constantly."]},{en:"Nitrogen is largely inert in the atmosphere, making up about 78% of air.",ja:"窒素は大気中では主に不活性であり、空気の約78%を占めています。",wrong:["Nitrogen is highly reactive in the atmosphere.","Nitrogen actively combines with oxygen.","Nitrogen is extremely unstable in air."]}]},{word:"inference",meaning:"推論",example:"Statistical inference allows generalisation from sample data.",category:"science",difficulty:5,examples:[{en:"Based on the evidence, the detective made an inference about who committed the crime.",ja:"証拠に基づいて、刑事は誰が犯罪を犯したかについての推論を立てました。",wrong:["The detective ignored all evidence.","The detective made a direct observation.","The detective avoided drawing conclusions."]},{en:"The inference drawn from the study suggests that exercise improves mental health.",ja:"その研究から引き出された推論は、運動が精神的健康を改善することを示唆しています。",wrong:["The study proved nothing about exercise.","Exercise has no connection to mental health.","The inference contradicts the data."]},{en:"Through logical inference, we can determine the missing piece of the puzzle.",ja:"論理的な推論を通じて、パズルの欠落した部分を決定することができます。",wrong:["We can only guess randomly.","Inference prevents us from solving problems.","Logic has nothing to do with conclusions."]}]},{word:"innate",meaning:"生まれつきの",example:"Chomsky argued that language ability is innate.",category:"science",difficulty:5,examples:[{en:"Some psychologists believe that certain personality traits are innate rather than learned.",ja:"一部の心理学者は、特定の性格特性は学習されたものではなく生まれつきのものだと信じています。",wrong:["All personality traits are learned.","No traits are determined at birth.","Experience alone shapes our character."]},{en:"Children have an innate curiosity about the world around them.",ja:"子どもたちは周囲の世界に対して生まれつきの好奇心を持っています。",wrong:["Children are born without curiosity.","Curiosity can only be taught.","Children show no natural interest in anything."]},{en:"Humans have innate abilities for language acquisition that develop from birth.",ja:"人間は誕生から発達する言語習得のための生まれつきの能力を持っています。",wrong:["Language ability is never innate.","Humans are not naturally inclined to language.","All language skills must be artificially taught."]}]},{word:"inoculate",meaning:"接種する",example:"Millions of children were inoculated against polio.",category:"science",difficulty:5,examples:[{en:"The nurse will inoculate the child against measles using a vaccine.",ja:"看護師はワクチンを使用して子どもに麻疹の接種を行います。",wrong:["The nurse will spread the disease.","The vaccine will cause infection.","The inoculation will harm the patient."]},{en:"Farmers inoculate their crops with beneficial bacteria to improve soil quality.",ja:"農民は土壌の質を改善するために、有益な細菌で作物に接種します。",wrong:["Farmers use harmful chemicals to damage crops.","Inoculation destroys the soil.","Bacteria always harm plants."]},{en:"To inoculate someone against propaganda, we need to teach critical thinking skills.",ja:"プロパガンダに対して人を免疫化するために、批判的思考スキルを教える必要があります。",wrong:["We should promote uncritical thinking.","Inoculation means accepting all information.","Critical thinking harms immunity against lies."]}]},{word:"interdisciplinary",meaning:"学際的な",example:"The programme encourages interdisciplinary research.",category:"science",difficulty:5,examples:[{en:"The university launched an interdisciplinary program combining biology, chemistry, and physics.",ja:"大学は生物学、化学、物理学を組み合わせた学際的なプログラムを開始しました。",wrong:["The program focuses only on a single subject.","Different disciplines should never work together.","Interdisciplinary work reduces understanding."]},{en:"Modern environmental studies require an interdisciplinary approach involving economics, science, and policy.",ja:"現代の環境研究は、経済学、科学、政策を含む学際的なアプローチが必要です。",wrong:["Environmental studies should ignore economics.","Science and policy should be separated.","Single-discipline approaches are superior."]},{en:"The research team brought together experts from interdisciplinary backgrounds to solve the complex problem.",ja:"研究チームは複雑な問題を解決するために、学際的背景を持つ専門家をまとめました。",wrong:["Only specialists from one field should work together.","Diverse expertise hinders problem-solving.","Collaboration between disciplines is ineffective."]}]},{word:"interpolate",meaning:"補間する",example:"Missing data points were interpolated using statistical methods.",category:"science",difficulty:6,examples:[{en:"The mathematician had to interpolate missing values in the dataset to complete the analysis.",ja:"数学者は分析を完了するためにデータセット内の欠落した値を補間する必要がありました。",wrong:["Interpolation ignores missing data.","The mathematician deleted the missing values.","Estimation is impossible with gaps in data."]},{en:"The software interpolates pixel values to create smoother image transitions.",ja:"ソフトウェアはピクセル値を補間して、よりスムーズな画像遷移を作成します。",wrong:["Interpolation makes images blurry and low quality.","The software skips missing pixels.","Smoother transitions require no calculation."]},{en:"Scientists interpolate data points between measurements to better understand the trend.",ja:"科学者は測定値の間にデータポイントを補間してトレンドをより良く理解します。",wrong:["Interpolation distorts scientific data.","Scientists should ignore gaps in measurements.","Trends cannot be understood through interpolation."]}]},{word:"intersect",meaning:"交差する",example:"The two fields of study intersect in interesting ways.",category:"science",difficulty:5,examples:[{en:"The two roads intersect at the traffic light in the center of town.",ja:"2本の道路は町の中心の信号機で交差しています。",wrong:["The roads run parallel forever.","The roads meet at multiple points.","The roads never cross."]},{en:"In mathematics, the circles intersect at two distinct points.",ja:"数学では、円は2つの異なる点で交差しています。",wrong:["The circles are completely separate.","The circles intersect at infinite points.","The circles overlap entirely."]},{en:"The interests of business and environmental protection intersect in sustainable development.",ja:"ビジネスと環境保護の関心は持続可能な発展で交差しています。",wrong:["Business and environment have no common ground.","These interests are completely opposite.","There is no overlap between these fields."]}]},{word:"isotope",meaning:"同位体",example:"Carbon-14 is a radioactive isotope used in dating.",category:"science",difficulty:5,examples:[{en:"Carbon-12 and Carbon-14 are isotopes of the same element with different numbers of neutrons.",ja:"カーボン12とカーボン14は、異なる数の中性子を持つ同じ元素の同位体です。",wrong:["Isotopes are completely different elements.","Isotopes have the same atomic number and mass number.","All atoms of an element are identical."]},{en:"Radioactive isotopes are used in medical imaging to diagnose diseases.",ja:"放射性同位体は、病気を診断するための医療画像処理で使用されています。",wrong:["Isotopes cannot be used in medicine.","Medical imaging uses no radioactive materials.","Isotopes are always dangerous for humans."]},{en:"Scientists use stable isotopes to trace the movement of water through ecosystems.",ja:"科学者は安定同位体を使用して、生態系を通じた水の動きを追跡します。",wrong:["Stable isotopes cannot be detected.","Isotopes cannot show chemical pathways.","Water movement cannot be traced scientifically."]}]},{word:"juxtapose",meaning:"並置する",example:"The artist juxtaposed modern and classical elements.",category:"culture",difficulty:6,examples:[{en:"The artist chose to juxtapose bright colors next to dark colors to create contrast.",ja:"アーティストはコントラストを作成するために、明るい色を暗い色の横に並置することを選びました。",wrong:["The artist avoided using contrasts.","Juxtaposing colors creates confusion.","Colors should be blended, not placed together."]},{en:"The documentary juxtaposes scenes of poverty and wealth to highlight social inequality.",ja:"そのドキュメンタリーは、社会的不平等を強調するために貧困と富のシーンを並置しています。",wrong:["The documentary ignores social differences.","Juxtaposition hides inequalities.","Contrasting images reduce understanding."]},{en:"In his speech, the politician juxtaposed promises of change with memories of the past.",ja:"彼の演説で、その政治家は変化の約束と過去の思い出を並置しました。",wrong:["The politician avoided mentioning the past.","Juxtaposing ideas weakens arguments.","Contrast prevents effective communication."]}]},{word:"kinetic",meaning:"運動の",example:"Kinetic energy increases with velocity.",category:"science",difficulty:5,examples:[{en:"Kinetic energy is the energy that an object possesses due to its motion.",ja:"運動エネルギーは、物体がその運動によって持つエネルギーです。",wrong:["Kinetic energy is stored in stationary objects.","Moving objects have no kinetic energy.","Only heat generates kinetic energy."]},{en:"The kinetic sculpture moves and changes shape as viewers interact with it.",ja:"その運動彫刻は、鑑賞者がそれと相互作用するにつれて動きます。",wrong:["Kinetic sculptures are always stationary.","Movement prevents art from being art.","Interactive sculptures cannot move on their own."]},{en:"Athletes study kinetic movement to improve their performance and prevent injuries.",ja:"アスリートはパフォーマンスを改善し、けがを防ぐために運動の動きを研究します。",wrong:["Understanding movement harms athletic performance.","Kinetic analysis increases injury risk.","Motion studies are useless for athletes."]}]},{word:"latency",meaning:"潜伏期間",example:"The virus has a latency period of several weeks.",category:"science",difficulty:5,examples:[{en:"The latency period for the virus is typically two weeks before symptoms appear.",ja:"ウイルスの潜伏期間は通常、症状が現れるまで2週間です。",wrong:["The virus shows symptoms immediately upon infection.","There is no delay before symptoms appear.","Symptoms develop before infection occurs."]},{en:"In computer networks, low latency is crucial for real-time online gaming.",ja:"コンピュータネットワークでは、低遅延はリアルタイムオンラインゲームに重要です。",wrong:["High latency improves gaming performance.","Latency has no effect on online games.","Slow response times benefit gamers."]},{en:"The latency of the disease meant patients could spread it unknowingly for weeks.",ja:"その病気の潜伏期間は、患者が数週間無自覚にそれを広げることができることを意味していました。",wrong:["The disease shows all symptoms immediately.","Patients always know when they have the disease.","No disease has an asymptomatic period."]}]},{word:"lexicon",meaning:"語彙、辞書",example:"The word has entered the common lexicon.",category:"culture",difficulty:6,examples:[{en:"Shakespeare's lexicon is remarkably extensive, containing over 31,000 different words.",ja:"シェイクスピアの語彙は非常に広大で、30,000以上の異なる単語が含まれています。",wrong:["Shakespeare used only a limited vocabulary.","Great writers use simple language.","Extensive vocabulary makes writing poor."]},{en:"The medical lexicon includes many specialized terms that patients may not understand.",ja:"医学用語集には、患者が理解しないかもしれない多くの専門用語が含まれています。",wrong:["Medical terms are simple everyday words.","Specialists avoid using technical vocabulary.","Lexicon refers only to grammar rules."]},{en:"To improve your writing, you should continuously expand your lexicon.",ja:"あなたの執筆を改善するために、あなたは継続的にあなたの語彙を拡張する必要があります。",wrong:["Limited vocabulary improves writing quality.","Writers should use the same words repeatedly.","Expanding your vocabulary weakens communication."]}]},{word:"lineage",meaning:"系統、血統",example:"The study traced the genetic lineage of the species.",category:"science",difficulty:5,examples:[{en:"The royal family traced its lineage back to the medieval kings who ruled centuries ago.",ja:"王族は、数世紀前に統治した中世の王たちへの血統をたどりました。",wrong:["The family has no historical ancestry.","Lineage refers to current residence.","Royal lineage cannot be traced."]},{en:"Scientists use DNA analysis to determine the lineage of modern humans from ancient ancestors.",ja:"科学者はDNA分析を使用して、古代の祖先から現代の人間の系統を決定します。",wrong:["DNA cannot reveal ancestral relationships.","Modern humans have no evolutionary lineage.","Genetic analysis is unrelated to ancestry."]},{en:"The lineage of the company can be traced through several mergers and name changes over 50 years.",ja:"その企業の系統は、50年間のいくつかの合併と名前の変更を通じてたどることができます。",wrong:["Companies have no development history.","Lineage only applies to families.","Business evolution cannot be documented."]}]},{word:"logarithmic",meaning:"対数の",example:"The scale uses a logarithmic function.",category:"science",difficulty:6,examples:[{en:"The logarithmic scale helps us visualize data that spans multiple orders of magnitude.",ja:"対数スケールは複数の桁数にわたるデータを視覚化するのに役立ちます。",wrong:["The logarithmic scale is used to measure temperature in Celsius.","Logarithmic refers to the study of wood and trees.","A logarithmic function always produces negative numbers."]},{en:"Scientists use logarithmic graphs to analyze exponential growth in populations.",ja:"科学者は対数グラフを使用して個体群の指数関数的成長を分析します。",wrong:["Logarithmic graphs are only used in music theory.","A logarithmic graph cannot show any relationship between variables.","Logarithmic analysis is a type of cooking technique."]},{en:"The audio equipment displays volume in logarithmic decibels rather than linear units.",ja:"オーディオ機器は音量を線形単位ではなく対数デシベルで表示します。",wrong:["Logarithmic decibels measure the distance to the nearest speaker.","Volume in logarithmic form is only used in ancient mathematics.","The logarithmic decibel scale was invented by architects."]}]},{word:"longitudinal",meaning:"縦断的な",example:"A longitudinal study tracked participants over 20 years.",category:"science",difficulty:5,examples:[{en:"The longitudinal study followed the same participants over twenty years to track health changes.",ja:"縦断的研究は健康変化を追跡するために20年間同じ参加者を追跡しました。",wrong:["A longitudinal study examines subjects from east to west.","Longitudinal research only lasts for one day.","Longitudinal studies are banned in most countries."]},{en:"Engineers measured the longitudinal waves traveling through the earthquake zone.",ja:"エンジニアは地震地帯を通過する縦波を測定しました。",wrong:["Longitudinal waves only move horizontally.","Earthquakes produce no longitudinal waves.","Longitudinal wave measurement is impossible with modern technology."]},{en:"The longitudinal axis of the aircraft extends from the nose to the tail.",ja:"航空機の縦軸は機首から尾部に伸びています。",wrong:["The longitudinal axis runs from left wing to right wing.","Aircraft have no longitudinal axis.","The longitudinal axis is located underneath the aircraft."]}]},{word:"malignant",meaning:"悪性の",example:"The biopsy revealed a malignant growth.",category:"science",difficulty:5,examples:[{en:"The biopsy revealed a malignant tumor that required immediate surgery.",ja:"生検は即座に手術が必要な悪性腫瘍を明らかにしました。",wrong:["A malignant tumor is always painless and harmless.","Malignant means the tumor is beneficial to the patient.","Malignant tumors disappear on their own without treatment."]},{en:"The patient's prognosis improved after removing the malignant cells.",ja:"悪性細胞を除去した後、患者の予後が改善しました。",wrong:["Malignant cells are easy to remove with a simple band-aid.","Removing malignant cells makes the disease worse.","Malignant cells are found only in healthy people."]},{en:"Doctors distinguished between the benign and malignant growths using advanced imaging.",ja:"医師は高度なイメージング技術を使用して良性腫瘍と悪性腫瘍を区別しました。",wrong:["Benign and malignant growths are identical in appearance.","Advanced imaging cannot tell the difference between any growths.","Malignant growths are visible to the naked eye from miles away."]}]},{word:"matrix",meaning:"行列、母体",example:"The data were arranged in a matrix for analysis.",category:"science",difficulty:5,examples:[{en:"In mathematics, we multiplied the two matrices to solve the system of equations.",ja:"数学では、連立方程式を解くために2つの行列を乗算しました。",wrong:["A matrix is a type of pasta dish.","Matrices can only contain letters, not numbers.","Matrix multiplication is impossible in modern mathematics."]},{en:"The extracellular matrix provides structural support for cells in living tissues.",ja:"細胞外マトリックスは生きた組織の細胞に構造的サポートを提供します。",wrong:["The extracellular matrix only exists in robots.","The matrix has no role in supporting cell structure.","Living tissues do not contain any matrix."]},{en:"The social matrix of the community includes family, work, and friendship networks.",ja:"コミュニティの社会的マトリックスは、家族、仕事、友情ネットワークを含みます。",wrong:["A social matrix is a type of mathematical equation only.","Communities have no social matrix whatsoever.","The social matrix is found only in computers."]}]},{word:"mediation",meaning:"仲介、媒介",example:"Cultural mediation plays a key role in language learning.",category:"society",difficulty:5,examples:[{en:"The labor dispute was resolved through professional mediation between the union and management.",ja:"労働紛争は組合と経営陣の間の専門的な仲介を通じて解決されました。",wrong:["Mediation is when both parties fight until one wins completely.","Professional mediation always makes disputes worse.","Mediation has never been used successfully in any labor dispute."]},{en:"The therapist provided mediation to help the estranged couple communicate better.",ja:"セラピストは疎遠なカップルがより良くコミュニケーションするのを助けるために仲介を提供しました。",wrong:["Mediation is designed to separate people permanently.","A therapist's role is to take sides in every conflict.","Communication improvement through mediation is scientifically impossible."]},{en:"International mediation efforts aimed to reduce tensions between the two nations.",ja:"国際的な仲介努力は2つの国家間の緊張を軽減することを目的としていました。",wrong:["International mediation always increases conflict.","Mediation between nations is never attempted.","Tensions increase automatically after mediation efforts."]}]},{word:"methodology",meaning:"方法論",example:"The paper describes the methodology used in the study.",category:"science",difficulty:5,examples:[{en:"The research methodology included surveys, interviews, and statistical analysis of data.",ja:"研究方法論には調査、インタビュー、およびデータの統計分析が含まれていました。",wrong:["Methodology is the study of ancient metals.","A methodology is just a random collection of actions.","Methodology has no connection to how research is conducted."]},{en:"The company adopted a new methodology to improve product development efficiency.",ja:"企業は製品開発効率を改善するために新しい方法論を採用しました。",wrong:["Methodology always decreases efficiency in all situations.","New methodologies are invented daily and never used twice.","Product development has nothing to do with methodology."]},{en:"Different teaching methodologies work better for different students and learning styles.",ja:"異なる教授法は異なる学生と学習スタイルに対してより効果的に機能します。",wrong:["All teaching methodologies produce identical results regardless of student.","Teaching has no connection to methodology.","Learning styles are unrelated to which methodology works best."]}]},{word:"microcosm",meaning:"小宇宙、縮図",example:"The village serves as a microcosm of national trends.",category:"society",difficulty:6,examples:[{en:"The small town served as a microcosm of American society, with diverse populations and values.",ja:"その小さな町は多様な人口と価値観を持つアメリカ社会の縮図として機能しました。",wrong:["A microcosm is always larger than the whole universe.","A microcosm has no relationship to what it represents.","Small towns are never representative of larger societies."]},{en:"The classroom became a microcosm of the larger political conflict within the school.",ja:"教室は学校内のより大きな政治的紛争の縮図になりました。",wrong:["A classroom microcosm is always completely different from the school.","Classrooms never reflect larger conflicts.","Microcosms only exist in science fiction novels."]},{en:"The petri dish functioned as a microcosm of an entire ecosystem.",ja:"ペトリ皿は全生態系の縮図として機能しました。",wrong:["A petri dish is larger than any ecosystem.","Petri dishes contain nothing that resembles ecosystems.","Microcosms cannot be created in laboratory conditions."]}]},{word:"mitigation",meaning:"軽減、緩和",example:"Flood mitigation measures were implemented upstream.",category:"current",difficulty:5,examples:[{en:"Mitigation strategies included planting trees and reducing emissions to combat climate change.",ja:"軽減戦略には気候変動に対処するための木を植えることと排出量を削減することが含まれていました。",wrong:["Mitigation makes climate change worse immediately.","Planting trees and reducing emissions have no effect on anything.","Climate change cannot be mitigated by any action."]},{en:"The defendant's lawyer argued for mitigation of the harsh sentence due to circumstances.",ja:"被告人の弁護士は状況のため厳しい判決の軽減を主張しました。",wrong:["Mitigation in court always increases the punishment.","Circumstances are never considered for sentence reduction.","Defense lawyers never request mitigation."]},{en:"Disaster mitigation efforts reduced the impact of the hurricane on coastal communities.",ja:"災害軽減努力は沿岸地域のハリケーンの影響を軽減しました。",wrong:["Mitigation efforts always increase disaster damage.","Hurricanes cannot be mitigated in any way.","Coastal communities benefit from ignoring mitigation plans."]}]},{word:"modality",meaning:"様式、法性",example:"Different modalities of treatment were compared.",category:"science",difficulty:6,examples:[{en:"The study examined different modalities of pain management, including medication and therapy.",ja:"研究は投薬と治療を含む痛み管理のさまざまな様式を調査しました。",wrong:["Modality refers to the color of a substance.","Different modalities always produce identical results.","Pain management has no modalities whatsoever."]},{en:"The hospital offered multiple modalities for patient treatment, from surgery to holistic approaches.",ja:"病院は手術全体的アプローチまで、患者治療のための複数の様式を提供しました。",wrong:["Hospitals only use one treatment modality forever.","Multiple modalities confuse patients and doctors equally.","Surgical and holistic approaches are the same modality."]},{en:"In philosophy, modality discusses the necessity and possibility of propositions.",ja:"哲学では、様式は命題の必然性と可能性について論じます。",wrong:["Modality in philosophy refers only to music.","Philosophy contains no concept of modality.","Necessity and possibility have nothing to do with modality."]}]},{word:"morphology",meaning:"形態学",example:"The morphology of the cell changes during division.",category:"science",difficulty:6,examples:[{en:"The morphology of the plant species revealed evolutionary adaptations to desert conditions.",ja:"植物種の形態学は砂漠条件への進化的適応を明らかにしました。",wrong:["Morphology is the study of how to build things.","Plant morphology is unrelated to environmental adaptation.","Desert conditions have no effect on plant structure."]},{en:"Linguistic morphology examines how words are formed from smaller units called morphemes.",ja:"言語形態学は言葉がモルフェームと呼ばれる小さな単位からどのように形成されるかを調べます。",wrong:["Morphemes are irrelevant to word formation.","Linguistic morphology studies only very large words.","Words cannot be broken down into smaller units."]},{en:"The morphology of the rock formation indicated its geological history spanning millions of years.",ja:"岩層の形態学は数百万年にわたる地質学的歴史を示していました。",wrong:["Rock morphology tells us nothing about age or history.","Geological history is unrelated to rock structure.","Rocks have no morphology to study."]}]},{word:"multifaceted",meaning:"多面的な",example:"Poverty is a multifaceted problem requiring comprehensive solutions.",category:"society",difficulty:5,examples:[{en:"The problem proved to be multifaceted, requiring solutions from economics, psychology, and sociology.",ja:"問題は多面的であることが判明し、経済学、心理学、社会学からの解決策が必要でした。",wrong:["Multifaceted problems have only one simple cause.","A multifaceted issue requires no interdisciplinary approach.","Economics, psychology, and sociology are completely unrelated."]},{en:"The artist's multifaceted career spanned painting, sculpture, and film production.",ja:"アーティストの多面的なキャリアは絵画、彫刻、映画制作にわたっていました。",wrong:["A multifaceted career means doing the exact same thing every day.","Artists should only work in one medium forever.","Painting, sculpture, and film are unrelated fields."]},{en:"Understanding human behavior requires a multifaceted approach combining neuroscience, culture, and environment.",ja:"人間の行動を理解するには、神経科学、文化、環境を組み合わせた多面的なアプローチが必要です。",wrong:["Human behavior has a single cause that explains everything.","Neuroscience, culture, and environment have no relationship.","A single perspective is sufficient to understand all human behavior."]}]},{word:"nascent",meaning:"初期の、発生しつつある",example:"The nascent field of quantum computing shows great promise.",category:"technology",difficulty:6,examples:[{en:"The nascent technology showed promise but required further development before commercial use.",ja:"初期段階の技術は可能性を示していますが、商業利用前にさらなる開発が必要でした。",wrong:["Nascent technology is already fully mature and perfect.","Nascent means the technology is completely dead.","New technologies never require development or improvement."]},{en:"The nascent government struggled to establish institutions and build public trust.",ja:"初期の政府は制度を確立し、公的信頼を構築するのに苦労しました。",wrong:["A nascent government is fully established with centuries of history.","New governments never face challenges or struggles.","Institutions are irrelevant to government development."]},{en:"The artist's nascent career began with small exhibitions in local galleries.",ja:"アーティストの初期キャリアは地元ギャラリーでの小規模展覧会で始まりました。",wrong:["A nascent career means already achieving international fame.","Small exhibitions have nothing to do with starting careers.","Artists begin with massive shows from day one."]}]},{word:"nomenclature",meaning:"命名法",example:"Biological nomenclature follows standardised rules.",category:"science",difficulty:6,examples:[{en:"Scientific nomenclature uses Latin names to classify organisms in a standardized system.",ja:"科学命名法はラテン語の名前を使用して標準化されたシステムで生物を分類します。",wrong:["Scientific nomenclature uses random words without any rules.","Latin names are irrelevant to biological classification.","There is no standardized system for naming organisms."]},{en:"The medical nomenclature for different diseases helps doctors communicate precisely across countries.",ja:"異なる病気の医学命名法は医師が国境を越えて正確にコミュニケーションするのに役立ちます。",wrong:["Medical nomenclature confuses doctors and prevents communication.","Different countries use completely incompatible names for diseases.","Standardized medical names are unnecessary."]},{en:"Understanding the nomenclature of chemical compounds is essential for chemistry students.",ja:"化学化合物の命名法を理解することは化学学生にとって重要です。",wrong:["Chemical nomenclature is irrelevant to chemistry education.","All chemical compounds have identical names.","Chemistry requires no systematic naming system."]}]},{word:"normative",meaning:"規範的な",example:"Normative ethics deals with how people should act.",category:"society",difficulty:6,examples:[{en:"The study established normative values for healthy blood pressure in different age groups.",ja:"研究は異なる年齢層における正常な血圧の規範的価値を確立しました。",wrong:["Normative values are completely arbitrary and meaningless.","Blood pressure has no standard ranges whatsoever.","Age groups are irrelevant to defining health standards."]},{en:"Normative ethics examines what people should do based on moral principles and values.",ja:"規範倫理学は道徳原則と価値に基づいて人々が何をすべきかを調べます。",wrong:["Normative ethics ignores all moral principles completely.","What people should do has no connection to ethics.","Moral values are irrelevant to normative discussions."]},{en:"The normative standards in the industry ensure quality and consistency across products.",ja:"業界の規範的基準は製品全体の品質と一貫性を保証します。",wrong:["Normative standards guarantee poor quality products.","Industry standards have nothing to do with consistency.","Quality is unrelated to following established norms."]}]},{word:"nucleus",meaning:"核",example:"The nucleus of an atom contains protons and neutrons.",category:"science",difficulty:5,examples:[{en:"The nucleus of the cell contains the DNA that controls all genetic information.",ja:"細胞の核にはすべての遺伝情報を制御するDNAが含まれています。",wrong:["The nucleus is located outside the cell.","DNA is found everywhere except in the nucleus.","The nucleus has no role in controlling genetic information."]},{en:"The nucleus of the atom is composed of protons and neutrons held together by strong force.",ja:"原子の核は強い力によって一緒に保持されているプロトンと中性子で構成されています。",wrong:["The atomic nucleus contains only electrons.","Protons and neutrons are held together by weak gravity.","The nucleus has no internal structure whatsoever."]},{en:"The small group served as the nucleus of the larger organization that would eventually grow.",ja:"小さなグループは最終的に成長する大きな組織の核として機能しました。",wrong:["The nucleus of an organization has no foundational role.","Small groups cannot become large organizations.","Growth is independent of any central nucleus."]}]},{word:"ontology",meaning:"存在論",example:"Ontology studies the nature of being and existence.",category:"science",difficulty:6,examples:[{en:"Ontology is the philosophical study of the nature of being and existence.",ja:"存在論は、存在と実在の性質についての哲学的研究である。",wrong:["Ontology is the study of insects and their behavior.","Ontology refers to a collection of ancient written documents.","Ontology is a medical procedure used to examine internal organs."]},{en:"In computer science, an ontology defines the concepts and relationships within a specific domain.",ja:"コンピュータ科学では、存在論は特定の領域内の概念と関係を定義する。",wrong:["In computer science, ontology is a type of programming language.","Ontology describes the physical structure of computer hardware.","Ontology is a method for encrypting sensitive data."]},{en:"Aristotle's ontology had a profound influence on Western philosophy.",ja:"アリストテレスの存在論は西洋哲学に深い影響を与えた。",wrong:["Aristotle's ontology was primarily focused on mathematics.","Aristotle's ontology rejected all forms of logical reasoning.","Aristotle's ontology was first developed in the 20th century."]}]},{word:"oscillate",meaning:"振動する",example:"The pendulum oscillates at a constant frequency.",category:"science",difficulty:5,examples:[{en:"The pendulum continues to oscillate back and forth steadily.",ja:"振り子は着実に前後に振動し続ける。",wrong:["The pendulum oscillates by rotating in a vertical circle.","The pendulum oscillates by moving in a straight line upward.","The pendulum oscillates by remaining completely still."]},{en:"Her mood seemed to oscillate between happiness and sadness.",ja:"彼女の気分は幸福と悲しみの間で振動しているようだった。",wrong:["Her mood oscillates by remaining constant throughout the day.","Her mood oscillates by changing color rapidly.","Her mood oscillates by making loud noises."]},{en:"The alternating current oscillates at 60 hertz in most household outlets.",ja:"交流電流はほとんどの家庭用コンセントで60ヘルツで振動する。",wrong:["The current oscillates by flowing only in one direction.","The current oscillates by producing heat continuously.","The current oscillates at a fixed voltage level."]}]},{word:"osmosis",meaning:"浸透",example:"Water moves across the membrane by osmosis.",category:"science",difficulty:5,examples:[{en:"Water molecules move across the cell membrane through osmosis.",ja:"水分子は浸透を通じて細胞膜を横切って移動する。",wrong:["Water molecules move through osmosis by active muscle contractions.","Osmosis is the process where salt crystals dissolve instantly.","Osmosis occurs only in living organisms and never in non-living systems."]},{en:"Osmosis is the spontaneous movement of solvent molecules across a semipermeable membrane.",ja:"浸透は、半透膜を横切る溶媒分子の自発的な移動である。",wrong:["Osmosis is the rapid boiling of water at room temperature.","Osmosis is the process of breaking chemical bonds between molecules.","Osmosis requires external mechanical force to occur."]},{en:"By osmosis, a raisin will absorb water and swell when placed in pure water.",ja:"浸透により、レーズンを純水に入れると水を吸収して膨らむ。",wrong:["By osmosis, a raisin will immediately become hard and brittle.","Osmosis causes raisins to lose their water content.","Osmosis makes raisins change color to blue."]}]},{word:"paradigm",meaning:"思考の枠組み",example:"The discovery led to a paradigm shift in physics.",category:"science",difficulty:5,examples:[{en:"The scientific paradigm shifted when Einstein introduced the theory of relativity.",ja:"アインシュタインが相対性理論を導入したとき、科学的な思考の枠組みが変わった。",wrong:["The paradigm shift occurred because of new types of plants.","Einstein's paradigm was about the study of ancient civilizations.","The scientific paradigm remained unchanged for thousands of years."]},{en:"A paradigm shift in education moved from lecture-based to student-centered learning.",ja:"教育の思考の枠組みの転換は、講義ベースから学生中心の学習へ移った。",wrong:["The paradigm shift in education eliminated all forms of testing.","Paradigm shifts occur instantly without any period of adjustment.","The new educational paradigm removed the need for teachers entirely."]},{en:"Different cultures operate under different paradigms about family structure.",ja:"異なる文化は家族構造についての異なる思考の枠組みの下で機能している。",wrong:["All cultures share identical paradigms about family structure.","Paradigms about family are determined solely by geography.","Paradigms have never changed throughout human history."]}]},{word:"paradoxical",meaning:"逆説的な",example:"It is paradoxical that wealth does not guarantee happiness.",category:"society",difficulty:5,examples:[{en:"It is paradoxical that the more we learn, the more we realize how little we know.",ja:"私たちが学べば学ぶほど、自分たちがいかに少ししか知らないかに気づくというのは逆説的である。",wrong:["It is paradoxical that water always boils at 100 degrees Celsius.","It is paradoxical that the sun rises in the east.","It is paradoxical that heavy objects fall faster than light objects."]},{en:"The statement 'this sentence is false' is paradoxical because it contradicts itself.",ja:"「この文は偽である」という文は自分自身と矛盾するので逆説的である。",wrong:["The statement is paradoxical because it uses difficult vocabulary.","The statement is paradoxical because it is written in a foreign language.","The statement is paradoxical because most people disagree with it."]},{en:"It seems paradoxical that silence can be louder than noise in conveying emotion.",ja:"感情を伝えるのに沈黙が騒音より大きいというのは逆説的に思える。",wrong:["It seems paradoxical that sound travels faster than light.","It seems paradoxical that music requires electricity to be heard.","It seems paradoxical that emotions can be measured in decibels."]}]},{word:"pathogen",meaning:"病原体",example:"Pathogens can spread through contaminated water.",category:"science",difficulty:5,examples:[{en:"Bacteria and viruses are examples of pathogens that can cause disease.",ja:"細菌とウイルスは病気を引き起こす可能性がある病原体の例である。",wrong:["Pathogens are types of vitamins found in healthy food.","Pathogens are proteins that strengthen the immune system.","Pathogens are beneficial organisms that live in the digestive tract."]},{en:"The pathogen responsible for this infection has been identified as a novel coronavirus.",ja:"この感染症の原因となった病原体は新型コロナウイルスとして特定されている。",wrong:["The pathogen is a type of mineral found in soil.","The pathogen is a weather phenomenon that causes rain.","The pathogen is a chemical element on the periodic table."]},{en:"Antibiotics work by either killing pathogens or preventing their reproduction.",ja:"抗生物質は、病原体を殺すか、その繁殖を防ぐことで機能する。",wrong:["Antibiotics work by increasing the pathogen's ability to spread.","Antibiotics strengthen the pathogen's defenses against the immune system.","Antibiotics cause pathogens to become more virulent."]}]},{word:"pedagogy",meaning:"教育学",example:"Progressive pedagogy emphasises student-centred learning.",category:"society",difficulty:6,examples:[{en:"Pedagogy is the science and art of teaching and learning.",ja:"教育学は教えること学ぶことの科学と芸術である。",wrong:["Pedagogy is the study of ancient Greek architecture.","Pedagogy is a branch of medicine focused on treating disease.","Pedagogy is the practice of growing crops in urban areas."]},{en:"Modern pedagogy emphasizes critical thinking and student engagement over rote memorization.",ja:"現代の教育学は、暗記学習よりも批判的思考と学生の参加を強調する。",wrong:["Modern pedagogy discourages all forms of student interaction.","Pedagogy is primarily concerned with testing students' memory recall.","Pedagogy eliminates the need for qualified teachers."]},{en:"Different pedagogical approaches work better for different learning styles and age groups.",ja:"異なる教育学的アプローチは、異なる学習スタイルと年齢グループにより良く機能する。",wrong:["All pedagogical approaches are identical regardless of student age.","Pedagogy suggests that all students learn at exactly the same pace.","Pedagogical approaches have never changed since ancient times."]}]},{word:"pertinent",meaning:"関連する、適切な",example:"The committee raised several pertinent questions.",category:"society",difficulty:5,examples:[{en:"The lawyer presented only the most pertinent evidence to support her case.",ja:"弁護士は彼女の事件を支持するために最も関連した証拠のみを提示した。",wrong:["The lawyer presented evidence that was completely unrelated to the case.","Pertinent evidence is information that confuses the judge.","Pertinent means the evidence was proven to be false."]},{en:"His comments were pertinent to the discussion and added valuable insights.",ja:"彼のコメントは議論に関連があり、貴重な洞察を追加した。",wrong:["His comments were off-topic and irrelevant to the discussion.","Pertinent comments are those that contradict the main point.","His remarks were pertinent because they were lengthy and detailed."]},{en:"When applying for a job, include only pertinent information on your resume.",ja:"仕事に応募する場合、履歴書に関連情報のみを含める。",wrong:["When applying for a job, include all personal information regardless of relevance.","Pertinent resume information includes unrelated hobbies and interests.","Pertinent means including information that employers are forbidden to ask."]}]},{word:"phenotype",meaning:"表現型",example:"The phenotype is influenced by both genes and environment.",category:"science",difficulty:6,examples:[{en:"An organism's phenotype includes all its observable physical characteristics.",ja:"生物の表現型はその観察可能なすべての物理的特性を含む。",wrong:["A phenotype is the genetic code hidden inside a cell nucleus.","Phenotype refers to the evolutionary history of a species.","Phenotype describes the color of an organism's DNA."]},{en:"Environmental factors can influence an organism's phenotype even when the genotype remains unchanged.",ja:"環境要因は、遺伝子型が変わらなくても、生物の表現型に影響を与える可能性がある。",wrong:["Environmental factors never affect the phenotype of organisms.","Phenotype is determined solely by diet and cannot be influenced by genes.","Environmental factors cause permanent changes to an organism's genotype."]},{en:"Two plants with identical genotypes may display different phenotypes due to varying soil conditions.",ja:"同じ遺伝子型を持つ2つの植物は、土の条件が異なるため異なる表現型を示す可能性がある。",wrong:["Plants with identical genotypes will always have identical phenotypes regardless of environment.","Phenotype is determined before birth and never changes.","Soil conditions cannot possibly influence a plant's phenotype."]}]},{word:"plethora",meaning:"過多",example:"A plethora of studies have examined this topic.",category:"science",difficulty:6,examples:[{en:"The online store offers a plethora of options for every type of customer.",ja:"オンラインストアはあらゆるタイプの顧客向けに過多のオプションを提供している。",wrong:["A plethora means there is a severe shortage of items.","The store offers a plethora of only three products.","Plethora refers to items that are no longer available."]},{en:"After the announcement, the company received a plethora of job applications.",ja:"発表後、会社は過多の求人申請を受け取った。",wrong:["The company received a plethora of only two job applications.","A plethora means the company received no applications at all.","Plethora refers to applications that were rejected before review."]},{en:"The conference featured a plethora of expert speakers from around the world.",ja:"会議は世界中からの過多の専門家スピーカーを特徴としていた。",wrong:["The conference had a plethora of only one speaker.","Plethora means the conference had no speakers scheduled.","A plethora of speakers refers to speakers who cancelled their appearances."]}]},{word:"polarise",meaning:"二極化する",example:"The issue has polarised public opinion.",category:"society",difficulty:5,examples:[{en:"The controversial political issue began to polarise the community into two opposing groups.",ja:"物議を醸す政治的問題はコミュニティを2つの対立するグループに二極化し始めた。",wrong:["To polarise means to unite people into a single cohesive group.","Polarise refers to moving to the geographic poles.","Polarising an issue brings people closer together in agreement."]},{en:"Social media tends to polarise opinions by amplifying extreme viewpoints.",ja:"ソーシャルメディアは極端な見解を増幅することで意見を二極化する傾向がある。",wrong:["Social media polarises by preventing any discussion of differing views.","Polarise means to present all viewpoints as equally valid without taking sides.","Social media polarises people by keeping them unaware of opposing opinions."]},{en:"The referendum polarised the nation, with voters split almost evenly on the issue.",ja:"国民投票は国を二極化し、投票者がこの問題についてほぼ均等に分かれた。",wrong:["A polarised referendum means all voters agreed unanimously.","Polarise refers to making a decision that affects no one.","A polarised vote indicates there was no real debate about the issue."]}]},{word:"polymer",meaning:"重合体",example:"Plastics are made from synthetic polymers.",category:"science",difficulty:5,examples:[{en:"Plastic is a synthetic polymer made from long chains of carbon atoms.",ja:"プラスチックは炭素原子の長い鎖で作られた合成重合体である。",wrong:["A polymer is a type of metal used in construction.","Polymer refers to a single molecule that cannot be divided.","Polymers are naturally occurring only in living organisms."]},{en:"DNA is a natural polymer that carries genetic information in all living cells.",ja:"DNAはすべての生細胞の遺伝情報を運ぶ天然重合体である。",wrong:["DNA is a polymer that exists only in plants, not animals.","Polymers like DNA have no structural importance in cells.","DNA is not a polymer but a simple chemical compound."]},{en:"Polymers can be engineered to have different properties for various industrial applications.",ja:"重合体は、様々な産業用途のために異なる特性を持つように工学的に設計できる。",wrong:["Polymers cannot be modified and always have fixed properties.","Engineered polymers are weaker than naturally occurring polymers.","All polymers have identical properties regardless of their composition."]}]},{word:"postulate",meaning:"仮定する",example:"Einstein postulated that the speed of light is constant.",category:"science",difficulty:5,examples:[{en:"Euclid's geometry is based on five fundamental postulates about space and lines.",ja:"ユークリッドの幾何学は、空間と直線に関する5つの基本的な仮定に基づいている。",wrong:["Postulates are proven facts that have been verified by experiment.","Euclid's postulates were considered controversial but were easily proven.","A postulate is an observation that can be directly measured."]},{en:"The scientist postulated that dark matter exists to explain the observed gravitational effects.",ja:"科学者は、観測された重力効果を説明するためにダークマターが存在すると仮定した。",wrong:["To postulate means to prove something conclusively with evidence.","Postulating requires experimental verification before it can be stated.","Dark matter was postulated after it was directly observed and measured."]},{en:"We must postulate certain basic truths before we can construct a logical argument.",ja:"論理的な議論を構成する前に、特定の基本的な真実を仮定する必要がある。",wrong:["To postulate means to question everything without accepting any basic truths.","Postulating eliminates the need for logical reasoning.","Postulates are conclusions drawn after all evidence has been examined."]}]},{word:"pragmatic",meaning:"実用的な",example:"She took a pragmatic approach to the problem.",category:"society",difficulty:5,examples:[{en:"The manager took a pragmatic approach to solving the problem rather than relying on theory alone.",ja:"マネージャーは理論だけに頼るのではなく、問題を解くために実用的なアプローチを取った。",wrong:["A pragmatic approach ignores practical reality and focuses only on ideals.","Pragmatic solutions are those that sound good but don't actually work.","Pragmatism means refusing to adapt strategies based on results."]},{en:"A pragmatic businessman makes decisions based on what will actually work and generate profit.",ja:"実用的な実業家は、実際に機能し利益を生成するであろう決定に基づいて決定を下す。",wrong:["A pragmatic businessman ignores financial outcomes and focuses on ethics only.","Pragmatic business decisions are made without considering any consequences.","Pragmatism in business means following tradition without adapting to change."]},{en:"Despite their differences, both parties found a pragmatic solution to the conflict.",ja:"彼らの違いにもかかわらず、両当事者は紛争への実用的な解決策を見つけた。",wrong:["A pragmatic solution means refusing to compromise with the other side.","Pragmatic resolutions focus on what feels morally pure rather than results.","Finding a pragmatic solution means the conflict remains unresolved."]}]},{word:"precursor",meaning:"前駆体、先駆け",example:"The typewriter was a precursor to the computer.",category:"technology",difficulty:5,examples:[{en:"The steam engine was a precursor to the internal combustion engine.",ja:"蒸気機関は内燃機関の前駆体だった。",wrong:["A precursor is something that comes after something else in development.","The steam engine replaced the internal combustion engine as its precursor.","Precursor refers to something that has no connection to later inventions."]},{en:"Early symptoms can be a precursor to more serious illness if left untreated.",ja:"早期症状は、治療されないままだと、より深刻な病気の前駆体となる可能性がある。",wrong:["A precursor is a symptom that appears after the illness has fully developed.","Early symptoms are precursors that prove the person will never get sick.","Precursor symptoms indicate the disease has already reached its final stage."]},{en:"The 1960s social movements were precursors to the major political changes of the 1970s.",ja:"1960年代の社会運動は1970年代の大きな政治的変化の先駆けだった。",wrong:["The 1960s movements were precursors to events that occurred in the 1950s.","A precursor is something that has no influence on future events.","The 1960s were precursors to events happening at the exact same time."]}]},{word:"predicate",meaning:"述語、基づかせる",example:"The argument is predicated on the assumption of growth.",category:"science",difficulty:6,examples:[{en:"The success of the project is predicated on proper funding.",ja:"プロジェクトの成功は適切な資金調達に基づいている。",wrong:["プロジェクトの成功は予測される","プロジェクトの成功は述べられた","プロジェクトの成功は拒否される"]},{en:"In grammar, the predicate contains the verb and its modifiers.",ja:"文法では、述語は動詞とその修飾語を含む。",wrong:["文法では、述語は名詞だけを含む","文法では、述語は主語の後に来る","文法では、述語は形容詞である"]},{en:"We cannot predicate our decisions solely on emotions.",ja:"私たちは感情だけに基づいて決定することはできない。",wrong:["私たちは決定を述べることはできない","私たちは決定を否定することはできない","私たちは決定を予測することはできない"]}]},{word:"predispose",meaning:"〜しやすくする",example:"Genetic factors may predispose individuals to certain diseases.",category:"science",difficulty:5,examples:[{en:"Genetic factors predispose some people to heart disease.",ja:"遺伝的要因は、ある人々を心臓病にかかりやすくする。",wrong:["遺伝的要因は心臓病を治す","遺伝的要因は心臓病を予測する","遺伝的要因は心臓病を防ぐ"]},{en:"A stressful environment can predispose individuals to anxiety disorders.",ja:"ストレスの多い環境は、個人が不安障害にかかりやすくなる可能性がある。",wrong:["ストレスの多い環境は不安障害を治療する","ストレスの多い環境は不安障害を完全に治す","ストレスの多い環境は不安障害を引き起こさない"]},{en:"Early childhood experiences predispose us toward certain behavioral patterns.",ja:"幼年期の経験は、私たちが特定の行動パターンに傾く傾向がある。",wrong:["幼年期の経験は行動を決定する","幼年期の経験は行動を禁止する","幼年期の経験は行動と無関係である"]}]},{word:"prognosis",meaning:"予後",example:"The prognosis for early-stage patients is favourable.",category:"science",difficulty:5,examples:[{en:"The patient's prognosis improved after starting the new treatment.",ja:"新しい治療を開始した後、患者の予後は改善した。",wrong:["患者の予後は治療前に判明した","患者の予後は治療と無関係である","患者の予後は悪化が確定した"]},{en:"Doctors provided a favorable prognosis for her recovery.",ja:"医者は彼女の回復について好意的な予後を提供した。",wrong:["医者は回復の可能性を否定した","医者は予後を述べることができない","医者は予後について不確実である"]},{en:"The long-term prognosis for this condition depends on early intervention.",ja:"この状態の長期的予後は、早期介入に依存している。",wrong:["長期予後は介入と無関係である","長期予後は時間とともに悪化する","長期予後は改善不可能である"]}]},{word:"proliferate",meaning:"増殖する",example:"Cancer cells proliferate rapidly.",category:"science",difficulty:5,examples:[{en:"Cancer cells proliferate rapidly without normal growth controls.",ja:"癌細胞は正常な成長制御なしに急速に増殖する。",wrong:["癌細胞は減少する","癌細胞は静止状態にある","癌細胞は死滅する"]},{en:"Social media platforms have proliferated over the last decade.",ja:"ソーシャルメディアプラットフォームはここ10年で増殖した。",wrong:["ソーシャルメディアプラットフォームは減少した","ソーシャルメディアプラットフォームは消滅した","ソーシャルメディアプラットフォームは停滞している"]},{en:"Bacteria proliferate in warm, moist environments.",ja:"バクテリアは暖かく湿った環境で増殖する。",wrong:["バクテリアは冷たい環境で増殖する","バクテリアは増殖することができない","バクテリアは光の中で増殖する"]}]},{word:"propensity",meaning:"傾向",example:"Children have a natural propensity for language learning.",category:"science",difficulty:6,examples:[{en:"She has a propensity for organizing social events.",ja:"彼女は社交行事を整理する傾向がある。",wrong:["彼女は社交行事を避ける傾向がある","彼女は社交行事を組織することができない","彼女は社交行事に無関心である"]},{en:"Some individuals show a propensity toward risk-taking behavior.",ja:"一部の個人はリスクをとる行動に対する傾向を示す。",wrong:["一部の個人は安全を求める傾向がある","一部の個人はリスクを避ける傾向がある","一部の個人は行動に傾向がない"]},{en:"The research revealed a propensity for conflict in certain group dynamics.",ja:"研究は、特定のグループダイナミクスでの紛争に対する傾向を明らかにした。",wrong:["研究は平和的なグループを示した","研究は紛争の欠如を示した","研究は紛争が不可能であることを示した"]}]},{word:"proponent",meaning:"支持者",example:"Proponents of the theory cite numerous studies.",category:"science",difficulty:5,examples:[{en:"She is a strong proponent of renewable energy sources.",ja:"彼女は再生可能エネルギー源の強い支持者である。",wrong:["彼女は再生可能エネルギーの反対者である","彼女は再生可能エネルギーについて無関心である","彼女は再生可能エネルギーを反対している"]},{en:"Leading proponents of the theory presented their findings at the conference.",ja:"その理論の主要な支持者は会議で彼らの調査結果を発表した。",wrong:["理論の批評家が会議で発表した","理論の反対者が会議で発表した","理論の敵対者が会議で発表した"]},{en:"Proponents argue that this policy will improve public health.",ja:"支持者は、このポリシーが公衆衛生を改善すると主張している。",wrong:["反対者はこのポリシーを支持している","批評家はこのポリシーを推進している","敵対者はこのポリシーに賛成している"]}]},{word:"proposition",meaning:"命題、提案",example:"The proposition was tested using experimental data.",category:"science",difficulty:5,examples:[{en:"The company received an attractive business proposition from investors.",ja:"会社は投資家から魅力的なビジネス提案を受け取った。",wrong:["会社は投資家から拒否を受け取った","会社は投資家から反対を受け取った","会社は投資家から批判を受け取った"]},{en:"In logic, a proposition is a statement that is either true or false.",ja:"論理では、命題は真または偽のいずれかである陳述である。",wrong:["命題は質問である","命題は命令である","命題は意見である"]},{en:"He presented a proposition to solve the company's financial problems.",ja:"彼は会社の財務問題を解決するための提案を提示した。",wrong:["彼は問題を無視する提案をした","彼は問題を複雑にする提案をした","彼は問題についての苦情を言った"]}]},{word:"protocol",meaning:"手順、規約",example:"Strict protocols govern the handling of biohazards.",category:"science",difficulty:5,examples:[{en:"All employees must follow the safety protocol in the laboratory.",ja:"すべての従業員は研究室で安全プロトコルに従わなければならない。",wrong:["従業員は安全プロトコルを無視できる","従業員は独自のプロトコルを作成できる","従業員はプロトコルに従う必要がない"]},{en:"The diplomatic protocol requires formal greetings before negotiations begin.",ja:"外交プロトコルは交渉開始前に正式な挨拶を要求する。",wrong:["外交プロトコルは形式的でない","外交プロトコルは存在しない","外交プロトコルは無視される"]},{en:"The medical protocol for treating infections includes antibiotic administration.",ja:"感染症を治療するための医療プロトコルには、抗生物質の投与が含まれる。",wrong:["医療プロトコルは治療方法を示さない","医療プロトコルは単なる提案である","医療プロトコルは強制ではない"]}]},{word:"proxy",meaning:"代理指標",example:"Ice core data serve as a proxy for past temperatures.",category:"science",difficulty:6,examples:[{en:"Stock market performance is often used as a proxy for economic health.",ja:"株式市場のパフォーマンスは、経済的健全性の代理指標として使用されることがよくある。",wrong:["株式市場は経済の直接的な尺度である","株式市場は代理指標ではない","株式市場は経済と無関係である"]},{en:"She gave her proxy to vote on her behalf at the shareholder meeting.",ja:"彼女は株主総会で彼女に代わって投票する代理を与えた。",wrong:["彼女は直接投票した","彼女は投票権を失った","彼女は誰かが彼女のために投票することを許さなかった"]},{en:"Temperature readings can serve as a proxy for patient wellness.",ja:"体温測定値は患者の健康状態の代理指標として機能することができる。",wrong:["温度はゲージではない","温度は患者の健康と無関係である","温度は直接的な診断ツールである"]}]},{word:"putative",meaning:"推定上の",example:"The putative mechanism was tested in vitro.",category:"science",difficulty:6,examples:[{en:"The putative father was required to take a DNA test.",ja:"推定上の父親はDNA検査を受ける必要があった。",wrong:["確認された父親はDNA検査を受ける必要があった","本当の父親はDNA検査を受ける必要があった","不可能な父親はDNA検査を受ける必要があった"]},{en:"Scientists discovered a putative link between the chemical and cancer.",ja:"科学者は化学物質と癌の間の推定上の関連を発見した。",wrong:["科学者は確認された因果関係を発見した","科学者は疑わしい関連を発見した","科学者は証明された関連を発見した"]},{en:"The putative author of the anonymous manuscript remains unknown.",ja:"匿名原稿の推定上の著者は身元不明のままである。",wrong:["確認された著者は不明である","本当の著者は身元不明である","著者は特定された"]}]},{word:"qualitative",meaning:"質的な",example:"The study used qualitative methods including interviews.",category:"science",difficulty:5,examples:[{en:"Qualitative research focuses on understanding experiences and meanings.",ja:"質的研究は経験と意味の理解に焦点を当てている。",wrong:["質的研究は数値データのみを使用する","質的研究は統計分析のみを行う","質的研究は定量的研究と同じである"]},{en:"The interview provided qualitative insights into customer satisfaction.",ja:"インタビューは顧客満足度についての質的な洞察を提供した。",wrong:["インタビューは定量的なデータを提供した","インタビューは数値結果を示した","インタビューは統計を測定した"]},{en:"Qualitative analysis revealed themes that quantitative data missed.",ja:"質的分析は定量的データが見落とした主題を明らかにした。",wrong:["質的分析は数値を測定した","質的分析は統計を計算した","質的分析は定量的分析と同じ結果を示した"]}]},{word:"quantitative",meaning:"量的な",example:"Quantitative analysis revealed statistically significant results.",category:"science",difficulty:5,examples:[{en:"Quantitative analysis relies on numerical data and statistical methods.",ja:"定量分析は数値データと統計的方法に依存している。",wrong:["定量分析は感情的なデータを使用する","定量分析は説明的である","定量分析は統計を使用しない"]},{en:"The survey collected quantitative data about purchasing habits.",ja:"調査は購買習慣についての定量データを収集した。",wrong:["調査は質的インタビューを実施した","調査は経験について尋ねた","調査は数値を測定しなかった"]},{en:"Quantitative metrics showed a 25% increase in productivity.",ja:"定量的指標は生産性が25％増加したことを示した。",wrong:["定量的指標は改善を説明した","定量的指標は実感を測定した","定量的指標は定性的であった"]}]},{word:"rationale",meaning:"根拠、論理的根拠",example:"The paper explains the rationale behind the new approach.",category:"science",difficulty:5,examples:[{en:"The rationale for the policy change was to improve efficiency.",ja:"ポリシー変更の根拠は効率を改善することであった。",wrong:["根拠は変更の理由ではない","根拠は不明確である","根拠が存在しない"]},{en:"Scientists presented the rationale behind their experimental design.",ja:"科学者は彼らの実験設計の背後にある論理的根拠を提示した。",wrong:["科学者は根拠を説明しなかった","根拠は不合理である","根拠は必要ではない"]},{en:"Understanding the rationale helps employees support the new initiative.",ja:"根拠を理解すると、従業員が新しいイニシアチブをサポートできる。",wrong:["根拠を理解することは無関係である","根拠は従業員に説明されない","根拠は支持に影響しない"]}]},{word:"recapitulate",meaning:"要約する",example:"To recapitulate, there are three main findings.",category:"science",difficulty:6,examples:[{en:"Let me recapitulate the main points discussed in the meeting.",ja:"会議で議論された主要なポイントを要約させてください。",wrong:["要約することは新しい情報を追加することである","要約することは詳細を省略しない","要約することは主張を変えることである"]},{en:"The author recapitulated the key arguments in the conclusion.",ja:"著者は結論で主要な主張を要約した。",wrong:["著者は新しい主張を導入した","著者は議論を拡張した","著者は主張を削除した"]},{en:"The speaker will recapitulate the presentation's essential information.",ja:"スピーカーはプレゼンテーションの本質的な情報を要約します。",wrong:["スピーカーは新しいスライドを追加します","スピーカーはより詳細を説明します","スピーカーは情報を削除します"]}]},{word:"reciprocal",meaning:"相互的な",example:"Trade between the two nations is reciprocal.",category:"society",difficulty:5,examples:[{en:"The two countries established a reciprocal trade agreement.",ja:"2つの国は相互的な貿易協定を確立した。",wrong:["貿易協定は一方的である","協定は相互的ではない","協定は両国に同等に利益をもたらさない"]},{en:"In mathematics, the reciprocal of 2 is 1/2.",ja:"数学では、2の逆数は1/2である。",wrong:["2の逆数は2である","2の逆数は4である","2の逆数は存在しない"]},{en:"They maintained a reciprocal relationship built on mutual respect.",ja:"彼らは相互尊重に基づいた相互的な関係を維持した。",wrong:["関係は一方的である","関係は相互的ではない","関係は不均衡である"]}]},{word:"redundant",meaning:"冗長な、不要な",example:"Redundant data were removed from the analysis.",category:"technology",difficulty:5,examples:[{en:"The backup system is redundant but necessary for safety.",ja:"バックアップシステムは冗長ですが、安全性のために必要です。",wrong:["バックアップシステムは冗長で、完全に無駄です。","バックアップシステムは余分で、決して使われません。","バックアップシステムは不要で、削除すべきです。"]},{en:"His explanation was redundant because he repeated the same points.",ja:"彼の説明は冗長でした。同じポイントを繰り返したからです。",wrong:["彼の説明は簡潔でした。不要な言葉がなかったからです。","彼の説明は明確でした。すべてが新しい情報でした。","彼の説明は革新的でした。誰も聞いたことのない内容でした。"]},{en:"Having two managers for the same task is redundant.",ja:"同じタスクに2人のマネージャーがいるのは冗長です。",wrong:["同じタスクに2人のマネージャーがいるのは必須です。","同じタスクに2人のマネージャーがいるのは効率的です。","同じタスクに2人のマネージャーがいるのは望ましいです。"]}]},{word:"refractory",meaning:"難治性の、耐火の",example:"The infection proved refractory to standard antibiotics.",category:"science",difficulty:6,examples:[{en:"The patient's cancer was refractory to standard treatment.",ja:"患者のがんは標準治療に難治性でした。",wrong:["患者のがんは標準治療に完全に反応しました。","患者のがんは標準治療で簡単に治りました。","患者のがんは標準治療に敏感でした。"]},{en:"Refractory bricks are used in high-temperature furnaces.",ja:"耐火レンガは高温炉で使用されます。",wrong:["耐火レンガは低温環境で使用されます。","耐火レンガは容易に溶けます。","耐火レンガは熱に弱いです。"]},{en:"The refractory student refused to follow school rules.",ja:"反抗的な生徒は学校のルールに従うのを拒否しました。",wrong:["従順な生徒は学校のルールに従いました。","素直な生徒は権威を尊重しました。","協力的な生徒はすべての指示に従いました。"]}]},{word:"regression",meaning:"回帰、退行",example:"Linear regression was used to model the relationship.",category:"science",difficulty:5,examples:[{en:"The statistical regression analysis showed a strong correlation.",ja:"統計的回帰分析は強い相関を示しました。",wrong:["統計的回帰分析は相関がないことを示しました。","統計的回帰分析は負の値をもたらしました。","統計的回帰分析は予測不可能な結果を示しました。"]},{en:"The child's regression after the trauma required professional help.",ja:"トラウマ後の子どもの退行には専門的支援が必要でした。",wrong:["子どもの発達は創傷後に加速しました。","子どもは外傷後に成熟しました。","子どもはトラウマ後に正常に進化しました。"]},{en:"Linear regression is a fundamental tool in data science.",ja:"線形回帰はデータサイエンスの基本的なツールです。",wrong:["線形回帰は現代的な統計手法です。","線形回帰は複雑な計算を避けます。","線形回帰は予測ができません。"]}]},{word:"replicate",meaning:"複製する、再現する",example:"Other laboratories failed to replicate the results.",category:"science",difficulty:5,examples:[{en:"The scientist will replicate the experiment to verify results.",ja:"科学者は結果を検証するために実験を複製します。",wrong:["科学者は実験を簡潔にします。","科学者は実験を中止します。","科学者は実験の結果を変更します。"]},{en:"It is difficult to replicate the success of that startup.",ja:"そのスタートアップの成功を再現することは困難です。",wrong:["そのスタートアップの成功は簡単に再現されました。","そのスタートアップの成功は模倣不可能です。","そのスタートアップの失敗を再現するのは簡単です。"]},{en:"DNA molecules replicate themselves during cell division.",ja:"DNA分子は細胞分裂中に自己複製します。",wrong:["DNA分子は細胞分裂中に分解されます。","DNA分子は複製を停止します。","DNA分子は変異します。"]}]},{word:"residual",meaning:"残余の",example:"Residual effects of the treatment were monitored.",category:"science",difficulty:5,examples:[{en:"The residual stress in the material can cause failure.",ja:"材料の残留応力は破損を引き起こす可能性があります。",wrong:["材料の完全な応力は破損を引き起こします。","材料の初期応力は安定しています。","材料の外部応力は無視できます。"]},{en:"After paying bills, he had only residual income.",ja:"請求書を支払った後、彼は残余収入だけがありました。",wrong:["請求書を支払った後、彼は多くの収入がありました。","請求書を支払った後、彼は全額を失いました。","請求書を支払った後、彼は倍の収入を得ました。"]},{en:"The residual effects of the medication lasted several days.",ja:"薬剤の残留効果は数日間続きました。",wrong:["薬剤の主要効果は数日間続きました。","薬剤の完全な効果は即座に消えました。","薬剤の副作用は存在しません。"]}]},{word:"restitution",meaning:"返還、賠償",example:"The court ordered restitution for the stolen artefacts.",category:"society",difficulty:6,examples:[{en:"The court ordered restitution to the victims of the crime.",ja:"裁判所は犯罪被害者への返還を命じました。",wrong:["裁判所は被害者への賠償を拒否しました。","裁判所は加害者への報酬を命じました。","裁判所は被害者への任意の支払いを提案しました。"]},{en:"The company made restitution by refunding all customer payments.",ja:"会社はすべての顧客支払いを払い戻すことで返還しました。",wrong:["会社は顧客にさらに請求しました。","会社は顧客に謝罪せず返金しました。","会社は返還を拒否しました。"]},{en:"In physics, restitution describes the bouncing of objects.",ja:"物理学では、復元力は物体の反発を説明します。",wrong:["物理学では、復元力は物体の吸収を説明します。","物理学では、復元力は動きを停止させます。","物理学では、復元力は存在しません。"]}]},{word:"rudimentary",meaning:"基礎的な、未発達の",example:"The organism has only rudimentary sensory organs.",category:"science",difficulty:5,examples:[{en:"He has only rudimentary knowledge of the subject.",ja:"彼はその主題に関する基礎的な知識しか持っていません。",wrong:["彼はその主題の深い知識を持っています。","彼はその主題の専門家です。","彼はその主題について何も知りません。"]},{en:"Fish have rudimentary lungs compared to mammals.",ja:"魚は哺乳類と比較して未発達な肺を持っています。",wrong:["魚は哺乳類と同じ肺を持っています。","魚は肺を持っていません。","魚は高度な肺を持っています。"]},{en:"The early computer systems had rudimentary interfaces.",ja:"初期のコンピュータシステムは基礎的なインターフェースを持っていました。",wrong:["初期のコンピュータシステムは高度なインターフェースを持っていました。","初期のコンピュータシステムはインターフェースを持っていませんでした。","初期のコンピュータシステムは現代的なインターフェースを持っていました。"]}]},{word:"salient",meaning:"顕著な",example:"The report highlights the salient features of the proposal.",category:"society",difficulty:6,examples:[{en:"The salient points of the argument were clearly stated.",ja:"議論の顕著なポイントは明確に述べられました。",wrong:["議論の隠れたポイントは無視されました。","議論の取るに足らないポイントが強調されました。","議論には顕著なポイントがありませんでした。"]},{en:"His salient features made him easily recognizable.",ja:"彼の顕著な特徴は彼を容易に認識できるようにしました。",wrong:["彼の不明確な特徴は識別を困難にしました。","彼の隠れた特徴は見つけやすかったです。","彼は顕著な特徴がありませんでした。"]},{en:"The most salient issue in the debate was healthcare.",ja:"議論で最も顕著な問題はヘルスケアでした。",wrong:["議論で最も重要でない問題はヘルスケアでした。","議論には顕著な問題がありませんでした。","議論で最も隠れた問題はヘルスケアでした。"]}]},{word:"sediment",meaning:"堆積物",example:"River sediment accumulated at the delta.",category:"science",difficulty:5,examples:[{en:"The river carries sediment downstream to the delta.",ja:"川は堆積物をデルタへ下流に運びます。",wrong:["川は堆積物を上流に運びます。","川は堆積物を蒸発させます。","川には堆積物がありません。"]},{en:"Wine sediment settles at the bottom of the bottle.",ja:"ワインの堆積物はボトルの底に沈みます。",wrong:["ワインの堆積物はボトルの上に浮きます。","ワインには堆積物がありません。","ワインの堆積物は液体です。"]},{en:"Geologists study sediment layers to understand Earth's history.",ja:"地質学者は地球の歴史を理解するために堆積物の層を研究します。",wrong:["地質学者は液体を研究して地球の歴史を理解します。","地質学者は堆積物から何も学べません。","堆積物は地球の歴史を示しません。"]}]},{word:"seminal",meaning:"独創的な、影響力のある",example:"Darwin's seminal work transformed biology.",category:"science",difficulty:6},{word:"sequential",meaning:"連続的な",example:"The experiment followed a sequential design.",category:"science",difficulty:5,examples:[{en:"The sequential steps must be followed in order.",ja:"連続的なステップは順序に従う必要があります。",wrong:["ステップはランダムな順序で実行できます。","ステップの順序は重要ではありません。","ステップは同時に実行する必要があります。"]},{en:"Sequential processing is slower than parallel processing.",ja:"連続処理は並列処理より遅いです。",wrong:["連続処理は並列処理より速いです。","連続処理と並列処理は同じ速度です。","連続処理は最も効率的です。"]},{en:"The sequential numbers are 1, 2, 3, 4, 5.",ja:"連続的な数字は1、2、3、4、5です。",wrong:["連続的な数字はランダムです。","連続的な数字は同じです。","連続的な数字は逆順です。"]}]},{word:"spatial",meaning:"空間の",example:"Spatial analysis revealed patterns in species distribution.",category:"science",difficulty:5,examples:[{en:"The spatial arrangement of furniture affects room comfort.",ja:"家具の空間配置は部屋の快適さに影響を与えます。",wrong:["家具の色合いは空間的な快適さに影響を与えます。","家具の時間的配置は部屋に影響を与えます。","家具の大きさは空間配置と無関係です。"]},{en:"Spatial awareness is important in sports like basketball.",ja:"空間認識はバスケットボールのようなスポーツで重要です。",wrong:["時間認識はバスケットボールで最も重要です。","色彩認識はスポーツに必要です。","音声認識は空間スポーツで必要です。"]},{en:"GPS uses spatial coordinates to determine location.",ja:"GPSは位置を判定するために空間座標を使用します。",wrong:["GPSは時間座標を使用します。","GPSは色座標を使用します。","GPSは数値座標を使用しません。"]}]},{word:"specimen",meaning:"標本",example:"The museum houses over a million insect specimens.",category:"science",difficulty:5,examples:[{en:"The museum displayed a rare specimen of ancient pottery.",ja:"博物館は古い陶芸の珍しい標本を展示しました。",wrong:["博物館は標本を隠しました。","博物館には陶芸がありませんでした。","博物館は現代の陶芸を展示しました。"]},{en:"The biologist examined the specimen under the microscope.",ja:"生物学者は顕微鏡下で標本を検査しました。",wrong:["生物学者は標本を肉眼で見ました。","生物学者は標本を調べませんでした。","生物学者は標本を破壊しました。"]},{en:"A blood specimen was collected for the test.",ja:"検査のために血液標本が採取されました。",wrong:["血液標本は採取されませんでした。","唾液標本が検査に使用されました。","標本は分析されませんでした。"]}]},{word:"spectra",meaning:"分光の帯域（複数形）",example:"The spectra of distant galaxies show a red shift.",category:"science",difficulty:6,examples:[{en:"The light spectra revealed the composition of the star.",ja:"光の分光帯域は星の成分を明らかにしました。",wrong:["光の分光帯域は星の距離を示しました。","分光帯域は光学的には無関連です。","星には分光帯域がありません。"]},{en:"Different spectra of radiation have different properties.",ja:"異なる放射の分光帯域は異なる特性を持っています。",wrong:["すべての分光帯域は同じ特性を持っています。","放射には分光帯域がありません。","分光帯域は物理的には説明できません。"]},{en:"The scientist analyzed the infrared spectra of the sample.",ja:"科学者はサンプルの赤外分光帯域を分析しました。",wrong:["科学者は可視光を分析しました。","科学者は分光帯域を無視しました。","赤外分光帯域は分析できません。"]}]},{word:"spurious",meaning:"偽りの、見せかけの",example:"The correlation was found to be spurious.",category:"science",difficulty:6,examples:[{en:"The spurious claim had no scientific evidence.",ja:"その見せかけの主張は科学的証拠がありませんでした。",wrong:["その主張は確かな科学的証拠に基づいていました。","その主張は真実でした。","その主張は広く受け入れられました。"]},{en:"A spurious correlation can mislead researchers.",ja:"見せかけの相関は研究者を誤解させることができます。",wrong:["実際の相関は常に有用です。","相関は常に因果関係を意味します。","見せかけの相関は無視すべきではありません。"]},{en:"The spurious antique turned out to be a forgery.",ja:"その見せかけの骨董品は贋造品であることが判明しました。",wrong:["その骨董品は本物でした。","その品物は本当に古かったです。","骨董品の鑑定は信頼できます。"]}]},{word:"stagnation",meaning:"停滞",example:"Economic stagnation led to widespread unemployment.",category:"current",difficulty:5,examples:[{en:"The economy suffered from prolonged stagnation.",ja:"経済は長期的な停滞に苦しんだ。",wrong:["経済は長期的な成長に苦しんだ。","経済は長期的な発展に苦しんだ。","経済は長期的な繁栄に苦しんだ。"]},{en:"Water stagnation can lead to disease.",ja:"水の停滞は病気につながる可能性がある。",wrong:["水の流動は病気につながる可能性がある。","水の循環は病気につながる可能性がある。","水の動きは病気につながる可能性がある。"]},{en:"The company experienced creative stagnation.",ja:"その企業は創造的な停滞を経験した。",wrong:["その企業は創造的な革新を経験した。","その企業は創造的な進歩を経験した。","その企業は創造的な発展を経験した。"]}]},{word:"stipulate",meaning:"規定する",example:"The contract stipulates a minimum delivery period.",category:"society",difficulty:5,examples:[{en:"The contract stipulates payment within 30 days.",ja:"契約は30日以内の支払いを規定している。",wrong:["契約は30日以内の支払いを禁止している。","契約は30日以内の支払いを推奨している。","契約は30日以内の支払いを許可している。"]},{en:"The agreement stipulates that all parties must sign.",ja:"その合意はすべての当事者が署名しなければならないことを規定している。",wrong:["その合意はすべての当事者が署名しないことを規定している。","その合意はすべての当事者が署名することを禁止している。","その合意はすべての当事者が署名することを許可している。"]},{en:"The law stipulates minimum wage requirements.",ja:"その法律は最低賃金の要件を規定している。",wrong:["その法律は最低賃金の要件を廃止している。","その法律は最低賃金の要件を削除している。","その法律は最低賃金の要件を無視している。"]}]},{word:"stratify",meaning:"層化する",example:"The sample was stratified by age and gender.",category:"science",difficulty:6,examples:[{en:"Social classes stratify society into distinct groups.",ja:"社会階級は社会を異なるグループに層化する。",wrong:["社会階級は社会を統合する。","社会階級は社会を平等化する。","社会階級は社会を混合する。"]},{en:"The rocks stratify over millions of years.",ja:"岩は数百万年かけて層化する。",wrong:["岩は数百万年かけて溶解する。","岩は数百万年かけて粉砕される。","岩は数百万年かけて均質化する。"]},{en:"Educational systems often stratify students by ability.",ja:"教育システムは多くの場合、学生を能力によって層化する。",wrong:["教育システムは多くの場合、学生を能力によって統一する。","教育システムは多くの場合、学生を能力によって混合する。","教育システムは多くの場合、学生を能力によって平均化する。"]}]},{word:"stratum",meaning:"層",example:"Fossils were found in a deep geological stratum.",category:"science",difficulty:6,examples:[{en:"The archaeological team excavated each stratum carefully.",ja:"考古学チームは各層を注意深く発掘した。",wrong:["考古学チームは各層を埋め戻した。","考古学チームは各層を修復した。","考古学チームは各層を保存した。"]},{en:"Different strata of society have different opportunities.",ja:"社会のさまざまな階層には異なる機会がある。",wrong:["社会のさまざまな階層には同じ機会がある。","社会のさまざまな階層には平等な条件がある。","社会のさまざまな階層には統一された環境がある。"]},{en:"The geological stratum shows evidence of ancient life.",ja:"地質層は古代の生命の証拠を示している。",wrong:["地質層は現代の生命の証拠を示している。","地質層は未来の生命の証拠を示している。","地質層は生命の痕跡を隠している。"]}]},{word:"substantiate",meaning:"立証する",example:"The claims were substantiated by documentary evidence.",category:"science",difficulty:5,examples:[{en:"You must substantiate your claims with evidence.",ja:"あなたは証拠であなたの主張を立証しなければならない。",wrong:["あなたは証拠であなたの主張を否定しなければならない。","あなたは証拠であなたの主張を拒否しなければならない。","あなたは証拠であなたの主張を隠さなければならない。"]},{en:"The witness substantiated the defendant's alibi.",ja:"証人は被告人のアリバイを立証した。",wrong:["証人は被告人のアリバイを否定した。","証人は被告人のアリバイを撤回した。","証人は被告人のアリバイを反論した。"]},{en:"Recent studies substantiate the effectiveness of the treatment.",ja:"最近の研究は治療の有効性を立証している。",wrong:["最近の研究は治療の有効性を否定している。","最近の研究は治療の有効性を疑問視している。","最近の研究は治療の有効性に反対している。"]}]},{word:"succinct",meaning:"簡潔な",example:"The abstract provides a succinct summary of the research.",category:"society",difficulty:5,examples:[{en:"The professor's succinct explanation was easy to understand.",ja:"教授の簡潔な説明は理解しやすかった。",wrong:["教授の冗長な説明は理解しやすかった。","教授の詳細な説明は理解しやすかった。","教授の長い説明は理解しやすかった。"]},{en:"Please provide a succinct summary of the report.",ja:"レポートの簡潔な要約を提供してください。",wrong:["レポートの詳細な要約を提供してください。","レポートの複雑な要約を提供してください。","レポートの冗長な要約を提供してください。"]},{en:"Her succinct speech impressed the audience.",ja:"彼女の簡潔なスピーチは聴衆を感動させた。",wrong:["彼女の長いスピーチは聴衆を感動させた。","彼女の詳細なスピーチは聴衆を感動させた。","彼女の冗長なスピーチは聴衆を感動させた。"]}]},{word:"superfluous",meaning:"余分な",example:"Superfluous details were removed from the final draft.",category:"society",difficulty:6,examples:[{en:"The document contained superfluous information.",ja:"その文書は余分な情報を含んでいた。",wrong:["その文書は必要な情報を含んでいた。","その文書は重要な情報を含んでいた。","その文書は不足している情報を含んでいた。"]},{en:"He removed all superfluous details from the essay.",ja:"彼はエッセイから余分な詳細をすべて削除した。",wrong:["彼はエッセイから必須の詳細をすべて削除した。","彼はエッセイから重要な詳細をすべて削除した。","彼はエッセイに詳細を追加した。"]},{en:"Avoid superfluous words in your writing.",ja:"あなたの執筆で余分な単語は避けてください。",wrong:["あなたの執筆で必要な単語は避けてください。","あなたの執筆で重要な単語は避けてください。","あなたの執筆で正確な単語は避けてください。"]}]},{word:"supplant",meaning:"取って代わる",example:"Digital media has largely supplanted print.",category:"technology",difficulty:6,examples:[{en:"Digital technology has supplanted traditional methods.",ja:"デジタル技術は従来の方法に取って代わった。",wrong:["デジタル技術は従来の方法を補完した。","デジタル技術は従来の方法に従った。","デジタル技術は従来の方法を支援した。"]},{en:"The new system will supplant the old one.",ja:"新しいシステムは古いシステムに取って代わるだろう。",wrong:["新しいシステムは古いシステムを改善するだろう。","新しいシステムは古いシステムを補助するだろう。","新しいシステムは古いシステムに統合されるだろう。"]},{en:"The rival company tried to supplant our position.",ja:"ライバル企業は私たちの立場に取って代わろうとした。",wrong:["ライバル企業は私たちの立場を支援しようとした。","ライバル企業は私たちの立場を強化しようとした。","ライバル企業は私たちの立場を保護しようとした。"]}]},{word:"symbiotic",meaning:"共生の",example:"The two organisms exist in a symbiotic relationship.",category:"science",difficulty:5,examples:[{en:"The bacteria and plant have a symbiotic relationship.",ja:"バクテリアと植物は共生関係にある。",wrong:["バクテリアと植物は寄生関係にある。","バクテリアと植物は捕食関係にある。","バクテリアと植物は競争関係にある。"]},{en:"Business and ethics should have a symbiotic connection.",ja:"ビジネスと倫理は共生的な関係を持つべきである。",wrong:["ビジネスと倫理は対立的な関係を持つべきである。","ビジネスと倫理は独立した関係を持つべきである。","ビジネスと倫理は矛盾した関係を持つべきである。"]},{en:"The two artists created a symbiotic collaboration.",ja:"2人のアーティストは共生的なコラボレーションを作成した。",wrong:["2人のアーティストは競争的なコラボレーションを作成した。","2人のアーティストは独立したコラボレーションを作成した。","2人のアーティストは対立的なコラボレーションを作成した。"]}]},{word:"synthesis",meaning:"統合、合成",example:"The paper presents a synthesis of current research.",category:"science",difficulty:5,examples:[{en:"The synthesis of different ideas created a new theory.",ja:"異なるアイデアの統合は新しい理論を作成した。",wrong:["異なるアイデアの分離は新しい理論を作成した。","異なるアイデアの分析は新しい理論を作成した。","異なるアイデアの拒絶は新しい理論を作成した。"]},{en:"The chemical synthesis produced a new compound.",ja:"化学合成は新しい化合物を生成した。",wrong:["化学分解は新しい化合物を生成した。","化学溶解は新しい化合物を生成した。","化学反応は新しい化合物を破壊した。"]},{en:"Her essay showed a good synthesis of multiple sources.",ja:"彼女のエッセイは複数のソースの良好な統合を示していた。",wrong:["彼女のエッセイは複数のソースの分離を示していた。","彼女のエッセイは複数のソースの矛盾を示していた。","彼女のエッセイは複数のソースの否定を示していた。"]}]},{word:"systematic",meaning:"体系的な",example:"A systematic review of the literature was conducted.",category:"science",difficulty:5,examples:[{en:"A systematic approach to problem-solving is effective.",ja:"問題解決への体系的なアプローチは効果的である。",wrong:["問題解決へのランダムなアプローチは効果的である。","問題解決へのカオス的なアプローチは効果的である。","問題解決への無計画なアプローチは効果的である。"]},{en:"The researcher conducted a systematic review of all studies.",ja:"研究者はすべての研究の体系的なレビューを実施した。",wrong:["研究者はすべての研究のランダムなレビューを実施した。","研究者はすべての研究の恣意的なレビューを実施した。","研究者はすべての研究の混乱したレビューを実施した。"]},{en:"Systematic training improves performance.",ja:"体系的なトレーニングはパフォーマンスを向上させる。",wrong:["不規則なトレーニングはパフォーマンスを向上させる。","カオス的なトレーニングはパフォーマンスを向上させる。","偶発的なトレーニングはパフォーマンスを向上させる。"]}]},{word:"tangible",meaning:"具体的な、有形の",example:"The policy produced tangible improvements in air quality.",category:"society",difficulty:5,examples:[{en:"The company showed tangible results in the first quarter.",ja:"その会社は第1四半期に具体的な結果を示した。",wrong:["その会社は第1四半期に抽象的な結果を示した。","その会社は第1四半期に目に見えない結果を示した。","その会社は第1四半期に曖昧な結果を示した。"]},{en:"Tangible assets are easier to value than intangible ones.",ja:"有形資産は無形資産よりも評価しやすい。",wrong:["無形資産は無形資産よりも評価しやすい。","有形資産は有形資産よりも評価しやすい。","幻想的な資産は無形資産よりも評価しやすい。"]},{en:"She felt tangible relief after the exam.",ja:"彼女は試験後に具体的な安心を感じた。",wrong:["彼女は試験後に抽象的な安心を感じた。","彼女は試験後に幻想的な安心を感じた。","彼女は試験後に目に見えない安心を感じた。"]}]},{word:"taxonomy",meaning:"分類学",example:"Biological taxonomy organises species into hierarchical groups.",category:"science",difficulty:6,examples:[{en:"The taxonomy of animals is based on evolutionary relationships.",ja:"動物の分類学は進化的関係に基づいている。",wrong:["動物の形態学は進化的関係に基づいている。","動物の生態学は進化的関係に基づいている。","動物の行動学は進化的関係に基づいている。"]},{en:"Bloom's taxonomy is used in education.",ja:"ブルームの分類学は教育で使用されている。",wrong:["ブルームの理論は教育で使用されている。","ブルームの方法論は教育で使用されている。","ブルームの哲学は教育で使用されている。"]},{en:"A proper taxonomy helps organize information.",ja:"適切な分類学は情報を整理するのに役立つ。",wrong:["適切な統計学は情報を整理するのに役立つ。","適切な比較学は情報を整理するのに役立つ。","適切な批判学は情報を整理するのに役立つ。"]}]},{word:"tenet",meaning:"教義、信条",example:"A central tenet of democracy is free and fair elections.",category:"society",difficulty:6,examples:[{en:"A core tenet of Buddhism is the Four Noble Truths.",ja:"仏教の中心的な教義は四諦である。",wrong:["仏教の中心的な神話は四諦である。","仏教の中心的な歴史は四諦である。","仏教の中心的な伝説は四諦である。"]},{en:"The tenet of equality is fundamental to democracy.",ja:"平等の信条は民主主義の基本である。",wrong:["独裁の信条は民主主義の基本である。","支配の信条は民主主義の基本である。","階級の信条は民主主義の基本である。"]},{en:"He rejected the tenets of his former religion.",ja:"彼は以前の宗教の教義を拒否した。",wrong:["彼は以前の宗教の教義を受け入れた。","彼は以前の宗教の教義を守った。","彼は以前の宗教の教義を宣伝した。"]}]},{word:"theorem",meaning:"定理",example:"Pythagoras' theorem applies to right-angled triangles.",category:"science",difficulty:5},{word:"thesis",meaning:"論文、命題",example:"Her doctoral thesis examined post-colonial literature.",category:"culture",difficulty:5,examples:[{en:"She spent two years researching her doctoral thesis on climate change.",ja:"彼女は気候変動に関する博士論文の研究に2年間を費やした。",wrong:["彼女は気候変動について2年間の論文を読んだ。","彼女の命題は気候変動に関する2年間の研究である。","彼女は気候変動の論文を2年間教えた。"]},{en:"The thesis of his argument is that technology improves human happiness.",ja:"彼の議論の主張は、技術が人間の幸福を向上させるということである。",wrong:["彼の論文は技術が人間を幸せにすることを証明した。","彼の命題によって技術が人間を幸せにする。","彼の主題は技術が人間の幸福を破壊することである。"]},{en:"The professor rejected the thesis because it lacked sufficient evidence.",ja:"教授は十分な証拠がないため、その論文を却下した。",wrong:["教授は証拠がないため、その命題を作った。","教授は論文を受け入れ、証拠がない。","教授は論文の証拠を却下した。"]}]},{word:"trajectory",meaning:"軌道",example:"The trajectory of the comet was plotted by astronomers.",category:"science",difficulty:5,examples:[{en:"The missile followed a curved trajectory through the sky.",ja:"ミサイルは空を通じて曲がった軌道をたどった。",wrong:["ミサイルは空で直線的な軌道を飛んだ。","ミサイルの軌道は空を曲げた。","ミサイルは空の軌道に従わなかった。"]},{en:"Her career trajectory showed steady progress over a decade.",ja:"彼女のキャリアの軌跡は10年間にわたって着実な進歩を示した。",wrong:["彼女のキャリア軌道は10年間衰退した。","彼女の軌道はキャリアを破壊した。","彼女のキャリアは軌跡がない。"]},{en:"Scientists calculated the trajectory of the comet to predict its arrival.",ja:"科学者たちはその到着を予測するために彗星の軌道を計算した。",wrong:["彗星の軌道は科学者によって到着した。","科学者たちは軌道を彗星から予測した。","彗星の到着は軌道を計算した。"]}]},{word:"transgenic",meaning:"遺伝子導入の",example:"Transgenic crops have been modified for pest resistance.",category:"science",difficulty:6,examples:[{en:"Transgenic crops were engineered to resist pest damage.",ja:"遺伝子導入作物は害虫の被害に耐えるように設計された。",wrong:["遺伝子導入作物は害虫を導入した。","作物の遺伝子は害虫に耐えるように導入された。","遺伝子導入は害虫の被害を引き起こした。"]},{en:"The transgenic mouse model helped researchers understand the disease.",ja:"遺伝子導入マウスモデルは研究者が病気を理解するのに役立った。",wrong:["遺伝子導入マウスは病気の研究を妨げた。","マウスモデルは遺伝子導入の病気である。","研究者たちは遺伝子導入マウスから病気を導入した。"]},{en:"Transgenic bacteria were developed to produce insulin efficiently.",ja:"インスリンを効率的に生産するために遺伝子導入バクテリアが開発された。",wrong:["バクテリアはインスリンを遺伝子導入した。","遺伝子導入はバクテリアのインスリンを妨げた。","インスリンは遺伝子導入バクテリアを開発した。"]}]},{word:"transient",meaning:"一時的な",example:"The effects were transient and faded within hours.",category:"science",difficulty:5,examples:[{en:"The power outage was transient, lasting only a few minutes.",ja:"停電は一時的で、わずか数分間続いた。",wrong:["停電は数分間すべてを永続させた。","一時的な停電は永遠に続いた。","停電は一時的ではなく、完全だった。"]},{en:"His interest in painting proved to be transient and soon faded.",ja:"絵画への彼の興味は一時的であり、すぐに薄れた。",wrong:["彼の絵画への興味は永遠に続いた。","一時的な興味は絵画を消した。","彼の興味は薄れて絵画を永続させた。"]},{en:"The transient nature of adolescence makes it a challenging period.",ja:"思春期の一時的な性質はそれを困難な時期にしている。",wrong:["思春期は永遠で一時的ではない。","一時的な思春期は困難ではない。","思春期の性質は永続的である。"]}]},{word:"triage",meaning:"優先順位付け、選別",example:"Medical triage determines which patients are treated first.",category:"science",difficulty:5,examples:[{en:"Emergency room doctors perform triage to treat the most critical patients first.",ja:"救急室の医師は最も重篤な患者を最初に治療するために優先順位付けを行う。",wrong:["医師は優先順位付けをして最初に軽症患者を治療した。","優先順位付けは医師が患者を無視することである。","医師たちは優先順位付けなしに患者を治療した。"]},{en:"The hospital implemented a triage system to manage the influx of patients.",ja:"病院は患者の流入を管理するために選別システムを実装した。",wrong:["選別システムは患者の流入を増加させた。","病院は患者を選別せずに受け入れた。","選別は患者の管理を妨げた。"]},{en:"During the disaster, volunteers performed triage to identify priority cases.",ja:"災害中、ボランティアは優先事項を特定するために優先順位付けを行った。",wrong:["ボランティアは優先順位なしに災害に対応した。","優先順位付けは災害の事例を作った。","ボランティアは優先順位付けをして最も低い優先度を特定した。"]}]},{word:"truncate",meaning:"切り捨てる",example:"The data were truncated at the 95th percentile.",category:"science",difficulty:6,examples:[{en:"The programmer decided to truncate the decimal to two places.",ja:"プログラマーは小数を小数点以下2桁に切り詰めることにした。",wrong:["プログラマーは小数を完全に削除した。","切り詰めは小数を増やした。","小数は2桁に拡張された。"]},{en:"She truncated her message to fit the character limit.",ja:"彼女は文字数制限に適応させるためにメッセージを切り詰めた。",wrong:["彼女は文字数制限を無視してメッセージを拡張した。","メッセージの切り詰めは制限を増やした。","彼女は完全なメッセージを送った。"]},{en:"The database administrator had to truncate the table to remove all records.",ja:"データベース管理者はすべてのレコードを削除するためにテーブルを切り詰めなければならなかった。",wrong:["テーブルの切り詰めはレコードを保存した。","レコードを削除することはテーブルを展開した。","管理者は切り詰めずにすべてのレコードを削除した。"]}]},{word:"ubiquitous",meaning:"至る所にある",example:"Smartphones have become ubiquitous in modern life.",category:"technology",difficulty:5,examples:[{en:"Smartphones have become ubiquitous in modern society.",ja:"スマートフォンは現代社会で至る所にある存在になった。",wrong:["スマートフォンは現代社会ではまれである。","至る所にあることはスマートフォンを限定した。","スマートフォンは社会で見つからない。"]},{en:"The ubiquitous nature of social media affects how people communicate.",ja:"ソーシャルメディアの至る所にある性質は人々の通信方法に影響する。",wrong:["ソーシャルメディアの性質は人々を孤立させた。","至る所にあることはメディアを限定した。","ソーシャルメディアは通信に影響しない。"]},{en:"English has become ubiquitous as a global language.",ja:"英語はグローバル言語として至る所で見られるようになった。",wrong:["英語はグローバルでは限定的な言語である。","至る所にあることは英語を消した。","英語は全世界で話されていない。"]}]},{word:"unilateral",meaning:"一方的な",example:"The country took unilateral military action.",category:"society",difficulty:5,examples:[{en:"The company made a unilateral decision without consulting its employees.",ja:"その企業は従業員に相談せずに一方的な決定を下した。",wrong:["一方的な決定は従業員と相談した。","企業は全員と相談して決定した。","一方的な決定は複数の当事者を含んだ。"]},{en:"The unilateral action by one nation angered other members of the alliance.",ja:"1つの国による一方的な行動は同盟の他のメンバーを怒らせた。",wrong:["一方的な行動は他の国と相談された。","同盟のメンバーは一方的な行動を支持した。","一方的な行動は全員の同意で行われた。"]},{en:"He made a unilateral decision to leave the project without discussion.",ja:"彼は議論なしにプロジェクトから去るという一方的な決定を下した。",wrong:["一方的な決定は議論の後である。","彼は去る前にチーム全体と相談した。","一方的な決定はすべての当事者の同意を含んだ。"]}]},{word:"utilitarian",meaning:"功利主義の",example:"A utilitarian approach weighs overall benefit against cost.",category:"society",difficulty:6,examples:[{en:"The utilitarian approach focuses on maximizing the greatest good for the greatest number.",ja:"功利主義的アプローチは最大多数の最大幸福を最大化することに焦点を当てている。",wrong:["功利主義的アプローチは個人の権利を最大化する。","最大多数の最大幸福は功利主義ではない。","功利主義は少数者の利益を優先する。"]},{en:"Her utilitarian design philosophy emphasizes function over form.",ja:"彼女の功利主義的デザイン哲学は形式よりも機能を強調する。",wrong:["功利主義的デザインは形式を強調する。","機能を強調することは功利主義ではない。","彼女のデザイン哲学は美しさだけを優先する。"]},{en:"Utilitarian ethics considers the consequences of actions to determine morality.",ja:"功利主義倫理は道徳性を決定するために行動の結果を考慮する。",wrong:["功利主義倫理は結果を無視する。","結果を考慮することは道徳性ではない。","功利主義は行動の意図のみに焦点を当てる。"]}]},{word:"variance",meaning:"分散",example:"The model explains 85 percent of the variance in the data.",category:"science",difficulty:5,examples:[{en:"The variance in test scores showed a wide range of student performance.",ja:"テストスコアの分散は学生のパフォーマンスの広い範囲を示した。",wrong:["分散はテストスコアがすべて同じであることを示す。","学生のパフォーマンスは分散がない。","分散は限られた範囲を示した。"]},{en:"Statistical variance is a measure of how spread out data points are.",ja:"統計的分散はデータポイントがどの程度広がっているかの尺度である。",wrong:["分散はデータポイントがどの程度近いかを測定する。","分散はデータの中心値である。","統計的分散はデータの範囲を測定しない。"]},{en:"The budget variance indicated that actual expenses exceeded projections.",ja:"予算の分散は実際の支出が予測を超えたことを示した。",wrong:["予算分散は実際の支出が予測より少なかった。","分散は予測と実際の支出が同じであることを示す。","予算の分散は支出を測定しない。"]}]},{word:"vector",meaning:"ベクトル、媒介",example:"Mosquitoes act as vectors for malaria.",category:"science",difficulty:5,examples:[{en:"In physics, a vector has both magnitude and direction.",ja:"物理学では、ベクトルは大きさと方向の両方を持つ。",wrong:["物理学では、ベクトルは方向だけを持つ。","ベクトルは大きさを持たない。","ベクトルは大きさと方向がない。"]},{en:"Mosquitoes serve as vectors for transmitting diseases like malaria.",ja:"蚊はマラリアのような病気を伝染させるための媒介者として機能する。",wrong:["蚊は病気を媒介しない。","病気の媒介者は蚊ではない。","蚊はマラリアを治療する媒介者である。"]},{en:"The engineer calculated the force vector to determine the resultant force.",ja:"エンジニアは合力を決定するために力のベクトルを計算した。",wrong:["力のベクトルは合力を示さない。","ベクトルの計算は結果を決定しない。","エンジニアはベクトルを使わずに合力を計算した。"]}]},{word:"vernacular",meaning:"現地語、日常語",example:"The author wrote in the vernacular rather than Latin.",category:"culture",difficulty:6,examples:[{en:"The author wrote in the vernacular to make her work accessible to common people.",ja:"著者は彼女の作品を一般の人々がアクセスしやすくするために日常語で書いた。",wrong:["著者は専門的な言語を使って一般人に分かりにくくした。","日常語で書くことは作品を理解しにくくした。","著者は現地語を避けて作品を書いた。"]},{en:"The vernacular architecture reflects the local building traditions and materials.",ja:"現地の建築は地元の建築伝統と材料を反映している。",wrong:["現地建築は地元の伝統を無視する。","建築の伝統は現地の材料を反映しない。","現地建築は外国の建築様式を使用する。"]},{en:"Speaking in the vernacular helped the politician connect with rural voters.",ja:"日常語で話すことは政治家が農村の有権者と結びつくのを助けた。",wrong:["日常語を使うことは有権者から遠ざかった。","政治家は専門用語を使って有権者と結びついた。","日常語での話は農村の有権者を混乱させた。"]}]},{word:"viscosity",meaning:"粘性",example:"Honey has a much higher viscosity than water.",category:"science",difficulty:5,examples:[{en:"The viscosity of honey is much higher than that of water.",ja:"蜂蜜の粘性は水のものより非常に高い。",wrong:["蜂蜜の粘性は水と同じである。","粘性が高いほど流れやすい。","水は蜂蜜より粘性が高い。"]},{en:"Engine oil viscosity affects how well it protects the engine at different temperatures.",ja:"エンジンオイルの粘性は異なる温度でエンジンを保護する程度に影響する。",wrong:["粘性はエンジンの保護に影響しない。","エンジンオイルの粘性は温度に影響されない。","粘性はエンジンのパフォーマンスに無関係である。"]},{en:"The high viscosity of lava allows it to flow slowly down the volcano.",ja:"溶岩の高い粘性は火山からゆっくり流れることができる。",wrong:["溶岩の粘性が高いほど速く流れる。","粘性は溶岩の流れを決定しない。","低粘性の溶岩がゆっくり流れる。"]}]},{word:"volition",meaning:"意志",example:"She made the decision of her own volition.",category:"society",difficulty:6,examples:[{en:"He made the decision of his own volition without any external pressure.",ja:"彼は外部の圧力なしに自分の意志で決定を下した。",wrong:["彼の意志は外部の圧力に依存していた。","自分の意志で決定することは外部の圧力を意味する。","意志のない決定は圧力によるものである。"]},{en:"Acting of one's own volition means taking responsibility for your choices.",ja:"自分の意志で行動することは自分の選択に責任を持つことを意味する。",wrong:["自分の意志で行動することは責任を回避することである。","意志のある行動は責任を持たない。","自分の意志で行動することは選択を放棄することである。"]},{en:"She left the organization of her own volition, not due to dismissal.",ja:"彼女は解雇のためではなく、自分の意志で組織を去った。",wrong:["彼女は解雇のために組織を去った。","自分の意志で去ることは解雇を意味する。","彼女は意志に反して組織を去った。"]}]},{word:"wavelength",meaning:"波長",example:"Different colours correspond to different wavelengths of light.",category:"science",difficulty:5,examples:[{en:"Different colors of light have different wavelengths in the electromagnetic spectrum.",ja:"異なる光の色は電磁スペクトム内で異なる波長を持つ。",wrong:["すべての光の色は同じ波長を持つ。","波長は光の色と関係がない。","電磁スペクトラムは波長を決定しない。"]},{en:"The wavelength of radio waves is much longer than that of visible light.",ja:"電波の波長は可視光のものより非常に長い。",wrong:["電波の波長は可視光より短い。","ラジオ波と可視光の波長は同じである。","波長は電波と光に影響しない。"]},{en:"We're on the same wavelength means we understand each other well.",ja:"同じ波長の上にいるとは、互いに良く理解していることを意味する。",wrong:["同じ波長にいることは互いに理解していないことを意味する。","波長は人間関係と関係がない。","異なる波長にいることは良い理解を意味する。"]}]},{word:"xenophobia",meaning:"外国人嫌悪",example:"Xenophobia has increased in times of economic hardship.",category:"society",difficulty:6,examples:[{en:"The rise of xenophobia in the country has made it difficult for immigrants to find acceptance.",ja:"その国での外国人嫌悪の高まりにより、移民が受け入れられることが難しくなった。",wrong:["その国での外国人への好意が移民を簡単に受け入れた。","外国人嫌悪により、移民はすぐに市民権を得た。","その国は外国人嫌悪のため、多くの観光客を歓迎した。"]},{en:"Xenophobia often stems from fear and misunderstanding of different cultures.",ja:"外国人嫌悪はしばしば異なる文化への恐怖と誤解から生じる。",wrong:["外国人嫌悪は異文化への深い理解から生じる。","外国人嫌悪は外国人との友情を促進する。","外国人嫌悪により、多くの国際交流が増加した。"]},{en:"Many countries have passed laws to combat xenophobia and discrimination.",ja:"多くの国は外国人嫌悪と差別に対抗するための法律を制定している。",wrong:["多くの国は外国人嫌悪を奨励する法律を制定している。","外国人嫌悪に対する法律はどの国にも存在しない。","法律により外国人嫌悪がさらに増加した。"]}]},{word:"precipitate",meaning:"促進する、沈殿させる",example:"The crisis precipitated a change in government policy.",category:"science",difficulty:5,examples:[{en:"The heavy rain will precipitate flooding in low-lying areas.",ja:"大雨は低地での洪水を促進するだろう。",wrong:["大雨は洪水を防ぐだろう。","大雨は土地を高くさせるだろう。","大雨は低地での乾燥を促進するだろう。"]},{en:"In chemistry, salt will precipitate out of solution when cooled.",ja:"化学では、塩は冷やされると溶液から沈殿する。",wrong:["塩は加熱されると溶液から沈殿する。","塩は溶液にさらに溶ける。","冷却により塩はより透明になる。"]},{en:"His reckless actions precipitated a crisis within the organization.",ja:"彼の無分別な行動は組織内の危機を引き起こした。",wrong:["彼の慎重な行動は危機を促進した。","彼の行動は組織の安定をもたらした。","彼の行動は何の影響も与えなかった。"]}]},{word:"axiom",meaning:"公理",example:"The proof begins with a set of axioms.",category:"science",difficulty:6,examples:[{en:"In mathematics, the axiom of choice is a fundamental principle.",ja:"数学では、選択公理は基本的な原理である。",wrong:["選択公理は数学では使われない。","選択公理は数学における推測である。","選択公理は最近になって否定された。"]},{en:"Euclid's axioms form the foundation of classical geometry.",ja:"ユークリッドの公理は古典幾何学の基礎を形成する。",wrong:["ユークリッドの公理は幾何学では証明される必要がある。","ユークリッドの公理は古典幾何学では使われない。","ユークリッドの公理は最近発見された。"]},{en:"The axiom that all people are equal is central to democratic philosophy.",ja:"すべての人が平等であるという公理は民主的哲学の中心である。",wrong:["人間の平等は哲学的な公理ではない。","民主主義は人間の不平等に基づいている。","この公理は民主主義と関係がない。"]}]},{word:"pedagogue",meaning:"教育者",example:"Socrates is regarded as one of history's greatest pedagogues.",category:"history",difficulty:6},{word:"ameliorate",meaning:"改善する",example:"Policies were introduced to ameliorate living conditions.",category:"society",difficulty:6,examples:[{en:"The new policy aims to ameliorate living conditions for low-income families.",ja:"新しい政策は低所得家族の生活条件を改善することを目指している。",wrong:["新しい政策は低所得家族の状況を悪化させる。","新しい政策は生活条件に変化をもたらさない。","新しい政策は貧困を増加させる。"]},{en:"Regular exercise can ameliorate symptoms of depression.",ja:"定期的な運動は抑うつの症状を改善することができる。",wrong:["運動は抑うつの症状を悪化させる。","運動は精神的健康に影響しない。","運動は抑うつをより重くする。"]},{en:"The government implemented reforms to ameliorate the environmental crisis.",ja:"政府は環境危機を改善するための改革を実施した。",wrong:["政府は環境危機を深刻にする改革を行った。","政府は環境問題に対処しない。","改革は環境をさらに汚染させた。"]}]}]],91524)}]);